    const group_side = if (parts[3].len > 0) try alloc.dupe(u8, parts[3]) else null;
    errdefer if (group_side) |value| alloc.free(value);
    const measure_side = if (parts[4].len > 0) try alloc.dupe(u8, parts[4]) else null;
    errdefer if (measure_side) |value| alloc.free(value);

    const group_by = try alloc.alloc([]u8, group_count);
    errdefer if (group_by.len > 0) alloc.free(group_by);
    var group_initialized: usize = 0;
    errdefer {
        for (group_by[0..group_initialized]) |field| alloc.free(field);
    }
    for (group_by, 0..) |*field, i| {
        field.* = try alloc.dupe(u8, parts[pos + i]);
        group_initialized += 1;
    }
    pos += group_count;

    const histogram_interval = std.fmt.parseFloat(f64, parts[pos]) catch return error.InvalidAlgebraicTensorExpr;
    pos += 1;
    const histogram_field = if (parts[pos].len > 0) try alloc.dupe(u8, parts[pos]) else null;
    errdefer if (histogram_field) |value| alloc.free(value);
    pos += 1;
    const histogram_role = if (parts[pos].len > 0)
        std.meta.stringToEnum(fact_mod.Role, parts[pos]) orelse return error.InvalidAlgebraicTensorExpr
    else
        null;
    pos += 1;
    const range_field = if (parts[pos].len > 0) try alloc.dupe(u8, parts[pos]) else null;
    errdefer if (range_field) |value| alloc.free(value);
    pos += 1;
    const range_role = if (parts[pos].len > 0)
        std.meta.stringToEnum(fact_mod.Role, parts[pos]) orelse return error.InvalidAlgebraicTensorExpr
    else
        null;
    pos += 1;
    const range_kind = if (parts[pos].len > 0)
        std.meta.stringToEnum(DerivedJoinRangeKind, parts[pos]) orelse return error.InvalidAlgebraicTensorExpr
    else
        null;
    pos += 1;
    const range_start = if (parts[pos].len > 0) try alloc.dupe(u8, parts[pos]) else null;
    errdefer if (range_start) |value| alloc.free(value);
    pos += 1;
    const range_end = if (parts[pos].len > 0) try alloc.dupe(u8, parts[pos]) else null;
    errdefer if (range_end) |value| alloc.free(value);
    pos += 1;
    const range_inclusive_start = parseMetadataBool(parts[pos]) orelse return error.InvalidAlgebraicTensorExpr;
    pos += 1;
    const range_inclusive_end = parseMetadataBool(parts[pos]) orelse return error.InvalidAlgebraicTensorExpr;
    pos += 1;
    const time_field = if (parts[pos].len > 0) try alloc.dupe(u8, parts[pos]) else null;
    errdefer if (time_field) |value| alloc.free(value);
    pos += 1;
    const time_bucket = if (parts[pos].len > 0) try alloc.dupe(u8, parts[pos]) else null;
    errdefer if (time_bucket) |value| alloc.free(value);
    pos += 1;
    const measure = if (parts[pos].len > 0) try alloc.dupe(u8, parts[pos]) else null;
    errdefer if (measure) |value| alloc.free(value);
    pos += 1;
    const constraint_count = parseMetadataCount(parts[pos], "constraints:") orelse return error.InvalidAlgebraicTensorExpr;
    pos += 1;
    if (parts.len != pos + constraint_count * 2) return error.InvalidAlgebraicTensorExpr;

    const constraints = try alloc.alloc(ir.Constraint, constraint_count);
    errdefer if (constraints.len > 0) alloc.free(constraints);
    var constraints_initialized: usize = 0;
    errdefer {
        for (constraints[0..constraints_initialized]) |constraint| {
            alloc.free(@constCast(constraint.field));
            alloc.free(@constCast(constraint.value));
        }
    }
    for (constraints) |*constraint| {
        const field = try alloc.dupe(u8, parts[pos]);
        var field_moved = false;
        errdefer if (!field_moved) alloc.free(field);
        const value = try alloc.dupe(u8, parts[pos + 1]);
        constraint.* = .{
            .field = field,
            .value = value,
        };
        field_moved = true;
        constraints_initialized += 1;
        pos += 2;
    }

    return .{
        .request = .{
            .join = .{
                .name = join_name,
                .kind = join_kind,
                .group_side = group_side,
                .measure_side = measure_side,
            },
            .op = op,
            .group_by = group_by,
            .histogram_field = histogram_field,
            .histogram_role = histogram_role,
            .histogram_interval = histogram_interval,
            .range_field = range_field,
            .range_role = range_role,
            .range_kind = range_kind,
            .range_start = range_start,
            .range_end = range_end,
            .range_inclusive_start = range_inclusive_start,
            .range_inclusive_end = range_inclusive_end,
            .time_field = time_field,
            .time_bucket = time_bucket,
            .measure = measure,
            .constraints = constraints,
        },
        .join_name = join_name,
        .group_side = group_side,
        .measure_side = measure_side,
        .group_by = group_by,
        .histogram_field = histogram_field,
        .range_field = range_field,
        .range_start = range_start,
        .range_end = range_end,
        .time_field = time_field,
        .time_bucket = time_bucket,
        .measure = measure,
        .constraints = constraints,
    };
}

pub fn docFactBucketFoldMetadataAlloc(alloc: Allocator, request: DocFactBucketFoldRequest) ![]u8 {
    var parts = std.ArrayListUnmanaged([]const u8).empty;
    defer parts.deinit(alloc);
    var owned = std.ArrayListUnmanaged([]u8).empty;
    defer {
        for (owned.items) |item| alloc.free(item);
        owned.deinit(alloc);
    }

    const interval = try std.fmt.allocPrint(alloc, "{d}", .{request.histogram_interval});
    try appendOwnedMetadataToken(alloc, &parts, &owned, interval);
    try parts.insertSlice(alloc, 0, &.{
        "docfact-bucket-fold:v1",
        @tagName(request.kind),
        @tagName(request.op),
        request.bucket_field,
        @tagName(request.bucket_role),
    });
    try parts.appendSlice(alloc, &.{
        request.range_start orelse "",
        request.range_end orelse "",
        if (request.range_inclusive_start) "1" else "0",
        if (request.range_inclusive_end) "1" else "0",
        request.measure orelse "",
    });
    const constraint_count = try std.fmt.allocPrint(alloc, "constraints:{d}", .{request.constraints.len});
    try appendOwnedMetadataToken(alloc, &parts, &owned, constraint_count);
    for (request.constraints) |constraint| {
        try parts.appendSlice(alloc, &.{ constraint.field, constraint.value });
    }
    return try token.canonicalTupleAlloc(alloc, parts.items);
}

