fn parseMetadataBool(text: []const u8) ?bool {
    if (std.mem.eql(u8, text, "1")) return true;
    if (std.mem.eql(u8, text, "0")) return false;
    return null;
}

fn parseMetadataCount(text: []const u8, prefix: []const u8) ?usize {
    if (!std.mem.startsWith(u8, text, prefix)) return null;
    return std.fmt.parseUnsigned(usize, text[prefix.len..], 10) catch null;
}

fn appendOwnedMetadataToken(
    alloc: Allocator,
    parts: *std.ArrayListUnmanaged([]const u8),
    owned: *std.ArrayListUnmanaged([]u8),
    item: []u8,
) !void {
    var owned_by_list = false;
    errdefer if (!owned_by_list) alloc.free(item);
    try owned.append(alloc, item);
    owned_by_list = true;
    try parts.append(alloc, item);
}

