const AdaptiveMaterializationSpec = struct {
    name: []u8,
    recommendation: []u8,
    op: algebra.Op,
    measure: ?[]u8 = null,
    group_by: [][]u8 = &.{},
    time: ?[]u8 = null,
    bucket: ?[]u8 = null,
    join: ?[]u8 = null,
    group_side: ?[]u8 = null,
    measure_side: ?[]u8 = null,
    path_promotion_path: ?[]u8 = null,
    path_promotion_kind: ?pathfact_mod.Kind = null,
    path_promotion_reason: ?[]u8 = null,

    fn deinit(self: *AdaptiveMaterializationSpec, alloc: Allocator) void {
        alloc.free(self.name);
        alloc.free(self.recommendation);
        if (self.measure) |value| alloc.free(value);
        for (self.group_by) |value| alloc.free(value);
        if (self.group_by.len > 0) alloc.free(self.group_by);
        if (self.time) |value| alloc.free(value);
        if (self.bucket) |value| alloc.free(value);
        if (self.join) |value| alloc.free(value);
        if (self.group_side) |value| alloc.free(value);
        if (self.measure_side) |value| alloc.free(value);
        if (self.path_promotion_path) |value| alloc.free(value);
        if (self.path_promotion_reason) |value| alloc.free(value);
        self.* = undefined;
    }

    fn clone(self: AdaptiveMaterializationSpec, alloc: Allocator) !AdaptiveMaterializationSpec {
        var out = AdaptiveMaterializationSpec{
            .name = &.{},
            .recommendation = &.{},
            .op = self.op,
            .path_promotion_kind = self.path_promotion_kind,
        };
        errdefer out.deinit(alloc);
        out.name = try alloc.dupe(u8, self.name);
        out.recommendation = try alloc.dupe(u8, self.recommendation);
        if (self.measure) |value| out.measure = try alloc.dupe(u8, value);
        if (self.group_by.len > 0) {
            out.group_by = try alloc.alloc([]u8, self.group_by.len);
            for (out.group_by) |*value| value.* = &.{};
            for (self.group_by, 0..) |value, i| out.group_by[i] = try alloc.dupe(u8, value);
        }
        if (self.time) |value| out.time = try alloc.dupe(u8, value);
        if (self.bucket) |value| out.bucket = try alloc.dupe(u8, value);
        if (self.join) |value| out.join = try alloc.dupe(u8, value);
        if (self.group_side) |value| out.group_side = try alloc.dupe(u8, value);
        if (self.measure_side) |value| out.measure_side = try alloc.dupe(u8, value);
        if (self.path_promotion_path) |value| out.path_promotion_path = try alloc.dupe(u8, value);
        if (self.path_promotion_reason) |value| out.path_promotion_reason = try alloc.dupe(u8, value);
        return out;
    }
};

