const BatchMaintenanceContext = struct {
    ready_specs: []AdaptiveMaterializationSpec = &.{},
    disabled_recommendations: std.StringHashMapUnmanaged(void) = .empty,
    dirty_path_promotion_dictionaries: std.StringHashMapUnmanaged(void) = .empty,
    tensor_accumulator: AppendOnlyAccumulator = .{},
    coalesce_tensor_deltas: bool = false,

    fn deinit(self: *BatchMaintenanceContext, alloc: Allocator) void {
        for (self.ready_specs) |*spec| spec.deinit(alloc);
        if (self.ready_specs.len > 0) alloc.free(self.ready_specs);
        var disabled_it = self.disabled_recommendations.keyIterator();
        while (disabled_it.next()) |key| alloc.free(key.*);
        self.disabled_recommendations.deinit(alloc);
        var dirty_it = self.dirty_path_promotion_dictionaries.keyIterator();
        while (dirty_it.next()) |key| alloc.free(key.*);
        self.dirty_path_promotion_dictionaries.deinit(alloc);
        self.tensor_accumulator.deinit(alloc);
        self.* = .{};
    }

    fn isDisabled(self: *const BatchMaintenanceContext, recommendation: []const u8) bool {
        return self.disabled_recommendations.contains(recommendation);
    }

    fn disable(self: *BatchMaintenanceContext, alloc: Allocator, recommendation: []const u8) !void {
        if (self.disabled_recommendations.contains(recommendation)) return;
        const owned = try alloc.dupe(u8, recommendation);
        errdefer alloc.free(owned);
        try self.disabled_recommendations.put(alloc, owned, {});
    }

    fn markPathPromotionDictionaryDirty(self: *BatchMaintenanceContext, alloc: Allocator, materialization_id: []const u8) !void {
        if (self.dirty_path_promotion_dictionaries.contains(materialization_id)) return;
        const owned = try alloc.dupe(u8, materialization_id);
        errdefer alloc.free(owned);
        try self.dirty_path_promotion_dictionaries.put(alloc, owned, {});
    }

    fn pathPromotionDictionaryDirty(self: *const BatchMaintenanceContext, materialization_id: []const u8) bool {
        return self.dirty_path_promotion_dictionaries.contains(materialization_id);
    }
};

