const ProjectedFact = struct {
    parts: [][]u8,

    fn deinit(self: *ProjectedFact, alloc: Allocator) void {
        for (self.parts) |part| alloc.free(part);
        if (self.parts.len > 0) alloc.free(self.parts);
        self.* = undefined;
    }

    fn decode(alloc: Allocator, payload: []const u8) !ProjectedFact {
        const parts = try token.decodeTupleAlloc(alloc, payload);
        errdefer {
            for (parts) |part| alloc.free(part);
            if (parts.len > 0) alloc.free(parts);
        }
        if (parts.len == 0 or !std.mem.eql(u8, parts[0], "f1")) return error.InvalidAlgebraicFact;
        return .{ .parts = parts };
    }

    fn groupKeyAlloc(self: ProjectedFact, alloc: Allocator, fields: []const []const u8) ![]u8 {
        var values = try alloc.alloc([]const u8, fields.len);
        defer alloc.free(values);
        for (fields, 0..) |field_name, i| {
            values[i] = self.findGroupToken(field_name) orelse return error.MissingField;
        }
        return try token.canonicalTupleAlloc(alloc, values);
    }

    fn measureAlloc(self: ProjectedFact, alloc: Allocator, field_name: []const u8) !?MeasureValue {
        var pos: usize = 1;
        while (pos < self.parts.len) {
            const kind = self.parts[pos];
            if (std.mem.eql(u8, kind, "m")) {
                if (pos + 3 >= self.parts.len) return error.InvalidAlgebraicFact;
                if (std.mem.eql(u8, self.parts[pos + 1], field_name)) {
                    return .{
                        .raw = try alloc.dupe(u8, self.parts[pos + 2]),
                        .support_token = try alloc.dupe(u8, self.parts[pos + 3]),
                    };
                }
                pos += 4;
            } else if (std.mem.eql(u8, kind, "g") or std.mem.eql(u8, kind, "t")) {
                if (pos + 2 >= self.parts.len) return error.InvalidAlgebraicFact;
                pos += 3;
            } else {
                return error.InvalidAlgebraicFact;
            }
        }
        return null;
    }

    fn timeText(self: ProjectedFact, field_name: []const u8) !?[]const u8 {
        var pos: usize = 1;
        while (pos < self.parts.len) {
            const kind = self.parts[pos];
            if (std.mem.eql(u8, kind, "t")) {
                if (pos + 2 >= self.parts.len) return error.InvalidAlgebraicFact;
                if (std.mem.eql(u8, self.parts[pos + 1], field_name)) return self.parts[pos + 2];
                pos += 3;
            } else if (std.mem.eql(u8, kind, "g")) {
                if (pos + 2 >= self.parts.len) return error.InvalidAlgebraicFact;
                pos += 3;
            } else if (std.mem.eql(u8, kind, "m")) {
                if (pos + 3 >= self.parts.len) return error.InvalidAlgebraicFact;
                pos += 4;
            } else {
                return error.InvalidAlgebraicFact;
            }
        }
        return null;
    }

    fn findGroupToken(self: ProjectedFact, field_name: []const u8) ?[]const u8 {
        var pos: usize = 1;
        while (pos < self.parts.len) {
            const kind = self.parts[pos];
            if (std.mem.eql(u8, kind, "g")) {
                if (pos + 2 >= self.parts.len) return null;
                if (std.mem.eql(u8, self.parts[pos + 1], field_name)) return self.parts[pos + 2];
                pos += 3;
            } else if (std.mem.eql(u8, kind, "t")) {
                if (pos + 2 >= self.parts.len) return null;
                pos += 3;
            } else if (std.mem.eql(u8, kind, "m")) {
                if (pos + 3 >= self.parts.len) return null;
                pos += 4;
            } else {
                return null;
            }
        }
        return null;
    }

    fn groupTokenConstraintMatch(self: ProjectedFact, field_name: []const u8, scalar: []const u8) !?bool {
        var pos: usize = 1;
        var saw_field = false;
        while (pos < self.parts.len) {
            const kind = self.parts[pos];
            if (std.mem.eql(u8, kind, "g")) {
                if (pos + 2 >= self.parts.len) return error.InvalidAlgebraicFact;
                if (std.mem.eql(u8, self.parts[pos + 1], field_name)) {
                    saw_field = true;
                    if (!std.mem.eql(u8, self.parts[pos + 2], scalar)) return false;
                }
                pos += 3;
            } else if (std.mem.eql(u8, kind, "t")) {
                if (pos + 2 >= self.parts.len) return error.InvalidAlgebraicFact;
                pos += 3;
            } else if (std.mem.eql(u8, kind, "m")) {
                if (pos + 3 >= self.parts.len) return error.InvalidAlgebraicFact;
                pos += 4;
            } else {
                return error.InvalidAlgebraicFact;
            }
        }
        return if (saw_field) true else null;
    }
};

