fn containsDocId(doc_ids: []const []const u8, expected: []const u8) bool {
    for (doc_ids) |doc_id| {
        if (std.mem.eql(u8, doc_id, expected)) return true;
    }
    return false;
}

fn containsOrdinal(ordinals: []const doc_set.DocOrdinal, expected: doc_set.DocOrdinal) bool {
    for (ordinals) |ordinal| {
        if (ordinal == expected) return true;
    }
    return false;
}

fn ordinalComponent(ordinal: doc_set.DocOrdinal) [4]u8 {
    var out: [4]u8 = undefined;
    std.mem.writeInt(u32, &out, ordinal, .big);
    return out;
}

const SymbolCache = struct {
    entries: std.StringHashMapUnmanaged([]u8) = .empty,

    fn deinit(self: *SymbolCache, alloc: Allocator) void {
        var it = self.entries.iterator();
        while (it.next()) |entry| {
            alloc.free(entry.key_ptr.*);
            alloc.free(entry.value_ptr.*);
        }
        self.entries.deinit(alloc);
        self.* = .{};
    }

    fn resolve(
        self: *SymbolCache,
        index: *Index,
        txn: anytype,
        id: []const u8,
    ) !?[]const u8 {
        if (self.entries.get(id)) |canonical| {
            index.symbol_cache_hits += 1;
            return canonical;
        }
        index.symbol_cache_misses += 1;
        const canonical = (try index.resolveSymbolAlloc(txn, id)) orelse return null;
        errdefer index.alloc.free(canonical);
        const owned_id = try index.alloc.dupe(u8, id);
        errdefer index.alloc.free(owned_id);
        try self.entries.put(index.alloc, owned_id, canonical);
        return canonical;
    }
};

// Running value for one group in a single-law fold. The additive group laws
// (count/sum/sumsquares/avg) accumulate as native numbers and are formatted to
// text exactly once in entriesAlloc, instead of round-tripping the running
// total through decimal text on every contribution. Because encode/parse for
// i64 and f64 ("{d}") round-trip exactly and contributions are applied in the
// same order, the formatted result is byte-identical to the previous text
// merge. The remaining laws (min/max, booleans, set/tuple, timestamps) keep the
// text-merge path, where order/text identity matters.
const FoldValue = union(enum) {
    int: i64,
    float: f64,
    avg: algebra.AvgState,
    text: ?[]u8,

    fn initFor(law_id: law_mod.Id) FoldValue {
        return switch (law_id) {
            .count => .{ .int = 0 },
            .sum, .sumsquares => .{ .float = 0 },
            .avg => .{ .avg = .{} },
            else => .{ .text = null },
        };
    }
};

const DerivedJoinFoldAccumulator = struct {
    values: std.StringHashMapUnmanaged(FoldValue) = .empty,

    fn deinit(self: *@This(), alloc: Allocator) void {
        var it = self.values.iterator();
        while (it.next()) |entry| {
            alloc.free(entry.key_ptr.*);
            switch (entry.value_ptr.*) {
                .text => |value| if (value) |bytes| alloc.free(bytes),
                else => {},
            }
        }
        self.values.deinit(alloc);
        self.* = .{};
    }

    fn add(
        self: *@This(),
        alloc: Allocator,
        group_key: []const u8,
        law_id: law_mod.Id,
        contribution: []const u8,
    ) !void {
        const gop = try self.values.getOrPut(alloc, group_key);
        if (gop.found_existing) {
            // The caller owns the transient group key. The map already owns
            // the existing key.
        } else {
            errdefer _ = self.values.remove(group_key);
            gop.key_ptr.* = try alloc.dupe(u8, group_key);
            gop.value_ptr.* = FoldValue.initFor(law_id);
        }
        switch (gop.value_ptr.*) {
            .int => |*running| running.* += try algebra.parseI64(contribution),
            .float => |*running| running.* += try algebra.parseF64(contribution),
            .avg => |*running| {
                const delta = try algebra.parseAvg(contribution);
                running.sum += delta.sum;
                running.count += delta.count;
            },
            .text => |*running| {
                const next = try tensor_mod.mergeOneSlotValuesAlloc(alloc, law_id, running.*, contribution);
                if (running.*) |old| alloc.free(old);
                running.* = next;
            },
        }
    }

    fn entriesAlloc(self: *@This(), alloc: Allocator) ![]FoldEntry {
        var count: usize = 0;
        var count_it = self.values.iterator();
        while (count_it.next()) |entry| {
            switch (entry.value_ptr.*) {
                .text => |value| if (value != null) {
                    count += 1;
                },
                else => count += 1,
            }
        }
        const entries = try alloc.alloc(FoldEntry, count);
        var initialized: usize = 0;
        errdefer {
            for (entries[0..initialized]) |*entry| entry.deinit(alloc);
            if (entries.len > 0) alloc.free(entries);
        }
        var it = self.values.iterator();
        while (it.next()) |entry| {
            const value_bytes = switch (entry.value_ptr.*) {
                .int => |running| try algebra.encodeI64Alloc(alloc, running),
                .float => |running| try algebra.encodeF64Alloc(alloc, running),
                .avg => |running| try algebra.encodeAvgAlloc(alloc, running),
                .text => |running| try alloc.dupe(u8, running orelse continue),
            };
            errdefer alloc.free(value_bytes);
            entries[initialized] = .{
                .group_key = try alloc.dupe(u8, entry.key_ptr.*),
                .value = value_bytes,
            };
            initialized += 1;
        }
        return entries;
    }
};

const PendingSlot = struct {
    slot_idx: usize,
    law_id: law_mod.Id,
    delta: []u8,

    fn deinit(self: *PendingSlot, alloc: Allocator) void {
        alloc.free(self.delta);
        self.* = undefined;
    }
};

const PendingRow = struct {
    key: []u8,
    law_ids: []law_mod.Id,
    row: ?[]u8 = null,

    fn deinit(self: *PendingRow, alloc: Allocator) void {
        alloc.free(self.key);
        if (self.law_ids.len > 0) alloc.free(self.law_ids);
        if (self.row) |bytes| alloc.free(bytes);
        self.* = undefined;
    }

    fn applyDelta(
        self: *PendingRow,
        alloc: Allocator,
        slot_idx: usize,
        law_id: law_mod.Id,
        delta: []const u8,
    ) !void {
        const next = (try tensor_mod.applyRowSlotToBytesAlloc(alloc, self.row, self.law_ids, slot_idx, law_id, delta, false)) orelse return error.InvalidAlgebraicTensorRow;
        if (self.row) |old| alloc.free(old);
        self.row = next;
    }

    fn slotDeltasAlloc(self: *PendingRow, alloc: Allocator) ![]PendingSlot {
        const row_bytes = self.row orelse return try alloc.alloc(PendingSlot, 0);
        var row = try tensor_mod.rowFromBytesOrLayoutAlloc(alloc, row_bytes, self.law_ids);
        defer row.deinit(alloc);
        var out = std.ArrayListUnmanaged(PendingSlot).empty;
        errdefer {
            for (out.items) |*slot| slot.deinit(alloc);
            out.deinit(alloc);
        }
        for (row.slots, 0..) |slot, slot_idx| {
            const value = slot.value orelse continue;
            try out.append(alloc, .{
                .slot_idx = slot_idx,
                .law_id = slot.law_id,
                .delta = try alloc.dupe(u8, value),
            });
        }
        return try out.toOwnedSlice(alloc);
    }
};

const PendingSupport = struct {
    key: []u8,
    row: ?[]u8 = null,

    fn deinit(self: *PendingSupport, alloc: Allocator) void {
        alloc.free(self.key);
        if (self.row) |bytes| alloc.free(bytes);
        self.* = undefined;
    }

    fn applyDelta(self: *PendingSupport, alloc: Allocator, delta: i64) !void {
        var mutation = try tensor_mod.applyCountSupportDeltaAlloc(alloc, self.row, delta);
        defer mutation.deinit(alloc);
        if (self.row) |old| alloc.free(old);
        self.row = if (mutation.encoded) |bytes| blk: {
            const owned = try alloc.dupe(u8, bytes);
            break :blk owned;
        } else null;
    }
};

const AppendOnlyAccumulator = struct {
    expression_rows: std.StringHashMapUnmanaged(PendingRow) = .empty,
    support_counts: std.StringHashMapUnmanaged(PendingSupport) = .empty,

    fn entryCount(self: *const AppendOnlyAccumulator) usize {
        return self.expression_rows.count() + self.support_counts.count();
    }

    fn estimatedBytes(self: *const AppendOnlyAccumulator) u64 {
        var total: u64 = 0;
        var expression_it = self.expression_rows.iterator();
        while (expression_it.next()) |entry| {
            const pending = entry.value_ptr;
            total +|= @as(u64, @intCast(pending.key.len));
            total +|= @as(u64, @intCast(pending.law_ids.len * @sizeOf(law_mod.Id)));
            if (pending.row) |bytes| total +|= @as(u64, @intCast(bytes.len));
            total +|= 64;
        }

        var support_it = self.support_counts.iterator();
        while (support_it.next()) |entry| {
            const pending = entry.value_ptr;
            total +|= @as(u64, @intCast(pending.key.len));
            if (pending.row) |bytes| total +|= @as(u64, @intCast(bytes.len));
            total +|= 64;
        }
        return total;
    }

    fn deinit(self: *AppendOnlyAccumulator, alloc: Allocator) void {
        var expression_it = self.expression_rows.iterator();
        while (expression_it.next()) |entry| entry.value_ptr.deinit(alloc);
        self.expression_rows.deinit(alloc);

        var support_it = self.support_counts.iterator();
        while (support_it.next()) |entry| entry.value_ptr.deinit(alloc);
        self.support_counts.deinit(alloc);
        self.* = .{};
    }

    fn expressionRow(self: *AppendOnlyAccumulator, alloc: Allocator, owned_key: []u8, law_ids: []const law_mod.Id) !*PendingRow {
        const gop = try self.expression_rows.getOrPut(alloc, owned_key);
        if (gop.found_existing) {
            alloc.free(owned_key);
            if (gop.value_ptr.law_ids.len != law_ids.len) return error.InvalidAlgebraicConfig;
            for (gop.value_ptr.law_ids, law_ids) |existing, expected| {
                if (existing != expected) return error.InvalidAlgebraicConfig;
            }
            return gop.value_ptr;
        }
        var key_owned = true;
        errdefer if (key_owned) alloc.free(owned_key);
        errdefer _ = self.expression_rows.remove(owned_key);
        const law_ids_owned = try alloc.dupe(law_mod.Id, law_ids);
        errdefer alloc.free(law_ids_owned);
        gop.key_ptr.* = owned_key;
        gop.value_ptr.* = .{
            .key = owned_key,
            .law_ids = law_ids_owned,
        };
        key_owned = false;
        return gop.value_ptr;
    }

    fn addSupport(self: *AppendOnlyAccumulator, alloc: Allocator, owned_key: []u8, delta: i64) !void {
        const gop = try self.support_counts.getOrPut(alloc, owned_key);
        if (gop.found_existing) {
            alloc.free(owned_key);
            try gop.value_ptr.applyDelta(alloc, delta);
            return;
        }
        var key_owned = true;
        errdefer if (key_owned) alloc.free(owned_key);
        errdefer _ = self.support_counts.remove(owned_key);
        gop.key_ptr.* = owned_key;
        gop.value_ptr.* = .{
            .key = owned_key,
        };
        key_owned = false;
        errdefer gop.value_ptr.deinit(alloc);
        try gop.value_ptr.applyDelta(alloc, delta);
    }
};

const StoredJoinFact = struct {
    ref_key: ?[]u8 = null,
    key: []u8,
    join_id: []u8,
    payload: []u8,

    fn deinit(self: *StoredJoinFact, alloc: Allocator) void {
        if (self.ref_key) |bytes| alloc.free(bytes);
        alloc.free(self.key);
        alloc.free(self.join_id);
        alloc.free(self.payload);
        self.* = undefined;
    }
};

fn storedJoinFactSlicesEquivalent(left: []const StoredJoinFact, right: []const StoredJoinFact) bool {
    if (left.len != right.len) return false;
    for (left) |lhs| {
        var found = false;
        for (right) |rhs| {
            if (std.mem.eql(u8, lhs.key, rhs.key) and
                std.mem.eql(u8, lhs.join_id, rhs.join_id) and
                std.mem.eql(u8, lhs.payload, rhs.payload))
            {
                found = true;
                break;
            }
        }
        if (!found) return false;
    }
    return true;
}

const JoinScanBounds = struct {
    prefix: []u8,
    start: []u8,
    max_time_key: ?[]u8 = null,

    fn deinit(self: JoinScanBounds, alloc: Allocator) void {
        alloc.free(self.prefix);
        alloc.free(self.start);
        if (self.max_time_key) |value| alloc.free(value);
    }
};

pub const Index = struct {
    alloc: Allocator,
    name: []u8,
    parsed: std.json.Parsed(Config),
    parse_error_count: u64 = 0,
    last_error_doc_key: ?[]u8 = null,
    last_error_reason: ?[]u8 = null,
    join_facts_scanned: u64 = 0,
    join_facts_matched: u64 = 0,
    join_facts_pruned: u64 = 0,
    accumulator_flush_count: u64 = 0,
    symbol_cache_hits: u64 = 0,
    symbol_cache_misses: u64 = 0,
    minmax_cache_hits: u64 = 0,
    minmax_cache_misses: u64 = 0,
    minmax_support_scans: u64 = 0,
    planner_algebraic_selected: u64 = 0,
    planner_fallback_count: u64 = 0,
    planner_last_decision: ?PlannerDecision = null,
    planner_last_fallback_reason: ?[]u8 = null,
    planner_last_estimated_scan_rows: ?usize = null,
    planner_last_estimated_result_buckets: ?usize = null,
    observed_query_shapes: std.StringHashMapUnmanaged(QueryShapeStat) = .empty,
    observed_query_shape_count: u64 = 0,
    recommendation_count: u64 = 0,
    last_observed_query_shape: ?[]u8 = null,
    last_recommended_materialization: ?[]u8 = null,
    doc_fact_write_count: u64 = 0,
    doc_fact_delete_count: u64 = 0,
    doc_join_fact_ref_write_count: u64 = 0,
    doc_join_fact_ref_delete_count: u64 = 0,
    dictionary_registry_claimed_count: u64 = 0,
    dictionary_registry_already_owned_count: u64 = 0,
    dictionary_registry_owned_by_other_count: u64 = 0,
    dictionary_registry_ready_hit_count: u64 = 0,
    dictionary_registry_ready_miss_count: u64 = 0,
    path_dictionary_fst_rebuild_count: u64 = 0,
    distributed_partial_validation_proven_count: u64 = 0,
    distributed_partial_validation_rejected_count: u64 = 0,
    distributed_partial_rows_exported_count: u64 = 0,
    vector_filter_attempt_count: u64 = 0,
    vector_filter_resolved_count: u64 = 0,
    vector_filter_unsupported_count: u64 = 0,
    vector_filter_fail_closed_count: u64 = 0,
    vector_filter_include_doc_id_count: u64 = 0,
    vector_filter_exclude_doc_id_count: u64 = 0,
    adaptive_maintenance_plan_build_count: u64 = 0,
    adaptive_maintenance_cached_spec_count: u64 = 0,
    adaptive_maintenance_disabled_count: u64 = 0,
    adaptive_ready_spec_cache: ?ReadyAdaptiveSpecCache = null,
    bulk_ingest_session_depth: u32 = 0,
    bulk_dirty_path_promotion_dictionaries: std.StringHashMapUnmanaged(void) = .empty,
    resource_manager: ?*resource_manager_mod.ResourceManager = null,
    append_only_accumulator_resource_bytes: u64 = 0,
    maintenance_accumulator_resource_bytes: u64 = 0,
    // Optional durable-job lane used to rebuild HLL cardinality sketches in the
    // background after deletes/overwrites (which the append-only sketches cannot
    // fold back). When unset, callers drive rebuilds via runHllMaintenance.
    hll_maintenance_lane: ?background_runtime.DurableJobLane = null,
    hll_maintenance_owner_id: u64 = 0,
    // Serializes index write transactions. The store contract is single-writer,
    // but background HLL maintenance (runHllMaintenance) opens its own write txn
    // on a separate thread concurrently with foreground applyBatch calls. Both
    // acquire this so at most one write txn against the index's store is open at
    // a time; readers are unaffected (they use the store's snapshots).
    write_mutex: std.atomic.Mutex = .unlocked,

    pub fn open(alloc: Allocator, name: []const u8, config_json: []const u8) !Index {
        var parsed = try std.json.parseFromSlice(Config, alloc, config_json, .{ .allocate = .alloc_always });
        errdefer parsed.deinit();
        try validateConfig(parsed.value);
        return .{
            .alloc = alloc,
            .name = try alloc.dupe(u8, name),
            .parsed = parsed,
        };
    }

    pub fn attachResourceManager(self: *Index, manager: *resource_manager_mod.ResourceManager) void {
        self.resource_manager = manager;
    }

    /// Attaches a durable-job lane so HLL cardinality rebuilds (after deletes or
    /// overwrites) run as background maintenance work rather than on a read.
    /// `owner_id` is used to drain pending rebuilds when the index closes.
    pub fn attachHllMaintenanceLane(self: *Index, lane: background_runtime.DurableJobLane, owner_id: u64) void {
        self.hll_maintenance_lane = lane;
        self.hll_maintenance_owner_id = owner_id;
    }

    // Acquires the index write lock, spinning/yielding (the codebase's pattern
    // for std.atomic.Mutex, which has no blocking lock()). Held only around a
    // write transaction, so contention is brief.
    fn lockWrites(self: *Index) void {
        while (!self.write_mutex.tryLock()) std.Thread.yield() catch {};
    }

    fn unlockWrites(self: *Index) void {
        self.write_mutex.unlock();
    }

    pub fn close(self: *Index) void {
        if (self.hll_maintenance_lane) |lane| lane.drainOwner(self.hll_maintenance_owner_id);
        self.clearAccumulatorResourceUsage(&self.append_only_accumulator_resource_bytes);
        self.clearAccumulatorResourceUsage(&self.maintenance_accumulator_resource_bytes);
        self.alloc.free(self.name);
        if (self.last_error_doc_key) |value| self.alloc.free(value);
        if (self.last_error_reason) |value| self.alloc.free(value);
        if (self.planner_last_fallback_reason) |value| self.alloc.free(value);
        self.clearObservedQueryState();
        self.invalidateAdaptiveReadySpecCache();
        self.clearBulkDirtyPathPromotionDictionaries();
        self.parsed.deinit();
        self.* = undefined;
    }

    fn clearObservedQueryState(self: *Index) void {
        var observed_it = self.observed_query_shapes.iterator();
        while (observed_it.next()) |entry| {
            self.alloc.free(entry.key_ptr.*);
            entry.value_ptr.deinit(self.alloc);
        }
        self.observed_query_shapes.deinit(self.alloc);
        self.observed_query_shapes = .empty;
        self.observed_query_shape_count = 0;
        self.recommendation_count = 0;
        if (self.last_observed_query_shape) |value| self.alloc.free(value);
        if (self.last_recommended_materialization) |value| self.alloc.free(value);
        self.last_observed_query_shape = null;
        self.last_recommended_materialization = null;
    }

    pub fn sync(_: *Index, _: bool) !void {}

    pub fn beginBulkIngestSession(self: *Index) !void {
        self.bulk_ingest_session_depth += 1;
    }

    pub fn finishBulkIngestSessionWithOptions(
        self: *Index,
        store: *docstore_mod.DocStore,
        options: backend_types.BulkIngestFinishOptions,
    ) !void {
        _ = options;
        if (self.bulk_ingest_session_depth == 0) return;
        if (self.bulk_ingest_session_depth > 1) {
            self.bulk_ingest_session_depth -= 1;
            return;
        }
        errdefer self.abortBulkIngestSession();
        if (self.bulk_dirty_path_promotion_dictionaries.count() > 0) {
            var txn = try store.beginWriteTxn();
            errdefer txn.abort();
            try self.flushBulkSessionPathPromotionDictionariesTxn(&txn);
            try txn.commit();
        }
        self.clearBulkDirtyPathPromotionDictionaries();
        self.bulk_ingest_session_depth = 0;
    }

    pub fn abortBulkIngestSession(self: *Index) void {
        self.clearBulkDirtyPathPromotionDictionaries();
        self.bulk_ingest_session_depth = 0;
    }

    pub fn applyBatch(self: *Index, store: *docstore_mod.DocStore, batch: derived_types.DerivedBatch) !void {
        return try self.applyBatchWithOptions(store, batch, .{});
    }

    pub fn applyBatchWithOptions(
        self: *Index,
        store: *docstore_mod.DocStore,
        batch: derived_types.DerivedBatch,
        options: ApplyOptions,
    ) !void {
        // Serialize against concurrent background HLL maintenance (which opens
        // its own write txn on another thread); the store is single-writer.
        // Scheduling runs after the lock is released — it only opens a read txn
        // and submits a job, and must not be held while doing so.
        try self.applyBatchWritesLocked(store, batch, options);
        self.scheduleHllMaintenanceIfDirty(store);
    }

    fn applyBatchWritesLocked(
        self: *Index,
        store: *docstore_mod.DocStore,
        batch: derived_types.DerivedBatch,
        options: ApplyOptions,
    ) !void {
        self.lockWrites();
        defer self.unlockWrites();

        if (self.canUseAppendOnlyBulkPath(batch, options) and try self.appendOnlyDocFactsAreMissing(store, batch)) {
            return try self.applyAppendOnlyBatchWithOptions(store, batch, options);
        }

        if (options.batch_options.mode == .bulk_ingest) {
            var write_batch = try store.beginWriteBatchWithOptions(options.batch_options);
            errdefer write_batch.abort();
            const txn = write_batch.asTxn();
            try self.applyBatchMutationsWithTxn(txn, batch, options);
            try write_batch.commit();
            return;
        }

        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        try self.applyBatchMutationsWithTxn(&txn, batch, options);
        try txn.commit();
    }

    fn applyBatchMutationsWithTxn(
        self: *Index,
        txn: anytype,
        batch: derived_types.DerivedBatch,
        options: ApplyOptions,
    ) !void {
        var maintenance_context = try self.buildBatchMaintenanceContext(txn, options);
        defer if (maintenance_context) |*ctx| {
            self.clearAccumulatorResourceUsage(&self.maintenance_accumulator_resource_bytes);
            ctx.deinit(self.alloc);
        };

        for (batch.deleted_keys) |key| try self.removeDoc(txn, key, if (maintenance_context) |*ctx| ctx else null);
        for (batch.overwritten_doc_keys) |key| {
            if (batchContainsUpsertDocument(batch, key)) continue;
            try self.removeDoc(txn, key, if (maintenance_context) |*ctx| ctx else null);
        }
        for (batch.documents) |doc| {
            if (doc.action != .upsert) continue;
            const value = doc.cleaned_value orelse blk: {
                const store_key = try documentStoreKeyAlloc(self.alloc, doc.key);
                defer self.alloc.free(store_key);
                break :blk txn.get(store_key) catch |err| switch (err) {
                    error.NotFound => continue,
                    else => return err,
                };
            };
            try self.addDoc(txn, doc.key, value, if (maintenance_context) |*ctx| ctx else null);
        }
        if (maintenance_context) |*ctx| {
            self.observeAccumulatorResourceUsage(&self.maintenance_accumulator_resource_bytes, &ctx.tensor_accumulator);
            try self.flushBatchMaintenanceTensorDeltasTxn(txn, ctx);
            try self.flushBatchMaintenanceContextTxn(txn, ctx);
        }
    }

    fn flushBatchMaintenanceTensorDeltasTxn(self: *Index, txn: anytype, ctx: *BatchMaintenanceContext) !void {
        if (!ctx.coalesce_tensor_deltas) return;
        try self.flushAccumulator(txn, &ctx.tensor_accumulator, true);
    }

    fn flushBatchMaintenanceContextTxn(self: *Index, txn: anytype, ctx: *BatchMaintenanceContext) !void {
        if (ctx.dirty_path_promotion_dictionaries.count() == 0) return;
        if (self.bulk_ingest_session_depth > 0) {
            var dirty_it = ctx.dirty_path_promotion_dictionaries.keyIterator();
            while (dirty_it.next()) |materialization_id| {
                try self.markBulkPathPromotionDictionaryDirty(materialization_id.*);
            }
            return;
        }
        for (ctx.ready_specs) |spec| {
            if (ctx.isDisabled(spec.recommendation)) continue;
            if (!ctx.pathPromotionDictionaryDirty(spec.name)) continue;
            if (spec.path_promotion_path == null or spec.path_promotion_kind == null) continue;
            if (!(try self.pathPromotionOwnsDictionaryTxn(txn, spec))) continue;
            try self.rebuildPathDictionaryFstTxn(txn, spec);
        }
    }

    fn markBulkPathPromotionDictionaryDirty(self: *Index, materialization_id: []const u8) !void {
        if (self.bulk_dirty_path_promotion_dictionaries.contains(materialization_id)) return;
        const owned = try self.alloc.dupe(u8, materialization_id);
        errdefer self.alloc.free(owned);
        try self.bulk_dirty_path_promotion_dictionaries.put(self.alloc, owned, {});
    }

    fn clearBulkDirtyPathPromotionDictionaries(self: *Index) void {
        var dirty_it = self.bulk_dirty_path_promotion_dictionaries.keyIterator();
        while (dirty_it.next()) |key| self.alloc.free(key.*);
        self.bulk_dirty_path_promotion_dictionaries.deinit(self.alloc);
        self.bulk_dirty_path_promotion_dictionaries = .empty;
    }

    fn invalidateAdaptiveReadySpecCache(self: *Index) void {
        if (self.adaptive_ready_spec_cache) |*cache| cache.deinit(self.alloc);
        self.adaptive_ready_spec_cache = null;
    }

    fn cloneReadySpecsAlloc(self: *Index, specs: []const AdaptiveMaterializationSpec) ![]AdaptiveMaterializationSpec {
        if (specs.len == 0) return &.{};
        const out = try self.alloc.alloc(AdaptiveMaterializationSpec, specs.len);
        for (out) |*spec| spec.* = undefined;
        var initialized: usize = 0;
        errdefer {
            for (out[0..initialized]) |*spec| spec.deinit(self.alloc);
            self.alloc.free(out);
        }
        for (specs, 0..) |spec, i| {
            out[i] = try spec.clone(self.alloc);
            initialized += 1;
        }
        return out;
    }

    fn bulkPathPromotionDictionaryDirty(self: *const Index, materialization_id: []const u8) bool {
        return self.bulk_dirty_path_promotion_dictionaries.contains(materialization_id);
    }

    fn flushBulkSessionPathPromotionDictionariesTxn(self: *Index, txn: anytype) !void {
        if (self.bulk_dirty_path_promotion_dictionaries.count() == 0) return;
        const progress_rows = try self.scanPersistedAdaptiveProgressTxn(txn);
        defer {
            for (progress_rows) |*progress| progress.deinit(self.alloc);
            if (progress_rows.len > 0) self.alloc.free(progress_rows);
        }
        for (progress_rows) |progress| {
            if (progress.lifecycle != .ready) continue;
            if (!self.adaptiveProgressMatchesCurrentConfig(progress)) continue;
            if (!self.bulkPathPromotionDictionaryDirty(progress.materialization_id)) continue;
            if (!(try self.persistedMaterializationStateReadyTxn(txn, progress.recommendation))) continue;
            var spec = self.adaptiveSpecFromRecommendationAlloc(progress.materialization_id, progress.recommendation) catch continue;
            defer spec.deinit(self.alloc);
            if (spec.path_promotion_path == null or spec.path_promotion_kind == null) continue;
            if (!(try self.pathPromotionOwnsDictionaryTxn(txn, spec))) continue;
            try self.rebuildPathDictionaryFstTxn(txn, spec);
        }
    }

    fn documentStoreKeyAlloc(alloc: Allocator, doc_key: []const u8) ![]u8 {
        return if (internal_keys.isInternalUserKey(doc_key))
            try alloc.dupe(u8, doc_key)
        else
            try internal_keys.documentKeyAlloc(alloc, doc_key);
    }

    fn batchContainsUpsertDocument(batch: derived_types.DerivedBatch, doc_key: []const u8) bool {
        for (batch.documents) |doc| {
            if (doc.action == .upsert and std.mem.eql(u8, doc.key, doc_key)) return true;
        }
        return false;
    }

    fn canUseAppendOnlyBulkPath(self: *Index, batch: derived_types.DerivedBatch, options: ApplyOptions) bool {
        if (options.batch_options.mode != .bulk_ingest) return false;
        if (self.config().materializations.len != 0) return false;
        if (self.config().joins.len != 0) return false;
        if (self.config().adaptive.observe or self.config().adaptive.lazy_materialization) return false;
        if (batch.documents.len == 0) return false;
        if (batch.deleted_keys.len != 0 or batch.overwritten_doc_keys.len != 0) return false;
        for (batch.documents) |doc| {
            if (doc.action != .upsert or doc.cleaned_value == null) return false;
        }
        return true;
    }

    fn appendOnlyDocFactsAreMissing(self: *Index, store: *docstore_mod.DocStore, batch: derived_types.DerivedBatch) !bool {
        var txn = try store.beginReadTxn();
        defer txn.abort();
        for (batch.documents) |doc| {
            const fact_key = try self.docFactKey(doc.key);
            defer self.alloc.free(fact_key);
            _ = txn.get(fact_key) catch |err| switch (err) {
                error.NotFound => continue,
                else => return err,
            };
            return false;
        }
        return true;
    }

    fn applyAppendOnlyBatchWithOptions(
        self: *Index,
        store: *docstore_mod.DocStore,
        batch: derived_types.DerivedBatch,
        options: ApplyOptions,
    ) !void {
        var write_batch = try store.beginWriteBatchWithOptions(options.batch_options);
        errdefer write_batch.abort();
        const txn = write_batch.asTxn();
        var accumulator = AppendOnlyAccumulator{};
        defer {
            self.clearAccumulatorResourceUsage(&self.append_only_accumulator_resource_bytes);
            accumulator.deinit(self.alloc);
        }
        var maintenance_context = try self.buildBatchMaintenanceContext(txn, options);
        defer if (maintenance_context) |*ctx| {
            self.clearAccumulatorResourceUsage(&self.maintenance_accumulator_resource_bytes);
            ctx.deinit(self.alloc);
        };

        for (batch.documents) |doc| {
            const value = doc.cleaned_value.?;
            try self.writeDocFacts(txn, doc.key, value, if (maintenance_context) |*ctx| ctx else null);
            try self.applyWrittenAdaptiveDocFactDeltaAppendOnly(txn, &accumulator, doc.key, if (maintenance_context) |*ctx| ctx else null);
            try self.applyDocDeltaAppendOnlyPreaggregated(txn, &accumulator, doc.key, value, if (maintenance_context) |*ctx| ctx else null);
            self.observeAccumulatorResourceUsage(&self.append_only_accumulator_resource_bytes, &accumulator);
            if (accumulator.entryCount() >= self.maxBatchAccumulatorEntries()) {
                try self.flushAppendOnlyAccumulator(txn, &accumulator);
                accumulator.deinit(self.alloc);
                accumulator = .{};
                self.clearAccumulatorResourceUsage(&self.append_only_accumulator_resource_bytes);
                self.accumulator_flush_count += 1;
            }
        }
        self.observeAccumulatorResourceUsage(&self.append_only_accumulator_resource_bytes, &accumulator);
        try self.flushAppendOnlyAccumulator(txn, &accumulator);
        self.accumulator_flush_count += 1;
        if (maintenance_context) |*ctx| {
            self.observeAccumulatorResourceUsage(&self.maintenance_accumulator_resource_bytes, &ctx.tensor_accumulator);
            try self.flushBatchMaintenanceContextTxn(txn, ctx);
        }

        try write_batch.commit();
    }

    fn maxBatchAccumulatorEntries(self: *const Index) usize {
        return self.config().max_batch_accumulator_entries orelse 64 * 1024;
    }

    fn observeAccumulatorResourceUsage(
        self: *Index,
        current: *u64,
        accumulator: *const AppendOnlyAccumulator,
    ) void {
        const manager = self.resource_manager orelse return;
        manager.observeUsage(.algebraic_tensor_accumulators, current, accumulator.estimatedBytes());
    }

    fn clearAccumulatorResourceUsage(self: *Index, current: *u64) void {
        const manager = self.resource_manager orelse {
            current.* = 0;
            return;
        };
        manager.observeUsage(.algebraic_tensor_accumulators, current, 0);
    }

    fn minMaxCandidateCacheSize(self: *const Index) usize {
        return self.config().min_max_candidate_cache_size orelse 8;
    }

    pub fn countValue(self: *Index, store: *docstore_mod.DocStore, materialization: []const u8, group_key: []const u8) !i64 {
        const raw = try self.rawValueAlloc(store, materialization, group_key);
        defer if (raw) |bytes| self.alloc.free(bytes);
        return if (raw) |bytes| try algebra.parseI64(bytes) else 0;
    }

    pub fn numericValue(self: *Index, store: *docstore_mod.DocStore, materialization: []const u8, group_key: []const u8) !?f64 {
        const raw = try self.rawValueAlloc(store, materialization, group_key);
        defer if (raw) |bytes| self.alloc.free(bytes);
        return if (raw) |bytes| try algebra.parseF64(bytes) else null;
    }

    pub fn rawValueAlloc(self: *Index, store: *docstore_mod.DocStore, materialization: []const u8, group_key: []const u8) !?[]u8 {
        if (try self.materializedExpressionRawValueForMaterializationAlloc(store, materialization, group_key, null)) |expr_raw| {
            return expr_raw.raw;
        }
        return null;
    }

    pub fn adaptiveTensorRawValueAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        materialization_id: []const u8,
        axes_canonical: []const u8,
        bucket: ?[]const u8,
    ) !?[]u8 {
        var txn = try store.beginReadTxn();
        defer txn.abort();
        const key = try tensor_mod.keyAlloc(self.alloc, self.name, .{
            .materialization = materialization_id,
            .axes_canonical = axes_canonical,
            .bucket = bucket,
        });
        defer self.alloc.free(key);
        const raw_row = txn.get(key) catch |err| switch (err) {
            error.NotFound => return null,
            else => return err,
        };
        var row = try tensor_mod.decodeRowAlloc(self.alloc, raw_row);
        defer row.deinit(self.alloc);
        if (row.slots.len == 0) return null;
        return if (row.slots[0].value) |value| try self.alloc.dupe(u8, value) else null;
    }

    pub fn applyMaterializedExpressionDelta(
        self: *Index,
        store: *docstore_mod.DocStore,
        expr: ir.TensorExpr,
        axes_canonical: []const u8,
        bucket: ?[]const u8,
        law_id: law_mod.Id,
        delta: []const u8,
    ) !void {
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        const axis_id = try self.ensureSymbol(&txn, axes_canonical);
        self.alloc.free(axis_id);
        const key = try tensor_mod.expressionKeyAlloc(self.alloc, self.name, .{
            .expr_id = expr_id,
            .axes_canonical = axes_canonical,
            .bucket = bucket,
        });
        defer self.alloc.free(key);
        const existing = txn.get(key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        const encoded = (try tensor_mod.applyRowSlotToBytesAlloc(self.alloc, existing, &.{law_id}, 0, law_id, delta, true)) orelse {
            txn.delete(key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            try txn.commit();
            return;
        };
        defer self.alloc.free(encoded);
        try txn.put(key, encoded);
        try txn.commit();
    }

    pub fn materializedExpressionRawValueAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        expr: ir.TensorExpr,
        axes_canonical: []const u8,
        bucket: ?[]const u8,
        law_id: law_mod.Id,
    ) !?[]u8 {
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        const key = try tensor_mod.expressionKeyAlloc(self.alloc, self.name, .{
            .expr_id = expr_id,
            .axes_canonical = axes_canonical,
            .bucket = bucket,
        });
        defer self.alloc.free(key);
        const raw_row = txn.get(key) catch |err| switch (err) {
            error.NotFound => return null,
            else => return err,
        };
        var row = try tensor_mod.rowFromBytesOrLayoutAlloc(self.alloc, raw_row, &.{law_id});
        defer row.deinit(self.alloc);
        return if (row.slots[0].value) |value| try self.alloc.dupe(u8, value) else null;
    }

    pub fn rebuildMaterializedExpressionFromMaterialization(
        self: *Index,
        store: *docstore_mod.DocStore,
        expr: ir.TensorExpr,
        materialization: []const u8,
    ) !usize {
        const mat_idx = self.materializationIndex(materialization) orelse return error.InvalidAlgebraicConfig;
        const mat = self.config().materializations[mat_idx];
        const op = algebra.Op.parse(mat.op) orelse return error.InvalidAlgebraicConfig;
        const law_id = self.materializationLawId(mat, op);
        if (expr.law_id == null or expr.law_id.? != law_id) return error.InvalidAlgebraicTensorExpr;

        var txn = try store.beginReadTxn();
        const entries = if (mat.join == null)
            try self.scanFoldEntriesFromDocFactsTxn(&txn, mat, op, law_id)
        else
            try self.scanFoldEntriesFromConfiguredJoinFactsTxn(&txn, mat, op, law_id);
        txn.abort();
        defer {
            for (entries) |*entry| entry.deinit(self.alloc);
            if (entries.len > 0) self.alloc.free(entries);
        }
        return try self.rebuildMaterializedExpressionFromEntries(store, expr, law_id, mat.time != null, entries);
    }

    pub fn rebuildMaterializedExpressionFromAdaptiveRecommendation(
        self: *Index,
        store: *docstore_mod.DocStore,
        expr: ir.TensorExpr,
        recommendation: []const u8,
    ) !?usize {
        const materialization_id = (try self.readyAdaptiveMaterializationIdAlloc(store, recommendation)) orelse return null;
        defer self.alloc.free(materialization_id);
        var spec = try self.adaptiveSpecFromRecommendationAlloc(materialization_id, recommendation);
        defer spec.deinit(self.alloc);
        const law_id = law_mod.fromOp(spec.op);
        if (expr.law_id == null or expr.law_id.? != law_id) return error.InvalidAlgebraicTensorExpr;

        const entries = try self.scanAdaptiveTensorEntries(store, materialization_id);
        defer {
            for (entries) |*entry| entry.deinit(self.alloc);
            if (entries.len > 0) self.alloc.free(entries);
        }
        return try self.rebuildMaterializedExpressionFromEntries(store, expr, law_id, spec.time != null, entries);
    }

    fn refreshReadyAdaptiveExpressionCache(
        self: *Index,
        store: *docstore_mod.DocStore,
        recommendation: []const u8,
    ) !?usize {
        const materialization_id = (try self.readyAdaptiveMaterializationIdAlloc(store, recommendation)) orelse return null;
        defer self.alloc.free(materialization_id);
        var spec = try self.adaptiveSpecFromRecommendationAlloc(materialization_id, recommendation);
        defer spec.deinit(self.alloc);
        const expr = adaptiveMaterializedExpression(spec) orelse return null;
        return try self.rebuildMaterializedExpressionFromAdaptiveRecommendation(store, expr, recommendation);
    }

    fn adaptiveMaterializedExpression(spec: AdaptiveMaterializationSpec) ?ir.TensorExpr {
        if (spec.path_promotion_path != null) return .{
            .fragment = .reduce,
            .input_dims = &expression_doc_path_kind_scalar_input_dims,
            .output_dims = &expression_kind_scalar_output_dims,
            .semantic_id = spec.recommendation,
            .layout = .materialized_expr,
            .law_id = .count,
        };
        return .{
            .fragment = .reduce,
            .input_dims = if (spec.time != null)
                &expression_doc_time_input_dims
            else if (spec.measure != null)
                &expression_doc_scalar_input_dims
            else
                &expression_doc_input_dims,
            .output_dims = if (spec.time != null)
                &expression_time_bucket_scalar_output_dims
            else if (spec.group_by.len > 0)
                &expression_bucket_output_dims
            else
                &expression_scalar_output_dims,
            .semantic_id = spec.recommendation,
            .layout = .materialized_expr,
            .law_id = law_mod.fromOp(spec.op),
        };
    }

    fn materializationExpression(mat: MaterializationConfig, law_id: law_mod.Id) ir.TensorExpr {
        return .{
            .fragment = .reduce,
            .input_dims = if (mat.time != null)
                &expression_doc_time_input_dims
            else if (mat.measure != null)
                &expression_doc_scalar_input_dims
            else
                &expression_doc_input_dims,
            .output_dims = if (mat.time != null)
                &expression_time_bucket_scalar_output_dims
            else if (mat.group_by.len > 0 or mat.axes.len > 0)
                &expression_bucket_output_dims
            else
                &expression_scalar_output_dims,
            .semantic_id = mat.name,
            .layout = .materialized_expr,
            .law_id = law_id,
        };
    }

    fn rebuildMaterializedExpressionFromEntries(
        self: *Index,
        store: *docstore_mod.DocStore,
        expr: ir.TensorExpr,
        law_id: law_mod.Id,
        has_time_bucket: bool,
        entries: []const FoldEntry,
    ) !usize {
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const prefix = try tensor_mod.expressionPrefixAlloc(self.alloc, self.name, expr_id);
        defer self.alloc.free(prefix);

        var txn = try store.beginWriteTxn();
        errdefer txn.abort();

        var keys = std.ArrayListUnmanaged([]u8).empty;
        defer {
            for (keys.items) |key| self.alloc.free(key);
            keys.deinit(self.alloc);
        }
        {
            var cursor = try txn.openCursor();
            defer cursor.close();
            var row_opt = try cursor.seekAtOrAfter(prefix);
            while (row_opt) |row| : (row_opt = try cursor.next()) {
                if (!std.mem.startsWith(u8, row.key, prefix)) break;
                try keys.append(self.alloc, try self.alloc.dupe(u8, row.key));
            }
        }
        for (keys.items) |key| txn.delete(key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };

        var written: usize = 0;
        for (entries) |entry| {
            const ExpressionCoordinate = struct {
                bucket: ?[]const u8,
                axes: []const u8,
            };
            const expression_coordinate: ExpressionCoordinate = if (has_time_bucket) blk: {
                const bucket_component = token.componentAt(entry.group_key, 0) catch return error.InvalidAlgebraicTensorExpr;
                const group_component = token.componentAt(entry.group_key, bucket_component.next) catch return error.InvalidAlgebraicTensorExpr;
                if (group_component.next != entry.group_key.len) return error.InvalidAlgebraicTensorExpr;
                break :blk .{
                    .bucket = bucket_component.payload,
                    .axes = group_component.payload,
                };
            } else .{ .bucket = @as(?[]const u8, null), .axes = entry.group_key };
            const axis_id = try self.ensureSymbol(&txn, expression_coordinate.axes);
            self.alloc.free(axis_id);
            const key = try tensor_mod.expressionKeyAlloc(self.alloc, self.name, .{
                .expr_id = expr_id,
                .axes_canonical = expression_coordinate.axes,
                .bucket = expression_coordinate.bucket,
            });
            defer self.alloc.free(key);
            const existing = txn.get(key) catch |err| switch (err) {
                error.NotFound => null,
                else => return err,
            };
            const encoded = (try tensor_mod.applyRowSlotToBytesAlloc(self.alloc, existing, &.{law_id}, 0, law_id, entry.value, true)) orelse continue;
            defer self.alloc.free(encoded);
            try txn.put(key, encoded);
            written += 1;
        }

        try txn.commit();
        return written;
    }

    fn materializedExpressionIdForLawAlloc(self: *Index, expr: ir.TensorExpr, law_id: law_mod.Id) ![]u8 {
        if (expr.law_id) |declared| {
            if (declared != law_id) return error.InvalidAlgebraicTensorExpr;
        } else return error.InvalidAlgebraicTensorExpr;
        const plan = (try ir.planMaterializedExpressionAlloc(self.alloc, expr)) orelse return error.InvalidAlgebraicTensorExpr;
        defer self.alloc.free(plan.law_ids);
        return plan.expr_id;
    }

    pub fn readyAdaptiveMaterializationIdAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        recommendation: []const u8,
    ) !?[]u8 {
        if (!self.plannerLifecycleReady()) return null;
        var txn = try store.beginReadTxn();
        defer txn.abort();
        const progress = (try self.loadAdaptiveProgressForRecommendation(&txn, recommendation)) orelse return null;
        var owned_progress = progress;
        defer owned_progress.deinit(self.alloc);
        if (owned_progress.lifecycle != .ready) return null;
        if (!self.adaptiveProgressMatchesCurrentConfig(owned_progress)) return null;
        if (!(try self.persistedMaterializationStateReady(&txn, recommendation))) return null;
        return try self.alloc.dupe(u8, owned_progress.materialization_id);
    }

    pub fn adaptiveTensorRawValueForRecommendationAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        recommendation: []const u8,
        axes_canonical: []const u8,
        bucket: ?[]const u8,
    ) !?AdaptiveRawResult {
        const materialization_id = (try self.readyAdaptiveMaterializationIdAlloc(store, recommendation)) orelse return null;
        defer self.alloc.free(materialization_id);
        return .{ .raw = try self.adaptiveTensorRawValueAlloc(store, materialization_id, axes_canonical, bucket) };
    }

    pub fn adaptiveMaterializedExpressionRawValueForRecommendationAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        recommendation: []const u8,
        axes_canonical: []const u8,
        bucket: ?[]const u8,
    ) !?AdaptiveRawResult {
        const materialization_id = (try self.readyAdaptiveMaterializationIdAlloc(store, recommendation)) orelse return null;
        defer self.alloc.free(materialization_id);
        var spec = try self.adaptiveSpecFromRecommendationAlloc(materialization_id, recommendation);
        defer spec.deinit(self.alloc);
        const expr = adaptiveMaterializedExpression(spec) orelse return null;
        const law_id = law_mod.fromOp(spec.op);
        const raw = (try self.materializedExpressionRawValueAlloc(store, expr, axes_canonical, bucket, law_id)) orelse return null;
        return .{ .raw = raw };
    }

    pub fn materializedExpressionRawValueForMaterializationAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        materialization: []const u8,
        axes_canonical: []const u8,
        bucket: ?[]const u8,
    ) !?AdaptiveRawResult {
        const mat_idx = self.materializationIndex(materialization) orelse return null;
        const mat = self.config().materializations[mat_idx];
        const op = algebra.Op.parse(mat.op) orelse return null;
        const law_id = self.materializationLawId(mat, op);
        const expr = materializationExpression(mat, law_id);
        const raw = (try self.materializedExpressionRawValueAlloc(store, expr, axes_canonical, bucket, law_id)) orelse return null;
        return .{ .raw = raw };
    }

    pub fn scanMaterializedExpressionEntries(
        self: *Index,
        store: *docstore_mod.DocStore,
        expr: ir.TensorExpr,
        law_id: law_mod.Id,
    ) ![]FoldEntry {
        var txn = try store.beginReadTxn();
        defer txn.abort();
        return try self.scanMaterializedExpressionEntriesTxn(&txn, expr, law_id, expressionHasDimension(expr.output_dims, .time));
    }

    pub fn scanAdaptiveTensorEntriesForRecommendation(
        self: *Index,
        store: *docstore_mod.DocStore,
        recommendation: []const u8,
    ) !?[]FoldEntry {
        const materialization_id = (try self.readyAdaptiveMaterializationIdAlloc(store, recommendation)) orelse return null;
        defer self.alloc.free(materialization_id);
        var spec = try self.adaptiveSpecFromRecommendationAlloc(materialization_id, recommendation);
        defer spec.deinit(self.alloc);
        const expression_entries = try self.scanAdaptiveEntriesFromExpression(store, spec);
        if (expression_entries) |entries| {
            if (entries.len > 0) return entries;
            self.alloc.free(entries);
        }
        return try self.scanAdaptiveTensorEntries(store, materialization_id);
    }

    pub fn countAdaptiveTensorRowsForRecommendationUpTo(
        self: *Index,
        store: *docstore_mod.DocStore,
        recommendation: []const u8,
        limit: usize,
    ) !?usize {
        const materialization_id = (try self.readyAdaptiveMaterializationIdAlloc(store, recommendation)) orelse return null;
        defer self.alloc.free(materialization_id);
        var spec = try self.adaptiveSpecFromRecommendationAlloc(materialization_id, recommendation);
        defer spec.deinit(self.alloc);
        if (try self.countAdaptiveExpressionRowsUpTo(store, spec, limit)) |count| {
            if (count > 0) return count;
        }
        return try self.countAdaptiveTensorRowsUpTo(store, materialization_id, limit);
    }

    pub fn scanAdaptiveTensorEntriesForMaterializationId(
        self: *Index,
        store: *docstore_mod.DocStore,
        materialization_id: []const u8,
    ) ![]FoldEntry {
        return try self.scanAdaptiveTensorEntries(store, materialization_id);
    }

    pub fn symbolValueAlloc(self: *Index, store: *docstore_mod.DocStore, canonical: []const u8) !?[]u8 {
        var txn = try store.beginReadTxn();
        defer txn.abort();
        const id = try symbol.idAlloc(self.alloc, canonical);
        defer self.alloc.free(id);
        return try self.resolveSymbolAlloc(&txn, id);
    }

    pub fn scanMaterializedExpressionEntriesForMaterialization(self: *Index, store: *docstore_mod.DocStore, materialization: []const u8) ![]FoldEntry {
        var txn = try store.beginReadTxn();
        defer txn.abort();
        return try self.scanMaterializedExpressionEntriesForMaterializationTxn(&txn, materialization);
    }

    pub fn scanDerivedJoinFoldEntries(
        self: *Index,
        store: *docstore_mod.DocStore,
        request: DerivedJoinFoldRequest,
    ) !?[]FoldEntry {
        return try self.scanDerivedJoinFoldEntriesAtGeneration(store, request, null);
    }

    pub fn scanDerivedJoinFoldEntriesAtGeneration(
        self: *Index,
        store: *docstore_mod.DocStore,
        request: DerivedJoinFoldRequest,
        generation: ?u64,
    ) !?[]FoldEntry {
        if (!self.plannerLifecycleReady()) return null;
        const join_cfg = self.joinConfigByName(request.join.name) orelse return null;
        const law_id = law_mod.fromOp(request.op);
        const proof = join_mod.queryRewriteProof(join_cfg, request.join, .{
            .kind = .derived_distributive_fold,
            .law_id = law_id,
            .bounded_fanout = join_cfg.max_fanout != null,
        });
        if (!proof.safe()) return null;
        if (request.op != .count and request.measure == null) return null;

        var txn = try store.beginReadTxn();
        defer txn.abort();
        return try self.scanDerivedJoinFoldEntriesTxn(&txn, join_cfg, request, law_id, generation);
    }

    pub fn scanDerivedJoinFoldEntriesWithTensorProgram(
        self: *Index,
        store: *docstore_mod.DocStore,
        request: DerivedJoinFoldRequest,
        access_paths: []const ir.PhysicalAccessPath,
        program: ir.TensorProgram,
        output_ref: ir.TensorProgramRef,
    ) !?[]FoldEntry {
        return try self.scanDerivedJoinFoldEntriesWithTensorProgramAtGeneration(store, request, access_paths, program, output_ref, null);
    }

    pub fn scanDerivedJoinFoldEntriesWithTensorProgramAtGeneration(
        self: *Index,
        store: *docstore_mod.DocStore,
        request: DerivedJoinFoldRequest,
        access_paths: []const ir.PhysicalAccessPath,
        program: ir.TensorProgram,
        output_ref: ir.TensorProgramRef,
        generation: ?u64,
    ) !?[]FoldEntry {
        const proof = try ir.tensorProgramProof(self.alloc, access_paths, program);
        if (!proof.safe()) return null;
        if (!derivedJoinProgramHasAccessPath(request, access_paths)) return null;
        const output_step = switch (output_ref) {
            .step => |idx| idx,
            .input => return null,
        };
        if (output_step >= program.steps.len) return null;
        const expr = program.steps[output_step].expr;
        if (expr.fragment != .join) return null;
        if (expr.law_id == null or expr.law_id.? != law_mod.fromOp(request.op)) return null;
        if (!std.mem.eql(ir.Dimension, expr.output_dims, derivedJoinFoldProgramOutputDims(request))) return null;
        const expected_metadata = try derivedJoinFoldMetadataAlloc(self.alloc, request);
        defer self.alloc.free(expected_metadata);
        const metadata = expr.metadata orelse return null;
        if (!std.mem.eql(u8, metadata, expected_metadata)) return null;
        return try self.scanDerivedJoinFoldEntriesAtGeneration(store, request, generation);
    }

    fn derivedJoinProgramHasAccessPath(request: DerivedJoinFoldRequest, access_paths: []const ir.PhysicalAccessPath) bool {
        for (access_paths) |path| {
            if (std.mem.eql(u8, path.owner, request.join.name) and path.layout == .join_fact_rows) return true;
        }
        return false;
    }

    fn derivedJoinFoldProgramOutputDims(request: DerivedJoinFoldRequest) []const ir.Dimension {
        if (request.time_field != null) return &distributed_time_bucket_scalar_output_dims;
        if (request.group_by.len > 0 or request.histogram_field != null or request.range_field != null) return &distributed_bucket_scalar_output_dims;
        return &distributed_scalar_output_dims;
    }

    pub fn scanDocFactBucketFoldEntriesWithTensorProgram(
        self: *Index,
        store: *docstore_mod.DocStore,
        request: DocFactBucketFoldRequest,
        access_paths: []const ir.PhysicalAccessPath,
        program: ir.TensorProgram,
        output_ref: ir.TensorProgramRef,
    ) !?[]FoldEntry {
        return try self.scanDocFactBucketFoldEntriesWithTensorProgramAtGeneration(store, request, access_paths, program, output_ref, null);
    }

    pub fn scanDocFactBucketFoldEntriesWithTensorProgramAtGeneration(
        self: *Index,
        store: *docstore_mod.DocStore,
        request: DocFactBucketFoldRequest,
        access_paths: []const ir.PhysicalAccessPath,
        program: ir.TensorProgram,
        output_ref: ir.TensorProgramRef,
        generation: ?u64,
    ) !?[]FoldEntry {
        if (!self.plannerLifecycleReady()) return null;
        const proof = try ir.tensorProgramProof(self.alloc, access_paths, program);
        if (!proof.safe()) return null;
        if (!docFactProgramHasAccessPath(self.name, access_paths)) return null;
        const output_step = switch (output_ref) {
            .step => |idx| idx,
            .input => return null,
        };
        if (output_step >= program.steps.len) return null;
        const expr = program.steps[output_step].expr;
        if (expr.fragment != .reduce) return null;
        if (expr.law_id == null or expr.law_id.? != law_mod.fromOp(request.op)) return null;
        if (!std.mem.eql(ir.Dimension, expr.output_dims, &distributed_bucket_scalar_output_dims)) return null;
        const expected_metadata = try docFactBucketFoldMetadataAlloc(self.alloc, request);
        defer self.alloc.free(expected_metadata);
        const metadata = expr.metadata orelse return null;
        if (!std.mem.eql(u8, metadata, expected_metadata)) return null;
        var txn = try store.beginReadTxn();
        defer txn.abort();
        return try self.scanDocFactBucketFoldEntriesTxn(&txn, request, law_mod.fromOp(request.op), generation);
    }

