    pub fn scanDistributedCardinalityPartialsWithTensorProgram(
        self: *Index,
        store: *docstore_mod.DocStore,
        request: CardinalityPartialsRequest,
        access_paths: []const ir.PhysicalAccessPath,
        program: ir.TensorProgram,
        output_ref: ir.TensorProgramRef,
    ) !?[]distributed_mod.Partial {
        return try self.scanDistributedCardinalityPartialsWithTensorProgramAtGeneration(store, request, access_paths, program, output_ref, null);
    }

    pub fn scanDistributedCardinalityPartialsWithTensorProgramAtGeneration(
        self: *Index,
        store: *docstore_mod.DocStore,
        request: CardinalityPartialsRequest,
        access_paths: []const ir.PhysicalAccessPath,
        program: ir.TensorProgram,
        output_ref: ir.TensorProgramRef,
        generation: ?u64,
    ) !?[]distributed_mod.Partial {
        if (!self.plannerLifecycleReady()) return null;
        const proof = try ir.tensorProgramProof(self.alloc, access_paths, program);
        if (!proof.safe()) return null;
        const expects_path = isExplicitJsonPointerPath(request.field_or_path);
        if (expects_path) {
            if (!pathFactProgramHasAccessPath(self.name, access_paths)) return null;
        } else {
            if (!docFactProgramHasAccessPath(self.name, access_paths)) return null;
        }
        const output_step = switch (output_ref) {
            .step => |idx| idx,
            .input => return null,
        };
        if (output_step >= program.steps.len) return null;
        const expr = program.steps[output_step].expr;
        if (expr.fragment != .reduce) return null;
        if (expr.law_id == null or expr.law_id.? != .count) return null;
        if (!std.mem.eql(ir.Dimension, expr.output_dims, &distributed_scalar_output_dims)) return null;
        const expected_metadata = try cardinalityPartialsMetadataAlloc(self.alloc, request);
        defer self.alloc.free(expected_metadata);
        const metadata = expr.metadata orelse return null;
        if (!std.mem.eql(u8, metadata, expected_metadata)) return null;
        return (try self.scanDistributedCardinalityPartials(
            store,
            request.aggregation_name,
            request.field_or_path,
            request.constraints,
            generation,
        )) orelse return null;
    }

