    pub fn scanDistributedTermsCardinalityPartialsWithTensorProgramAtGeneration(
        self: *Index,
        store: *docstore_mod.DocStore,
        request: TermsCardinalityPartialsRequest,
        access_paths: []const ir.PhysicalAccessPath,
        program: ir.TensorProgram,
        output_ref: ir.TensorProgramRef,
        generation: ?u64,
    ) !?[]distributed_mod.Partial {
        if (!self.plannerLifecycleReady()) return null;
        if (request.children.len == 0) return null;
        const proof = try ir.tensorProgramProof(self.alloc, access_paths, program);
        if (!proof.safe()) return null;
        if (!cardinalityAccessPathsSatisfyField(self.name, access_paths, request.bucket_field_or_path)) return null;
        for (request.children) |child| {
            if (!cardinalityAccessPathsSatisfyField(self.name, access_paths, child.field)) return null;
        }
        for (request.constraints) |constraint| {
            if (!cardinalityAccessPathsSatisfyField(self.name, access_paths, constraint.field)) return null;
        }
        const output_step = switch (output_ref) {
            .step => |idx| idx,
            .input => return null,
        };
        if (output_step >= program.steps.len) return null;
        const expr = program.steps[output_step].expr;
        if (expr.fragment != .reduce) return null;
        if (expr.law_id == null or expr.law_id.? != .count) return null;
        if (!std.mem.eql(ir.Dimension, expr.output_dims, &distributed_bucket_scalar_output_dims)) return null;
        const expected_metadata = try termsCardinalityPartialsMetadataAlloc(self.alloc, request);
        defer self.alloc.free(expected_metadata);
        const metadata = expr.metadata orelse return null;
        if (!std.mem.eql(u8, metadata, expected_metadata)) return null;
        return (try self.scanDistributedTermsCardinalityPartials(
            store,
            request.aggregation_name,
            request.bucket_field_or_path,
            request.children,
            request.constraints,
            generation,
        )) orelse return null;
    }

