    fn docFactProgramHasAccessPath(index_name: []const u8, access_paths: []const ir.PhysicalAccessPath) bool {
        for (access_paths) |path| {
            if (std.mem.eql(u8, path.owner, index_name) and path.layout == .docfact_rows) return true;
        }
        return false;
    }

    fn pathFactProgramHasAccessPath(index_name: []const u8, access_paths: []const ir.PhysicalAccessPath) bool {
        for (access_paths) |path| {
            if (std.mem.eql(u8, path.owner, index_name) and path.layout == .pathfact_rows) return true;
        }
        return false;
    }

    fn cardinalityAccessPathsSatisfyField(index_name: []const u8, access_paths: []const ir.PhysicalAccessPath, field_or_path: []const u8) bool {
        return if (isExplicitJsonPointerPath(field_or_path))
            pathFactProgramHasAccessPath(index_name, access_paths)
        else
            docFactProgramHasAccessPath(index_name, access_paths);
    }

    pub fn scanMaterializedExpressionRows(self: *Index, store: *docstore_mod.DocStore, materializations: []const []const u8) !?[]MaterializedExpressionRowEntry {
        if (materializations.len == 0) return null;
        var txn = try store.beginReadTxn();
        defer txn.abort();
        return try self.scanMaterializedExpressionRowsTxn(&txn, materializations);
    }

    pub fn scanDistributedPartials(self: *Index, store: *docstore_mod.DocStore, materializations: []const []const u8) ![]distributed_mod.Partial {
        if (materializations.len == 0) return try self.alloc.alloc(distributed_mod.Partial, 0);
        const law_ids = try self.distributedMaterializationLawIdsAlloc(materializations);
        defer self.alloc.free(law_ids);

        const rows = (try self.scanMaterializedExpressionRows(store, materializations)) orelse return try self.alloc.alloc(distributed_mod.Partial, 0);
        defer {
            for (rows) |*row| row.deinit(self.alloc);
            if (rows.len > 0) self.alloc.free(rows);
        }

        var partials = std.ArrayListUnmanaged(distributed_mod.Partial).empty;
        errdefer {
            for (partials.items) |partial| {
                self.alloc.free(@constCast(partial.canonical_axis));
                if (partial.metric.len > 0) self.alloc.free(@constCast(partial.metric));
                self.alloc.free(@constCast(partial.value));
            }
            partials.deinit(self.alloc);
        }
        for (rows) |row| {
            for (row.values, 0..) |value_opt, slot_idx| {
                const value = value_opt orelse continue;
                const canonical_axis = try self.alloc.dupe(u8, row.group_key);
                errdefer self.alloc.free(canonical_axis);
                const metric = try self.alloc.dupe(u8, materializations[slot_idx]);
                errdefer self.alloc.free(metric);
                const partial_value = try self.alloc.dupe(u8, value);
                errdefer self.alloc.free(partial_value);
                try partials.append(self.alloc, .{
                    .canonical_axis = canonical_axis,
                    .metric = metric,
                    .law_id = law_ids[slot_idx],
                    .value = partial_value,
                });
            }
        }
        return try partials.toOwnedSlice(self.alloc);
    }

    pub fn scanDistributedPartialsForExpressions(self: *Index, store: *docstore_mod.DocStore, exprs: []const ir.TensorExpr) ![]distributed_mod.Partial {
        if (exprs.len == 0) return try self.alloc.alloc(distributed_mod.Partial, 0);

        var partials = std.ArrayListUnmanaged(distributed_mod.Partial).empty;
        errdefer {
            for (partials.items) |partial| {
                self.alloc.free(@constCast(partial.canonical_axis));
                if (partial.metric.len > 0) self.alloc.free(@constCast(partial.metric));
                self.alloc.free(@constCast(partial.value));
            }
            partials.deinit(self.alloc);
        }

        for (exprs) |expr| {
            const law_id = expr.law_id orelse return error.InvalidAlgebraicTensorExpr;
            var plan = (try ir.planMaterializedExpressionAlloc(self.alloc, expr)) orelse return error.InvalidAlgebraicTensorExpr;
            defer plan.deinit(self.alloc);
            const metric_name = expr.semantic_id orelse plan.expr_id;
            const entries = try self.scanMaterializedExpressionEntries(store, expr, law_id);
            defer {
                for (entries) |*entry| entry.deinit(self.alloc);
                if (entries.len > 0) self.alloc.free(entries);
            }
            for (entries) |entry| {
                const canonical_axis = try self.alloc.dupe(u8, entry.group_key);
                errdefer self.alloc.free(canonical_axis);
                const metric = try self.alloc.dupe(u8, metric_name);
                errdefer self.alloc.free(metric);
                const value = try self.alloc.dupe(u8, entry.value);
                errdefer self.alloc.free(value);
                try partials.append(self.alloc, .{
                    .canonical_axis = canonical_axis,
                    .metric = metric,
                    .law_id = law_id,
                    .value = value,
                });
            }
        }
        return try partials.toOwnedSlice(self.alloc);
    }

    pub fn scanDistributedPartialsForTensorProgram(
        self: *Index,
        store: *docstore_mod.DocStore,
        access_paths: []const ir.PhysicalAccessPath,
        program: ir.TensorProgram,
    ) !?[]distributed_mod.Partial {
        return try self.scanDistributedPartialsForTensorProgramAtGeneration(store, access_paths, program, null);
    }

    pub fn scanDistributedPartialsForTensorProgramAtGeneration(
        self: *Index,
        store: *docstore_mod.DocStore,
        access_paths: []const ir.PhysicalAccessPath,
        program: ir.TensorProgram,
        generation: ?u64,
    ) !?[]distributed_mod.Partial {
        const proof = try ir.tensorProgramProof(self.alloc, access_paths, program);
        if (!proof.safe()) {
            self.distributed_partial_validation_rejected_count += 1;
            return null;
        }
        self.distributed_partial_validation_proven_count += 1;
        const refs = if (program.outputs.len > 0) program.outputs else &[_]ir.TensorProgramRef{program.output};
        var partials = std.ArrayListUnmanaged(distributed_mod.Partial).empty;
        errdefer {
            for (partials.items) |partial| {
                self.alloc.free(@constCast(partial.canonical_axis));
                if (partial.metric.len > 0) self.alloc.free(@constCast(partial.metric));
                self.alloc.free(@constCast(partial.value));
            }
            partials.deinit(self.alloc);
        }
        var handled_any = false;
        for (refs) |ref| {
            const step_idx = switch (ref) {
                .step => |idx| idx,
                .input => return null,
            };
            if (step_idx >= program.steps.len) return null;
            const expr = program.steps[step_idx].expr;
            if (expr.metadata == null) return null;
            var cardinality = decodeCardinalityPartialsMetadataAlloc(self.alloc, expr.metadata.?) catch |cardinality_err| switch (cardinality_err) {
                error.InvalidAlgebraicTensorExpr => null,
                else => return cardinality_err,
            };
            if (cardinality) |*cardinality_request| {
                defer cardinality_request.deinit(self.alloc);
                const cardinality_partials = (try self.scanDistributedCardinalityPartialsWithTensorProgramAtGeneration(store, cardinality_request.request, access_paths, program, ref, generation)) orelse return null;
                defer distributed_mod.freePartials(self.alloc, cardinality_partials);
                for (cardinality_partials) |partial| {
                    try self.appendDistributedPartialForCanonicalAxis(&partials, partial.canonical_axis, partial.metric, partial.law_id, partial.value);
                }
                handled_any = true;
                continue;
            }
            var terms_cardinality = decodeTermsCardinalityPartialsMetadataAlloc(self.alloc, expr.metadata.?) catch |terms_cardinality_err| switch (terms_cardinality_err) {
                error.InvalidAlgebraicTensorExpr => null,
                else => return terms_cardinality_err,
            };
            if (terms_cardinality) |*terms_cardinality_request| {
                defer terms_cardinality_request.deinit(self.alloc);
                const terms_cardinality_partials = (try self.scanDistributedTermsCardinalityPartialsWithTensorProgramAtGeneration(store, terms_cardinality_request.request, access_paths, program, ref, generation)) orelse return null;
                defer distributed_mod.freePartials(self.alloc, terms_cardinality_partials);
                for (terms_cardinality_partials) |partial| {
                    try self.appendDistributedPartialForCanonicalAxis(&partials, partial.canonical_axis, partial.metric, partial.law_id, partial.value);
                }
                handled_any = true;
                continue;
            }
            var range_cardinality = decodeRangeCardinalityPartialsMetadataAlloc(self.alloc, expr.metadata.?) catch |range_cardinality_err| switch (range_cardinality_err) {
                error.InvalidAlgebraicTensorExpr => null,
                else => return range_cardinality_err,
            };
            if (range_cardinality) |*range_cardinality_request| {
                defer range_cardinality_request.deinit(self.alloc);
                const range_cardinality_partials = (try self.scanDistributedRangeCardinalityPartialsWithTensorProgramAtGeneration(store, range_cardinality_request.request, access_paths, program, ref, generation)) orelse return null;
                defer distributed_mod.freePartials(self.alloc, range_cardinality_partials);
                for (range_cardinality_partials) |partial| {
                    try self.appendDistributedPartialForCanonicalAxis(&partials, partial.canonical_axis, partial.metric, partial.law_id, partial.value);
                }
                handled_any = true;
                continue;
            }
            var histogram_cardinality = decodeHistogramCardinalityPartialsMetadataAlloc(self.alloc, expr.metadata.?) catch |histogram_cardinality_err| switch (histogram_cardinality_err) {
                error.InvalidAlgebraicTensorExpr => null,
                else => return histogram_cardinality_err,
            };
            if (histogram_cardinality) |*histogram_cardinality_request| {
                defer histogram_cardinality_request.deinit(self.alloc);
                const histogram_cardinality_partials = (try self.scanDistributedHistogramCardinalityPartialsWithTensorProgramAtGeneration(store, histogram_cardinality_request.request, access_paths, program, ref, generation)) orelse return null;
                defer distributed_mod.freePartials(self.alloc, histogram_cardinality_partials);
                for (histogram_cardinality_partials) |partial| {
                    try self.appendDistributedPartialForCanonicalAxis(&partials, partial.canonical_axis, partial.metric, partial.law_id, partial.value);
                }
                handled_any = true;
                continue;
            }
            var fold = decodeDocFactBucketFoldMetadataAlloc(self.alloc, expr.metadata.?) catch |err| switch (err) {
                error.InvalidAlgebraicTensorExpr => {
                    var path_fold = decodePathFactBucketFoldMetadataAlloc(self.alloc, expr.metadata.?) catch |path_err| switch (path_err) {
                        error.InvalidAlgebraicTensorExpr => {
                            var join_fold = decodeDerivedJoinFoldMetadataAlloc(self.alloc, expr.metadata.?) catch |join_err| switch (join_err) {
                                error.InvalidAlgebraicTensorExpr => return null,
                                else => return join_err,
                            };
                            defer join_fold.deinit(self.alloc);
                            const entries = (try self.scanDerivedJoinFoldEntriesWithTensorProgramAtGeneration(store, join_fold.request, access_paths, program, ref, generation)) orelse return null;
                            defer {
                                for (entries) |*entry| entry.deinit(self.alloc);
                                if (entries.len > 0) self.alloc.free(entries);
                            }
                            const metric_name = expr.semantic_id orelse "derived_join_fold";
                            try self.appendDistributedPartialsFromFoldEntries(&partials, entries, metric_name, law_mod.fromOp(join_fold.request.op));
                            handled_any = true;
                            continue;
                        },
                        else => return path_err,
                    };
                    defer path_fold.deinit(self.alloc);
                    const entries = (try self.scanPathFactBucketFoldEntriesWithTensorProgramAtGeneration(store, path_fold.request, access_paths, program, ref, generation)) orelse return null;
                    defer {
                        for (entries) |*entry| entry.deinit(self.alloc);
                        if (entries.len > 0) self.alloc.free(entries);
                    }
                    const metric_name = expr.semantic_id orelse "pathfact_bucket_fold";
                    try self.appendDistributedPartialsFromFoldEntries(&partials, entries, metric_name, law_mod.fromOp(path_fold.request.op));
                    handled_any = true;
                    continue;
                },
                else => return err,
            };
            defer fold.deinit(self.alloc);
            const entries = (try self.scanDocFactBucketFoldEntriesWithTensorProgramAtGeneration(store, fold.request, access_paths, program, ref, generation)) orelse return null;
            defer {
                for (entries) |*entry| entry.deinit(self.alloc);
                if (entries.len > 0) self.alloc.free(entries);
            }
            const metric_name = expr.semantic_id orelse "docfact_bucket_fold";
            try self.appendDistributedPartialsFromFoldEntries(&partials, entries, metric_name, law_mod.fromOp(fold.request.op));
            handled_any = true;
        }
        if (!handled_any) {
            self.distributed_partial_validation_rejected_count += 1;
            return null;
        }
        const owned = try partials.toOwnedSlice(self.alloc);
        self.distributed_partial_rows_exported_count += owned.len;
        return owned;
    }

    pub fn scanDistributedPartialEnvelopesForTensorProgram(
        self: *Index,
        store: *docstore_mod.DocStore,
        access_paths: []const ir.PhysicalAccessPath,
        program: ir.TensorProgram,
    ) !?[]distributed_mod.PartialEnvelope {
        if (access_paths.len == 0) return null;
        const output_ref = if (program.outputs.len == 0) program.output else if (program.outputs.len == 1) program.outputs[0] else return null;
        const output_step_idx = switch (output_ref) {
            .step => |idx| idx,
            .input => return null,
        };
        if (output_step_idx >= program.steps.len) return null;
        const output_expr = program.steps[output_step_idx].expr;
        const law_id = output_expr.law_id orelse return null;
        const access_path = access_paths[0];
        const owner = output_expr.owner orelse access_path.owner;
        const layout = output_expr.layout orelse access_path.layout;
        const program_id = try ir.tensorProgramIdAlloc(self.alloc, program);
        defer self.alloc.free(program_id);
        const expression_id = try ir.tensorExprIdAlloc(self.alloc, output_expr);
        defer self.alloc.free(expression_id);
        const dictionary_identity = if (output_expr.dictionary) |dictionary|
            try dictionary.keyAlloc(self.alloc)
        else if (access_path.dictionary) |dictionary|
            try dictionary.keyAlloc(self.alloc)
        else
            null;
        defer if (dictionary_identity) |identity| self.alloc.free(identity);

        const partials = (try self.scanDistributedPartialsForTensorProgram(store, access_paths, program)) orelse return null;
        defer distributed_mod.freePartials(self.alloc, partials);
        var envelopes = std.ArrayListUnmanaged(distributed_mod.PartialEnvelope).empty;
        errdefer distributed_mod.freePartialEnvelopes(self.alloc, envelopes.items);
        for (partials) |partial| {
            if (partial.law_id != law_id) return error.InvalidDistributedAlgebraicMerge;
            const protocol_owner = try self.alloc.dupe(u8, owner);
            errdefer self.alloc.free(protocol_owner);
            const protocol_dims = try self.alloc.dupe(ir.Dimension, output_expr.output_dims);
            errdefer if (protocol_dims.len > 0) self.alloc.free(protocol_dims);
            const protocol_metric = try self.alloc.dupe(u8, partial.metric);
            errdefer if (protocol_metric.len > 0) self.alloc.free(protocol_metric);
            const protocol_program_id = try self.alloc.dupe(u8, program_id);
            errdefer if (protocol_program_id.len > 0) self.alloc.free(protocol_program_id);
            const protocol_expression_id = try self.alloc.dupe(u8, expression_id);
            errdefer if (protocol_expression_id.len > 0) self.alloc.free(protocol_expression_id);
            const protocol_dictionary_identity = if (dictionary_identity) |identity|
                try self.alloc.dupe(u8, identity)
            else
                null;
            errdefer if (protocol_dictionary_identity) |identity| self.alloc.free(identity);
            const canonical_axis = try self.alloc.dupe(u8, partial.canonical_axis);
            errdefer self.alloc.free(canonical_axis);
            const metric = try self.alloc.dupe(u8, partial.metric);
            errdefer if (metric.len > 0) self.alloc.free(metric);
            const value = try self.alloc.dupe(u8, partial.value);
            errdefer self.alloc.free(value);
            try envelopes.append(self.alloc, .{
                .protocol = .{
                    .owner = protocol_owner,
                    .layout = layout,
                    .fragment = output_expr.fragment,
                    .output_dims = protocol_dims,
                    .law_id = partial.law_id,
                    .metric = protocol_metric,
                    .program_id = protocol_program_id,
                    .expression_id = protocol_expression_id,
                    .dictionary_identity = protocol_dictionary_identity,
                },
                .partial = .{
                    .canonical_axis = canonical_axis,
                    .metric = metric,
                    .law_id = partial.law_id,
                    .value = value,
                },
            });
        }
        return try envelopes.toOwnedSlice(self.alloc);
    }

    fn appendDistributedPartialsFromFoldEntries(
        self: *Index,
        partials: *std.ArrayListUnmanaged(distributed_mod.Partial),
        entries: []const FoldEntry,
        metric_name: []const u8,
        law_id: law_mod.Id,
    ) !void {
        for (entries) |entry| {
            const canonical_axis = try self.alloc.dupe(u8, entry.group_key);
            errdefer self.alloc.free(canonical_axis);
            const metric = try self.alloc.dupe(u8, metric_name);
            errdefer self.alloc.free(metric);
            const value = try self.alloc.dupe(u8, entry.value);
            errdefer self.alloc.free(value);
            try partials.append(self.alloc, .{
                .canonical_axis = canonical_axis,
                .metric = metric,
                .law_id = law_id,
                .value = value,
            });
        }
    }

    fn appendDistributedPartialForCanonicalAxis(
        self: *Index,
        partials: *std.ArrayListUnmanaged(distributed_mod.Partial),
        canonical_axis: []const u8,
        metric_name: []const u8,
        law_id: law_mod.Id,
        raw_value: []const u8,
    ) !void {
        const axis = try self.alloc.dupe(u8, canonical_axis);
        errdefer self.alloc.free(axis);
        const metric = try self.alloc.dupe(u8, metric_name);
        errdefer self.alloc.free(metric);
        const value = try self.alloc.dupe(u8, raw_value);
        errdefer self.alloc.free(value);
        try partials.append(self.alloc, .{
            .canonical_axis = axis,
            .metric = metric,
            .law_id = law_id,
            .value = value,
        });
    }

    pub fn docIdsForConstraintsAlloc(self: *Index, store: *docstore_mod.DocStore, constraints: []const ir.Constraint) ![][]u8 {
        if (constraints.len == 0) return try self.alloc.alloc([]u8, 0);

        const EncodedConstraint = struct {
            field: []const u8,
            scalar: []u8,

            fn deinit(item: *@This(), alloc: Allocator) void {
                alloc.free(item.scalar);
                item.* = undefined;
            }
        };
        var encoded = std.ArrayListUnmanaged(EncodedConstraint).empty;
        defer {
            for (encoded.items) |*item| item.deinit(self.alloc);
            encoded.deinit(self.alloc);
        }
        for (constraints) |constraint| {
            const field = self.fieldConfig(constraint.field, .group) orelse return try self.alloc.alloc([]u8, 0);
            try encoded.append(self.alloc, .{
                .field = field.name,
                .scalar = try self.constraintTokenAlloc(self.alloc, field.name, constraint.value),
            });
        }

        var out: ?[][]u8 = null;
        errdefer if (out) |ids| self.freeDocIds(ids);
        for (encoded.items) |constraint| {
            const item_ids = try self.docIdsForScalarFactAlloc(store, .group, constraint.field, constraint.scalar);
            if (out) |current| {
                defer self.freeDocIds(current);
                defer self.freeDocIds(item_ids);
                out = try self.intersectDocIdsAlloc(current, item_ids);
            } else {
                out = item_ids;
            }
        }
        return out orelse try self.alloc.alloc([]u8, 0);
    }

    pub fn resolvedDocSetForConstraintsAlloc(self: *Index, store: *docstore_mod.DocStore, constraints: []const ir.Constraint) !?doc_set.ResolvedDocSet {
        return try self.resolvedDocSetForConstraintsAtGenerationAlloc(store, constraints, null);
    }

    pub fn resolvedDocSetForConstraintsAtGenerationAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        constraints: []const ir.Constraint,
        generation: ?u64,
    ) !?doc_set.ResolvedDocSet {
        if (constraints.len == 0) return .all;

        var out: ?doc_set.ResolvedDocSet = null;
        errdefer if (out) |*set| set.deinit(self.alloc);

        for (constraints) |constraint| {
            const field = self.fieldConfig(constraint.field, .group) orelse return .none;
            const scalar = try self.constraintTokenAlloc(self.alloc, field.name, constraint.value);
            defer self.alloc.free(scalar);
            var item_set = (try self.resolvedDocSetForScalarFactAlloc(store, .group, field.name, scalar)) orelse return null;
            defer item_set.deinit(self.alloc);
            if (out) |*current| {
                const next = (try doc_set.intersectAlloc(self.alloc, current, &item_set)) orelse return null;
                current.deinit(self.alloc);
                out = next;
            } else {
                out = try doc_set.cloneAlloc(self.alloc, &item_set);
            }
        }

        var resolved = out orelse .none;
        defer resolved.deinit(self.alloc);
        return try doc_identity.visibleFilteredDocSetFromStoreAlloc(self.alloc, store, &resolved, generation);
    }

    pub fn exactCardinalityForFieldAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        field_or_path: []const u8,
        constraints: []const ir.Constraint,
    ) !?u64 {
        const constraint_ids = (try self.docIdsForSupportedCardinalityConstraintsAlloc(store, constraints)) orelse return null;
        defer self.freeDocIds(constraint_ids);

        if (isExplicitJsonPointerPath(field_or_path)) {
            return try self.exactPathCardinalityAlloc(store, field_or_path, constraint_ids);
        }

        const field = self.uniqueExistingFactField(field_or_path) orelse return null;
        return try self.exactDocFactCardinalityAlloc(store, field, constraint_ids);
    }

    pub fn exactCardinalityForFieldAtGenerationAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        field_or_path: []const u8,
        constraints: []const ir.Constraint,
        generation: ?u64,
    ) !?u64 {
        if (generation == null) return try self.exactCardinalityForFieldAlloc(store, field_or_path, constraints);

        const constraint_ids = (try self.docIdsForSupportedCardinalityConstraintsAlloc(store, constraints)) orelse return null;
        defer self.freeDocIds(constraint_ids);

        if (isExplicitJsonPointerPath(field_or_path)) {
            return try self.exactPathCardinalityAtGenerationAlloc(store, field_or_path, constraint_ids, generation);
        }

        const field = self.uniqueExistingFactField(field_or_path) orelse return null;
        return try self.exactDocFactCardinalityAtGenerationAlloc(store, field, constraint_ids, generation);
    }

    pub fn exactCardinalityForDocIdsAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        field_or_path: []const u8,
        doc_ids: []const []const u8,
    ) !?u64 {
        if (doc_ids.len == 0) return 0;
        if (isExplicitJsonPointerPath(field_or_path)) {
            return try self.exactPathCardinalityAlloc(store, field_or_path, doc_ids);
        }
        const field = self.uniqueExistingFactField(field_or_path) orelse return null;
        return try self.exactDocFactCardinalityAlloc(store, field, doc_ids);
    }

    pub fn scanDistributedCardinalityPartials(
        self: *Index,
        store: *docstore_mod.DocStore,
        aggregation_name: []const u8,
        field_or_path: []const u8,
        constraints: []const ir.Constraint,
        generation: ?u64,
    ) !?[]distributed_mod.Partial {
        const constraint_ids = (try self.docIdsForSupportedCardinalityConstraintsAlloc(store, constraints)) orelse return null;
        defer self.freeDocIds(constraint_ids);

        var values = std.StringHashMapUnmanaged(void).empty;
        defer {
            var it = values.keyIterator();
            while (it.next()) |key| self.alloc.free(key.*);
            values.deinit(self.alloc);
        }

        if (isExplicitJsonPointerPath(field_or_path)) {
            try self.collectPathCardinalityValuesAtGeneration(store, field_or_path, constraint_ids, generation, &values);
        } else {
            const field = self.uniqueExistingFactField(field_or_path) orelse return null;
            try self.collectDocFactCardinalityValuesAtGeneration(store, field, constraint_ids, generation, &values);
        }

        var partials = std.ArrayListUnmanaged(distributed_mod.Partial).empty;
        errdefer {
            for (partials.items) |partial| {
                self.alloc.free(@constCast(partial.canonical_axis));
                if (partial.metric.len > 0) self.alloc.free(@constCast(partial.metric));
                self.alloc.free(@constCast(partial.value));
            }
            partials.deinit(self.alloc);
        }
        var it = values.keyIterator();
        while (it.next()) |value_key| {
            try self.appendCardinalityPartial(&partials, aggregation_name, value_key.*);
        }
        return try partials.toOwnedSlice(self.alloc);
    }

    pub fn scanDistributedRangeCardinalityPartials(
        self: *Index,
        store: *docstore_mod.DocStore,
        aggregation_name: []const u8,
        field_or_path: []const u8,
        kind: CardinalityRangeKind,
        ranges: []const CardinalityRangeRequest,
        child_requests: []const CardinalityChildRequest,
        constraints: []const ir.Constraint,
        generation: ?u64,
    ) !?[]distributed_mod.Partial {
        if (ranges.len == 0 or child_requests.len == 0) return null;
        const constraint_ids = (try self.docIdsForSupportedCardinalityConstraintsAlloc(store, constraints)) orelse return null;
        defer self.freeDocIds(constraint_ids);
        var live_txn: ?docstore_mod.DocStore.Txn = null;
        if (generation != null) live_txn = try store.beginReadTxn();
        defer if (live_txn) |*txn| txn.abort();

        var partials = std.ArrayListUnmanaged(distributed_mod.Partial).empty;
        errdefer {
            for (partials.items) |partial| {
                self.alloc.free(@constCast(partial.canonical_axis));
                if (partial.metric.len > 0) self.alloc.free(@constCast(partial.metric));
                self.alloc.free(@constCast(partial.value));
            }
            partials.deinit(self.alloc);
        }

        const child_indexes = (try self.buildChildCardinalityIndexesAlloc(store, child_requests)) orelse return null;
        defer self.freeChildCardinalityIndexes(child_indexes);

        for (ranges) |range| {
            const filter_json = try self.rangeCardinalityFilterJsonAlloc(field_or_path, kind, range);
            defer self.alloc.free(filter_json);
            const range_ids = (try self.docIdsForFilterJsonAlloc(store, filter_json)) orelse return null;
            defer self.freeDocIds(range_ids);
            const effective_ids = if (constraint_ids.len > 0)
                try self.intersectDocIdsAlloc(range_ids, constraint_ids)
            else
                try self.dupeDocIdsAlloc(range_ids);
            defer self.freeDocIds(effective_ids);
            const live_effective_ids = if (live_txn) |*txn|
                try self.filterDocIdsVisibleAtGenerationAlloc(txn, effective_ids, generation)
            else
                null;
            defer if (live_effective_ids) |ids| self.freeDocIds(ids);
            const bucket_ids = live_effective_ids orelse effective_ids;
            const axis = try rangeCardinalityAxisAlloc(self.alloc, kind, range);
            defer self.alloc.free(axis);
            try self.appendDistributedCountPartial(&partials, axis, aggregation_name, @intCast(bucket_ids.len));
            for (child_requests, child_indexes) |child, *child_index| {
                try self.appendBucketChildCardinalityPartials(&partials, axis, .raw, child.name, child_index, bucket_ids);
            }
        }

        return try partials.toOwnedSlice(self.alloc);
    }

    pub fn scanDistributedHistogramCardinalityPartials(
        self: *Index,
        store: *docstore_mod.DocStore,
        aggregation_name: []const u8,
        field_name: []const u8,
        kind: CardinalityHistogramKind,
        numeric_interval: f64,
        date_bucket_name: []const u8,
        child_requests: []const CardinalityChildRequest,
        constraints: []const ir.Constraint,
        generation: ?u64,
    ) !?[]distributed_mod.Partial {
        if (field_name.len == 0 or child_requests.len == 0) return null;
        if (kind == .numeric and numeric_interval <= 0) return null;
        const constraint_ids = (try self.docIdsForSupportedCardinalityConstraintsAlloc(store, constraints)) orelse return null;
        defer self.freeDocIds(constraint_ids);

        if (isExplicitJsonPointerPath(field_name)) {
            return try self.scanDistributedPathHistogramCardinalityPartials(
                store,
                aggregation_name,
                field_name,
                kind,
                numeric_interval,
                date_bucket_name,
                child_requests,
                constraint_ids,
                generation,
            );
        }

        const role: fact_mod.Role = switch (kind) {
            .numeric => blk: {
                if (self.fieldConfig(field_name, .measure) != null) break :blk .measure;
                const group_field = self.fieldConfig(field_name, .group) orelse return null;
                const bucket_kind = value_mod.kindFromFieldType(group_field.type);
                if (bucket_kind != .number and bucket_kind != .integer) return null;
                if (self.constraintValueForFieldName(constraints, group_field.name) != null) return null;
                break :blk .group;
            },
            .date => blk: {
                _ = self.fieldConfig(field_name, .time) orelse return null;
                _ = cylinder.Bucket.parse(date_bucket_name) orelse return null;
                break :blk .time;
            },
        };

        const entries = try self.scalarDocFactEntriesForFieldAlloc(store, role, field_name);
        defer {
            for (entries) |*entry| entry.deinit(self.alloc);
            if (entries.len > 0) self.alloc.free(entries);
        }
        var live_txn: ?docstore_mod.DocStore.Txn = null;
        if (generation != null) live_txn = try store.beginReadTxn();
        defer if (live_txn) |*txn| txn.abort();

        const BucketDocs = struct {
            axis: []u8,
            doc_ids: std.ArrayListUnmanaged([]u8) = .empty,

            fn appendDocId(item: *@This(), alloc: Allocator, doc_id: []const u8) !void {
                for (item.doc_ids.items) |existing| {
                    if (std.mem.eql(u8, existing, doc_id)) return;
                }
                try item.doc_ids.append(alloc, try alloc.dupe(u8, doc_id));
            }

            fn deinit(item: *@This(), alloc: Allocator) void {
                alloc.free(item.axis);
                for (item.doc_ids.items) |doc_id| alloc.free(doc_id);
                item.doc_ids.deinit(alloc);
                item.* = undefined;
            }
        };
        var buckets = std.ArrayListUnmanaged(BucketDocs).empty;
        defer {
            for (buckets.items) |*bucket| bucket.deinit(self.alloc);
            buckets.deinit(self.alloc);
        }

        var constraint_set = try DocIdConstraintSet.init(self.alloc, constraint_ids);
        defer constraint_set.deinit(self.alloc);
        for (entries) |entry| {
            if (!constraint_set.matches(entry.doc_id)) continue;
            if (live_txn) |*txn| {
                if (!try self.docVisibleAtGenerationTxn(txn, entry.doc_id, generation)) continue;
            }
            const axis = switch (kind) {
                .numeric => blk: {
                    const text = try self.scalarTokenTextAlloc(self.alloc, entry.scalar);
                    defer self.alloc.free(text);
                    const numeric = std.fmt.parseFloat(f64, text) catch continue;
                    const bucket_index: i64 = @intFromFloat(@floor(numeric / numeric_interval));
                    break :blk try std.fmt.allocPrint(self.alloc, "{d}", .{bucket_index});
                },
                .date => blk: {
                    const bucket = cylinder.Bucket.parse(date_bucket_name) orelse return null;
                    const text = try self.scalarTokenTextAlloc(self.alloc, entry.scalar);
                    defer self.alloc.free(text);
                    break :blk cylinder.bucketStartAlloc(self.alloc, bucket, text) catch continue;
                },
            };
            defer self.alloc.free(axis);
            const bucket = blk: {
                for (buckets.items) |*bucket| {
                    if (std.mem.eql(u8, bucket.axis, axis)) break :blk bucket;
                }
                try buckets.append(self.alloc, .{
                    .axis = try self.alloc.dupe(u8, axis),
                });
                break :blk &buckets.items[buckets.items.len - 1];
            };
            try bucket.doc_ids.append(self.alloc, try self.alloc.dupe(u8, entry.doc_id));
        }

        var partials = std.ArrayListUnmanaged(distributed_mod.Partial).empty;
        errdefer {
            for (partials.items) |partial| {
                self.alloc.free(@constCast(partial.canonical_axis));
                if (partial.metric.len > 0) self.alloc.free(@constCast(partial.metric));
                self.alloc.free(@constCast(partial.value));
            }
            partials.deinit(self.alloc);
        }

        const child_indexes = (try self.buildChildCardinalityIndexesAlloc(store, child_requests)) orelse return null;
        defer self.freeChildCardinalityIndexes(child_indexes);
        for (buckets.items) |bucket| {
            try self.appendDistributedCountPartial(&partials, bucket.axis, aggregation_name, @intCast(bucket.doc_ids.items.len));
            for (child_requests, child_indexes) |child, *child_index| {
                try self.appendBucketChildCardinalityPartials(&partials, bucket.axis, .raw, child.name, child_index, bucket.doc_ids.items);
            }
        }

        return try partials.toOwnedSlice(self.alloc);
    }

    pub fn docVisibleAtGenerationTxn(
        self: *Index,
        txn: anytype,
        doc_id: []const u8,
        generation: ?u64,
    ) !bool {
        const at = generation orelse return true;
        const ordinal = (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_id)) orelse return false;
        const state = (try doc_identity.lookupStateTxn(txn, ordinal)) orelse return false;
        return state.isVisibleAt(at);
    }

    fn docOrdinalVisibleAtGenerationTxn(
        self: *Index,
        txn: anytype,
        ordinal: doc_set.DocOrdinal,
        generation: ?u64,
    ) !bool {
        _ = self;
        const at = generation orelse return true;
        const state = (try doc_identity.lookupStateTxn(txn, ordinal)) orelse return false;
        return state.isVisibleAt(at);
    }

    fn docFactKeyVisibleAtGenerationTxn(
        self: *Index,
        txn: anytype,
        key: []const u8,
        prefix: []const u8,
        generation: ?u64,
    ) !bool {
        const at = generation orelse return true;
        _ = at;
        const doc_component = token.componentAt(key, prefix.len) catch return true;
        if (doc_component.next != key.len) return true;
        return try self.docVisibleAtGenerationTxn(txn, doc_component.payload, generation);
    }

    fn joinFactKeyVisibleAtGenerationTxn(
        self: *Index,
        txn: anytype,
        key: []const u8,
        generation: ?u64,
    ) !bool {
        _ = generation orelse return true;
        var pos: usize = namespace_prefix.len;
        var component_index: usize = 0;
        var row_namespace: ?[]const u8 = null;
        var last_component: ?[]const u8 = null;
        while (pos < key.len) {
            const component = token.componentAt(key, pos) catch return true;
            if (component_index == 2) row_namespace = component.payload;
            last_component = component.payload;
            component_index += 1;
            pos = component.next;
        }
        const identity = last_component orelse return true;
        if (row_namespace) |kind| {
            if (std.mem.eql(u8, kind, "jf_ord")) {
                if (identity.len != 4) return true;
                const ordinal = std.mem.readInt(u32, identity[0..4], .big);
                return try self.docOrdinalVisibleAtGenerationTxn(txn, ordinal, generation);
            }
        }
        return try self.docVisibleAtGenerationTxn(txn, identity, generation);
    }

    fn filterDocIdsVisibleAtGenerationAlloc(
        self: *Index,
        txn: *docstore_mod.DocStore.Txn,
        doc_ids: []const []const u8,
        generation: ?u64,
    ) ![][]u8 {
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer self.freeDocIds(out.items);
        for (doc_ids) |doc_id| {
            if (!try self.docVisibleAtGenerationTxn(txn, doc_id, generation)) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_id));
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn scanDistributedPathHistogramCardinalityPartials(
        self: *Index,
        store: *docstore_mod.DocStore,
        aggregation_name: []const u8,
        path: []const u8,
        kind: CardinalityHistogramKind,
        numeric_interval: f64,
        date_bucket_name: []const u8,
        child_requests: []const CardinalityChildRequest,
        constraint_ids: []const []const u8,
        generation: ?u64,
    ) !?[]distributed_mod.Partial {
        const date_bucket = if (kind == .date) cylinder.Bucket.parse(date_bucket_name) orelse return null else undefined;
        const BucketDocs = struct {
            axis: []u8,
            doc_ids: std.ArrayListUnmanaged([]u8) = .empty,

            fn appendDocId(item: *@This(), alloc: Allocator, doc_id: []const u8) !void {
                for (item.doc_ids.items) |existing| {
                    if (std.mem.eql(u8, existing, doc_id)) return;
                }
                try item.doc_ids.append(alloc, try alloc.dupe(u8, doc_id));
            }

            fn deinit(item: *@This(), alloc: Allocator) void {
                alloc.free(item.axis);
                for (item.doc_ids.items) |doc_id| alloc.free(doc_id);
                item.doc_ids.deinit(alloc);
                item.* = undefined;
            }
        };
        var buckets = std.ArrayListUnmanaged(BucketDocs).empty;
        defer {
            for (buckets.items) |*bucket| bucket.deinit(self.alloc);
            buckets.deinit(self.alloc);
        }

        var txn = try store.beginReadTxn();
        defer txn.abort();
        const allow_numeric_string = if (kind == .numeric) try self.pathFactNumericStringPathAllowedTxn(&txn, path) else false;
        const allow_datetime_string = if (kind == .date) try self.pathFactDatetimeStringPathAllowedTxn(&txn, path) else false;
        if (kind == .date and !allow_datetime_string) return null;
        const prefix = try self.keyAlloc(&.{"pathfact"});
        defer self.alloc.free(prefix);
        var constraint_set = try DocIdConstraintSet.init(self.alloc, constraint_ids);
        defer constraint_set.deinit(self.alloc);
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const doc_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (doc_component.next != entry.key.len) continue;
            if (!constraint_set.matches(doc_component.payload)) continue;
            if (generation != null and !try self.docVisibleAtGenerationTxn(&txn, doc_component.payload, generation)) continue;
            var projection = pathfact_mod.decodeProjectionAlloc(self.alloc, entry.value) catch |err| switch (err) {
                error.InvalidPathFactList => continue,
                else => return err,
            };
            defer projection.deinit(self.alloc);
            const axis = switch (kind) {
                .numeric => blk: {
                    const number_fact = pathFactByPathAndKind(projection.facts, path, .number);
                    const string_fact = if (number_fact == null and allow_numeric_string)
                        pathFactByPathAndKind(projection.facts, path, .string)
                    else
                        null;
                    const fact = number_fact orelse string_fact orelse continue;
                    const numeric = std.fmt.parseFloat(f64, fact.value) catch continue;
                    const bucket_index: i64 = @intFromFloat(@floor(numeric / numeric_interval));
                    break :blk try std.fmt.allocPrint(self.alloc, "{d}", .{bucket_index});
                },
                .date => blk: {
                    const fact = pathFactByPathAndKind(projection.facts, path, .string) orelse continue;
                    break :blk cylinder.bucketStartAlloc(self.alloc, date_bucket, fact.value) catch continue;
                },
            };
            defer self.alloc.free(axis);
            const bucket = blk: {
                for (buckets.items) |*bucket| {
                    if (std.mem.eql(u8, bucket.axis, axis)) break :blk bucket;
                }
                try buckets.append(self.alloc, .{ .axis = try self.alloc.dupe(u8, axis) });
                break :blk &buckets.items[buckets.items.len - 1];
            };
            try bucket.doc_ids.append(self.alloc, try self.alloc.dupe(u8, doc_component.payload));
        }

        var partials = std.ArrayListUnmanaged(distributed_mod.Partial).empty;
        errdefer {
            for (partials.items) |partial| {
                self.alloc.free(@constCast(partial.canonical_axis));
                if (partial.metric.len > 0) self.alloc.free(@constCast(partial.metric));
                self.alloc.free(@constCast(partial.value));
            }
            partials.deinit(self.alloc);
        }
        const child_indexes = (try self.buildChildCardinalityIndexesAlloc(store, child_requests)) orelse return null;
        defer self.freeChildCardinalityIndexes(child_indexes);
        for (buckets.items) |bucket| {
            try self.appendDistributedCountPartial(&partials, bucket.axis, aggregation_name, @intCast(bucket.doc_ids.items.len));
            for (child_requests, child_indexes) |child, *child_index| {
                try self.appendBucketChildCardinalityPartials(&partials, bucket.axis, .raw, child.name, child_index, bucket.doc_ids.items);
            }
        }
        return try partials.toOwnedSlice(self.alloc);
    }

    pub fn scanDistributedTermsCardinalityPartials(
        self: *Index,
        store: *docstore_mod.DocStore,
        terms_aggregation_name: []const u8,
        bucket_field_name: []const u8,
        child_requests: []const CardinalityChildRequest,
        constraints: []const ir.Constraint,
        generation: ?u64,
    ) !?[]distributed_mod.Partial {
        if (child_requests.len == 0) return null;
        if (isExplicitJsonPointerPath(bucket_field_name)) {
            return try self.scanDistributedPathTermsCardinalityPartials(store, terms_aggregation_name, bucket_field_name, child_requests, constraints, generation);
        }
        const bucket_field = self.fieldConfig(bucket_field_name, .group) orelse return null;
        if (self.constraintValueForFieldName(constraints, bucket_field.name) != null) return null;
        const constraint_ids = (try self.docIdsForSupportedCardinalityConstraintsAlloc(store, constraints)) orelse return null;
        defer self.freeDocIds(constraint_ids);

        const BucketDocs = struct {
            axis: []u8,
            doc_ids: std.ArrayListUnmanaged([]u8) = .empty,

            fn appendDocId(item: *@This(), alloc: Allocator, doc_id: []const u8) !void {
                for (item.doc_ids.items) |existing| {
                    if (std.mem.eql(u8, existing, doc_id)) return;
                }
                try item.doc_ids.append(alloc, try alloc.dupe(u8, doc_id));
            }

            fn deinit(item: *@This(), alloc: Allocator) void {
                alloc.free(item.axis);
                for (item.doc_ids.items) |doc_id| alloc.free(doc_id);
                item.doc_ids.deinit(alloc);
                item.* = undefined;
            }
        };
        var buckets = std.ArrayListUnmanaged(BucketDocs).empty;
        defer {
            for (buckets.items) |*bucket| bucket.deinit(self.alloc);
            buckets.deinit(self.alloc);
        }

        const bucket_entries = try self.scalarDocFactEntriesForFieldAlloc(store, .group, bucket_field.name);
        defer {
            for (bucket_entries) |*entry| entry.deinit(self.alloc);
            if (bucket_entries.len > 0) self.alloc.free(bucket_entries);
        }
        var live_txn: ?docstore_mod.DocStore.Txn = null;
        if (generation != null) live_txn = try store.beginReadTxn();
        defer if (live_txn) |*txn| txn.abort();

        var constraint_set = try DocIdConstraintSet.init(self.alloc, constraint_ids);
        defer constraint_set.deinit(self.alloc);
        for (bucket_entries) |entry| {
            if (!constraint_set.matches(entry.doc_id)) continue;
            if (live_txn) |*txn| {
                if (!try self.docVisibleAtGenerationTxn(txn, entry.doc_id, generation)) continue;
            }
            const bucket = blk: {
                for (buckets.items) |*bucket| {
                    if (std.mem.eql(u8, bucket.axis, entry.scalar)) break :blk bucket;
                }
                try buckets.append(self.alloc, .{ .axis = try self.alloc.dupe(u8, entry.scalar) });
                break :blk &buckets.items[buckets.items.len - 1];
            };
            try BucketDocs.appendDocId(bucket, self.alloc, entry.doc_id);
        }

        var partials = std.ArrayListUnmanaged(distributed_mod.Partial).empty;
        errdefer {
            for (partials.items) |partial| {
                self.alloc.free(@constCast(partial.canonical_axis));
                if (partial.metric.len > 0) self.alloc.free(@constCast(partial.metric));
                self.alloc.free(@constCast(partial.value));
            }
            partials.deinit(self.alloc);
        }

        const child_indexes = (try self.buildChildCardinalityIndexesAlloc(store, child_requests)) orelse return null;
        defer self.freeChildCardinalityIndexes(child_indexes);
        for (buckets.items) |bucket| {
            try self.appendDistributedCountPartial(&partials, bucket.axis, terms_aggregation_name, @intCast(bucket.doc_ids.items.len));
            for (child_requests, child_indexes) |child, *child_index| {
                try self.appendBucketChildCardinalityPartials(&partials, bucket.axis, .raw, child.name, child_index, bucket.doc_ids.items);
            }
        }

        return try partials.toOwnedSlice(self.alloc);
    }

    fn scanDistributedPathTermsCardinalityPartials(
        self: *Index,
        store: *docstore_mod.DocStore,
        terms_aggregation_name: []const u8,
        bucket_path: []const u8,
        child_requests: []const CardinalityChildRequest,
        constraints: []const ir.Constraint,
        generation: ?u64,
    ) !?[]distributed_mod.Partial {
        const constraint_ids = (try self.docIdsForSupportedCardinalityConstraintsAlloc(store, constraints)) orelse return null;
        defer self.freeDocIds(constraint_ids);

        const BucketDocs = struct {
            axis: []u8,
            doc_ids: std.ArrayListUnmanaged([]u8) = .empty,

            fn appendDocId(item: *@This(), alloc: Allocator, doc_id: []const u8) !void {
                for (item.doc_ids.items) |existing| {
                    if (std.mem.eql(u8, existing, doc_id)) return;
                }
                try item.doc_ids.append(alloc, try alloc.dupe(u8, doc_id));
            }

            fn deinit(item: *@This(), alloc: Allocator) void {
                alloc.free(item.axis);
                for (item.doc_ids.items) |doc_id| alloc.free(doc_id);
                item.doc_ids.deinit(alloc);
                item.* = undefined;
            }
        };
        var buckets = std.ArrayListUnmanaged(BucketDocs).empty;
        defer {
            for (buckets.items) |*bucket| bucket.deinit(self.alloc);
            buckets.deinit(self.alloc);
        }

        const prefix = try self.keyAlloc(&.{"pathfact"});
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var constraint_set = try DocIdConstraintSet.init(self.alloc, constraint_ids);
        defer constraint_set.deinit(self.alloc);
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const doc_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (doc_component.next != entry.key.len) continue;
            if (!constraint_set.matches(doc_component.payload)) continue;
            if (generation != null and !try self.docVisibleAtGenerationTxn(&txn, doc_component.payload, generation)) continue;
            var projection = pathfact_mod.decodeProjectionAlloc(self.alloc, entry.value) catch |err| switch (err) {
                error.InvalidPathFactList => continue,
                else => return err,
            };
            defer projection.deinit(self.alloc);
            const scalar_array_bucket = pathFactsHaveScalarAtPath(projection.facts, bucket_path);
            for (projection.facts) |fact| {
                if (!std.mem.eql(u8, fact.path, bucket_path)) continue;
                if (fact.kind == .array and scalar_array_bucket) continue;
                const axis = try token.canonicalTupleAlloc(self.alloc, &.{ @tagName(fact.kind), fact.value });
                defer self.alloc.free(axis);
                const bucket = blk: {
                    for (buckets.items) |*bucket| {
                        if (std.mem.eql(u8, bucket.axis, axis)) break :blk bucket;
                    }
                    try buckets.append(self.alloc, .{ .axis = try self.alloc.dupe(u8, axis) });
                    break :blk &buckets.items[buckets.items.len - 1];
                };
                try BucketDocs.appendDocId(bucket, self.alloc, doc_component.payload);
            }
        }

        var partials = std.ArrayListUnmanaged(distributed_mod.Partial).empty;
        errdefer {
            for (partials.items) |partial| {
                self.alloc.free(@constCast(partial.canonical_axis));
                if (partial.metric.len > 0) self.alloc.free(@constCast(partial.metric));
                self.alloc.free(@constCast(partial.value));
            }
            partials.deinit(self.alloc);
        }
        const child_indexes = (try self.buildChildCardinalityIndexesAlloc(store, child_requests)) orelse return null;
        defer self.freeChildCardinalityIndexes(child_indexes);
        for (buckets.items) |bucket| {
            const count_value = try algebra.encodeI64Alloc(self.alloc, @intCast(bucket.doc_ids.items.len));
            defer self.alloc.free(count_value);
            try self.appendDistributedPartialForCanonicalAxis(&partials, bucket.axis, terms_aggregation_name, .count, count_value);
            for (child_requests, child_indexes) |child, *child_index| {
                try self.appendBucketChildCardinalityPartials(&partials, bucket.axis, .canonical, child.name, child_index, bucket.doc_ids.items);
            }
        }

        return try partials.toOwnedSlice(self.alloc);
    }

    // Per-document index of distinct cardinality value-keys for one child
    // field, populated with a single cursor scan over that field. Bucketed
    // cardinality (histogram / range / terms children) used to re-scan the
    // entire child field once per bucket; with this index we scan once and look
    // up each bucket's documents, turning O(buckets * field_entries) into
    // O(field_entries + total_bucket_members).
    const ChildCardinalityIndex = struct {
        by_doc: std.StringHashMapUnmanaged(std.ArrayListUnmanaged([]u8)) = .empty,

        fn deinit(self: *ChildCardinalityIndex, alloc: Allocator) void {
            var it = self.by_doc.iterator();
            while (it.next()) |entry| {
                for (entry.value_ptr.items) |value_key| alloc.free(value_key);
                entry.value_ptr.deinit(alloc);
                alloc.free(entry.key_ptr.*);
            }
            self.by_doc.deinit(alloc);
            self.* = .{};
        }

        fn add(self: *ChildCardinalityIndex, alloc: Allocator, doc_id: []const u8, value_key: []const u8) !void {
            const gop = try self.by_doc.getOrPut(alloc, doc_id);
            if (!gop.found_existing) {
                errdefer _ = self.by_doc.remove(doc_id);
                gop.key_ptr.* = try alloc.dupe(u8, doc_id);
                gop.value_ptr.* = .empty;
            }
            for (gop.value_ptr.items) |existing| {
                if (std.mem.eql(u8, existing, value_key)) return;
            }
            try gop.value_ptr.append(alloc, try alloc.dupe(u8, value_key));
        }

        fn valuesFor(self: *const ChildCardinalityIndex, doc_id: []const u8) []const []u8 {
            const entry = self.by_doc.getPtr(doc_id) orelse return &.{};
            return entry.items;
        }
    };

    fn buildChildCardinalityIndexAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        field_or_path: []const u8,
    ) !?ChildCardinalityIndex {
        var index = ChildCardinalityIndex{};
        errdefer index.deinit(self.alloc);
        if (isExplicitJsonPointerPath(field_or_path)) {
            try self.collectPathCardinalityValuesByDoc(store, field_or_path, &index);
        } else {
            const field = self.uniqueExistingFactField(field_or_path) orelse return null;
            try self.collectDocFactCardinalityValuesByDoc(store, field, &index);
        }
        return index;
    }

    // Builds one ChildCardinalityIndex per child request. Returns null (so the
    // caller falls back to a document scan) if any child field is unsupported,
    // mirroring the per-bucket scanDistributedCardinalityPartialsForDocIds path.
    fn buildChildCardinalityIndexesAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        child_requests: []const CardinalityChildRequest,
    ) !?[]ChildCardinalityIndex {
        const indexes = try self.alloc.alloc(ChildCardinalityIndex, child_requests.len);
        var built: usize = 0;
        errdefer {
            for (indexes[0..built]) |*index| index.deinit(self.alloc);
            self.alloc.free(indexes);
        }
        for (child_requests, 0..) |child, i| {
            indexes[i] = (try self.buildChildCardinalityIndexAlloc(store, child.field)) orelse return null;
            built = i + 1;
        }
        return indexes;
    }

    fn freeChildCardinalityIndexes(self: *Index, indexes: []ChildCardinalityIndex) void {
        for (indexes) |*index| index.deinit(self.alloc);
        self.alloc.free(indexes);
    }

    fn collectDocFactCardinalityValuesByDoc(
        self: *Index,
        store: *docstore_mod.DocStore,
        field: ExistsFieldSpec,
        index: *ChildCardinalityIndex,
    ) !void {
        const prefix = try self.docFactScalarFieldPrefixAlloc(field.role, field.field);
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const scalar_component = token.componentAt(entry.key, prefix.len) catch continue;
            const doc_component = token.componentAt(entry.key, scalar_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            try index.add(self.alloc, doc_component.payload, scalar_component.payload);
        }
    }

    fn collectPathCardinalityValuesByDoc(
        self: *Index,
        store: *docstore_mod.DocStore,
        path: []const u8,
        index: *ChildCardinalityIndex,
    ) !void {
        const prefix = try self.pathLookupPathPrefixAlloc(path);
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const kind_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (!pathLookupKindIsScalarValue(kind_component.payload)) continue;
            const value_component = token.componentAt(entry.key, kind_component.next) catch continue;
            const doc_component = token.componentAt(entry.key, value_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            const value_key = try token.canonicalTupleAlloc(self.alloc, &.{ kind_component.payload, value_component.payload });
            defer self.alloc.free(value_key);
            try index.add(self.alloc, doc_component.payload, value_key);
        }
    }

    const BucketAxisKind = enum { raw, canonical };

    // Emits the distinct-value cardinality partials for one bucket and child,
    // reproducing scanDistributedCardinalityPartialsForDocIds + the parent's
    // re-wrap of each child partial, but sourced from a prebuilt
    // ChildCardinalityIndex instead of a fresh per-bucket field scan. The
    // `axis_kind` selects whether the bucket axis still needs canonical-tuple
    // wrapping (raw) or is already canonical (path-terms buckets).
    fn appendBucketChildCardinalityPartials(
        self: *Index,
        partials: *std.ArrayListUnmanaged(distributed_mod.Partial),
        axis: []const u8,
        axis_kind: BucketAxisKind,
        child_name: []const u8,
        child_index: *const ChildCardinalityIndex,
        bucket_doc_ids: []const []const u8,
    ) !void {
        var seen = std.StringHashMapUnmanaged(void).empty;
        defer seen.deinit(self.alloc);
        for (bucket_doc_ids) |doc_id| {
            for (child_index.valuesFor(doc_id)) |value_key| {
                const gop = try seen.getOrPut(self.alloc, value_key);
                if (gop.found_existing) continue;
                // `value_key` is owned by child_index, which outlives `seen`.
                gop.key_ptr.* = value_key;
                const metric = try token.canonicalTupleAlloc(self.alloc, &.{ "cardinality:v1", child_name, value_key });
                defer self.alloc.free(metric);
                const value = try algebra.encodeI64Alloc(self.alloc, 1);
                defer self.alloc.free(value);
                switch (axis_kind) {
                    .raw => try self.appendDistributedPartialForAxis(partials, axis, metric, .count, value),
                    .canonical => try self.appendDistributedPartialForCanonicalAxis(partials, axis, metric, .count, value),
                }
            }
        }
    }

    pub fn scanDistributedCardinalityPartialsForDocIds(
        self: *Index,
        store: *docstore_mod.DocStore,
        aggregation_name: []const u8,
        field_or_path: []const u8,
        doc_ids: []const []const u8,
    ) !?[]distributed_mod.Partial {
        var values = std.StringHashMapUnmanaged(void).empty;
        defer {
            var it = values.keyIterator();
            while (it.next()) |key| self.alloc.free(key.*);
            values.deinit(self.alloc);
        }

        if (isExplicitJsonPointerPath(field_or_path)) {
            try self.collectPathCardinalityValues(store, field_or_path, doc_ids, &values);
        } else {
            const field = self.uniqueExistingFactField(field_or_path) orelse return null;
            try self.collectDocFactCardinalityValues(store, field, doc_ids, &values);
        }

        var partials = std.ArrayListUnmanaged(distributed_mod.Partial).empty;
        errdefer {
            for (partials.items) |partial| {
                self.alloc.free(@constCast(partial.canonical_axis));
                if (partial.metric.len > 0) self.alloc.free(@constCast(partial.metric));
                self.alloc.free(@constCast(partial.value));
            }
            partials.deinit(self.alloc);
        }
        var it = values.keyIterator();
        while (it.next()) |value_key| {
            try self.appendCardinalityPartial(&partials, aggregation_name, value_key.*);
        }
        return try partials.toOwnedSlice(self.alloc);
    }

    fn docIdsForSupportedCardinalityConstraintsAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        constraints: []const ir.Constraint,
    ) !?[][]u8 {
        if (constraints.len == 0) return try self.alloc.alloc([]u8, 0);
        var out: ?[][]u8 = null;
        errdefer if (out) |ids| self.freeDocIds(ids);
        for (constraints) |constraint| {
            const item_ids = if (isExplicitJsonPointerPath(constraint.field))
                try self.docIdsForPathFactConstraintAlloc(store, constraint)
            else blk: {
                const field = self.fieldConfig(constraint.field, .group) orelse return null;
                const scalar = try self.constraintTokenAlloc(self.alloc, field.name, constraint.value);
                defer self.alloc.free(scalar);
                break :blk try self.docIdsForScalarFactAlloc(store, .group, field.name, scalar);
            };
            if (out) |current| {
                defer self.freeDocIds(current);
                defer self.freeDocIds(item_ids);
                out = try self.intersectDocIdsAlloc(current, item_ids);
            } else {
                out = item_ids;
            }
        }
        return out orelse try self.alloc.alloc([]u8, 0);
    }

    fn docIdsForPathFactConstraintAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        constraint: ir.Constraint,
    ) ![][]u8 {
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer {
            for (out.items) |doc_id| self.alloc.free(doc_id);
            out.deinit(self.alloc);
        }
        const prefix = try self.keyAlloc(&.{"pathfact"});
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        const constraints = [_]ir.Constraint{constraint};
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const doc_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (doc_component.next != entry.key.len) continue;
            var projection = pathfact_mod.decodeProjectionAlloc(self.alloc, entry.value) catch |err| switch (err) {
                error.InvalidPathFactList => continue,
                else => return err,
            };
            defer projection.deinit(self.alloc);
            if (!(try self.pathFactsMatchConstraints(projection.facts, constraints[0..]))) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_component.payload));
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn exactDocFactCardinalityAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        field: ExistsFieldSpec,
        constraint_ids: []const []const u8,
    ) !u64 {
        var values = std.StringHashMapUnmanaged(void).empty;
        defer {
            var it = values.keyIterator();
            while (it.next()) |key| self.alloc.free(key.*);
            values.deinit(self.alloc);
        }
        try self.collectDocFactCardinalityValues(store, field, constraint_ids, &values);
        return values.count();
    }

    fn exactDocFactCardinalityAtGenerationAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        field: ExistsFieldSpec,
        constraint_ids: []const []const u8,
        generation: ?u64,
    ) !u64 {
        var values = std.StringHashMapUnmanaged(void).empty;
        defer {
            var it = values.keyIterator();
            while (it.next()) |key| self.alloc.free(key.*);
            values.deinit(self.alloc);
        }
        try self.collectDocFactCardinalityValuesAtGeneration(store, field, constraint_ids, generation, &values);
        return values.count();
    }

    fn collectDocFactCardinalityValues(
        self: *Index,
        store: *docstore_mod.DocStore,
        field: ExistsFieldSpec,
        constraint_ids: []const []const u8,
        values: *std.StringHashMapUnmanaged(void),
    ) !void {
        const prefix = try self.docFactScalarFieldPrefixAlloc(field.role, field.field);
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var constraint_set = try DocIdConstraintSet.init(self.alloc, constraint_ids);
        defer constraint_set.deinit(self.alloc);
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const scalar_component = token.componentAt(entry.key, prefix.len) catch continue;
            const doc_component = token.componentAt(entry.key, scalar_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            if (!constraint_set.matches(doc_component.payload)) continue;
            const gop = try values.getOrPut(self.alloc, scalar_component.payload);
            if (!gop.found_existing) gop.key_ptr.* = try self.alloc.dupe(u8, scalar_component.payload);
        }
    }

    fn collectDocFactCardinalityValuesAtGeneration(
        self: *Index,
        store: *docstore_mod.DocStore,
        field: ExistsFieldSpec,
        constraint_ids: []const []const u8,
        generation: ?u64,
        values: *std.StringHashMapUnmanaged(void),
    ) !void {
        const prefix = try self.docFactScalarFieldPrefixAlloc(field.role, field.field);
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var constraint_set = try DocIdConstraintSet.init(self.alloc, constraint_ids);
        defer constraint_set.deinit(self.alloc);
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const scalar_component = token.componentAt(entry.key, prefix.len) catch continue;
            const doc_component = token.componentAt(entry.key, scalar_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            if (!constraint_set.matches(doc_component.payload)) continue;
            if (!try self.docVisibleAtGenerationTxn(&txn, doc_component.payload, generation)) continue;
            const gop = try values.getOrPut(self.alloc, scalar_component.payload);
            if (!gop.found_existing) gop.key_ptr.* = try self.alloc.dupe(u8, scalar_component.payload);
        }
    }

    fn exactPathCardinalityAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        path: []const u8,
        constraint_ids: []const []const u8,
    ) !u64 {
        var values = std.StringHashMapUnmanaged(void).empty;
        defer {
            var it = values.keyIterator();
            while (it.next()) |key| self.alloc.free(key.*);
            values.deinit(self.alloc);
        }
        try self.collectPathCardinalityValues(store, path, constraint_ids, &values);
        return values.count();
    }

    fn exactPathCardinalityAtGenerationAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        path: []const u8,
        constraint_ids: []const []const u8,
        generation: ?u64,
    ) !u64 {
        var values = std.StringHashMapUnmanaged(void).empty;
        defer {
            var it = values.keyIterator();
            while (it.next()) |key| self.alloc.free(key.*);
            values.deinit(self.alloc);
        }
        try self.collectPathCardinalityValuesAtGeneration(store, path, constraint_ids, generation, &values);
        return values.count();
    }

    fn collectPathCardinalityValues(
        self: *Index,
        store: *docstore_mod.DocStore,
        path: []const u8,
        constraint_ids: []const []const u8,
        values: *std.StringHashMapUnmanaged(void),
    ) !void {
        const prefix = try self.pathLookupPathPrefixAlloc(path);
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var constraint_set = try DocIdConstraintSet.init(self.alloc, constraint_ids);
        defer constraint_set.deinit(self.alloc);
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const kind_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (!pathLookupKindIsScalarValue(kind_component.payload)) continue;
            const value_component = token.componentAt(entry.key, kind_component.next) catch continue;
            const doc_component = token.componentAt(entry.key, value_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            if (!constraint_set.matches(doc_component.payload)) continue;
            const value_key = try token.canonicalTupleAlloc(self.alloc, &.{ kind_component.payload, value_component.payload });
            const gop = try values.getOrPut(self.alloc, value_key);
            if (gop.found_existing) {
                self.alloc.free(value_key);
            } else {
                gop.key_ptr.* = value_key;
            }
        }
    }

    fn collectPathCardinalityValuesAtGeneration(
        self: *Index,
        store: *docstore_mod.DocStore,
        path: []const u8,
        constraint_ids: []const []const u8,
        generation: ?u64,
        values: *std.StringHashMapUnmanaged(void),
    ) !void {
        const prefix = try self.pathLookupPathPrefixAlloc(path);
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var constraint_set = try DocIdConstraintSet.init(self.alloc, constraint_ids);
        defer constraint_set.deinit(self.alloc);
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const kind_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (!pathLookupKindIsScalarValue(kind_component.payload)) continue;
            const value_component = token.componentAt(entry.key, kind_component.next) catch continue;
            const doc_component = token.componentAt(entry.key, value_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            if (!constraint_set.matches(doc_component.payload)) continue;
            if (!try self.docVisibleAtGenerationTxn(&txn, doc_component.payload, generation)) continue;
            const value_key = try token.canonicalTupleAlloc(self.alloc, &.{ kind_component.payload, value_component.payload });
            const gop = try values.getOrPut(self.alloc, value_key);
            if (gop.found_existing) {
                self.alloc.free(value_key);
            } else {
                gop.key_ptr.* = value_key;
            }
        }
    }

    fn appendCardinalityPartial(
        self: *Index,
        partials: *std.ArrayListUnmanaged(distributed_mod.Partial),
        aggregation_name: []const u8,
        value_key: []const u8,
    ) !void {
        const canonical_axis = try token.canonicalTupleAlloc(self.alloc, &.{});
        errdefer self.alloc.free(canonical_axis);
        const metric = try token.canonicalTupleAlloc(self.alloc, &.{ "cardinality:v1", aggregation_name, value_key });
        errdefer self.alloc.free(metric);
        const value = try algebra.encodeI64Alloc(self.alloc, 1);
        errdefer self.alloc.free(value);
        try partials.append(self.alloc, .{
            .canonical_axis = canonical_axis,
            .metric = metric,
            .law_id = .count,
            .value = value,
        });
    }

    fn appendDistributedCountPartial(
        self: *Index,
        partials: *std.ArrayListUnmanaged(distributed_mod.Partial),
        axis: []const u8,
        metric_name: []const u8,
        count: i64,
    ) !void {
        const value = try algebra.encodeI64Alloc(self.alloc, count);
        defer self.alloc.free(value);
        try self.appendDistributedPartialForAxis(partials, axis, metric_name, .count, value);
    }

    fn appendDistributedPartialForAxis(
        self: *Index,
        partials: *std.ArrayListUnmanaged(distributed_mod.Partial),
        axis: []const u8,
        metric_name: []const u8,
        law_id: law_mod.Id,
        raw_value: []const u8,
    ) !void {
        const canonical_axis = try token.canonicalTupleAlloc(self.alloc, &.{axis});
        errdefer self.alloc.free(canonical_axis);
        const metric = try self.alloc.dupe(u8, metric_name);
        errdefer self.alloc.free(metric);
        const value = try self.alloc.dupe(u8, raw_value);
        errdefer self.alloc.free(value);
        try partials.append(self.alloc, .{
            .canonical_axis = canonical_axis,
            .metric = metric,
            .law_id = law_id,
            .value = value,
        });
    }

    fn constraintValueForFieldName(self: *const Index, constraints: []const ir.Constraint, field: []const u8) ?[]const u8 {
        for (constraints) |constraint| {
            const cfg = self.fieldConfig(constraint.field, .group) orelse continue;
            if (std.mem.eql(u8, cfg.name, field)) return constraint.value;
        }
        return null;
    }

    fn rangeCardinalityAxisAlloc(alloc: Allocator, kind: CardinalityRangeKind, range: CardinalityRangeRequest) ![]u8 {
        if (kind == .date) return try token.canonicalTupleAlloc(alloc, &.{ range.start orelse "", range.end orelse "" });
        const start_text = if (range.start) |start| blk: {
            const numeric = try std.fmt.parseFloat(f64, start);
            break :blk try std.fmt.allocPrint(alloc, "{d}", .{numeric});
        } else null;
        defer if (start_text) |text| alloc.free(text);
        const end_text = if (range.end) |end| blk: {
            const numeric = try std.fmt.parseFloat(f64, end);
            break :blk try std.fmt.allocPrint(alloc, "{d}", .{numeric});
        } else null;
        defer if (end_text) |text| alloc.free(text);
        return try token.canonicalTupleAlloc(alloc, &.{ start_text orelse "", end_text orelse "" });
    }

    fn rangeCardinalityFilterJsonAlloc(
        self: *Index,
        field_or_path: []const u8,
        kind: CardinalityRangeKind,
        range: CardinalityRangeRequest,
    ) ![]u8 {
        const field_key = if (isExplicitJsonPointerPath(field_or_path)) "path" else "field";
        var out = std.ArrayListUnmanaged(u8).empty;
        defer out.deinit(self.alloc);
        try out.appendSlice(self.alloc, switch (kind) {
            .numeric => "{\"numeric_range\":{",
            .date => "{\"date_range\":{",
        });
        try appendJsonStringField(self.alloc, &out, field_key, field_or_path, false);
        switch (kind) {
            .numeric => {
                if (range.start) |start| try appendRawJsonField(self.alloc, &out, "min", start, true);
                if (range.end) |end| try appendRawJsonField(self.alloc, &out, "max", end, true);
                if (!range.inclusive_start) try out.appendSlice(self.alloc, ",\"inclusive_min\":false");
                if (range.inclusive_end) try out.appendSlice(self.alloc, ",\"inclusive_max\":true");
            },
            .date => {
                if (range.start) |start| try appendJsonStringField(self.alloc, &out, "start", start, true);
                if (range.end) |end| try appendJsonStringField(self.alloc, &out, "end", end, true);
                if (!range.inclusive_start) try out.appendSlice(self.alloc, ",\"inclusive_start\":false");
                if (range.inclusive_end) try out.appendSlice(self.alloc, ",\"inclusive_end\":true");
            },
        }
        try out.appendSlice(self.alloc, "}}");
        return try out.toOwnedSlice(self.alloc);
    }

    fn appendJsonStringField(
        alloc: Allocator,
        out: *std.ArrayListUnmanaged(u8),
        name: []const u8,
        value: []const u8,
        prepend_comma: bool,
    ) !void {
        if (prepend_comma) try out.append(alloc, ',');
        try out.append(alloc, '"');
        try out.appendSlice(alloc, name);
        try out.appendSlice(alloc, "\":");
        const encoded = try std.json.Stringify.valueAlloc(alloc, value, .{});
        defer alloc.free(encoded);
        try out.appendSlice(alloc, encoded);
    }

    fn appendRawJsonField(
        alloc: Allocator,
        out: *std.ArrayListUnmanaged(u8),
        name: []const u8,
        value: []const u8,
        prepend_comma: bool,
    ) !void {
        if (prepend_comma) try out.append(alloc, ',');
        try out.append(alloc, '"');
        try out.appendSlice(alloc, name);
        try out.appendSlice(alloc, "\":");
        try out.appendSlice(alloc, value);
    }

    fn pathLookupKindIsScalarValue(kind: []const u8) bool {
        return std.mem.eql(u8, kind, "null") or
            std.mem.eql(u8, kind, "bool") or
            std.mem.eql(u8, kind, "number") or
            std.mem.eql(u8, kind, "string");
    }

    // Membership view over a doc-id constraint slice. The slice owns the keys;
    // this set only borrows them, so it must not outlive `constraint_ids`.
    //
    // The cardinality scans below walk the full doc-fact/path-fact prefix for a
    // field and test each entry against the active constraint set. When that
    // set is a bucket's doc-id list (histogram/range children) or a constraint
    // result set (root cardinality), a linear membership test makes the scan
    // O(entries * constraints), which is quadratic in the document count. A hash
    // set turns each test into O(1) and the scan back into a single linear pass.
    const DocIdConstraintSet = struct {
        set: std.StringHashMapUnmanaged(void) = .empty,
        active: bool = false,

        fn init(alloc: Allocator, constraint_ids: []const []const u8) !DocIdConstraintSet {
            if (constraint_ids.len == 0) return .{};
            var set = std.StringHashMapUnmanaged(void).empty;
            errdefer set.deinit(alloc);
            try set.ensureTotalCapacity(alloc, @intCast(constraint_ids.len));
            for (constraint_ids) |id| set.putAssumeCapacity(id, {});
            return .{ .set = set, .active = true };
        }

        fn deinit(self: *DocIdConstraintSet, alloc: Allocator) void {
            self.set.deinit(alloc);
            self.* = .{};
        }

        fn matches(self: *const DocIdConstraintSet, doc_id: []const u8) bool {
            if (!self.active) return true;
            return self.set.contains(doc_id);
        }
    };

    pub fn rawMetricForResolvedDocIdsAlloc(self: *Index, store: *docstore_mod.DocStore, op: algebra.Op, resolved: ResolvedMeasureField, doc_ids: []const []const u8) !?[]u8 {
        if (op == .count) {
            if (doc_ids.len == 0) return null;
            return try algebra.encodeI64Alloc(self.alloc, @intCast(doc_ids.len));
        }
        const law_id = law_mod.fromOp(op);
        var raw: ?[]u8 = null;
        errdefer if (raw) |bytes| self.alloc.free(bytes);
        var found = false;

        var txn = try store.beginReadTxn();
        defer txn.abort();
        for (doc_ids) |doc_id| {
            const fact_key = try self.docFactKey(doc_id);
            defer self.alloc.free(fact_key);
            const payload = txn.get(fact_key) catch |err| switch (err) {
                error.NotFound => continue,
                else => return err,
            };
            var facts = fact_mod.decodeListAlloc(self.alloc, payload) catch |err| switch (err) {
                error.InvalidAlgebraicFact => continue,
                else => return err,
            };
            defer facts.deinit(self.alloc);
            const measure = (try self.factMeasureAlloc(facts.facts, resolved.field.name)) orelse continue;
            defer measure.deinit(self.alloc);
            const contribution = switch (op) {
                .sum, .min, .max => try self.alloc.dupe(u8, measure.raw),
                .sumsquares => blk: {
                    const numeric = try algebra.parseF64(measure.raw);
                    break :blk try algebra.encodeF64Alloc(self.alloc, numeric * numeric);
                },
                .avg => blk: {
                    const numeric = try algebra.parseF64(measure.raw);
                    break :blk try algebra.encodeAvgAlloc(self.alloc, .{ .sum = numeric, .count = 1 });
                },
                .count => unreachable,
            };
            defer self.alloc.free(contribution);
            const next = try tensor_mod.mergeOneSlotValuesAlloc(self.alloc, law_id, raw, contribution);
            if (raw) |old| self.alloc.free(old);
            raw = next;
            found = true;
        }
        if (!found) return null;
        return raw;
    }

    pub fn rawMetricForDocIdsAlloc(self: *Index, store: *docstore_mod.DocStore, op: algebra.Op, field: []const u8, doc_ids: []const []const u8) !?[]u8 {
        if (op == .count) {
            if (doc_ids.len == 0) return null;
            return try algebra.encodeI64Alloc(self.alloc, @intCast(doc_ids.len));
        }
        const resolved = self.resolveMeasureField(field) orelse return null;
        return try self.rawMetricForResolvedDocIdsAlloc(store, op, resolved, doc_ids);
    }

    pub fn scalarDocFactEntriesForFieldAlloc(self: *Index, store: *docstore_mod.DocStore, role: fact_mod.Role, field: []const u8) ![]ScalarDocFactEntry {
        const prefix = try self.docFactScalarFieldPrefixAlloc(role, field);
        defer self.alloc.free(prefix);
        var out = std.ArrayListUnmanaged(ScalarDocFactEntry).empty;
        errdefer {
            for (out.items) |*entry| entry.deinit(self.alloc);
            out.deinit(self.alloc);
        }

        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const scalar_component = token.componentAt(entry.key, prefix.len) catch continue;
            const doc_component = token.componentAt(entry.key, scalar_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            try out.append(self.alloc, .{
                .scalar = try self.alloc.dupe(u8, scalar_component.payload),
                .doc_id = try self.alloc.dupe(u8, doc_component.payload),
            });
        }
        return try out.toOwnedSlice(self.alloc);
    }

    pub fn docIdsForFilterJsonAlloc(self: *Index, store: *docstore_mod.DocStore, filter_json: []const u8) !?[][]u8 {
        if (filter_json.len == 0) return null;
        var parsed = std.json.parseFromSlice(std.json.Value, self.alloc, filter_json, .{}) catch return null;
        defer parsed.deinit();
        return try self.docIdsForFilterValueAlloc(store, parsed.value);
    }

    pub const FilterDocIdSet = struct {
        include: ?[][]u8 = null,
        exclude: [][]u8 = &.{},

        pub fn deinit(self: *FilterDocIdSet, index: *Index) void {
            if (self.include) |ids| index.freeDocIds(ids);
            index.freeDocIds(self.exclude);
            self.* = .{};
        }
    };

    pub const FilterBinding = struct {
        name: []const u8,
        set: FilterDocIdSet,
    };

    pub const ResolvedFilterBinding = struct {
        name: []const u8,
        filter: doc_set.ResolvedDocFilter,
    };

    pub fn docIdSetForFilterJsonAlloc(self: *Index, store: *docstore_mod.DocStore, filter_json: []const u8) !?FilterDocIdSet {
        return try self.docIdSetForFilterJsonWithBindingsAlloc(store, filter_json, &.{});
    }

    pub fn docIdSetForFilterJsonWithBindingsAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        filter_json: []const u8,
        bindings: []const FilterBinding,
    ) !?FilterDocIdSet {
        if (filter_json.len == 0) return null;
        var parsed = std.json.parseFromSlice(std.json.Value, self.alloc, filter_json, .{}) catch return null;
        defer parsed.deinit();
        return try self.docIdSetForFilterValueWithBindingsAlloc(store, parsed.value, bindings);
    }

    pub fn resolvedDocFilterForFilterJsonAlloc(self: *Index, store: *docstore_mod.DocStore, filter_json: []const u8) !?doc_set.ResolvedDocFilter {
        return try self.resolvedDocFilterForFilterJsonAtGenerationAlloc(store, filter_json, null);
    }

    pub fn resolvedDocFilterForFilterJsonAtGenerationAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        filter_json: []const u8,
        generation: ?u64,
    ) !?doc_set.ResolvedDocFilter {
        if (filter_json.len == 0) return null;
        var parsed = std.json.parseFromSlice(std.json.Value, self.alloc, filter_json, .{}) catch return null;
        defer parsed.deinit();

        if (try self.resolvedDocFilterForFilterValueAlloc(store, parsed.value, generation, &.{})) |resolved| {
            var owned_resolved = resolved;
            defer owned_resolved.deinit(self.alloc);
            var filter = doc_set.ResolvedDocFilter{
                .include = try doc_identity.visibleFilteredDocSetFromStoreAlloc(self.alloc, store, &owned_resolved.include, generation),
                .exclude = try doc_identity.visibleFilteredDocSetFromStoreAlloc(self.alloc, store, &owned_resolved.exclude, generation),
            };
            errdefer filter.deinit(self.alloc);
            return filter;
        }

        var id_set = (try self.docIdSetForFilterValueWithBindingsAlloc(store, parsed.value, &.{})) orelse return null;
        defer id_set.deinit(self);

        var txn = try store.beginProbeTxn();
        defer txn.abort();
        var filter = doc_set.ResolvedDocFilter{};
        errdefer filter.deinit(self.alloc);
        if (id_set.include) |include| {
            filter.include = try doc_identity.resolvedDocSetForIdsAtGenerationTxn(self.alloc, &txn, include, generation);
        }
        if (id_set.exclude.len > 0) {
            filter.exclude = try doc_identity.resolvedDocSetForIdsAtGenerationTxn(self.alloc, &txn, id_set.exclude, generation);
        }
        return filter;
    }

    pub fn resolvedDocFilterForFilterJsonWithBindingsAtGenerationAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        filter_json: []const u8,
        generation: ?u64,
        bindings: []const ResolvedFilterBinding,
    ) !?doc_set.ResolvedDocFilter {
        if (filter_json.len == 0) return null;
        var parsed = std.json.parseFromSlice(std.json.Value, self.alloc, filter_json, .{}) catch return null;
        defer parsed.deinit();

        var resolved = (try self.resolvedDocFilterForFilterValueAlloc(store, parsed.value, generation, bindings)) orelse return null;
        defer resolved.deinit(self.alloc);
        var filter = doc_set.ResolvedDocFilter{
            .include = try doc_identity.visibleFilteredDocSetFromStoreAlloc(self.alloc, store, &resolved.include, generation),
            .exclude = try doc_identity.visibleFilteredDocSetFromStoreAlloc(self.alloc, store, &resolved.exclude, generation),
        };
        errdefer filter.deinit(self.alloc);
        return filter;
    }

    pub fn resolvedDocFilterForFilterJsonUncheckedAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        filter_json: []const u8,
        bindings: []const ResolvedFilterBinding,
    ) !?doc_set.ResolvedDocFilter {
        if (filter_json.len == 0) return null;
        var parsed = std.json.parseFromSlice(std.json.Value, self.alloc, filter_json, .{}) catch return null;
        defer parsed.deinit();
        return try self.resolvedDocFilterForFilterValueAlloc(store, parsed.value, null, bindings);
    }

    fn resolvedDocFilterForFilterValueAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        value: std.json.Value,
        generation: ?u64,
        bindings: []const ResolvedFilterBinding,
    ) !?doc_set.ResolvedDocFilter {
        const object = switch (value) {
            .object => |object| object,
            else => return null,
        };
        if (object.get("ref")) |ref_value| {
            const name = jsonStringValue(ref_value) orelse return null;
            const binding = findResolvedFilterBinding(bindings, name) orelse return null;
            return try self.visibleFilteredResolvedDocFilterAlloc(store, &binding.filter, generation);
        }
        if (object.get("bool")) |bool_value| return try self.resolvedDocFilterForBoolFilterAlloc(store, bool_value, generation, bindings);
        if (try self.resolvedDocSetForFilterValueAlloc(store, value, generation, bindings)) |include| {
            var filter = doc_set.ResolvedDocFilter{ .include = include };
            errdefer filter.deinit(self.alloc);
            return filter;
        }
        return null;
    }

    fn resolvedDocSetForFilterValueAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        value: std.json.Value,
        generation: ?u64,
        bindings: []const ResolvedFilterBinding,
    ) !?doc_set.ResolvedDocSet {
        const object = switch (value) {
            .object => |object| object,
            else => return null,
        };
        if (object.get("ref")) |ref_value| {
            const name = jsonStringValue(ref_value) orelse return null;
            const binding = findResolvedFilterBinding(bindings, name) orelse return null;
            return try self.resolvedDocSetForFilterAlloc(store, &binding.filter, generation);
        }
        if (object.get("match_none") != null) return .none;
        if (object.get("match_all") != null) return .all;
        if (object.get("ids")) |ids_value| return try self.resolvedDocSetForIdsFilterAlloc(store, ids_value, generation);
        if (object.get("doc_id")) |ids_value| return try self.resolvedDocSetForIdsFilterAlloc(store, ids_value, generation);
        if (object.get("doc_ids")) |ids_value| return try self.resolvedDocSetForIdsFilterAlloc(store, ids_value, generation);
        if (object.get("docids")) |ids_value| return try self.resolvedDocSetForIdsFilterAlloc(store, ids_value, generation);
        if (object.get("term")) |term_value| return try self.resolvedDocSetForTermFilterAlloc(store, term_value);
        if (object.get("bool_field")) |bool_value| return try self.resolvedDocSetForBoolFieldFilterAlloc(store, bool_value);
        if (object.get("terms")) |terms_value| return try self.resolvedDocSetForTermsFilterAlloc(store, terms_value);
        if (object.get("match")) |match_value| return try self.resolvedDocSetForMatchFilterAlloc(store, match_value);
        if (object.get("range")) |range_value| return try self.resolvedDocSetForStandardRangeFilterAlloc(store, range_value);
        if (object.get("numeric_range")) |range_value| return try self.resolvedDocSetForRangeFilterAlloc(store, range_value, .numeric);
        if (object.get("term_range")) |range_value| return try self.resolvedDocSetForRangeFilterAlloc(store, range_value, .term);
        if (object.get("date_range")) |range_value| return try self.resolvedDocSetForRangeFilterAlloc(store, range_value, .date);
        if (object.get("ip_range")) |range_value| return try self.resolvedDocSetForIpRangeFilterAlloc(store, range_value);
        if (object.get("geo_bbox")) |geo_value| return try self.resolvedDocSetForGeoBBoxFilterAlloc(store, geo_value);
        if (object.get("geo_distance")) |geo_value| return try self.resolvedDocSetForGeoDistanceFilterAlloc(store, geo_value);
        if (object.get("geo_shape")) |geo_value| return try self.resolvedDocSetForGeoShapeFilterAlloc(store, geo_value);
        if (object.get("prefix")) |prefix_value| return try self.resolvedDocSetForPrefixFilterAlloc(store, prefix_value, object.get("field"));
        if (object.get("wildcard")) |wildcard_value| return try self.resolvedDocSetForWildcardFilterAlloc(store, wildcard_value);
        if (object.get("regexp")) |regexp_value| return try self.resolvedDocSetForRegexpFilterAlloc(store, regexp_value);
        if (object.get("fuzzy")) |fuzzy_value| return try self.resolvedDocSetForFuzzyFilterAlloc(store, fuzzy_value);
        if (object.get("exists")) |exists_value| return try self.resolvedDocSetForExistsFilterAlloc(store, exists_value);
        if (object.get("conjuncts")) |conjuncts| return try self.resolvedDocSetForAllFilterValueAlloc(store, conjuncts, generation, bindings);
        if (object.get("disjuncts")) |disjuncts| return try self.resolvedDocSetForAnyFilterValueAlloc(store, disjuncts, generation, bindings);
        if (object.get("bool")) |bool_value| return try self.resolvedDocSetForBoolFilterAlloc(store, bool_value, generation, bindings);
        return null;
    }

    fn resolvedDocFilterForBoolFilterAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        value: std.json.Value,
        generation: ?u64,
        bindings: []const ResolvedFilterBinding,
    ) anyerror!?doc_set.ResolvedDocFilter {
        const bool_object = switch (value) {
            .object => |inner| inner,
            else => return null,
        };
        var include_filter: ?doc_set.ResolvedDocFilter = null;
        var exclude: ?doc_set.ResolvedDocSet = null;
        errdefer {
            if (include_filter) |*filter| filter.deinit(self.alloc);
            if (exclude) |*set| set.deinit(self.alloc);
        }

        if (bool_object.get("must")) |must_value| {
            include_filter = (try self.resolvedDocFilterForAllFilterValueAlloc(store, must_value, generation, bindings)) orelse return null;
        }
        if (bool_object.get("filter")) |filter_value| {
            var filter_clause = (try self.resolvedDocFilterForAllFilterValueAlloc(store, filter_value, generation, bindings)) orelse return null;
            defer filter_clause.deinit(self.alloc);
            if (include_filter) |*current| {
                const next = (try doc_set.intersectFiltersAlloc(self.alloc, current, &filter_clause)) orelse return null;
                current.deinit(self.alloc);
                include_filter = next;
            } else {
                include_filter = try cloneResolvedDocFilterAlloc(self.alloc, &filter_clause);
            }
        }
        if (bool_object.get("should")) |should_value| {
            if (include_filter != null) {
                if (!boolMinimumShouldMatchIsOptional(bool_object.get("minimum_should_match"))) return null;
            } else if (boolMinimumShouldMatchIsSingleRequired(bool_object.get("minimum_should_match"))) {
                const include = (try self.resolvedDocSetForAnyFilterValueAlloc(store, should_value, generation, bindings)) orelse return null;
                include_filter = .{ .include = include };
            } else if (!boolMinimumShouldMatchIsOptional(bool_object.get("minimum_should_match"))) {
                return null;
            }
        }
        if (bool_object.get("must_not")) |must_not_value| {
            exclude = (try self.resolvedDocSetForAnyFilterValueAlloc(store, must_not_value, generation, bindings)) orelse return null;
        }
        if (include_filter == null and exclude == null) return null;

        var filter = if (include_filter) |owned| blk: {
            include_filter = null;
            break :blk owned;
        } else doc_set.ResolvedDocFilter{};
        errdefer filter.deinit(self.alloc);
        if (exclude) |set| {
            var owned_set = set;
            exclude = null;
            defer owned_set.deinit(self.alloc);
            const merged = (try doc_set.unionAlloc(self.alloc, &filter.exclude, &owned_set)) orelse return null;
            filter.exclude.deinit(self.alloc);
            filter.exclude = merged;
        }
        return filter;
    }

    fn resolvedDocFilterForAllFilterValueAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        value: std.json.Value,
        generation: ?u64,
        bindings: []const ResolvedFilterBinding,
    ) anyerror!?doc_set.ResolvedDocFilter {
        const array = switch (value) {
            .array => |array| array,
            else => {
                var filter = (try self.resolvedDocFilterForFilterValueAlloc(store, value, generation, bindings)) orelse return null;
                defer filter.deinit(self.alloc);
                return try self.visibleFilteredResolvedDocFilterAlloc(store, &filter, generation);
            },
        };
        if (array.items.len == 0) return null;
        var out: ?doc_set.ResolvedDocFilter = null;
        errdefer if (out) |*filter| filter.deinit(self.alloc);
        for (array.items) |item| {
            var raw_item_filter = (try self.resolvedDocFilterForFilterValueAlloc(store, item, generation, bindings)) orelse return null;
            defer raw_item_filter.deinit(self.alloc);
            if (out) |*current| {
                const maybe_next = try doc_set.intersectFiltersAlloc(self.alloc, current, &raw_item_filter);
                const next = maybe_next orelse {
                    current.deinit(self.alloc);
                    out = null;
                    return null;
                };
                current.deinit(self.alloc);
                out = next;
            } else {
                out = try cloneResolvedDocFilterAlloc(self.alloc, &raw_item_filter);
            }
        }
        return out;
    }

    fn resolvedDocSetForAllFilterValueAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        value: std.json.Value,
        generation: ?u64,
        bindings: []const ResolvedFilterBinding,
    ) anyerror!?doc_set.ResolvedDocSet {
        const array = switch (value) {
            .array => |array| array,
            else => {
                var set = (try self.resolvedDocSetForFilterValueAlloc(store, value, generation, bindings)) orelse return null;
                defer set.deinit(self.alloc);
                return try doc_identity.visibleFilteredDocSetFromStoreAlloc(self.alloc, store, &set, generation);
            },
        };
        if (array.items.len == 0) return null;
        var out: ?doc_set.ResolvedDocSet = null;
        errdefer if (out) |*set| set.deinit(self.alloc);
        for (array.items) |item| {
            var raw_item_set = (try self.resolvedDocSetForFilterValueAlloc(store, item, generation, bindings)) orelse return null;
            defer raw_item_set.deinit(self.alloc);
            if (out) |*current| {
                const maybe_next = try doc_set.intersectAlloc(self.alloc, current, &raw_item_set);
                const next = maybe_next orelse {
                    current.deinit(self.alloc);
                    out = null;
                    return null;
                };
                current.deinit(self.alloc);
                out = next;
            } else {
                out = try doc_set.cloneAlloc(self.alloc, &raw_item_set);
            }
        }
        return out;
    }

    fn resolvedDocSetForAnyFilterValueAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        value: std.json.Value,
        generation: ?u64,
        bindings: []const ResolvedFilterBinding,
    ) anyerror!?doc_set.ResolvedDocSet {
        const array = switch (value) {
            .array => |array| array,
            else => {
                var set = (try self.resolvedDocSetForFilterValueAlloc(store, value, generation, bindings)) orelse return null;
                defer set.deinit(self.alloc);
                return try doc_identity.visibleFilteredDocSetFromStoreAlloc(self.alloc, store, &set, generation);
            },
        };
        if (array.items.len == 0) return null;
        var out: doc_set.ResolvedDocSet = .none;
        errdefer out.deinit(self.alloc);
        for (array.items) |item| {
            var raw_item_set = (try self.resolvedDocSetForFilterValueAlloc(store, item, generation, bindings)) orelse return null;
            defer raw_item_set.deinit(self.alloc);
            const maybe_next = try doc_set.unionAlloc(self.alloc, &out, &raw_item_set);
            const next = maybe_next orelse {
                out.deinit(self.alloc);
                out = .none;
                return null;
            };
            out.deinit(self.alloc);
            out = next;
        }
        return out;
    }

    fn resolvedDocSetForBoolFilterAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        value: std.json.Value,
        generation: ?u64,
        bindings: []const ResolvedFilterBinding,
    ) anyerror!?doc_set.ResolvedDocSet {
        const bool_object = switch (value) {
            .object => |inner| inner,
            else => return null,
        };
        if (bool_object.get("must_not") != null) return null;
        var out: ?doc_set.ResolvedDocSet = null;
        errdefer if (out) |*set| set.deinit(self.alloc);
        if (bool_object.get("must")) |must_value| {
            out = (try self.resolvedDocSetForAllFilterValueAlloc(store, must_value, generation, bindings)) orelse return null;
        }
        if (bool_object.get("filter")) |filter_value| {
            var filter_set = (try self.resolvedDocSetForAllFilterValueAlloc(store, filter_value, generation, bindings)) orelse return null;
            defer filter_set.deinit(self.alloc);
            if (out) |*current| {
                const next = (try doc_set.intersectAlloc(self.alloc, current, &filter_set)) orelse return null;
                current.deinit(self.alloc);
                out = next;
            } else {
                out = try doc_set.cloneAlloc(self.alloc, &filter_set);
            }
        }
        if (bool_object.get("should")) |should_value| {
            if (out != null) {
                if (!boolMinimumShouldMatchIsOptional(bool_object.get("minimum_should_match"))) {
                    if (out) |*current| current.deinit(self.alloc);
                    return null;
                }
            } else {
                if (!boolMinimumShouldMatchIsSingleRequired(bool_object.get("minimum_should_match"))) return null;
                out = (try self.resolvedDocSetForAnyFilterValueAlloc(store, should_value, generation, bindings)) orelse return null;
            }
        }
        return out;
    }

    fn findResolvedFilterBinding(bindings: []const ResolvedFilterBinding, name: []const u8) ?ResolvedFilterBinding {
        for (bindings) |binding| {
            if (std.mem.eql(u8, binding.name, name)) return binding;
        }
        return null;
    }

    fn cloneResolvedDocFilterAlloc(alloc: std.mem.Allocator, filter: *const doc_set.ResolvedDocFilter) !doc_set.ResolvedDocFilter {
        var out = doc_set.ResolvedDocFilter{
            .include = try doc_set.cloneAlloc(alloc, &filter.include),
        };
        errdefer out.deinit(alloc);
        out.exclude = try doc_set.cloneAlloc(alloc, &filter.exclude);
        return out;
    }

    fn visibleFilteredResolvedDocFilterAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        filter: *const doc_set.ResolvedDocFilter,
        generation: ?u64,
    ) !doc_set.ResolvedDocFilter {
        var out = doc_set.ResolvedDocFilter{
            .include = try doc_identity.visibleFilteredDocSetFromStoreAlloc(self.alloc, store, &filter.include, generation),
        };
        errdefer out.deinit(self.alloc);
        out.exclude = try doc_identity.visibleFilteredDocSetFromStoreAlloc(self.alloc, store, &filter.exclude, generation);
        return out;
    }

    fn resolvedDocSetIsNone(set: *const doc_set.ResolvedDocSet) bool {
        return switch (set.*) {
            .none => true,
            else => false,
        };
    }

    fn resolvedDocSetForFilterAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        filter: *const doc_set.ResolvedDocFilter,
        generation: ?u64,
    ) !?doc_set.ResolvedDocSet {
        var normalized = try self.visibleFilteredResolvedDocFilterAlloc(store, filter, generation);
        defer normalized.deinit(self.alloc);

        if (resolvedDocSetIsNone(&normalized.exclude)) return try doc_set.cloneAlloc(self.alloc, &normalized.include);
        if (try doc_set.differenceAlloc(self.alloc, &normalized.include, &normalized.exclude)) |difference| return difference;

        switch (normalized.include) {
            .all => switch (normalized.exclude) {
                .ordinals, .ordinal_bitmap => {
                    var visible = try doc_identity.visibleDocSetFromStoreAlloc(self.alloc, store, generation);
                    defer visible.deinit(self.alloc);
                    return try doc_set.differenceAlloc(self.alloc, &visible, &normalized.exclude);
                },
                .doc_keys => return null,
                .none, .all => unreachable,
            },
            .none, .doc_keys, .ordinals, .ordinal_bitmap => return null,
        }
    }

    fn resolvedDocSetForIdsFilterAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        value: std.json.Value,
        generation: ?u64,
    ) anyerror!?doc_set.ResolvedDocSet {
        const ids = (try self.docIdsForIdsFilterAlloc(store, value)) orelse return null;
        defer self.freeDocIds(ids);
        var txn = try store.beginProbeTxn();
        defer txn.abort();
        return try doc_identity.resolvedDocSetForIdsAtGenerationTxn(self.alloc, &txn, ids, generation);
    }

    fn docIdsForFilterValueAlloc(self: *Index, store: *docstore_mod.DocStore, value: std.json.Value) anyerror!?[][]u8 {
        return try self.docIdsForFilterValueWithBindingsAlloc(store, value, &.{});
    }

    fn docIdsForFilterValueWithBindingsAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        value: std.json.Value,
        bindings: []const FilterBinding,
    ) anyerror!?[][]u8 {
        var constraints = std.ArrayListUnmanaged(ir.Constraint).empty;
        defer freeConstraintList(self.alloc, &constraints);
        if (try self.collectFilterConstraintsAlloc(value, &constraints)) {
            if (constraints.items.len == 0) return null;
            return try self.docIdsForConstraintsAlloc(store, constraints.items);
        }

        const object = switch (value) {
            .object => |object| object,
            else => return null,
        };
        if (object.get("ref")) |ref_value| {
            const name = jsonStringValue(ref_value) orelse return null;
            const binding = self.findFilterBinding(bindings, name) orelse return null;
            if (binding.set.exclude.len > 0) return null;
            const include = binding.set.include orelse return null;
            return try self.cloneDocIdsAlloc(include);
        }
        if (object.get("match_none") != null) return try self.alloc.alloc([]u8, 0);
        if (object.get("match_all") != null) return null;
        if (object.get("range")) |range_value| return try self.docIdsForStandardRangeFilterAlloc(store, range_value);
        if (object.get("numeric_range")) |range_value| return try self.docIdsForRangeFilterAlloc(store, range_value, .numeric);
        if (object.get("term_range")) |range_value| return try self.docIdsForRangeFilterAlloc(store, range_value, .term);
        if (object.get("date_range")) |range_value| return try self.docIdsForRangeFilterAlloc(store, range_value, .date);
        if (object.get("ip_range")) |range_value| return try self.docIdsForIpRangeFilterAlloc(store, range_value);
        if (object.get("geo_bbox")) |geo_value| return try self.docIdsForGeoBBoxFilterAlloc(store, geo_value);
        if (object.get("geo_distance")) |geo_value| return try self.docIdsForGeoDistanceFilterAlloc(store, geo_value);
        if (object.get("geo_shape")) |geo_value| return try self.docIdsForGeoShapeFilterAlloc(store, geo_value);
        if (object.get("ids")) |ids_value| return try self.docIdsForIdsFilterAlloc(store, ids_value);
        if (object.get("doc_id")) |ids_value| return try self.docIdsForIdsFilterAlloc(store, ids_value);
        if (object.get("doc_ids")) |ids_value| return try self.docIdsForIdsFilterAlloc(store, ids_value);
        if (object.get("docids")) |ids_value| return try self.docIdsForIdsFilterAlloc(store, ids_value);
        if (object.get("term")) |term_value| return try self.docIdsForTermFilterAlloc(store, term_value);
        if (object.get("terms")) |terms_value| return try self.docIdsForTermsFilterAlloc(store, terms_value);
        if (object.get("match")) |match_value| return try self.docIdsForMatchFilterAlloc(store, match_value);
        if (object.get("bool_field")) |bool_value| return try self.docIdsForBoolFieldFilterAlloc(store, bool_value);
        if (object.get("prefix")) |prefix_value| return try self.docIdsForPrefixFilterAlloc(store, prefix_value, object.get("field"));
        if (object.get("wildcard")) |wildcard_value| return try self.docIdsForWildcardFilterAlloc(store, wildcard_value);
        if (object.get("regexp")) |regexp_value| return try self.docIdsForRegexpFilterAlloc(store, regexp_value);
        if (object.get("fuzzy")) |fuzzy_value| return try self.docIdsForFuzzyFilterAlloc(store, fuzzy_value);
        if (object.get("exists")) |exists_value| return try self.docIdsForExistsFilterAlloc(store, exists_value);
        if (object.get("conjuncts")) |conjuncts| return try self.docIdsForAllFilterArrayWithBindingsAlloc(store, conjuncts, bindings);
        if (object.get("disjuncts")) |disjuncts| return try self.docIdsForAnyFilterValueWithBindingsAlloc(store, disjuncts, bindings);
        if (object.get("bool")) |bool_value| {
            const bool_object = switch (bool_value) {
                .object => |inner| inner,
                else => return null,
            };
            if (bool_object.get("must_not") != null) return null;
            var out: ?[][]u8 = null;
            errdefer if (out) |ids| self.freeDocIds(ids);
            if (bool_object.get("must")) |must_value| {
                out = (try self.docIdsForAllFilterValueWithBindingsAlloc(store, must_value, bindings)) orelse return null;
            }
            if (bool_object.get("filter")) |filter_value| {
                const filter_ids = (try self.docIdsForAllFilterValueWithBindingsAlloc(store, filter_value, bindings)) orelse return null;
                if (out) |current| {
                    defer self.freeDocIds(current);
                    defer self.freeDocIds(filter_ids);
                    out = try self.intersectDocIdsAlloc(current, filter_ids);
                } else {
                    out = filter_ids;
                }
            }
            if (bool_object.get("should")) |should_value| {
                if (out != null) {
                    if (!boolMinimumShouldMatchIsOptional(bool_object.get("minimum_should_match"))) {
                        self.freeDocIds(out.?);
                        return null;
                    }
                } else {
                    if (!boolMinimumShouldMatchIsSingleRequired(bool_object.get("minimum_should_match"))) return null;
                    out = (try self.docIdsForAnyFilterValueWithBindingsAlloc(store, should_value, bindings)) orelse return null;
                }
            }
            return out;
        }
        return null;
    }

    fn docIdsForStandardRangeFilterAlloc(self: *Index, store: *docstore_mod.DocStore, value: std.json.Value) anyerror!?[][]u8 {
        const object = switch (value) {
            .object => |object| object,
            else => return null,
        };

        if (object.get("field") != null or object.get("path") != null) {
            if (try self.pathStandardRangePredicateAlloc(object)) |predicate| {
                return try self.docIdsForPathRangeAlloc(store, predicate);
            }
            const field_name = jsonStringValue(object.get("field") orelse return null) orelse return null;
            const field = self.standardRangeFieldSpec(field_name, object.get("role")) orelse return null;
            const spec = (standardRangeSpecFromObject(field, object) catch return null) orelse return null;
            return try self.docIdsForRangeSpecAlloc(store, spec);
        }

        if (object.count() != 1) return null;
        var it = object.iterator();
        const entry = it.next() orelse return null;
        const range_object = switch (entry.value_ptr.*) {
            .object => |inner| inner,
            else => return null,
        };
        if (isExplicitJsonPointerPath(entry.key_ptr.*)) {
            const predicate = (try self.pathStandardRangePredicateFromObjectAlloc(entry.key_ptr.*, range_object)) orelse return null;
            return try self.docIdsForPathRangeAlloc(store, predicate);
        }
        const field = self.standardRangeFieldSpec(entry.key_ptr.*, range_object.get("role")) orelse return null;
        const spec = (standardRangeSpecFromObject(field, range_object) catch return null) orelse return null;
        return try self.docIdsForRangeSpecAlloc(store, spec);
    }

    fn docIdsForRangeFilterAlloc(self: *Index, store: *docstore_mod.DocStore, value: std.json.Value, kind: RangeKind) anyerror!?[][]u8 {
        const object = switch (value) {
            .object => |object| object,
            else => return null,
        };
        if (try self.pathRangePredicateAlloc(object, kind)) |predicate| {
            return try self.docIdsForPathRangeAlloc(store, predicate);
        }
        const field_name = jsonStringValue(object.get("field") orelse return null) orelse return null;
        const field = self.rangeFieldSpec(field_name, object.get("role"), kind) orelse return null;
        const spec = switch (kind) {
            .numeric => blk: {
                if (!rangeFieldAcceptsNumeric(field.type)) return null;
                const min = jsonOptionalF64Strict(object.get("min")) catch return null;
                const max = jsonOptionalF64Strict(object.get("max")) catch return null;
                break :blk RangeSpec{
                    .field = field.field,
                    .role = field.role,
                    .kind = .numeric,
                    .min_number = min,
                    .max_number = max,
                    .inclusive_min = (jsonOptionalBoolStrict(object.get("inclusive_min")) catch return null) orelse true,
                    .inclusive_max = (jsonOptionalBoolStrict(object.get("inclusive_max")) catch return null) orelse false,
                };
            },
            .term => blk: {
                if (!rangeFieldAcceptsTerm(field.type)) return null;
                break :blk RangeSpec{
                    .field = field.field,
                    .role = field.role,
                    .kind = .term,
                    .min_term = jsonOptionalStringStrict(object.get("min")) catch return null,
                    .max_term = jsonOptionalStringStrict(object.get("max")) catch return null,
                    .inclusive_min = (jsonOptionalBoolStrict(object.get("inclusive_min")) catch return null) orelse true,
                    .inclusive_max = (jsonOptionalBoolStrict(object.get("inclusive_max")) catch return null) orelse false,
                };
            },
            .date => blk: {
                if (value_mod.kindFromFieldType(field.type) != .datetime) return null;
                const start_ns = if (object.get("start_ns") != null)
                    jsonOptionalU64Strict(object.get("start_ns")) catch return null
                else
                    jsonOptionalDateTimeNsStrict(object.get("start")) catch return null;
                const end_ns = if (object.get("end_ns") != null)
                    jsonOptionalU64Strict(object.get("end_ns")) catch return null
                else
                    jsonOptionalDateTimeNsStrict(object.get("end")) catch return null;
                break :blk RangeSpec{
                    .field = field.field,
                    .role = field.role,
                    .kind = .date,
                    .start_ns = start_ns,
                    .end_ns = end_ns,
                    .inclusive_min = (jsonOptionalBoolStrict(object.get("inclusive_start")) catch return null) orelse true,
                    .inclusive_max = (jsonOptionalBoolStrict(object.get("inclusive_end")) catch return null) orelse false,
                };
            },
        };
        return try self.docIdsForRangeSpecAlloc(store, spec);
    }

    fn docIdsForRangeSpecAlloc(self: *Index, store: *docstore_mod.DocStore, spec: RangeSpec) ![][]u8 {
        const prefix = try self.docFactScalarFieldPrefixAlloc(spec.role, spec.field);
        defer self.alloc.free(prefix);
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);

        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const scalar_component = token.componentAt(entry.key, prefix.len) catch continue;
            const doc_component = token.componentAt(entry.key, scalar_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            if (!(rangeSpecMatchesScalar(self.alloc, spec, scalar_component.payload) catch false)) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_component.payload));
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn resolvedDocSetForRangeSpecAlloc(self: *Index, store: *docstore_mod.DocStore, spec: RangeSpec) !?doc_set.ResolvedDocSet {
        var legacy_count: usize = 0;
        {
            const legacy_prefix = try self.docFactScalarFieldPrefixAlloc(spec.role, spec.field);
            defer self.alloc.free(legacy_prefix);
