    fn pathGeoBBoxSpecFromObject(self: *Index, object: anytype) !?PathGeoBBoxSpec {
        _ = self;
        if (object.get("role") != null) return null;
        const path = jsonStringValue(object.get("path") orelse object.get("field") orelse return null) orelse return null;
        if (!isExplicitJsonPointerPath(path)) return null;
        const min_lat = (try jsonOptionalF64Strict(object.get("min_lat"))) orelse return null;
        const min_lon = (try jsonOptionalF64Strict(object.get("min_lon"))) orelse return null;
        const max_lat = (try jsonOptionalF64Strict(object.get("max_lat"))) orelse return null;
        const max_lon = (try jsonOptionalF64Strict(object.get("max_lon"))) orelse return null;
        if (!validGeoLatitude(min_lat) or !validGeoLatitude(max_lat) or !validGeoLongitude(min_lon) or !validGeoLongitude(max_lon)) return null;
        if (min_lat > max_lat) return null;
        return .{
            .path = path,
            .min_lat = min_lat,
            .min_lon = min_lon,
            .max_lat = max_lat,
            .max_lon = max_lon,
        };
    }

    fn pathGeoDistanceSpecFromObject(self: *Index, object: anytype) !?PathGeoDistanceSpec {
        _ = self;
        if (object.get("role") != null) return null;
        const path = jsonStringValue(object.get("path") orelse object.get("field") orelse return null) orelse return null;
        if (!isExplicitJsonPointerPath(path)) return null;
        const lat = (try jsonOptionalF64Strict(object.get("lat"))) orelse return null;
        const lon = (try jsonOptionalF64Strict(object.get("lon"))) orelse return null;
        const radius_meters = (try jsonOptionalF64Strict(object.get("radius_meters"))) orelse return null;
        if (!validGeoLatitude(lat) or !validGeoLongitude(lon) or !std.math.isFinite(radius_meters) or radius_meters < 0) return null;
        return .{
            .path = path,
            .center = .{ .lat = lat, .lon = lon },
            .radius_meters = radius_meters,
        };
    }

    fn pathGeoShapeSpecFromObject(self: *Index, object: anytype) !?PathGeoShapeSpec {
        if (object.get("role") != null) return null;
        const path = jsonStringValue(object.get("path") orelse object.get("field") orelse return null) orelse return null;
        if (!isExplicitJsonPointerPath(path)) return null;
        const relation = jsonStringValue(object.get("relation") orelse .{ .string = "intersects" }) orelse return null;
        if (!std.mem.eql(u8, relation, "intersects") and !std.mem.eql(u8, relation, "within")) return null;
        const polygons_value = object.get("polygons") orelse object.get("polygon") orelse return null;
        const polygons = try self.parseGeoShapePolygonsAlloc(polygons_value);
        errdefer {
            for (polygons) |polygon| {
                if (polygon.len > 0) self.alloc.free(@constCast(polygon));
            }
            if (polygons.len > 0) self.alloc.free(polygons);
        }
        return .{
            .path = path,
            .relation = relation,
            .polygons = polygons,
        };
    }

    fn parseGeoShapePolygonsAlloc(self: *Index, value: std.json.Value) ![]const []const geo_mod.GeoPoint {
        const array = switch (value) {
            .array => |array| array,
            else => return error.InvalidAlgebraicTensorExpr,
        };
        if (array.items.len == 0) return error.InvalidAlgebraicTensorExpr;

        const first_is_point = array.items[0] == .object;
        const polygon_count: usize = if (first_is_point) 1 else array.items.len;
        var out = try self.alloc.alloc([]const geo_mod.GeoPoint, polygon_count);
        var initialized: usize = 0;
        errdefer {
            for (out[0..initialized]) |polygon| {
                if (polygon.len > 0) self.alloc.free(@constCast(polygon));
            }
            if (out.len > 0) self.alloc.free(out);
        }

        if (first_is_point) {
            out[0] = try self.parseGeoShapePolygonAlloc(value);
            initialized = 1;
        } else {
            for (array.items, 0..) |item, i| {
                out[i] = try self.parseGeoShapePolygonAlloc(item);
                initialized += 1;
            }
        }
        return out;
    }

    fn parseGeoShapePolygonAlloc(self: *Index, value: std.json.Value) ![]const geo_mod.GeoPoint {
        const array = switch (value) {
            .array => |array| array,
            else => return error.InvalidAlgebraicTensorExpr,
        };
        if (array.items.len < 3) return error.InvalidAlgebraicTensorExpr;
        var out = try self.alloc.alloc(geo_mod.GeoPoint, array.items.len);
        errdefer if (out.len > 0) self.alloc.free(out);
        for (array.items, 0..) |item, i| {
            const object = switch (item) {
                .object => |object| object,
                else => return error.InvalidAlgebraicTensorExpr,
            };
            const lat = (try jsonOptionalF64Strict(object.get("lat"))) orelse return error.InvalidAlgebraicTensorExpr;
            const lon = (try jsonOptionalF64Strict(object.get("lon"))) orelse return error.InvalidAlgebraicTensorExpr;
            if (!validGeoLatitude(lat) or !validGeoLongitude(lon)) return error.InvalidAlgebraicTensorExpr;
            out[i] = .{ .lat = lat, .lon = lon };
        }
        return out;
    }

    fn docIdsForPathGeoBBoxAlloc(self: *Index, store: *docstore_mod.DocStore, spec: PathGeoBBoxSpec) ![][]u8 {
        return try self.docIdsForPathGeoPredicateAlloc(store, spec.path, .{ .bbox = spec });
    }

    fn docIdsForPathGeoDistanceAlloc(self: *Index, store: *docstore_mod.DocStore, spec: PathGeoDistanceSpec) ![][]u8 {
        return try self.docIdsForPathGeoPredicateAlloc(store, spec.path, .{ .distance = spec });
    }

    fn docIdsForPathGeoShapeAlloc(self: *Index, store: *docstore_mod.DocStore, spec: PathGeoShapeSpec) ![][]u8 {
        return try self.docIdsForPathGeoPredicateAlloc(store, spec.path, .{ .shape = spec });
    }

    const PathGeoPredicate = union(enum) {
        bbox: PathGeoBBoxSpec,
        distance: PathGeoDistanceSpec,
        shape: PathGeoShapeSpec,
    };

    fn docIdsForPathGeoPredicateAlloc(self: *Index, store: *docstore_mod.DocStore, path: []const u8, predicate: PathGeoPredicate) ![][]u8 {
        const lat_path = try self.pathGeoChildPathAlloc(path, "lat");
        defer self.alloc.free(lat_path);
        const lon_path = try self.pathGeoChildPathAlloc(path, "lon");
        defer self.alloc.free(lon_path);
        if (!(try self.pathProfileHasKind(store, lat_path, .number)) or !(try self.pathProfileHasKind(store, lon_path, .number))) {
            return try self.alloc.alloc([]u8, 0);
        }

        const prefix = try self.keyAlloc(&.{"pathfact"});
        defer self.alloc.free(prefix);
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const doc_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (doc_component.next != entry.key.len) continue;
            var projection = pathfact_mod.decodeProjectionAlloc(self.alloc, entry.value) catch |err| switch (err) {
                error.InvalidPathFactList => continue,
                else => return err,
            };
            defer projection.deinit(self.alloc);
            const point = pathGeoPointFromFacts(projection.facts, lat_path, lon_path) orelse continue;
            if (!pathGeoPredicateMatches(predicate, point)) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_component.payload));
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn resolvedDocSetForPathGeoPredicateAlloc(self: *Index, store: *docstore_mod.DocStore, path: []const u8, predicate: PathGeoPredicate) !?doc_set.ResolvedDocSet {
        const lat_path = try self.pathGeoChildPathAlloc(path, "lat");
        defer self.alloc.free(lat_path);
        const lon_path = try self.pathGeoChildPathAlloc(path, "lon");
        defer self.alloc.free(lon_path);
        if (!(try self.pathProfileHasKind(store, lat_path, .number)) or !(try self.pathProfileHasKind(store, lon_path, .number))) {
            return .none;
        }

        const legacy_ids = try self.docIdsForPathGeoPredicateAlloc(store, path, predicate);
        defer self.freeDocIds(legacy_ids);

        const prefix = try self.pathFactOrdinalPrefixAlloc();
        defer self.alloc.free(prefix);
        var ordinals = std.ArrayListUnmanaged(doc_set.DocOrdinal).empty;
        defer ordinals.deinit(self.alloc);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const ordinal_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (ordinal_component.next != entry.key.len or ordinal_component.payload.len != @sizeOf(doc_set.DocOrdinal)) continue;
            var projection = pathfact_mod.decodeProjectionAlloc(self.alloc, entry.value) catch |err| switch (err) {
                error.InvalidPathFactList => continue,
                else => return err,
            };
            defer projection.deinit(self.alloc);
            const point = pathGeoPointFromFacts(projection.facts, lat_path, lon_path) orelse continue;
            if (!pathGeoPredicateMatches(predicate, point)) continue;
            const ordinal = std.mem.readInt(u32, ordinal_component.payload[0..4], .big);
            if (containsOrdinal(ordinals.items, ordinal)) continue;
            try ordinals.append(self.alloc, ordinal);
        }
        if (ordinals.items.len == 0 and legacy_ids.len > 0) return null;
        if (ordinals.items.len != legacy_ids.len) return null;
        return try doc_set.fromOrdinalsAlloc(self.alloc, ordinals.items);
    }

    fn pathGeoChildPathAlloc(self: *Index, path: []const u8, child: []const u8) ![]u8 {
        if (std.mem.eql(u8, path, "/")) return try std.fmt.allocPrint(self.alloc, "/{s}", .{child});
        return try std.fmt.allocPrint(self.alloc, "{s}/{s}", .{ path, child });
    }

    fn pathGeoPointFromFacts(facts: []const pathfact_mod.Fact, lat_path: []const u8, lon_path: []const u8) ?geo_mod.GeoPoint {
        const lat = pathFactNumberAt(facts, lat_path) orelse return null;
        const lon = pathFactNumberAt(facts, lon_path) orelse return null;
        if (!validGeoLatitude(lat) or !validGeoLongitude(lon)) return null;
        return .{ .lat = lat, .lon = lon };
    }

    fn pathFactNumberAt(facts: []const pathfact_mod.Fact, path: []const u8) ?f64 {
        for (facts) |fact| {
            if (fact.kind != .number or !std.mem.eql(u8, fact.path, path)) continue;
            const value = std.fmt.parseFloat(f64, fact.value) catch continue;
            if (!std.math.isFinite(value)) continue;
            return value;
        }
        return null;
    }

    fn pathGeoPredicateMatches(predicate: PathGeoPredicate, point: geo_mod.GeoPoint) bool {
        return switch (predicate) {
            .bbox => |bbox| point.lat >= bbox.min_lat and point.lat <= bbox.max_lat and geoLongitudeInRange(point.lon, bbox.min_lon, bbox.max_lon),
            .distance => |distance| geo_mod.haversineDistance(distance.center, point) <= distance.radius_meters,
            .shape => |shape| pathGeoShapeMatches(shape, point),
        };
    }

    fn pathGeoShapeMatches(shape: PathGeoShapeSpec, point: geo_mod.GeoPoint) bool {
        if (!std.mem.eql(u8, shape.relation, "intersects") and !std.mem.eql(u8, shape.relation, "within")) return false;
        for (shape.polygons) |polygon| {
            if (pointInGeoPolygon(point, polygon)) return true;
        }
        return false;
    }

    fn pointInGeoPolygon(point: geo_mod.GeoPoint, polygon: []const geo_mod.GeoPoint) bool {
        if (polygon.len < 3) return false;
        var inside = false;
        var j = polygon.len - 1;
        for (polygon, 0..) |current, i| {
            const previous = polygon[j];
            if (pointOnGeoSegment(point, previous, current)) return true;
            const crosses = (current.lat > point.lat) != (previous.lat > point.lat);
            if (crosses) {
                const lon_at_lat = (previous.lon - current.lon) * (point.lat - current.lat) / (previous.lat - current.lat) + current.lon;
                if (point.lon < lon_at_lat) inside = !inside;
            }
            j = i;
        }
        return inside;
    }

    fn pointOnGeoSegment(point: geo_mod.GeoPoint, a: geo_mod.GeoPoint, b: geo_mod.GeoPoint) bool {
        const epsilon = 0.000000001;
        const cross = (point.lat - a.lat) * (b.lon - a.lon) - (point.lon - a.lon) * (b.lat - a.lat);
        if (@abs(cross) > epsilon) return false;
        const min_lat = @min(a.lat, b.lat) - epsilon;
        const max_lat = @max(a.lat, b.lat) + epsilon;
        const min_lon = @min(a.lon, b.lon) - epsilon;
        const max_lon = @max(a.lon, b.lon) + epsilon;
        return point.lat >= min_lat and point.lat <= max_lat and point.lon >= min_lon and point.lon <= max_lon;
    }

    fn geoLongitudeInRange(lon: f64, min_lon: f64, max_lon: f64) bool {
        if (min_lon <= max_lon) return lon >= min_lon and lon <= max_lon;
        return lon >= min_lon or lon <= max_lon;
    }

    const RangeFieldSpec = struct {
        field: []const u8,
        role: fact_mod.Role,
        type: []const u8,
    };

    const ScalarFieldSpec = struct {
        field: []const u8,
        role: fact_mod.Role,
        type: []const u8,
    };

    fn standardRangeFieldSpec(self: *const Index, field_name: []const u8, role_value: ?std.json.Value) ?RangeFieldSpec {
        const scalar = self.scalarFieldSpec(field_name, role_value) orelse return null;
        if (rangeKindForFieldType(scalar.type) == null) return null;
        return .{ .field = scalar.field, .role = scalar.role, .type = scalar.type };
    }

    fn scalarFieldSpec(self: *const Index, field_name: []const u8, role_value: ?std.json.Value) ?ScalarFieldSpec {
        if (role_value) |actual| {
            const role_text = jsonStringValue(actual) orelse return null;
            const class = fieldClassFromFactRoleText(role_text) orelse return null;
            const role = factRoleFromFieldClass(class) orelse return null;
            const field = self.fieldConfig(field_name, class) orelse return null;
            return .{ .field = field.name, .role = role, .type = field.type };
        }

        var found: ?ScalarFieldSpec = null;
        if (self.fieldConfig(field_name, .group)) |field| {
            found = .{ .field = field.name, .role = .group, .type = field.type };
        }
        if (self.fieldConfig(field_name, .measure)) |field| {
            if (found != null) return null;
            found = .{ .field = field.name, .role = .measure, .type = field.type };
        }
        if (self.fieldConfig(field_name, .time)) |field| {
            if (found != null) return null;
            found = .{ .field = field.name, .role = .time, .type = field.type };
        }
        return found;
    }

    fn rangeFieldSpec(self: *const Index, field_name: []const u8, role_value: ?std.json.Value, kind: RangeKind) ?RangeFieldSpec {
        if (role_value) |actual| {
            const role_text = jsonStringValue(actual) orelse return null;
            const class = fieldClassFromFactRoleText(role_text) orelse return null;
            const role = factRoleFromFieldClass(class) orelse return null;
            const field = self.fieldConfig(field_name, class) orelse return null;
            if (!rangeFieldAcceptsKind(field.type, kind)) return null;
            return .{ .field = field.name, .role = role, .type = field.type };
        }

        var found: ?RangeFieldSpec = null;
        if (self.fieldConfig(field_name, .group)) |field| {
            if (rangeFieldAcceptsKind(field.type, kind)) {
                found = .{ .field = field.name, .role = .group, .type = field.type };
            }
        }
        if (self.fieldConfig(field_name, .measure)) |field| {
            if (rangeFieldAcceptsKind(field.type, kind)) {
                if (found != null) return null;
                found = .{ .field = field.name, .role = .measure, .type = field.type };
            }
        }
        if (self.fieldConfig(field_name, .time)) |field| {
            if (rangeFieldAcceptsKind(field.type, kind)) {
                if (found != null) return null;
                found = .{ .field = field.name, .role = .time, .type = field.type };
            }
        }
        return found;
    }

    fn docIdSetForFilterValueAlloc(self: *Index, store: *docstore_mod.DocStore, value: std.json.Value) anyerror!?FilterDocIdSet {
        return try self.docIdSetForFilterValueWithBindingsAlloc(store, value, &.{});
    }

    fn docIdSetForFilterValueWithBindingsAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        value: std.json.Value,
        bindings: []const FilterBinding,
    ) anyerror!?FilterDocIdSet {
        const object = switch (value) {
            .object => |object| object,
            else => return null,
        };
        if (object.get("ref")) |ref_value| {
            const name = jsonStringValue(ref_value) orelse return null;
            const binding = self.findFilterBinding(bindings, name) orelse return null;
            return try self.cloneFilterDocIdSetAlloc(binding.set);
        }
        if (object.get("bool")) |bool_value| {
            const bool_object = switch (bool_value) {
                .object => |inner| inner,
                else => return null,
            };
            var out = FilterDocIdSet{};
            errdefer out.deinit(self);
            if (bool_object.get("must")) |must_value| {
                out.include = (try self.docIdsForAllFilterValueWithBindingsAlloc(store, must_value, bindings)) orelse return null;
            }
            if (bool_object.get("filter")) |filter_value| {
                const filter_ids = (try self.docIdsForAllFilterValueWithBindingsAlloc(store, filter_value, bindings)) orelse return null;
                if (out.include) |current| {
                    defer self.freeDocIds(current);
                    defer self.freeDocIds(filter_ids);
                    out.include = try self.intersectDocIdsAlloc(current, filter_ids);
                } else {
                    out.include = filter_ids;
                }
            }
            if (bool_object.get("should")) |should_value| {
                if (out.include != null) {
                    if (!boolMinimumShouldMatchIsOptional(bool_object.get("minimum_should_match"))) {
                        out.deinit(self);
                        return null;
                    }
                } else if (boolMinimumShouldMatchIsSingleRequired(bool_object.get("minimum_should_match"))) {
                    out.include = (try self.docIdsForAnyFilterValueWithBindingsAlloc(store, should_value, bindings)) orelse return null;
                } else if (!boolMinimumShouldMatchIsOptional(bool_object.get("minimum_should_match"))) {
                    out.deinit(self);
                    return null;
                }
            }
            if (bool_object.get("must_not")) |must_not_value| {
                out.exclude = (try self.docIdsForAnyFilterValueWithBindingsAlloc(store, must_not_value, bindings)) orelse return null;
            }
            if (out.include == null and out.exclude.len == 0) return null;
            return out;
        }

        const include = (try self.docIdsForFilterValueWithBindingsAlloc(store, value, bindings)) orelse return null;
        errdefer self.freeDocIds(include);
        return .{ .include = include };
    }

    fn findFilterBinding(self: *Index, bindings: []const FilterBinding, name: []const u8) ?FilterBinding {
        _ = self;
        for (bindings) |binding| {
            if (std.mem.eql(u8, binding.name, name)) return binding;
        }
        return null;
    }

    fn cloneFilterDocIdSetAlloc(self: *Index, set: FilterDocIdSet) !FilterDocIdSet {
        return .{
            .include = if (set.include) |include| try self.cloneDocIdsAlloc(include) else null,
            .exclude = try self.cloneDocIdsAlloc(set.exclude),
        };
    }

    fn cloneDocIdsAlloc(self: *Index, doc_ids: []const []const u8) ![][]u8 {
        var out = try self.alloc.alloc([]u8, doc_ids.len);
        var initialized: usize = 0;
        errdefer {
            for (out[0..initialized]) |item| self.alloc.free(item);
            if (out.len > 0) self.alloc.free(out);
        }
        for (doc_ids, 0..) |doc_id, i| {
            out[i] = try self.alloc.dupe(u8, doc_id);
            initialized += 1;
        }
        return out;
    }

    pub fn freeDocIds(self: *Index, doc_ids: [][]u8) void {
        for (doc_ids) |doc_id| self.alloc.free(doc_id);
        if (doc_ids.len > 0) self.alloc.free(doc_ids);
    }

    pub fn countMaterializedExpressionRowsUpTo(self: *Index, store: *docstore_mod.DocStore, materialization: []const u8, limit: usize) !usize {
        var txn = try store.beginReadTxn();
        defer txn.abort();
        return try self.countMaterializedExpressionRowsFromLayoutUpTo(&txn, materialization, limit);
    }

    fn collectFilterConstraintsAlloc(self: *Index, value: std.json.Value, out: *std.ArrayListUnmanaged(ir.Constraint)) Allocator.Error!bool {
        const object = switch (value) {
            .object => |object| object,
            else => return false,
        };
        if (object.get("term")) |term_value| return try self.collectSingleFieldConstraintAlloc(term_value, out);
        if (object.get("conjuncts")) |conjuncts| return try self.collectConstraintArrayAlloc(conjuncts, out);
        if (object.get("bool")) |bool_value| {
            const bool_object = switch (bool_value) {
                .object => |inner| inner,
                else => return false,
            };
            if (bool_object.get("should") != null or bool_object.get("must_not") != null) return false;
            var collected = false;
            if (bool_object.get("must")) |must_value| {
                if (!(try self.collectConstraintArrayAlloc(must_value, out))) return false;
                collected = true;
            }
            if (bool_object.get("filter")) |filter_value| {
                if (!(try self.collectConstraintArrayAlloc(filter_value, out))) return false;
                collected = true;
            }
            return collected;
        }
        return false;
    }

    fn boolMinimumShouldMatchIsOptional(value: ?std.json.Value) bool {
        const parsed = parseBoolMinimumShouldMatch(value) orelse return value == null;
        return parsed == 0;
    }

    fn boolMinimumShouldMatchIsSingleRequired(value: ?std.json.Value) bool {
        const parsed = parseBoolMinimumShouldMatch(value) orelse return value == null;
        return parsed == 1;
    }

    fn parseBoolMinimumShouldMatch(value: ?std.json.Value) ?u64 {
        const raw = value orelse return null;
        return switch (raw) {
            .integer => |int| if (int >= 0) @intCast(int) else null,
            .float => |float| blk: {
                if (!std.math.isFinite(float) or float < 0) break :blk null;
                const truncated = @floor(float);
                if (truncated != float) break :blk null;
                break :blk @intFromFloat(float);
            },
            .string => |text| std.fmt.parseUnsigned(u64, text, 10) catch null,
            else => null,
        };
    }

    fn collectConstraintArrayAlloc(self: *Index, value: std.json.Value, out: *std.ArrayListUnmanaged(ir.Constraint)) Allocator.Error!bool {
        const array = switch (value) {
            .array => |array| array,
            else => return false,
        };
        if (array.items.len == 0) return false;
        for (array.items) |item| {
            if (!(try self.collectFilterConstraintsAlloc(item, out))) return false;
        }
        return true;
    }

    fn buildBatchMaintenanceContext(self: *Index, txn: anytype, options: ApplyOptions) !?BatchMaintenanceContext {
        if (options.batch_options.mode != .bulk_ingest) return null;
        if (!self.shouldMaintainReadyAdaptiveMaterializations()) return null;

        var context = BatchMaintenanceContext{};
        errdefer context.deinit(self.alloc);
        context.coalesce_tensor_deltas = true;

        if (self.adaptive_ready_spec_cache) |cache| {
            context.ready_specs = try self.cloneReadySpecsAlloc(cache.specs);
            self.adaptive_maintenance_cached_spec_count += context.ready_specs.len;
            return context;
        }

        const progress_rows = try self.scanPersistedAdaptiveProgressTxn(txn);
        defer {
            for (progress_rows) |*progress| progress.deinit(self.alloc);
            if (progress_rows.len > 0) self.alloc.free(progress_rows);
        }

        var specs = std.ArrayListUnmanaged(AdaptiveMaterializationSpec).empty;
        errdefer {
            for (specs.items) |*spec| spec.deinit(self.alloc);
            specs.deinit(self.alloc);
        }
        for (progress_rows) |progress| {
            if (progress.lifecycle != .ready) continue;
            if (!self.adaptiveProgressMatchesCurrentConfig(progress)) continue;
            if (!(try self.persistedMaterializationStateReadyTxn(txn, progress.recommendation))) continue;
            var spec = self.adaptiveSpecFromRecommendationAlloc(progress.materialization_id, progress.recommendation) catch continue;
            errdefer spec.deinit(self.alloc);
            try specs.append(self.alloc, spec);
        }
        const ready_specs = try specs.toOwnedSlice(self.alloc);
        specs = .empty;
        self.adaptive_ready_spec_cache = .{ .specs = ready_specs };
        context.ready_specs = try self.cloneReadySpecsAlloc(ready_specs);
        self.adaptive_maintenance_plan_build_count += 1;
        self.adaptive_maintenance_cached_spec_count += context.ready_specs.len;
        return context;
    }

