    fn docIdsForIdsFilterAlloc(self: *Index, store: *docstore_mod.DocStore, value: std.json.Value) anyerror!?[][]u8 {
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);

        var txn = try store.beginReadTxn();
        defer txn.abort();

        switch (value) {
            .array => |array| {
                for (array.items) |item| {
                    const doc_id = jsonStringValue(item) orelse return null;
                    try self.appendExistingDocIdCandidate(&txn, &out, doc_id);
                }
            },
            .object => |object| {
                if (object.get("values")) |values| {
                    const array = switch (values) {
                        .array => |array| array,
                        else => return null,
                    };
                    for (array.items) |item| {
                        const doc_id = jsonStringValue(item) orelse return null;
                        try self.appendExistingDocIdCandidate(&txn, &out, doc_id);
                    }
                } else if (object.get("ids")) |values| {
                    const array = switch (values) {
                        .array => |array| array,
                        else => return null,
                    };
                    for (array.items) |item| {
                        const doc_id = jsonStringValue(item) orelse return null;
                        try self.appendExistingDocIdCandidate(&txn, &out, doc_id);
                    }
                } else if (object.get("value")) |single| {
                    const doc_id = jsonStringValue(single) orelse return null;
                    try self.appendExistingDocIdCandidate(&txn, &out, doc_id);
                } else if (object.get("id")) |single| {
                    const doc_id = jsonStringValue(single) orelse return null;
                    try self.appendExistingDocIdCandidate(&txn, &out, doc_id);
                } else {
                    return null;
                }
            },
            .string => |doc_id| try self.appendExistingDocIdCandidate(&txn, &out, doc_id),
            else => return null,
        }

        return try out.toOwnedSlice(self.alloc);
    }

    fn appendExistingDocIdCandidate(self: *Index, txn: anytype, out: *std.ArrayListUnmanaged([]u8), doc_id: []const u8) !void {
        if (containsDocId(out.items, doc_id)) return;
        const fact_key = try self.docFactKey(doc_id);
        defer self.alloc.free(fact_key);
        _ = txn.get(fact_key) catch |err| switch (err) {
            error.NotFound => return,
            else => return err,
        };
        try out.append(self.alloc, try self.alloc.dupe(u8, doc_id));
    }

