    fn pathDictionaryLabelMatchesRange(self: *Index, label: []const u8, spec: PathRangePredicate) bool {
        _ = self;
        return switch (spec.kind) {
            .numeric => blk: {
                const parsed = std.fmt.parseFloat(f64, label) catch break :blk false;
                break :blk scalarInNumberRange(parsed, spec.min_number, spec.max_number, spec.inclusive_min, spec.inclusive_max);
            },
            .term => scalarInTermRange(label, spec.min_term, spec.max_term, spec.inclusive_min, spec.inclusive_max),
            .date => blk: {
                const parsed_ns = (parseDateTimeOptionalToNs(label) catch null) orelse break :blk false;
                break :blk scalarInDateRange(parsed_ns, spec.start_ns, spec.end_ns, spec.inclusive_min, spec.inclusive_max);
            },
        };
    }

