    fn dictionaryRegistryReadyForLayout(
        self: *Index,
        store: *docstore_mod.DocStore,
        identity: lexical_mod.DictionaryIdentity,
        layout: lexical_mod.DictionaryLayoutKind,
    ) !bool {
        var txn = try store.beginReadTxn();
        defer txn.abort();
        return try self.dictionaryRegistryReadyForLayoutTxn(&txn, identity, layout);
    }

    fn dictionaryRegistryReadyForLayoutTxn(
        self: *Index,
        txn: anytype,
        identity: lexical_mod.DictionaryIdentity,
        layout: lexical_mod.DictionaryLayoutKind,
    ) !bool {
        const registry_key = try identity.registryKeyAlloc(self.alloc);
        defer self.alloc.free(registry_key);
        const payload = txn.get(registry_key) catch |err| switch (err) {
            error.NotFound => {
                self.dictionary_registry_ready_miss_count += 1;
                return false;
            },
            else => return err,
        };
        var entry = lexical_mod.RegistryEntry.decodeAlloc(self.alloc, payload) catch {
            self.dictionary_registry_ready_miss_count += 1;
            return false;
        };
        defer entry.deinit(self.alloc);
        const ready = entry.layout == layout and std.mem.eql(u8, entry.state, "ready");
        if (ready) {
            self.dictionary_registry_ready_hit_count += 1;
        } else {
            self.dictionary_registry_ready_miss_count += 1;
        }
        return ready;
    }

    fn pathDictionaryFstLabelsForScanAlloc(
        self: *Index,
        fst_bytes: []const u8,
        scan: PathDictionaryStringScan,
    ) ![][]u8 {
        const labels = switch (scan) {
            .contains => try lexical_mod.fstLabelsInRangeAlloc(self.alloc, fst_bytes, null, null, true, false),
            .prefix => |prefix| try lexical_mod.fstLabelsWithPrefixAlloc(self.alloc, fst_bytes, prefix),
            .wildcard => |pattern| blk: {
                const literal_prefix = wildcardLiteralPrefix(pattern);
                break :blk try lexical_mod.fstLabelsWithPrefixAlloc(self.alloc, fst_bytes, literal_prefix);
            },
            .regexp => |pattern| blk: {
                var compiled = regex_mod.compile(self.alloc, pattern) catch return try self.alloc.alloc([]u8, 0);
                defer compiled.deinit();
                const start = regexpLiteralPrefix(pattern);
                break :blk try lexical_mod.fstLabelsMatchingAutomatonAlloc(self.alloc, fst_bytes, compiled.automaton(), if (start.len > 0) start else null);
            },
            .fuzzy => |fuzzy| blk: {
                var automaton = levenshtein_mod.LevenshteinAutomaton{
                    .term = fuzzy.folded_term,
                    .max_distance = fuzzy.max_edits,
                    .alloc = self.alloc,
                };
                defer automaton.deinit();
                break :blk try lexical_mod.fstLabelsMatchingAutomatonAlloc(self.alloc, fst_bytes, automaton.automaton(), fuzzy.literal_prefix);
            },
            .ip_range => try lexical_mod.fstLabelsInRangeAlloc(self.alloc, fst_bytes, null, null, true, false),
        };
        errdefer {
            for (labels) |label| self.alloc.free(label);
            if (labels.len > 0) self.alloc.free(labels);
        }
        var kept = std.ArrayListUnmanaged([]u8).empty;
        errdefer kept.deinit(self.alloc);
        for (labels) |label| {
            if (try self.pathDictionaryLabelMatchesScan(label, scan)) {
                try kept.append(self.alloc, label);
            } else {
                self.alloc.free(label);
            }
        }
        if (labels.len > 0) self.alloc.free(labels);
        return try kept.toOwnedSlice(self.alloc);
    }

    fn pathDictionaryLabelMatchesScan(self: *Index, label: []const u8, scan: PathDictionaryStringScan) !bool {
        return switch (scan) {
            .contains => |text| containsCaseInsensitive(label, text),
            .prefix => |prefix| std.mem.startsWith(u8, label, prefix),
            .wildcard => |pattern| wildcardMatch(pattern, label),
            .regexp => |pattern| blk: {
                var compiled = regex_mod.compile(self.alloc, pattern) catch break :blk false;
                defer compiled.deinit();
                break :blk regex_mod.matchesCompiled(pattern, &compiled, label);
            },
            .fuzzy => |fuzzy| std.mem.startsWith(u8, label, fuzzy.literal_prefix) and
                try fuzzyMatchesScalar(self.alloc, label, fuzzy.folded_term, fuzzy.max_edits),
            .ip_range => |query| ipRangeQueryMatches(query, label),
        };
    }

    fn docIdsForPathDictionaryAllPostingsAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        identity: lexical_mod.DictionaryIdentity,
    ) !?[][]u8 {
        if (!(try self.dictionaryRegistryReadyForLayout(store, identity, .lexicon_postings_rows))) return null;
        const lexicon_prefix = try self.pathDictionaryLexiconPrefixAlloc(identity);
        defer self.alloc.free(lexicon_prefix);
        const postings_prefix = try self.pathDictionaryPostingsDictionaryPrefixAlloc(identity);
        defer self.alloc.free(postings_prefix);
        var saw_dictionary = false;
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var lex_entry_opt = try cursor.seekAtOrAfter(lexicon_prefix);
        while (lex_entry_opt) |entry| : (lex_entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, lexicon_prefix)) break;
            saw_dictionary = true;
            break;
        }
        if (!saw_dictionary) return null;
        var entry_opt = try cursor.seekAtOrAfter(postings_prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, postings_prefix)) break;
            const label_component = token.componentAt(entry.key, postings_prefix.len) catch continue;
            const doc_component = token.componentAt(entry.key, label_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            if (containsDocId(out.items, doc_component.payload)) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_component.payload));
        }
        return try out.toOwnedSlice(self.alloc);
    }

