        defer self.alloc.free(owned_prefix);
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(owned_prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, owned_prefix)) break;
            const value_component = token.componentAt(entry.key, owned_prefix.len) catch continue;
            const doc_component = token.componentAt(entry.key, value_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            if (!std.mem.startsWith(u8, value_component.payload, literal_prefix)) continue;
            if (!(try fuzzyMatchesScalar(self.alloc, value_component.payload, folded_term, max_edits))) continue;
            if (containsDocId(out.items, doc_component.payload)) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_component.payload));
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn docIdsForPathRangeAlloc(self: *Index, store: *docstore_mod.DocStore, spec: PathRangePredicate) ![][]u8 {
        const path_kind: pathfact_mod.Kind = switch (spec.kind) {
            .numeric => .number,
            .term => .string,
            .date => .string,
        };
        if (!(try self.pathProfileHasKind(store, spec.path, path_kind))) return try self.alloc.alloc([]u8, 0);
        if (try self.readyPathPromotionMaterializationIdAlloc(store, spec.path, path_kind)) |materialization_id| {
            defer self.alloc.free(materialization_id);
            if (try self.docIdsForPathDictionaryRangeAlloc(store, spec, path_kind)) |ids| return ids;
        }
        const owned_prefix = if (try self.readyPathPromotionMaterializationIdAlloc(store, spec.path, path_kind)) |materialization_id| blk: {
            defer self.alloc.free(materialization_id);
            break :blk try self.promotedPathLookupKindPrefixAlloc(materialization_id, spec.path, path_kind);
        } else try self.pathLookupKindPrefixAlloc(spec.path, path_kind);
        defer self.alloc.free(owned_prefix);
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(owned_prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, owned_prefix)) break;
            const value_component = token.componentAt(entry.key, owned_prefix.len) catch continue;
            const doc_component = token.componentAt(entry.key, value_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            const matched = switch (spec.kind) {
                .numeric => blk: {
                    const parsed = std.fmt.parseFloat(f64, value_component.payload) catch break :blk false;
                    break :blk scalarInNumberRange(parsed, spec.min_number, spec.max_number, spec.inclusive_min, spec.inclusive_max);
                },
                .term => scalarInTermRange(value_component.payload, spec.min_term, spec.max_term, spec.inclusive_min, spec.inclusive_max),
                .date => blk: {
                    const parsed_ns = (parseDateTimeOptionalToNs(value_component.payload) catch null) orelse break :blk false;
                    break :blk scalarInDateRange(parsed_ns, spec.start_ns, spec.end_ns, spec.inclusive_min, spec.inclusive_max);
                },
            };
            if (!matched) continue;
            if (containsDocId(out.items, doc_component.payload)) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_component.payload));
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn resolvedDocSetForPathRangeAlloc(self: *Index, store: *docstore_mod.DocStore, spec: PathRangePredicate) !?doc_set.ResolvedDocSet {
        const path_kind: pathfact_mod.Kind = switch (spec.kind) {
            .numeric => .number,
            .term => .string,
            .date => .string,
        };
        if (!(try self.pathProfileHasKind(store, spec.path, path_kind))) return .none;
        if (try self.readyPathPromotionMaterializationIdAlloc(store, spec.path, path_kind)) |materialization_id| {
            defer self.alloc.free(materialization_id);
            return try self.resolvedDocSetForPathDictionaryRangeAlloc(store, spec, path_kind);
        }
        return try self.resolvedDocSetForPathLookupRangeAlloc(store, spec, path_kind);
    }

    fn pathProfileExists(self: *Index, store: *docstore_mod.DocStore, path: []const u8) !bool {
        const key = try self.pathProfileKeyAlloc(path);
        defer self.alloc.free(key);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        const payload = txn.get(key) catch |err| switch (err) {
            error.NotFound => return false,
            else => return err,
        };
        var profile = pathfact_mod.decodeProfileAlloc(self.alloc, path, payload) catch return false;
        defer profile.deinit(self.alloc);
        return !profile.empty();
    }

    fn pathProfileHasKind(self: *Index, store: *docstore_mod.DocStore, path: []const u8, kind: pathfact_mod.Kind) !bool {
        const key = try self.pathProfileKeyAlloc(path);
        defer self.alloc.free(key);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        const payload = txn.get(key) catch |err| switch (err) {
            error.NotFound => return false,
            else => return err,
        };
        var profile = pathfact_mod.decodeProfileAlloc(self.alloc, path, payload) catch return false;
        defer profile.deinit(self.alloc);
        return switch (kind) {
            .null => profile.null_count > 0,
            .bool => profile.bool_count > 0,
            .number => profile.number_count > 0,
            .string => profile.string_count > 0,
            .object, .array => false,
        };
    }

    pub const PathProfileStats = struct {
        profile: pathfact_mod.PathProfile,
        doc_count: u64 = 0,
        lookup_row_count: u64 = 0,
        unique_scalar_values: u64 = 0,
        max_value_doc_frequency: u64 = 0,

        pub fn deinit(self: *PathProfileStats, alloc: Allocator) void {
            self.profile.deinit(alloc);
            self.* = undefined;
        }
    };

    pub const PathPromotionRecommendation = struct {
        path: []const u8,
        stable_kind: ?pathfact_mod.Kind = null,
        doc_count: u64 = 0,
        lookup_row_count: u64 = 0,
        unique_scalar_values: u64 = 0,
        max_value_doc_frequency: u64 = 0,
        typed_projection: bool = false,
        numeric_projection: bool = false,
        datetime_projection: bool = false,
        lexical_dictionary: bool = false,
        aggregate_materialization: bool = false,
        reason: []const u8 = "missing_path",
    };

    pub const PathProfileHistoryEntry = struct {
        path: []u8,
        sequence: u64 = 0,
        stable_kind: ?pathfact_mod.Kind = null,
        doc_count: u64 = 0,
        lookup_row_count: u64 = 0,
        unique_scalar_values: u64 = 0,
        max_value_doc_frequency: u64 = 0,
        reason: []u8,

        pub fn deinit(self: *PathProfileHistoryEntry, alloc: Allocator) void {
            alloc.free(self.path);
            alloc.free(self.reason);
            self.* = undefined;
        }
    };

    pub fn freePathPromotionRecommendations(self: *Index, recommendations: []PathPromotionRecommendation) void {
        for (recommendations) |recommendation| self.alloc.free(@constCast(recommendation.path));
        if (recommendations.len > 0) self.alloc.free(recommendations);
    }

    pub fn pathPromotionRecommendationsAlloc(self: *Index, store: *docstore_mod.DocStore) ![]PathPromotionRecommendation {
        const prefix = try self.keyAlloc(&.{"path_profile"});
        defer self.alloc.free(prefix);
        var out = std.ArrayListUnmanaged(PathPromotionRecommendation).empty;
        errdefer {
            for (out.items) |recommendation| self.alloc.free(@constCast(recommendation.path));
            out.deinit(self.alloc);
        }
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const path_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (path_component.next != entry.key.len) continue;
            {
                const owned_path = try self.alloc.dupe(u8, path_component.payload);
                errdefer self.alloc.free(owned_path);
                var recommendation = try self.pathPromotionRecommendationAlloc(store, owned_path);
                recommendation.path = owned_path;
                try out.append(self.alloc, recommendation);
            }
        }
        return try out.toOwnedSlice(self.alloc);
    }

    pub fn pathProfileStatsAlloc(self: *Index, store: *docstore_mod.DocStore, path: []const u8) !?PathProfileStats {
        const profile_key = try self.pathProfileKeyAlloc(path);
        defer self.alloc.free(profile_key);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        const payload = txn.get(profile_key) catch |err| switch (err) {
            error.NotFound => return null,
            else => return err,
        };
        var profile = try pathfact_mod.decodeProfileAlloc(self.alloc, path, payload);
        errdefer profile.deinit(self.alloc);

        const lookup_prefix = try self.pathLookupPathPrefixAlloc(path);
        defer self.alloc.free(lookup_prefix);
        var docs = std.StringHashMapUnmanaged(void).empty;
        defer {
            var it = docs.keyIterator();
            while (it.next()) |key| self.alloc.free(key.*);
            docs.deinit(self.alloc);
        }
        var value_counts = std.StringHashMapUnmanaged(u64).empty;
        defer {
            var it = value_counts.keyIterator();
            while (it.next()) |key| self.alloc.free(key.*);
            value_counts.deinit(self.alloc);
        }

        var stats = PathProfileStats{ .profile = profile };
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(lookup_prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, lookup_prefix)) break;
            const kind_component = token.componentAt(entry.key, lookup_prefix.len) catch continue;
            const value_component = token.componentAt(entry.key, kind_component.next) catch continue;
            const doc_component = token.componentAt(entry.key, value_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            stats.lookup_row_count += 1;

            const doc_gop = try docs.getOrPut(self.alloc, doc_component.payload);
            if (!doc_gop.found_existing) doc_gop.key_ptr.* = try self.alloc.dupe(u8, doc_component.payload);

            if (!pathLookupKindIsScalarValue(kind_component.payload)) continue;
            const value_key = try token.canonicalTupleAlloc(self.alloc, &.{ kind_component.payload, value_component.payload });
            const value_gop = try value_counts.getOrPut(self.alloc, value_key);
            if (value_gop.found_existing) {
                self.alloc.free(value_key);
                value_gop.value_ptr.* += 1;
            } else {
                value_gop.key_ptr.* = value_key;
                value_gop.value_ptr.* = 1;
            }
            stats.max_value_doc_frequency = @max(stats.max_value_doc_frequency, value_gop.value_ptr.*);
        }
        stats.doc_count = docs.count();
        stats.unique_scalar_values = value_counts.count();
        return stats;
    }

    pub fn pathPromotionRecommendationAlloc(self: *Index, store: *docstore_mod.DocStore, path: []const u8) !PathPromotionRecommendation {
        var stats = (try self.pathProfileStatsAlloc(store, path)) orelse return .{ .path = path };
        defer stats.deinit(self.alloc);
        var out = PathPromotionRecommendation{
            .path = path,
            .doc_count = stats.doc_count,
            .lookup_row_count = stats.lookup_row_count,
            .unique_scalar_values = stats.unique_scalar_values,
            .max_value_doc_frequency = stats.max_value_doc_frequency,
        };
        const stable_kind = stableScalarKind(stats.profile) orelse {
            out.reason = if (stats.profile.scalarKindCount() == 0) "non_scalar_path" else "mixed_scalar_kinds";
            return out;
        };
        out.stable_kind = stable_kind;
        if (stats.doc_count < 2) {
            out.reason = "insufficient_observations";
            return out;
        }
        const numeric_string_path = stable_kind == .string and
            stats.profile.string_count > 0 and
            stats.profile.string_numeric_parse_success_count == stats.profile.string_count and
            stats.profile.string_numeric_parse_failure_count == 0;
        const datetime_string_path = stable_kind == .string and
            stats.profile.string_count > 0 and
            stats.profile.string_datetime_parse_success_count == stats.profile.string_count and
            stats.profile.string_datetime_parse_failure_count == 0;
        out.typed_projection = true;
        out.numeric_projection = stable_kind == .number or numeric_string_path;
        out.datetime_projection = datetime_string_path;
        out.lexical_dictionary = stable_kind == .string and stats.unique_scalar_values > 0;
        out.aggregate_materialization = stats.unique_scalar_values > 0 and stats.unique_scalar_values * 2 <= stats.doc_count;
        out.reason = if (datetime_string_path)
            "stable_datetime_string_path"
        else if (numeric_string_path)
            "stable_numeric_string_path"
        else if (out.aggregate_materialization)
            "stable_selective_path"
        else if (out.lexical_dictionary)
            "stable_lexical_path"
        else
            "stable_typed_path";
        return out;
    }

    pub fn persistSchemalessPathPromotionRecommendations(self: *Index, store: *docstore_mod.DocStore) !u64 {
        const policy = self.config().adaptive.policy();
        if (!policy.observe) return 0;
        const recommendations = try self.pathPromotionRecommendationsAlloc(store);
        defer self.freePathPromotionRecommendations(recommendations);
        var changed: u64 = 0;
        for (recommendations) |recommendation| {
            if (!recommendation.typed_projection) continue;
            const stable_kind = if (recommendation.stable_kind) |kind| @tagName(kind) else null;
            const token_recommendation = try adaptive_mod.pathPromotionRecommendationAlloc(self.alloc, recommendation.path, stable_kind, recommendation.reason);
            defer self.alloc.free(token_recommendation);
            const materialization_id = try adaptive_mod.materializationIdAlloc(self.alloc, token_recommendation);
            defer self.alloc.free(materialization_id);
            const lifecycle: adaptive_mod.Lifecycle = .recommended;
            const state_key = try adaptive_mod.materializationStateKeyAlloc(self.alloc, self.name, token_recommendation);
            defer self.alloc.free(state_key);
            const candidate_key = try adaptive_mod.candidateKeyAlloc(self.alloc, self.name, token_recommendation);
            defer self.alloc.free(candidate_key);
            const cost = AdaptiveCostInputs{
                .doc_rows = recommendation.doc_count,
                .bucket_cardinality = recommendation.unique_scalar_values,
                .tensor_rows = 0,
                .storage_bytes = 0,
                .write_amplification = 1 + @as(u64, @intFromBool(recommendation.lexical_dictionary)) + @as(u64, @intFromBool(recommendation.aggregate_materialization)),
            };
            const estimated_scan_rows_saved = saturatedMul(recommendation.doc_count, @max(recommendation.max_value_doc_frequency, @as(u64, 1)));
            const estimated_write_cost = adaptiveWriteCost(cost);
            const score = @as(i128, @intCast(estimated_scan_rows_saved)) - @as(i128, @intCast(estimated_write_cost));
            const should_start_backfill = policy.lazy_materialization and
                recommendation.doc_count >= policy.min_observations and
                estimated_scan_rows_saved >= policy.min_estimated_scan_rows_saved;
            const effective_lifecycle: adaptive_mod.Lifecycle = if (should_start_backfill) .backfilling else lifecycle;
            const effective_state_payload = try self.encodePersistedMaterializationStateAlloc(token_recommendation, effective_lifecycle, recommendation.doc_count);
            defer self.alloc.free(effective_state_payload);
            const base_decision = if (recommendation.datetime_projection)
                "schemaless_datetime_path_recommended"
            else if (recommendation.numeric_projection)
                "schemaless_numeric_path_recommended"
            else if (recommendation.aggregate_materialization)
                "schemaless_aggregate_path_recommended"
            else if (recommendation.lexical_dictionary)
                "schemaless_lexical_path_recommended"
            else
                "schemaless_typed_path_recommended";
            const decision = if (should_start_backfill) "schemaless_path_backfill_started" else base_decision;
            var txn = try store.beginWriteTxn();
            errdefer txn.abort();
            try self.persistPathProfileHistoryTxn(&txn, recommendation);
            const prior_state_payload = txn.get(state_key) catch |err| switch (err) {
                error.NotFound => null,
                else => return err,
            };
            var should_write_state = true;
            if (prior_state_payload) |payload| {
                var prior_state = self.decodePersistedMaterializationState(payload) catch null;
                if (prior_state) |*state| {
                    defer state.deinit(self.alloc);
                    should_write_state = state.lifecycle == .observing or state.lifecycle == .recommended;
                }
            }
            var prior_candidate: ?PersistedAdaptiveCandidate = null;
            const prior_candidate_payload = txn.get(candidate_key) catch |err| switch (err) {
                error.NotFound => null,
                else => return err,
            };
            if (prior_candidate_payload) |payload| prior_candidate = self.decodePersistedAdaptiveCandidate(payload) catch null;
            defer if (prior_candidate) |*candidate| candidate.deinit(self.alloc);
            const generation = if (prior_candidate) |candidate| candidate.generation + 1 else 1;
            const previous_decision = if (prior_candidate) |candidate| candidate.decision else "";
            const previous_score = if (prior_candidate) |candidate| candidate.score else 0;
            const candidate_payload = try self.encodePersistedAdaptiveCandidateAlloc(
                token_recommendation,
                materialization_id,
                effective_lifecycle,
                recommendation.doc_count,
                estimated_scan_rows_saved,
                estimated_write_cost,
                cost,
                score,
                decision,
                0,
                generation,
            );
            defer self.alloc.free(candidate_payload);
            const history_key = try adaptiveDecisionHistoryKeyAlloc(self.alloc, self.name, token_recommendation, generation);
            defer self.alloc.free(history_key);
            const history_payload = try self.encodePersistedAdaptiveDecisionAlloc(token_recommendation, materialization_id, effective_lifecycle, previous_decision, decision, recommendation.doc_count, estimated_scan_rows_saved, estimated_write_cost, score, score - previous_score, 0, generation);
            defer self.alloc.free(history_payload);
            if (should_write_state) {
                try txn.put(state_key, effective_state_payload);
                changed += 1;
            }
            try txn.put(candidate_key, candidate_payload);
            try txn.put(history_key, history_payload);
            if (should_start_backfill and should_write_state) {
                const progress_key = try adaptive_mod.progressKeyAlloc(self.alloc, self.name, token_recommendation);
                defer self.alloc.free(progress_key);
                const progress_payload = try self.encodePersistedAdaptiveProgressAlloc(token_recommendation, materialization_id, .backfilling, 0, 0, 0, 0, "");
                defer self.alloc.free(progress_payload);
                try txn.put(progress_key, progress_payload);
            }
            try txn.commit();
        }
        return changed;
    }

    pub fn scanPathProfileHistoryAlloc(self: *Index, store: *docstore_mod.DocStore, path: []const u8) ![]PathProfileHistoryEntry {
        const prefix = try self.pathProfileHistoryPrefixAlloc(path);
        defer self.alloc.free(prefix);
        var out = std.ArrayListUnmanaged(PathProfileHistoryEntry).empty;
        errdefer {
            for (out.items) |*entry| entry.deinit(self.alloc);
            out.deinit(self.alloc);
        }
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const seq_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (seq_component.next != entry.key.len) continue;
            var decoded = self.decodePathProfileHistoryEntryAlloc(path, seq_component.payload, entry.value) catch continue;
            errdefer decoded.deinit(self.alloc);
            try out.append(self.alloc, decoded);
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn persistPathProfileHistoryTxn(
        self: *Index,
        txn: anytype,
        recommendation: PathPromotionRecommendation,
    ) !void {
        const keep_last = self.config().adaptive.path_profile_history_retention;
        if (keep_last == 0) return;
        const sequence = try self.nextPathProfileHistorySequenceTxn(txn, recommendation.path);
        try self.compactPathProfileHistoryTxn(txn, recommendation.path, keep_last - 1);
        const key = try self.pathProfileHistoryKeyAlloc(recommendation.path, sequence);
        defer self.alloc.free(key);
        const payload = try self.encodePathProfileHistoryEntryAlloc(recommendation, sequence);
        defer self.alloc.free(payload);
        try txn.put(key, payload);
    }

    fn compactPathProfileHistoryTxn(
        self: *Index,
        txn: anytype,
        path: []const u8,
        keep_last: u64,
    ) !void {
        const prefix = try self.pathProfileHistoryPrefixAlloc(path);
        defer self.alloc.free(prefix);
        var keys = std.ArrayListUnmanaged([]u8).empty;
        defer {
            for (keys.items) |key| self.alloc.free(key);
            keys.deinit(self.alloc);
        }
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const seq_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (seq_component.next != entry.key.len) continue;
            try keys.append(self.alloc, try self.alloc.dupe(u8, entry.key));
        }
        if (keep_last >= keys.items.len) return;
        const delete_count: usize = @intCast(@as(u64, @intCast(keys.items.len)) - keep_last);
        for (keys.items[0..delete_count]) |key| {
            txn.delete(key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
        }
    }

    fn nextPathProfileHistorySequenceTxn(
        self: *Index,
        txn: anytype,
        path: []const u8,
    ) !u64 {
        const prefix = try self.pathProfileHistoryPrefixAlloc(path);
        defer self.alloc.free(prefix);
        var next: u64 = 1;
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const seq_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (seq_component.next != entry.key.len) continue;
            const seen = std.fmt.parseUnsigned(u64, seq_component.payload, 10) catch continue;
            next = @max(next, seen +| 1);
        }
        return next;
    }

    fn encodePathProfileHistoryEntryAlloc(
        self: *Index,
        recommendation: PathPromotionRecommendation,
        sequence: u64,
    ) ![]u8 {
        const sequence_text = try sortableU64TextAlloc(self.alloc, sequence);
        defer self.alloc.free(sequence_text);
        const doc_count_text = try std.fmt.allocPrint(self.alloc, "{d}", .{recommendation.doc_count});
        defer self.alloc.free(doc_count_text);
        const lookup_count_text = try std.fmt.allocPrint(self.alloc, "{d}", .{recommendation.lookup_row_count});
        defer self.alloc.free(lookup_count_text);
        const unique_text = try std.fmt.allocPrint(self.alloc, "{d}", .{recommendation.unique_scalar_values});
        defer self.alloc.free(unique_text);
        const max_frequency_text = try std.fmt.allocPrint(self.alloc, "{d}", .{recommendation.max_value_doc_frequency});
        defer self.alloc.free(max_frequency_text);
        return try token.canonicalTupleAlloc(self.alloc, &.{
            "path-profile-history:v1",
            recommendation.path,
            sequence_text,
            if (recommendation.stable_kind) |kind| @tagName(kind) else "",
            doc_count_text,
            lookup_count_text,
            unique_text,
            max_frequency_text,
            recommendation.reason,
        });
    }

    fn decodePathProfileHistoryEntryAlloc(
        self: *Index,
        fallback_path: []const u8,
        fallback_sequence: []const u8,
        payload: []const u8,
    ) !PathProfileHistoryEntry {
        const parts = try token.decodeTupleAlloc(self.alloc, payload);
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 9 or !std.mem.eql(u8, parts[0], "path-profile-history:v1")) return error.InvalidPathProfileHistory;
        return .{
            .path = try self.alloc.dupe(u8, if (parts[1].len > 0) parts[1] else fallback_path),
            .sequence = std.fmt.parseUnsigned(u64, if (parts[2].len > 0) parts[2] else fallback_sequence, 10) catch return error.InvalidPathProfileHistory,
            .stable_kind = if (parts[3].len == 0) null else std.meta.stringToEnum(pathfact_mod.Kind, parts[3]) orelse return error.InvalidPathProfileHistory,
            .doc_count = std.fmt.parseUnsigned(u64, parts[4], 10) catch return error.InvalidPathProfileHistory,
            .lookup_row_count = std.fmt.parseUnsigned(u64, parts[5], 10) catch return error.InvalidPathProfileHistory,
            .unique_scalar_values = std.fmt.parseUnsigned(u64, parts[6], 10) catch return error.InvalidPathProfileHistory,
            .max_value_doc_frequency = std.fmt.parseUnsigned(u64, parts[7], 10) catch return error.InvalidPathProfileHistory,
            .reason = try self.alloc.dupe(u8, parts[8]),
        };
    }

    fn readyPathPromotionMaterializationIdAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        path: []const u8,
        kind: ?pathfact_mod.Kind,
    ) !?[]u8 {
        const progress_rows = try self.scanPersistedAdaptiveProgress(store);
        defer {
            for (progress_rows) |*progress| progress.deinit(self.alloc);
            if (progress_rows.len > 0) self.alloc.free(progress_rows);
        }
        for (progress_rows) |progress| {
            if (progress.lifecycle != .ready) continue;
            if (!self.adaptiveProgressMatchesCurrentConfig(progress)) continue;
            const state_ready = blk: {
                var txn = try store.beginReadTxn();
                defer txn.abort();
                break :blk try self.persistedMaterializationStateReadyTxn(&txn, progress.recommendation);
            };
            if (!state_ready) continue;
            var spec = self.adaptiveSpecFromRecommendationAlloc(progress.materialization_id, progress.recommendation) catch continue;
            defer spec.deinit(self.alloc);
            const promoted_path = spec.path_promotion_path orelse continue;
            if (!std.mem.eql(u8, promoted_path, path)) continue;
            if (kind) |wanted_kind| {
                const promoted_kind = spec.path_promotion_kind orelse continue;
                if (promoted_kind != wanted_kind) continue;
            }
            return try self.alloc.dupe(u8, progress.materialization_id);
        }
        return null;
    }

    fn docIdsForIndexedPathLookupPathPrefixAlloc(self: *Index, store: *docstore_mod.DocStore, owned_prefix: []u8) ![][]u8 {
        defer self.alloc.free(owned_prefix);
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(owned_prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, owned_prefix)) break;
            const kind_component = token.componentAt(entry.key, owned_prefix.len) catch continue;
            const value_component = token.componentAt(entry.key, kind_component.next) catch continue;
            const doc_component = token.componentAt(entry.key, value_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            if (containsDocId(out.items, doc_component.payload)) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_component.payload));
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn docIdsForPrefixFilterAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        prefix_value: std.json.Value,
        sibling_field_value: ?std.json.Value,
    ) anyerror!?[][]u8 {
        if (pathPrefixPredicate(prefix_value, sibling_field_value)) |predicate| {
            return try self.docIdsForPathStringPrefixAlloc(store, predicate.path, predicate.prefix);
        }
        const FieldPrefix = struct {
            field: []const u8,
            prefix: []const u8,
            role: ?std.json.Value = null,
        };
        const parsed: FieldPrefix = switch (prefix_value) {
            .object => |object| blk: {
                if (object.get("field") != null or object.get("value") != null or object.get("prefix") != null or object.get("role") != null) {
                    const field_name = jsonStringValue(object.get("field") orelse return null) orelse return null;
                    const prefix_text = jsonStringValue(object.get("value") orelse object.get("prefix") orelse return null) orelse return null;
                    break :blk .{ .field = field_name, .prefix = prefix_text, .role = object.get("role") };
                }
                if (object.count() != 1) return null;
                var it = object.iterator();
                const entry = it.next() orelse return null;
                const prefix_text = jsonStringValue(entry.value_ptr.*) orelse return null;
                break :blk .{ .field = entry.key_ptr.*, .prefix = prefix_text };
            },
            .string => |prefix_text| blk: {
                const field_name = jsonStringValue(sibling_field_value orelse return null) orelse return null;
                break :blk .{ .field = field_name, .prefix = prefix_text };
            },
            else => return null,
        };
        const field = self.scalarFieldSpec(parsed.field, parsed.role) orelse return null;
        if (!rangeFieldAcceptsTerm(field.type)) return null;

        const prefix = try self.docFactScalarFieldPrefixAlloc(field.role, field.field);
        defer self.alloc.free(prefix);
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);

        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const scalar_component = token.componentAt(entry.key, prefix.len) catch continue;
            const doc_component = token.componentAt(entry.key, scalar_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            const scalar = value_mod.parseScalarAlloc(self.alloc, scalar_component.payload) catch continue;
            defer value_mod.deinitScalar(self.alloc, scalar);
            if (!std.mem.startsWith(u8, scalar.canonical, parsed.prefix)) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_component.payload));
        }
        return try out.toOwnedSlice(self.alloc);
    }

