    }

    fn docIdsForExistsFilterAlloc(self: *Index, store: *docstore_mod.DocStore, value: std.json.Value) anyerror!?[][]u8 {
        if (pathFromExistsFilter(value)) |path| return try self.docIdsForPathExistsAlloc(store, path);
        const spec = self.existsFieldSpec(value) orelse return null;
        return try self.docIdsForIndexedDocFactPrefixAlloc(store, try self.docFactFieldPrefixAlloc(spec.role, spec.field));
    }

    fn resolvedDocSetForExistsFilterAlloc(self: *Index, store: *docstore_mod.DocStore, value: std.json.Value) anyerror!?doc_set.ResolvedDocSet {
        if (pathFromExistsFilter(value)) |path| {
            if (!(try self.pathProfileExists(store, path))) return .none;
            if (try self.readyPathPromotionMaterializationIdAlloc(store, path, null)) |materialization_id| {
                defer self.alloc.free(materialization_id);
                return try self.resolvedDocSetForPathDictionaryExistsAlloc(store, path);
            }
            return try self.resolvedDocSetForPathLookupExistsAlloc(store, path);
        }
        const spec = self.existsFieldSpec(value) orelse return null;
        return try self.resolvedDocSetForFieldExistsAlloc(store, spec.role, spec.field);
    }

    fn resolvedDocSetForFieldExistsAlloc(self: *Index, store: *docstore_mod.DocStore, role: fact_mod.Role, field: []const u8) !?doc_set.ResolvedDocSet {
        const legacy_count = try self.countRowsWithPrefix(store, try self.docFactFieldPrefixAlloc(role, field));
        const ordinals = try self.ordinalPostingsForPrefixAlloc(store, try self.docFactFieldOrdinalPrefixAlloc(role, field));
        defer if (ordinals.len > 0) self.alloc.free(ordinals);
        if (ordinals.len == 0 and legacy_count > 0) return null;
        if (legacy_count != ordinals.len) return null;
        return try doc_set.fromOrdinalsAlloc(self.alloc, ordinals);
    }

    fn docIdsForIndexedDocFactPrefixAlloc(self: *Index, store: *docstore_mod.DocStore, owned_prefix: []u8) ![][]u8 {
        defer self.alloc.free(owned_prefix);
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(owned_prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, owned_prefix)) break;
            const doc_component = token.componentAt(entry.key, owned_prefix.len) catch continue;
            if (doc_component.next != entry.key.len) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_component.payload));
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn ordinalPostingsForPrefixAlloc(self: *Index, store: *docstore_mod.DocStore, owned_prefix: []u8) ![]doc_set.DocOrdinal {
        defer self.alloc.free(owned_prefix);
        var out = std.ArrayListUnmanaged(doc_set.DocOrdinal).empty;
        errdefer out.deinit(self.alloc);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(owned_prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, owned_prefix)) break;
            const ordinal_component = token.componentAt(entry.key, owned_prefix.len) catch continue;
            if (ordinal_component.next != entry.key.len or ordinal_component.payload.len != @sizeOf(doc_set.DocOrdinal)) continue;
            const ordinal = std.mem.readInt(u32, ordinal_component.payload[0..4], .big);
            try out.append(self.alloc, ordinal);
        }
        return try out.toOwnedSlice(self.alloc);
    }

    const ExistsFieldSpec = struct {
        field: []const u8,
        role: fact_mod.Role,
    };

    fn existsFieldSpec(self: *const Index, value: std.json.Value) ?ExistsFieldSpec {
        return switch (value) {
            .string => |field_name| self.uniqueExistingFactField(field_name),
            .object => |object| blk: {
                const field_name = jsonStringValue(object.get("field") orelse return null) orelse return null;
                if (object.get("role")) |role_value| {
                    const role_text = jsonStringValue(role_value) orelse return null;
                    const class = fieldClassFromFactRoleText(role_text) orelse return null;
                    const field = self.fieldConfig(field_name, class) orelse return null;
                    break :blk .{ .field = field.name, .role = factRoleFromFieldClass(class) orelse return null };
                }
                break :blk self.uniqueExistingFactField(field_name);
            },
            else => null,
        };
    }

    fn uniqueExistingFactField(self: *const Index, field_name: []const u8) ?ExistsFieldSpec {
        const resolved = self.resolveUniqueField(field_name) orelse return null;
        const role = factRoleFromFieldClass(resolved.role) orelse return null;
        return .{ .field = resolved.name, .role = role };
    }

    pub fn resolveUniqueField(self: *const Index, query_field: []const u8) ?ResolvedField {
        var found: ?ResolvedField = null;
        if (self.resolveField(query_field, .group)) |field| {
            found = field;
        }
        if (self.resolveField(query_field, .measure)) |field| {
            if (found != null) return null;
            found = field;
        }
        if (self.resolveField(query_field, .time)) |field| {
            if (found != null) return null;
            found = field;
        }
        return found;
    }

    fn unionDocIdsAlloc(self: *Index, left: [][]u8, right: [][]u8) ![][]u8 {
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);
        var seen = std.StringHashMapUnmanaged(void).empty;
        defer seen.deinit(self.alloc);
        for (left) |doc_id| {
            if (seen.contains(doc_id)) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_id));
            try seen.put(self.alloc, out.items[out.items.len - 1], {});
        }
        for (right) |doc_id| {
            if (seen.contains(doc_id)) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_id));
            try seen.put(self.alloc, out.items[out.items.len - 1], {});
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn dupeDocIdsAlloc(self: *Index, doc_ids: []const []const u8) ![][]u8 {
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);
        for (doc_ids) |doc_id| try out.append(self.alloc, try self.alloc.dupe(u8, doc_id));
        return try out.toOwnedSlice(self.alloc);
    }

    fn intersectDocIdsAlloc(self: *Index, left: [][]u8, right: [][]u8) ![][]u8 {
        var out = std.ArrayListUnmanaged([]u8).empty;
        errdefer freeDocIdList(self.alloc, &out);
        var right_set = std.StringHashMapUnmanaged(void).empty;
        defer right_set.deinit(self.alloc);
        try right_set.ensureTotalCapacity(self.alloc, @intCast(right.len));
        for (right) |doc_id| try right_set.put(self.alloc, doc_id, {});
        var emitted = std.StringHashMapUnmanaged(void).empty;
        defer emitted.deinit(self.alloc);
        for (left) |doc_id| {
            if (!right_set.contains(doc_id) or emitted.contains(doc_id)) continue;
            try out.append(self.alloc, try self.alloc.dupe(u8, doc_id));
            try emitted.put(self.alloc, out.items[out.items.len - 1], {});
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn collectSingleFieldConstraintAlloc(self: *Index, value: std.json.Value, out: *std.ArrayListUnmanaged(ir.Constraint)) Allocator.Error!bool {
        const object = switch (value) {
            .object => |object| object,
            else => return false,
        };
        if (object.count() != 1) return false;
        var it = object.iterator();
        const entry = it.next() orelse return false;
        return try self.appendFilterConstraintAlloc(out, entry.key_ptr.*, entry.value_ptr.*);
    }

    fn collectBoolFieldConstraintAlloc(self: *Index, value: std.json.Value, out: *std.ArrayListUnmanaged(ir.Constraint)) Allocator.Error!bool {
        const object = switch (value) {
            .object => |object| object,
            else => return false,
        };
        const field_value = object.get("field") orelse return false;
        const wanted_value = object.get("value") orelse return false;
        const field = switch (field_value) {
            .string => |field| field,
            else => return false,
        };
        return try self.appendFilterConstraintAlloc(out, field, wanted_value);
    }

    fn appendFilterConstraintAlloc(self: *Index, out: *std.ArrayListUnmanaged(ir.Constraint), field_name: []const u8, value: std.json.Value) Allocator.Error!bool {
        const field = self.fieldConfig(field_name, .group) orelse return false;
        const text = (try jsonScalarToStringAlloc(self.alloc, value)) orelse return false;
        errdefer self.alloc.free(text);
        try out.append(self.alloc, .{
            .field = try self.alloc.dupe(u8, field.name),
            .value = text,
        });
        return true;
    }

    fn scanMaterializedExpressionEntriesForMaterializationTxn(self: *Index, txn: anytype, materialization: []const u8) ![]FoldEntry {
        const mat_idx = self.materializationIndex(materialization) orelse return try self.alloc.alloc(FoldEntry, 0);
        const mat = self.config().materializations[mat_idx];
        const op = algebra.Op.parse(mat.op) orelse return try self.alloc.alloc(FoldEntry, 0);
        const law_id = self.materializationLawId(mat, op);
        const expr = materializationExpression(mat, law_id);
        return try self.scanMaterializedExpressionEntriesTxn(txn, expr, law_id, mat.time != null);
    }

    fn scanMaterializedExpressionEntriesTxn(
        self: *Index,
        txn: anytype,
        expr: ir.TensorExpr,
        law_id: law_mod.Id,
        has_time_bucket: bool,
    ) ![]FoldEntry {
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const prefix = try tensor_mod.expressionPrefixAlloc(self.alloc, self.name, expr_id);
        defer self.alloc.free(prefix);

        var out = std.ArrayListUnmanaged(FoldEntry).empty;
        errdefer {
            for (out.items) |*entry| entry.deinit(self.alloc);
            out.deinit(self.alloc);
        }
        var symbols = SymbolCache{};
        defer symbols.deinit(self.alloc);
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            var row = try tensor_mod.rowFromBytesOrLayoutAlloc(self.alloc, entry.value, &.{law_id});
            defer row.deinit(self.alloc);
            const slot_value = if (row.slots.len > 0) row.slots[0].value else null;
            const value = if (slot_value) |bytes| try self.alloc.dupe(u8, bytes) else continue;
            errdefer self.alloc.free(value);

            if (has_time_bucket) {
                const bucket_component = token.componentAt(entry.key, prefix.len) catch {
                    self.alloc.free(value);
                    continue;
                };
                const axis_component = token.componentAt(entry.key, bucket_component.next) catch {
                    self.alloc.free(value);
                    continue;
                };
                if (axis_component.next != entry.key.len) {
                    self.alloc.free(value);
                    continue;
                }
                const axis_id = symbol.idFromTextAlloc(self.alloc, axis_component.payload) catch {
                    self.alloc.free(value);
                    continue;
                };
                defer self.alloc.free(axis_id);
                const canonical_group = (symbols.resolve(self, txn, axis_id) catch |err| switch (err) {
                    error.InvalidSymbolId => null,
                    else => return err,
                }) orelse {
                    self.alloc.free(value);
                    continue;
                };
                const group_key = try token.canonicalTupleAlloc(self.alloc, &.{ bucket_component.payload, canonical_group });
                try out.append(self.alloc, .{
                    .group_key = group_key,
                    .value = value,
                });
            } else {
                const axis_component = token.componentAt(entry.key, prefix.len) catch {
                    self.alloc.free(value);
                    continue;
                };
                if (axis_component.next != entry.key.len) {
                    self.alloc.free(value);
                    continue;
                }
                const axis_id = symbol.idFromTextAlloc(self.alloc, axis_component.payload) catch {
                    self.alloc.free(value);
                    continue;
                };
                defer self.alloc.free(axis_id);
                const canonical_group = (symbols.resolve(self, txn, axis_id) catch |err| switch (err) {
                    error.InvalidSymbolId => null,
                    else => return err,
                }) orelse {
                    self.alloc.free(value);
                    continue;
                };
                try out.append(self.alloc, .{
                    .group_key = try self.alloc.dupe(u8, canonical_group),
                    .value = value,
                });
            }
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn expressionHasDimension(dims: []const ir.Dimension, dim: ir.Dimension) bool {
        for (dims) |item| {
            if (item == dim) return true;
        }
        return false;
    }

    fn scanFoldEntriesFromDocFactsTxn(
        self: *Index,
        txn: anytype,
        mat: MaterializationConfig,
        op: algebra.Op,
        law_id: law_mod.Id,
    ) ![]FoldEntry {
        var accumulator = DerivedJoinFoldAccumulator{};
        defer accumulator.deinit(self.alloc);

        const prefix = try self.docFactPrefixAlloc();
        defer self.alloc.free(prefix);
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            var facts = fact_mod.decodeListAlloc(self.alloc, entry.value) catch |err| switch (err) {
                error.InvalidAlgebraicFact => continue,
                else => return err,
            };
            defer facts.deinit(self.alloc);

            const group_axes = fact_mod.axisTupleAlloc(self.alloc, facts.facts, mat.group_by) catch |err| switch (err) {
                error.MissingField => continue,
                else => return err,
            };
            defer self.alloc.free(group_axes);

            var group_key: []u8 = undefined;
            var group_key_owned = false;
            defer if (group_key_owned) self.alloc.free(group_key);
            if (mat.time) |time_name| {
                const bucket_name = mat.bucket orelse continue;
                const bucket = cylinder.Bucket.parse(bucket_name) orelse continue;
                const time_value = (try self.factTimeTextAlloc(facts.facts, time_name)) orelse continue;
                defer self.alloc.free(time_value);
                const bucket_start = try cylinder.bucketStartAlloc(self.alloc, bucket, time_value);
                defer self.alloc.free(bucket_start);
                group_key = try token.canonicalTupleAlloc(self.alloc, &.{ bucket_start, group_axes });
                group_key_owned = true;
            } else {
                group_key = group_axes;
            }

            const measure_value = if (mat.measure) |measure_name|
                try self.factMeasureAlloc(facts.facts, measure_name)
            else
                null;
            defer if (measure_value) |value| value.deinit(self.alloc);

            const contribution = switch (op) {
                .count => try algebra.encodeI64Alloc(self.alloc, 1),
                .sum, .sumsquares, .avg => blk: {
                    const measure = measure_value orelse continue;
                    break :blk try self.materializationDeltaAlloc(op, measure, 1);
                },
                .min, .max => blk: {
                    const measure = measure_value orelse continue;
                    break :blk try self.alloc.dupe(u8, measure.raw);
                },
            };
            defer self.alloc.free(contribution);
            try accumulator.add(self.alloc, group_key, law_id, contribution);
        }

        return try accumulator.entriesAlloc(self.alloc);
    }

    fn scanDocFactBucketFoldEntriesTxn(
        self: *Index,
        txn: anytype,
        request: DocFactBucketFoldRequest,
        law_id: law_mod.Id,
        generation: ?u64,
    ) ![]FoldEntry {
        if (request.kind == .histogram and request.histogram_interval <= 0) return error.InvalidAlgebraicConfig;
        if (request.op != .count and request.measure == null) return error.InvalidAlgebraicConfig;
        var encoded_constraints = std.ArrayListUnmanaged(EncodedDerivedConstraint).empty;
        defer {
            for (encoded_constraints.items) |*item| item.deinit(self.alloc);
            encoded_constraints.deinit(self.alloc);
        }
        for (request.constraints) |constraint| {
            const field = self.fieldConfig(constraint.field, .group) orelse return error.InvalidAlgebraicConfig;
            try encoded_constraints.append(self.alloc, .{
                .field = field.name,
                .scalar = try self.constraintTokenAlloc(self.alloc, field.name, constraint.value),
            });
        }

        var accumulator = DerivedJoinFoldAccumulator{};
        defer accumulator.deinit(self.alloc);
        const prefix = try self.docFactPrefixAlloc();
        defer self.alloc.free(prefix);
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            if (!try self.docFactKeyVisibleAtGenerationTxn(txn, entry.key, prefix, generation)) continue;
            var facts = fact_mod.decodeListAlloc(self.alloc, entry.value) catch |err| switch (err) {
                error.InvalidAlgebraicFact => continue,
                else => return err,
            };
            defer facts.deinit(self.alloc);
            if (!docFactsMatchEncodedDerivedConstraints(facts.facts, encoded_constraints.items)) continue;
            const bucket_key = (try self.docFactBucketFoldGroupKeyAlloc(facts.facts, request)) orelse continue;
            defer self.alloc.free(bucket_key);
            const measure_value = if (request.measure) |measure_name|
                try self.factMeasureAlloc(facts.facts, measure_name)
            else
                null;
            defer if (measure_value) |value| value.deinit(self.alloc);
            const contribution = self.docFactBucketFoldContributionAlloc(request.op, measure_value) catch |err| switch (err) {
                error.MissingField, error.AlgebraicLawNotInvertible => continue,
                else => return err,
            };
            defer self.alloc.free(contribution);
            try accumulator.add(self.alloc, bucket_key, law_id, contribution);
        }
        return try accumulator.entriesAlloc(self.alloc);
    }

    fn docFactsMatchEncodedDerivedConstraints(facts: []const fact_mod.Fact, constraints: []const EncodedDerivedConstraint) bool {
        for (constraints) |constraint| {
            const scalar = fact_mod.findScalar(facts, .group, constraint.field) orelse return false;
            if (!std.mem.eql(u8, scalar, constraint.scalar)) return false;
        }
        return true;
    }

    fn docFactBucketFoldGroupKeyAlloc(
        self: *Index,
        facts: []const fact_mod.Fact,
        request: DocFactBucketFoldRequest,
    ) !?[]u8 {
        const scalar = fact_mod.findScalar(facts, request.bucket_role, request.bucket_field) orelse return null;
        const text = try token.scalarTokenTextAlloc(self.alloc, scalar);
        defer self.alloc.free(text);
        return switch (request.kind) {
            .terms => try self.alloc.dupe(u8, scalar),
            .histogram => blk: {
                const numeric = std.fmt.parseFloat(f64, text) catch return null;
                const bucket_index: i64 = @intFromFloat(@floor(numeric / request.histogram_interval));
                break :blk try std.fmt.allocPrint(self.alloc, "{d}", .{bucket_index});
            },
            .range => blk: {
                const numeric = std.fmt.parseFloat(f64, text) catch return null;
                if (!docFactNumericRangeMatches(numeric, request)) return null;
                const start = request.range_start orelse "";
                const end = request.range_end orelse "";
                break :blk try token.canonicalTupleAlloc(self.alloc, &.{ start, end });
            },
            .date_range => blk: {
                const timestamp_ns = (try parseRfc3339ToNs(text)) orelse return null;
                const start_ns = if (request.range_start) |start| (try parseRfc3339ToNs(start)) orelse return null else null;
                const end_ns = if (request.range_end) |end| (try parseRfc3339ToNs(end)) orelse return null else null;
                if (!scalarInDateRange(timestamp_ns, start_ns, end_ns, request.range_inclusive_start, request.range_inclusive_end)) return null;
                const start = request.range_start orelse "";
                const end = request.range_end orelse "";
                break :blk try token.canonicalTupleAlloc(self.alloc, &.{ start, end });
            },
        };
    }

    fn docFactNumericRangeMatches(value: f64, request: DocFactBucketFoldRequest) bool {
        if (request.range_start) |start_text| {
            const start = std.fmt.parseFloat(f64, start_text) catch return false;
            if (request.range_inclusive_start) {
                if (value < start) return false;
            } else if (value <= start) return false;
        }
        if (request.range_end) |end_text| {
            const end = std.fmt.parseFloat(f64, end_text) catch return false;
            if (request.range_inclusive_end) {
                if (value > end) return false;
            } else if (value >= end) return false;
        }
        return true;
    }

    fn docFactBucketFoldContributionAlloc(self: *Index, op: algebra.Op, measure_value: ?MeasureValue) ![]u8 {
        return switch (op) {
            .count => try algebra.encodeI64Alloc(self.alloc, 1),
            .sum, .sumsquares, .avg => try self.materializationDeltaAlloc(op, measure_value, 1),
            .min, .max => blk: {
                const measure = measure_value orelse return error.MissingField;
                break :blk try self.alloc.dupe(u8, measure.raw);
            },
        };
    }

    fn scanPathFactBucketFoldEntriesTxn(
        self: *Index,
        txn: anytype,
        request: PathFactBucketFoldRequest,
        law_id: law_mod.Id,
        generation: ?u64,
    ) ![]FoldEntry {
        if (request.kind == .histogram and request.histogram_interval <= 0) return error.InvalidAlgebraicConfig;
        if (request.op != .count and request.measure_path == null) return error.InvalidAlgebraicConfig;
        var accumulator = DerivedJoinFoldAccumulator{};
        defer accumulator.deinit(self.alloc);
        const prefix = try self.keyAlloc(&.{"pathfact"});
        defer self.alloc.free(prefix);
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            if (!try self.docFactKeyVisibleAtGenerationTxn(txn, entry.key, prefix, generation)) continue;
            var projection = pathfact_mod.decodeProjectionAlloc(self.alloc, entry.value) catch |err| switch (err) {
                error.InvalidPathFactList => continue,
                else => return err,
            };
            defer projection.deinit(self.alloc);
            if (!(try self.pathFactsMatchConstraints(projection.facts, request.constraints))) continue;
            const bucket_keys = try self.pathFactBucketFoldGroupKeysAlloc(projection.facts, request);
            defer {
                for (bucket_keys) |bucket_key| self.alloc.free(bucket_key);
                if (bucket_keys.len > 0) self.alloc.free(bucket_keys);
            }
            if (bucket_keys.len == 0) continue;
            const measure_value = if (request.measure_path) |measure_path|
                try self.pathFactMeasureAlloc(projection.facts, measure_path, request.measure_kind)
            else
                null;
            defer if (measure_value) |value| value.deinit(self.alloc);
            const contribution = self.pathFactBucketFoldContributionAlloc(request.op, measure_value) catch |err| switch (err) {
                error.MissingField, error.AlgebraicLawNotInvertible => continue,
                else => return err,
            };
            defer self.alloc.free(contribution);
            for (bucket_keys) |bucket_key| {
                try accumulator.add(self.alloc, bucket_key, law_id, contribution);
            }
        }
        return try accumulator.entriesAlloc(self.alloc);
    }

    fn pathFactStringCoercionAllowedTxn(
        self: *Index,
        txn: anytype,
        request: PathFactBucketFoldRequest,
    ) !bool {
        switch (request.kind) {
            .terms => {
                if (request.op != .count and request.measure_kind == .string) {
                    const measure_path = request.measure_path orelse return false;
                    if (!(try self.pathFactNumericStringPathAllowedTxn(txn, measure_path))) return false;
                }
                return true;
            },
            .histogram, .range => {
                if (request.bucket_kind == .string and !(try self.pathFactNumericStringPathAllowedTxn(txn, request.bucket_path))) {
                    return false;
                }
                if (request.op != .count and request.measure_kind == .string) {
                    const measure_path = request.measure_path orelse return false;
                    if (!(try self.pathFactNumericStringPathAllowedTxn(txn, measure_path))) return false;
                }
                return true;
            },
            .date_range => {
                if (request.bucket_kind == .string and !(try self.pathFactDatetimeStringPathAllowedTxn(txn, request.bucket_path))) {
                    return false;
                }
                if (request.op != .count and request.measure_kind == .string) {
                    const measure_path = request.measure_path orelse return false;
                    if (!(try self.pathFactNumericStringPathAllowedTxn(txn, measure_path))) return false;
                }
                return true;
            },
        }
    }

    fn pathFactNumericStringPathAllowedTxn(
        self: *Index,
        txn: anytype,
        path: []const u8,
    ) !bool {
        if (!self.parsed.value.pathfact_policy.allow_numeric_string_coercion) return false;
        const profile_key = try self.pathProfileKeyAlloc(path);
        defer self.alloc.free(profile_key);
        const payload = txn.get(profile_key) catch |err| switch (err) {
            error.NotFound => return true,
            else => return err,
        };
        var profile = try pathfact_mod.decodeProfileAlloc(self.alloc, path, payload);
        defer profile.deinit(self.alloc);
        if (profile.string_count == 0) return true;
        return profile.string_numeric_parse_success_count == profile.string_count and
            profile.string_numeric_parse_failure_count == 0;
    }

    fn pathFactDatetimeStringPathAllowedTxn(
        self: *Index,
        txn: anytype,
        path: []const u8,
    ) !bool {
        if (!self.parsed.value.pathfact_policy.allow_datetime_string_coercion) return false;
        const profile_key = try self.pathProfileKeyAlloc(path);
        defer self.alloc.free(profile_key);
        const payload = txn.get(profile_key) catch |err| switch (err) {
            error.NotFound => return true,
            else => return err,
        };
        var profile = try pathfact_mod.decodeProfileAlloc(self.alloc, path, payload);
        defer profile.deinit(self.alloc);
        if (profile.string_count == 0) return false;
        if (profile.null_count > 0 or profile.bool_count > 0 or profile.number_count > 0) return false;
        return profile.string_datetime_parse_success_count == profile.string_count and
            profile.string_datetime_parse_failure_count == 0;
    }

    const DecodedPathFactConstraint = struct {
        kind: pathfact_mod.Kind,
        value: []u8,

        fn deinit(self: *@This(), alloc: Allocator) void {
            alloc.free(self.value);
            self.* = undefined;
        }
    };

    const DecodedPathFactPrefixConstraint = struct {
        prefix: []u8,

        fn deinit(self: *@This(), alloc: Allocator) void {
            alloc.free(self.prefix);
            self.* = undefined;
        }
    };

    const DecodedPathFactAnyConstraint = struct {
        values: []DecodedPathFactConstraint,

        fn deinit(self: *@This(), alloc: Allocator) void {
            for (self.values) |*value| value.deinit(alloc);
            if (self.values.len > 0) alloc.free(self.values);
            self.* = undefined;
        }
    };

    const DecodedPathFactMatchConstraint = struct {
        text: []u8,

        fn deinit(self: *@This(), alloc: Allocator) void {
            alloc.free(self.text);
            self.* = undefined;
        }
    };

    const DecodedPathFactWildcardConstraint = struct {
        pattern: []u8,

        fn deinit(self: *@This(), alloc: Allocator) void {
            alloc.free(self.pattern);
            self.* = undefined;
        }
    };

    const DecodedPathFactRegexpConstraint = struct {
        pattern: []u8,
        compiled: regex_mod.RegexAutomaton,

        fn deinit(self: *@This(), alloc: Allocator) void {
            self.compiled.deinit();
            alloc.free(self.pattern);
            self.* = undefined;
        }
    };

    const DecodedPathFactFuzzyConstraint = struct {
        folded_term: []u8,
        literal_prefix: []u8,
        max_edits: u8,

        fn deinit(self: *@This(), alloc: Allocator) void {
            alloc.free(self.folded_term);
            alloc.free(self.literal_prefix);
            self.* = undefined;
        }
    };

    const DecodedPathFactNumericRangeConstraint = struct {
        min: ?f64,
        max: ?f64,
        inclusive_min: bool,
        inclusive_max: bool,
    };

    const DecodedPathFactTermRangeConstraint = struct {
        min: ?[]u8,
        max: ?[]u8,
        inclusive_min: bool,
        inclusive_max: bool,

        fn deinit(self: *@This(), alloc: Allocator) void {
            if (self.min) |value| alloc.free(value);
            if (self.max) |value| alloc.free(value);
            self.* = undefined;
        }
    };

    const DecodedPathFactDateRangeConstraint = struct {
        start_ns: ?u64,
        end_ns: ?u64,
        inclusive_start: bool,
        inclusive_end: bool,
    };

    const DecodedPathFactIpRangeConstraint = struct {
        cidr: ?IpCidr,
        exact_ip: ?[4]u8,
    };

    const DecodedPathFactGeoBBoxConstraint = struct {
        min_lat: f64,
        min_lon: f64,
        max_lat: f64,
        max_lon: f64,
    };

    const DecodedPathFactGeoDistanceConstraint = struct {
        center: geo_mod.GeoPoint,
        radius_meters: f64,
    };

    const DecodedPathFactGeoShapeConstraint = struct {
        relation: []u8,
        polygons: []const []const geo_mod.GeoPoint,

        fn deinit(self: *@This(), alloc: Allocator) void {
            alloc.free(self.relation);
            for (self.polygons) |polygon| {
                if (polygon.len > 0) alloc.free(@constCast(polygon));
            }
            if (self.polygons.len > 0) alloc.free(@constCast(self.polygons));
            self.* = undefined;
        }
    };

    fn decodePathFactConstraintAlloc(self: *Index, value: []const u8) !?DecodedPathFactConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 2) return null;
        const kind = std.meta.stringToEnum(pathfact_mod.Kind, parts[0]) orelse return null;
        switch (kind) {
            .bool, .number, .string => {},
            .null => if (parts[1].len != 0) return null,
            .object, .array => return null,
        }
        return .{
            .kind = kind,
            .value = try self.alloc.dupe(u8, parts[1]),
        };
    }

    fn decodePathFactPrefixConstraintAlloc(self: *Index, value: []const u8) !?DecodedPathFactPrefixConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 3 or !std.mem.eql(u8, parts[0], path_fact_prefix_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "string")) return null;
        return .{ .prefix = try self.alloc.dupe(u8, parts[2]) };
    }

    fn decodePathFactAnyConstraintAlloc(self: *Index, value: []const u8) !?DecodedPathFactAnyConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len < 2 or !std.mem.eql(u8, parts[0], path_fact_any_constraint_tag)) return null;
        const values = try self.alloc.alloc(DecodedPathFactConstraint, parts.len - 1);
        errdefer self.alloc.free(values);
        var initialized: usize = 0;
        errdefer {
            for (values[0..initialized]) |*item| item.deinit(self.alloc);
        }
        for (parts[1..], 0..) |part, i| {
            const decoded = (try self.decodePathFactConstraintAlloc(part)) orelse return null;
            values[i] = decoded;
            initialized += 1;
        }
        return .{ .values = values };
    }

    fn decodePathFactMatchConstraintAlloc(self: *Index, value: []const u8) !?DecodedPathFactMatchConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 3 or !std.mem.eql(u8, parts[0], path_fact_match_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "string")) return null;
        return .{ .text = try self.alloc.dupe(u8, parts[2]) };
    }

    fn decodePathFactWildcardConstraintAlloc(self: *Index, value: []const u8) !?DecodedPathFactWildcardConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 3 or !std.mem.eql(u8, parts[0], path_fact_wildcard_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "string")) return null;
        return .{ .pattern = try self.alloc.dupe(u8, parts[2]) };
    }

    fn decodePathFactRegexpConstraintAlloc(self: *Index, value: []const u8) !?DecodedPathFactRegexpConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 3 or !std.mem.eql(u8, parts[0], path_fact_regexp_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "string")) return null;
        const pattern = try self.alloc.dupe(u8, parts[2]);
        errdefer self.alloc.free(pattern);
        const compiled = regex_mod.compile(self.alloc, pattern) catch {
            self.alloc.free(pattern);
            return null;
        };
        return .{ .pattern = pattern, .compiled = compiled };
    }

    fn decodePathFactFuzzyConstraintAlloc(self: *Index, value: []const u8) !?DecodedPathFactFuzzyConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 5 or !std.mem.eql(u8, parts[0], path_fact_fuzzy_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "string")) return null;
        const max_edits = std.fmt.parseInt(u8, parts[3], 10) catch return null;
        const prefix_len = std.fmt.parseInt(u8, parts[4], 10) catch return null;
        if (prefix_len == 0) return null;
        const literal_prefix_len: usize = @intCast(prefix_len);
        if (parts[2].len < literal_prefix_len) return null;
        const folded_term = try asciiLowerAlloc(self.alloc, parts[2]);
        errdefer self.alloc.free(folded_term);
        const literal_prefix = try self.alloc.dupe(u8, parts[2][0..literal_prefix_len]);
        return .{
            .folded_term = folded_term,
            .literal_prefix = literal_prefix,
            .max_edits = max_edits,
        };
    }

    fn decodePathFactNumericRangeConstraint(self: *Index, value: []const u8) !?DecodedPathFactNumericRangeConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 6 or !std.mem.eql(u8, parts[0], path_fact_numeric_range_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "number")) return null;
        const min = if (parts[2].len > 0) std.fmt.parseFloat(f64, parts[2]) catch return null else null;
        const max = if (parts[3].len > 0) std.fmt.parseFloat(f64, parts[3]) catch return null else null;
        const inclusive_min = if (std.mem.eql(u8, parts[4], "1")) true else if (std.mem.eql(u8, parts[4], "0")) false else return null;
        const inclusive_max = if (std.mem.eql(u8, parts[5], "1")) true else if (std.mem.eql(u8, parts[5], "0")) false else return null;
        return .{
            .min = min,
            .max = max,
            .inclusive_min = inclusive_min,
            .inclusive_max = inclusive_max,
        };
    }

    fn decodePathFactTermRangeConstraintAlloc(self: *Index, value: []const u8) !?DecodedPathFactTermRangeConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 6 or !std.mem.eql(u8, parts[0], path_fact_term_range_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "string")) return null;
        if (parts[2].len == 0 and parts[3].len == 0) return null;
        const min = if (parts[2].len > 0) try self.alloc.dupe(u8, parts[2]) else null;
        errdefer if (min) |value_min| self.alloc.free(value_min);
        const max = if (parts[3].len > 0) try self.alloc.dupe(u8, parts[3]) else null;
        errdefer if (max) |value_max| self.alloc.free(value_max);
        const inclusive_min = if (std.mem.eql(u8, parts[4], "1")) true else if (std.mem.eql(u8, parts[4], "0")) false else return null;
        const inclusive_max = if (std.mem.eql(u8, parts[5], "1")) true else if (std.mem.eql(u8, parts[5], "0")) false else return null;
        return .{
            .min = min,
            .max = max,
            .inclusive_min = inclusive_min,
            .inclusive_max = inclusive_max,
        };
    }

    fn decodePathFactDateRangeConstraint(self: *Index, value: []const u8) !?DecodedPathFactDateRangeConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 6 or !std.mem.eql(u8, parts[0], path_fact_date_range_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "datetime")) return null;
        if (parts[2].len == 0 and parts[3].len == 0) return null;
        const start_ns = if (parts[2].len > 0) (try parseDateOrNsOptionalToNs(parts[2])) orelse return null else null;
        const end_ns = if (parts[3].len > 0) (try parseDateOrNsOptionalToNs(parts[3])) orelse return null else null;
        const inclusive_start = if (std.mem.eql(u8, parts[4], "1")) true else if (std.mem.eql(u8, parts[4], "0")) false else return null;
        const inclusive_end = if (std.mem.eql(u8, parts[5], "1")) true else if (std.mem.eql(u8, parts[5], "0")) false else return null;
        return .{
            .start_ns = start_ns,
            .end_ns = end_ns,
            .inclusive_start = inclusive_start,
            .inclusive_end = inclusive_end,
        };
    }

    fn decodePathFactIpRangeConstraint(self: *Index, value: []const u8) !?DecodedPathFactIpRangeConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 3 or !std.mem.eql(u8, parts[0], path_fact_ip_range_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "ipv4")) return null;
        const cidr = parseIpCidr(parts[2]);
        const exact_ip = if (cidr == null) parseIPv4(parts[2]) else null;
        if (cidr == null and exact_ip == null) return null;
        return .{ .cidr = cidr, .exact_ip = exact_ip };
    }

    fn decodePathFactGeoBBoxConstraint(self: *Index, value: []const u8) !?DecodedPathFactGeoBBoxConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 6 or !std.mem.eql(u8, parts[0], path_fact_geo_bbox_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "geo_point")) return null;
        const min_lat = std.fmt.parseFloat(f64, parts[2]) catch return null;
        const min_lon = std.fmt.parseFloat(f64, parts[3]) catch return null;
        const max_lat = std.fmt.parseFloat(f64, parts[4]) catch return null;
        const max_lon = std.fmt.parseFloat(f64, parts[5]) catch return null;
        if (!validGeoLatitude(min_lat) or !validGeoLatitude(max_lat) or !validGeoLongitude(min_lon) or !validGeoLongitude(max_lon)) return null;
        if (min_lat > max_lat) return null;
        return .{
            .min_lat = min_lat,
            .min_lon = min_lon,
            .max_lat = max_lat,
            .max_lon = max_lon,
        };
    }

    fn decodePathFactGeoDistanceConstraint(self: *Index, value: []const u8) !?DecodedPathFactGeoDistanceConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 5 or !std.mem.eql(u8, parts[0], path_fact_geo_distance_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "geo_point")) return null;
        const lat = std.fmt.parseFloat(f64, parts[2]) catch return null;
        const lon = std.fmt.parseFloat(f64, parts[3]) catch return null;
        const radius_meters = std.fmt.parseFloat(f64, parts[4]) catch return null;
        if (!validGeoLatitude(lat) or !validGeoLongitude(lon) or !std.math.isFinite(radius_meters) or radius_meters < 0) return null;
        return .{
            .center = .{ .lat = lat, .lon = lon },
            .radius_meters = radius_meters,
        };
    }

    fn decodePathFactGeoShapeConstraintAlloc(self: *Index, value: []const u8) !?DecodedPathFactGeoShapeConstraint {
        const parts = token.decodeTupleAlloc(self.alloc, value) catch return null;
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len < 6 or !std.mem.eql(u8, parts[0], path_fact_geo_shape_constraint_tag)) return null;
        if (!std.mem.eql(u8, parts[1], "geo_point")) return null;
        if (!std.mem.eql(u8, parts[2], "intersects") and !std.mem.eql(u8, parts[2], "within")) return null;
        const polygon_count = std.fmt.parseInt(usize, parts[3], 10) catch return null;
        if (polygon_count == 0) return null;

        var out = try self.alloc.alloc([]const geo_mod.GeoPoint, polygon_count);
        var initialized: usize = 0;
        var decoded = false;
        defer if (!decoded) freeGeoPolygons(self.alloc, out[0..initialized]);

        var cursor: usize = 4;
        while (initialized < polygon_count) {
            if (cursor >= parts.len) return null;
            const point_count = std.fmt.parseInt(usize, parts[cursor], 10) catch return null;
            cursor += 1;
            if (point_count < 3) return null;
            if (cursor + point_count * 2 > parts.len) return null;
            const polygon = try self.alloc.alloc(geo_mod.GeoPoint, point_count);
            var polygon_complete = false;
            defer if (!polygon_complete) self.alloc.free(polygon);
            for (polygon, 0..) |*point, i| {
                const lat = std.fmt.parseFloat(f64, parts[cursor + i * 2]) catch return null;
                const lon = std.fmt.parseFloat(f64, parts[cursor + i * 2 + 1]) catch return null;
                if (!validGeoLatitude(lat) or !validGeoLongitude(lon)) return null;
                point.* = .{ .lat = lat, .lon = lon };
            }
            cursor += point_count * 2;
            out[initialized] = polygon;
            initialized += 1;
            polygon_complete = true;
        }
        if (cursor != parts.len) return null;
        const relation = try self.alloc.dupe(u8, parts[2]);
        decoded = true;
        return .{
            .relation = relation,
            .polygons = out,
        };
    }

    fn freeGeoPolygons(alloc: Allocator, polygons: []const []const geo_mod.GeoPoint) void {
        for (polygons) |polygon| {
            if (polygon.len > 0) alloc.free(@constCast(polygon));
        }
        if (polygons.len > 0) alloc.free(@constCast(polygons));
    }

    fn pathFactsMatchConstraints(self: *Index, facts: []const pathfact_mod.Fact, constraints: []const ir.Constraint) !bool {
        for (constraints) |constraint| {
            if (!std.mem.startsWith(u8, constraint.field, "/")) return false;
            var typed = try self.decodePathFactConstraintAlloc(constraint.value);
            defer if (typed) |*item| item.deinit(self.alloc);
            var any = try self.decodePathFactAnyConstraintAlloc(constraint.value);
            defer if (any) |*item| item.deinit(self.alloc);
            var prefix = try self.decodePathFactPrefixConstraintAlloc(constraint.value);
            defer if (prefix) |*item| item.deinit(self.alloc);
            var match = try self.decodePathFactMatchConstraintAlloc(constraint.value);
            defer if (match) |*item| item.deinit(self.alloc);
            var wildcard = try self.decodePathFactWildcardConstraintAlloc(constraint.value);
            defer if (wildcard) |*item| item.deinit(self.alloc);
            var regexp = try self.decodePathFactRegexpConstraintAlloc(constraint.value);
            defer if (regexp) |*item| item.deinit(self.alloc);
            var fuzzy = try self.decodePathFactFuzzyConstraintAlloc(constraint.value);
            defer if (fuzzy) |*item| item.deinit(self.alloc);
            const numeric_range = try self.decodePathFactNumericRangeConstraint(constraint.value);
            var term_range = try self.decodePathFactTermRangeConstraintAlloc(constraint.value);
            defer if (term_range) |*item| item.deinit(self.alloc);
            const date_range = try self.decodePathFactDateRangeConstraint(constraint.value);
            const ip_range = try self.decodePathFactIpRangeConstraint(constraint.value);
            const geo_bbox = try self.decodePathFactGeoBBoxConstraint(constraint.value);
            const geo_distance = try self.decodePathFactGeoDistanceConstraint(constraint.value);
            var geo_shape = try self.decodePathFactGeoShapeConstraintAlloc(constraint.value);
            defer if (geo_shape) |*item| item.deinit(self.alloc);
            if (geo_bbox) |item| {
                const lat_path = try self.pathGeoChildPathAlloc(constraint.field, "lat");
                defer self.alloc.free(lat_path);
                const lon_path = try self.pathGeoChildPathAlloc(constraint.field, "lon");
                defer self.alloc.free(lon_path);
                const point = pathGeoPointFromFacts(facts, lat_path, lon_path) orelse return false;
                if (!pathGeoPredicateMatches(.{ .bbox = .{
                    .path = constraint.field,
                    .min_lat = item.min_lat,
                    .min_lon = item.min_lon,
                    .max_lat = item.max_lat,
                    .max_lon = item.max_lon,
                } }, point)) return false;
                continue;
            }
            if (geo_distance) |item| {
                const lat_path = try self.pathGeoChildPathAlloc(constraint.field, "lat");
                defer self.alloc.free(lat_path);
                const lon_path = try self.pathGeoChildPathAlloc(constraint.field, "lon");
                defer self.alloc.free(lon_path);
                const point = pathGeoPointFromFacts(facts, lat_path, lon_path) orelse return false;
                if (!pathGeoPredicateMatches(.{ .distance = .{
                    .path = constraint.field,
                    .center = item.center,
                    .radius_meters = item.radius_meters,
                } }, point)) return false;
                continue;
            }
            if (geo_shape) |item| {
                const lat_path = try self.pathGeoChildPathAlloc(constraint.field, "lat");
                defer self.alloc.free(lat_path);
                const lon_path = try self.pathGeoChildPathAlloc(constraint.field, "lon");
                defer self.alloc.free(lon_path);
                const point = pathGeoPointFromFacts(facts, lat_path, lon_path) orelse return false;
                if (!pathGeoShapeMatches(.{
                    .path = constraint.field,
                    .relation = item.relation,
                    .polygons = item.polygons,
                }, point)) return false;
                continue;
            }
            var matched = false;
            for (facts) |fact| {
                const value_matches = if (std.mem.eql(u8, constraint.value, path_fact_exists_constraint_value))
                    true
                else if (any) |item|
                    pathFactMatchesAny(fact, item.values)
                else if (prefix) |item|
                    fact.kind == .string and std.mem.startsWith(u8, fact.value, item.prefix)
                else if (match) |item|
                    fact.kind == .string and containsCaseInsensitive(fact.value, item.text)
                else if (wildcard) |item|
                    fact.kind == .string and wildcardMatch(item.pattern, fact.value)
                else if (regexp) |*item|
                    fact.kind == .string and regex_mod.matchesCompiled(item.pattern, &item.compiled, fact.value)
                else if (fuzzy) |item|
                    fact.kind == .string and std.mem.startsWith(u8, fact.value, item.literal_prefix) and
                        try fuzzyMatchesScalar(self.alloc, fact.value, item.folded_term, item.max_edits)
                else if (numeric_range) |item| blk: {
                    if (fact.kind != .number) break :blk false;
                    const numeric = std.fmt.parseFloat(f64, fact.value) catch break :blk false;
                    break :blk scalarInNumberRange(numeric, item.min, item.max, item.inclusive_min, item.inclusive_max);
                } else if (term_range) |item| blk: {
                    if (fact.kind != .string) break :blk false;
                    break :blk scalarInTermRange(fact.value, item.min, item.max, item.inclusive_min, item.inclusive_max);
                } else if (date_range) |item| blk: {
                    if (fact.kind != .string) break :blk false;
                    const timestamp_ns = (try parseDateTimeOptionalToNs(fact.value)) orelse break :blk false;
                    break :blk scalarInDateRange(timestamp_ns, item.start_ns, item.end_ns, item.inclusive_start, item.inclusive_end);
                } else if (ip_range) |item| blk: {
                    if (fact.kind != .string) break :blk false;
                    const candidate = parseIPv4(fact.value) orelse break :blk false;
                    break :blk if (item.cidr) |cidr|
                        ipInRange(candidate, cidr.network, cidr.prefix_len)
                    else if (item.exact_ip) |wanted|
                        std.mem.eql(u8, wanted[0..], candidate[0..])
                    else
                        false;
                } else if (typed) |item|
                    fact.kind == item.kind and std.mem.eql(u8, fact.value, item.value)
                else
                    std.mem.eql(u8, fact.value, constraint.value);
                if (std.mem.eql(u8, fact.path, constraint.field) and value_matches) {
                    matched = true;
                    break;
                }
            }
            if (!matched) return false;
        }
        return true;
    }

    fn pathFactMatchesAny(fact: pathfact_mod.Fact, values: []const DecodedPathFactConstraint) bool {
        for (values) |value| {
            if (fact.kind == value.kind and std.mem.eql(u8, fact.value, value.value)) return true;
        }
        return false;
    }

    fn pathFactBucketFoldGroupKeyAlloc(
        self: *Index,
        facts: []const pathfact_mod.Fact,
        request: PathFactBucketFoldRequest,
    ) !?[]u8 {
        const fact = pathFactByPathAndKind(facts, request.bucket_path, request.bucket_kind) orelse return null;
        const text = fact.value;
        return switch (request.kind) {
            .terms => try token.canonicalTupleAlloc(self.alloc, &.{ @tagName(request.bucket_kind), text }),
            .histogram => blk: {
                const numeric = std.fmt.parseFloat(f64, text) catch return null;
                const bucket_index: i64 = @intFromFloat(@floor(numeric / request.histogram_interval));
                break :blk try std.fmt.allocPrint(self.alloc, "{d}", .{bucket_index});
            },
            .range => blk: {
                const numeric = std.fmt.parseFloat(f64, text) catch return null;
                if (!pathFactNumericRangeMatches(numeric, request)) return null;
                const start = request.range_start orelse "";
                const end = request.range_end orelse "";
                break :blk try token.canonicalTupleAlloc(self.alloc, &.{ start, end });
            },
            .date_range => blk: {
                const timestamp_ns = (try parseRfc3339ToNs(text)) orelse return null;
                const start_ns = if (request.range_start) |start| (try parseRfc3339ToNs(start)) orelse return null else null;
                const end_ns = if (request.range_end) |end| (try parseRfc3339ToNs(end)) orelse return null else null;
                if (!scalarInDateRange(timestamp_ns, start_ns, end_ns, request.range_inclusive_start, request.range_inclusive_end)) return null;
                const start = request.range_start orelse "";
                const end = request.range_end orelse "";
                break :blk try token.canonicalTupleAlloc(self.alloc, &.{ start, end });
            },
        };
    }

    fn pathFactBucketFoldGroupKeysAlloc(
        self: *Index,
        facts: []const pathfact_mod.Fact,
        request: PathFactBucketFoldRequest,
    ) ![][]u8 {
        if (request.kind != .terms) {
            const key = (try self.pathFactBucketFoldGroupKeyAlloc(facts, request)) orelse return try self.alloc.alloc([]u8, 0);
            const out = try self.alloc.alloc([]u8, 1);
            out[0] = key;
            return out;
        }

        var keys = std.ArrayListUnmanaged([]u8).empty;
        errdefer {
            for (keys.items) |key| self.alloc.free(key);
            keys.deinit(self.alloc);
        }
        var seen = std.StringHashMapUnmanaged(void).empty;
        defer seen.deinit(self.alloc);

        for (facts) |fact| {
            if (fact.kind != request.bucket_kind or !std.mem.eql(u8, fact.path, request.bucket_path)) continue;
            const key = try token.canonicalTupleAlloc(self.alloc, &.{ @tagName(request.bucket_kind), fact.value });
            const gop = try seen.getOrPut(self.alloc, key);
            if (gop.found_existing) {
                self.alloc.free(key);
                continue;
            }
            gop.key_ptr.* = key;
            try keys.append(self.alloc, key);
        }

        return try keys.toOwnedSlice(self.alloc);
    }

    fn pathFactNumericRangeMatches(value: f64, request: PathFactBucketFoldRequest) bool {
        if (request.range_start) |start_text| {
            const start = std.fmt.parseFloat(f64, start_text) catch return false;
            if (request.range_inclusive_start) {
                if (value < start) return false;
            } else if (value <= start) return false;
        }
        if (request.range_end) |end_text| {
            const end = std.fmt.parseFloat(f64, end_text) catch return false;
            if (request.range_inclusive_end) {
                if (value > end) return false;
            } else if (value >= end) return false;
        }
        return true;
    }

    fn pathFactBucketFoldContributionAlloc(self: *Index, op: algebra.Op, measure_value: ?MeasureValue) ![]u8 {
        return switch (op) {
            .count => try algebra.encodeI64Alloc(self.alloc, 1),
            .sum, .sumsquares, .avg => try self.materializationDeltaAlloc(op, measure_value, 1),
            .min, .max => blk: {
                const measure = measure_value orelse return error.MissingField;
                break :blk try self.alloc.dupe(u8, measure.raw);
            },
        };
    }

    fn pathFactMeasureAlloc(self: *Index, facts: []const pathfact_mod.Fact, path: []const u8, kind: pathfact_mod.Kind) !?MeasureValue {
        const fact = pathFactByPathAndKind(facts, path, kind) orelse return null;
        const raw = try self.alloc.dupe(u8, fact.value);
        errdefer self.alloc.free(raw);
        const support_token = try self.alloc.dupe(u8, fact.value);
        return .{ .raw = raw, .support_token = support_token };
    }

    fn pathFactByPathAndKind(facts: []const pathfact_mod.Fact, path: []const u8, kind: pathfact_mod.Kind) ?pathfact_mod.Fact {
        for (facts) |fact| {
            if (fact.kind == kind and std.mem.eql(u8, fact.path, path)) return fact;
        }
        return null;
    }

    fn pathFactsHaveScalarAtPath(facts: []const pathfact_mod.Fact, path: []const u8) bool {
        for (facts) |fact| {
            if (!std.mem.eql(u8, fact.path, path)) continue;
            switch (fact.kind) {
                .null, .bool, .number, .string => return true,
                .object, .array => {},
            }
        }
        return false;
    }

    fn scanFoldEntriesFromConfiguredJoinFactsTxn(
        self: *Index,
        txn: anytype,
        mat: MaterializationConfig,
        op: algebra.Op,
        law_id: law_mod.Id,
    ) ![]FoldEntry {
        const join_name = mat.join orelse return try self.alloc.alloc(FoldEntry, 0);
        const join_cfg = self.joinConfig(join_name) orelse return error.InvalidAlgebraicConfig;
        const request = DerivedJoinFoldRequest{
            .join = .{
                .name = join_name,
                .group_side = mat.group_side orelse return error.InvalidAlgebraicConfig,
                .measure_side = mat.measure_side orelse return error.InvalidAlgebraicConfig,
                .kind = join_mod.temporalMode(join_cfg.temporal_bucket, join_cfg.temporal_window_seconds),
            },
            .op = op,
            .group_by = mat.group_by,
            .time_field = mat.time,
            .time_bucket = mat.bucket,
            .measure = mat.measure,
        };
        return try self.scanDerivedJoinFoldEntriesTxn(txn, join_cfg, request, law_id, null);
    }

    fn expressionRawValueForMaterializationTxn(
        self: *Index,
        txn: anytype,
        materialization: []const u8,
        axes_canonical: []const u8,
        bucket: ?[]const u8,
    ) !?[]u8 {
        const mat_idx = self.materializationIndex(materialization) orelse return null;
        const mat = self.config().materializations[mat_idx];
        const op = algebra.Op.parse(mat.op) orelse return null;
        const law_id = self.materializationLawId(mat, op);
        const expr = materializationExpression(mat, law_id);
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const key = try tensor_mod.expressionKeyAlloc(self.alloc, self.name, .{
            .expr_id = expr_id,
            .axes_canonical = axes_canonical,
            .bucket = bucket,
        });
        defer self.alloc.free(key);
        const raw_row = txn.get(key) catch |err| switch (err) {
            error.NotFound => return null,
            else => return err,
        };
        var row = try tensor_mod.rowFromBytesOrLayoutAlloc(self.alloc, raw_row, &.{law_id});
        defer row.deinit(self.alloc);
        if (row.slots.len == 0) return null;
        return if (row.slots[0].value) |value| try self.alloc.dupe(u8, value) else null;
    }

    fn scanMaterializedExpressionRowsTxn(self: *Index, txn: anytype, materializations: []const []const u8) !?[]MaterializedExpressionRowEntry {
        const first_mat_idx = self.materializationIndex(materializations[0]) orelse return null;
        const first_mat = self.config().materializations[first_mat_idx];
        const first_op = algebra.Op.parse(first_mat.op) orelse return null;
        const first_law_id = self.materializationLawId(first_mat, first_op);
        const first_expr = materializationExpression(first_mat, first_law_id);
        const first_expr_id = try self.materializedExpressionIdForLawAlloc(first_expr, first_law_id);
        defer self.alloc.free(first_expr_id);
        for (materializations[1..]) |name| {
            const mat_idx = self.materializationIndex(name) orelse return null;
            if (!sameLayoutShape(first_mat, self.config().materializations[mat_idx])) return null;
        }
        const prefix = try tensor_mod.expressionPrefixAlloc(self.alloc, self.name, first_expr_id);
        defer self.alloc.free(prefix);

        var out = std.ArrayListUnmanaged(MaterializedExpressionRowEntry).empty;
        errdefer {
            for (out.items) |*entry| entry.deinit(self.alloc);
            out.deinit(self.alloc);
        }
        var symbols = SymbolCache{};
        defer symbols.deinit(self.alloc);
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const values = try self.alloc.alloc(?[]u8, materializations.len);
            errdefer {
                for (values) |value| if (value) |bytes| self.alloc.free(bytes);
                if (values.len > 0) self.alloc.free(values);
            }
            @memset(values, null);
            var bucket_start: ?[]const u8 = null;
            var axis_text: []const u8 = undefined;
            if (first_mat.time != null) {
                const bucket_component = token.componentAt(entry.key, prefix.len) catch {
                    if (values.len > 0) self.alloc.free(values);
                    continue;
                };
                const axis_component = token.componentAt(entry.key, bucket_component.next) catch {
                    if (values.len > 0) self.alloc.free(values);
                    continue;
                };
                if (axis_component.next != entry.key.len) {
                    if (values.len > 0) self.alloc.free(values);
                    continue;
                }
                bucket_start = bucket_component.payload;
                axis_text = axis_component.payload;
            } else {
                const axis_component = token.componentAt(entry.key, prefix.len) catch {
                    if (values.len > 0) self.alloc.free(values);
                    continue;
                };
                if (axis_component.next != entry.key.len) {
                    if (values.len > 0) self.alloc.free(values);
                    continue;
                }
                axis_text = axis_component.payload;
            }
            const axis_id = symbol.idFromTextAlloc(self.alloc, axis_text) catch {
                if (values.len > 0) self.alloc.free(values);
                continue;
            };
            defer self.alloc.free(axis_id);
            const canonical_group = (symbols.resolve(self, txn, axis_id) catch |err| switch (err) {
                error.InvalidSymbolId => null,
                else => return err,
            }) orelse {
                if (values.len > 0) self.alloc.free(values);
                continue;
            };
            const group_key = if (first_mat.time != null)
                try token.canonicalTupleAlloc(self.alloc, &.{ bucket_start.?, canonical_group })
            else
                try self.alloc.dupe(u8, canonical_group);
            errdefer self.alloc.free(group_key);

            var row = try tensor_mod.rowFromBytesOrLayoutAlloc(self.alloc, entry.value, &.{first_law_id});
            defer row.deinit(self.alloc);
            if (row.slots.len > 0) {
                values[0] = if (row.slots[0].value) |value| try self.alloc.dupe(u8, value) else null;
            }
            var any_value = values[0] != null;
            for (materializations[1..], 1..) |name, i| {
                values[i] = try self.expressionRawValueForMaterializationTxn(txn, name, canonical_group, bucket_start);
                if (values[i] != null) any_value = true;
            }
            if (!any_value) {
                self.alloc.free(group_key);
                if (values.len > 0) self.alloc.free(values);
                continue;
            }
            try out.append(self.alloc, .{
                .group_key = group_key,
                .values = values,
            });
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn countMaterializedExpressionRowsFromLayoutUpTo(self: *Index, txn: anytype, materialization: []const u8, limit: usize) !usize {
        if (limit == 0) return 0;
        const mat_idx = self.materializationIndex(materialization) orelse return 0;
        const mat = self.config().materializations[mat_idx];
        const op = algebra.Op.parse(mat.op) orelse return 0;
        const law_id = self.materializationLawId(mat, op);
        const expr = materializationExpression(mat, law_id);
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const prefix = try tensor_mod.expressionPrefixAlloc(self.alloc, self.name, expr_id);
        defer self.alloc.free(prefix);

        var count: usize = 0;
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            count += 1;
            if (count >= limit) break;
        }
        return count;
    }

    fn countAdaptiveExpressionRowsUpTo(self: *Index, store: *docstore_mod.DocStore, spec: AdaptiveMaterializationSpec, limit: usize) !?usize {
        const expr = adaptiveMaterializedExpression(spec) orelse return null;
        const law_id = law_mod.fromOp(spec.op);
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const prefix = try tensor_mod.expressionPrefixAlloc(self.alloc, self.name, expr_id);
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        return try self.countRowsWithPrefixUpTo(&txn, prefix, limit);
    }

    fn countAdaptiveTensorRowsUpTo(self: *Index, store: *docstore_mod.DocStore, materialization_id: []const u8, limit: usize) !usize {
        const prefix = try self.adaptiveTensorPrefixAlloc(materialization_id);
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        return try self.countRowsWithPrefixUpTo(&txn, prefix, limit);
    }

    fn countRowsWithPrefixUpTo(_: *Index, txn: anytype, prefix: []const u8, limit: usize) !usize {
        if (limit == 0) return 0;
        var count: usize = 0;
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            count += 1;
            if (count >= limit) break;
        }
        return count;
    }

    fn countRowsWithPrefixTxn(_: *Index, txn: anytype, prefix: []const u8) !usize {
        var count: usize = 0;
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            count += 1;
        }
        return count;
    }

    fn scanAdaptiveTensorEntries(self: *Index, store: *docstore_mod.DocStore, materialization_id: []const u8) ![]FoldEntry {
        const prefix = try self.adaptiveTensorPrefixAlloc(materialization_id);
        defer self.alloc.free(prefix);
        var out = std.ArrayListUnmanaged(FoldEntry).empty;
        errdefer {
            for (out.items) |*entry| entry.deinit(self.alloc);
            out.deinit(self.alloc);
        }

        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            var row = tensor_mod.decodeRowAlloc(self.alloc, entry.value) catch continue;
            defer row.deinit(self.alloc);
            if (row.slots.len == 0 or row.slots[0].value == null) continue;

            const first_component = token.componentAt(entry.key, prefix.len) catch continue;
            var group_key: []u8 = undefined;
            if (first_component.next == entry.key.len) {
                const axis_id = symbol.idFromTextAlloc(self.alloc, first_component.payload) catch continue;
                defer self.alloc.free(axis_id);
                group_key = (try self.resolveSymbolAlloc(&txn, axis_id)) orelse continue;
            } else {
                const axis_component = token.componentAt(entry.key, first_component.next) catch continue;
                if (axis_component.next != entry.key.len) continue;
                const axis_id = symbol.idFromTextAlloc(self.alloc, axis_component.payload) catch continue;
                defer self.alloc.free(axis_id);
                const canonical_group = (try self.resolveSymbolAlloc(&txn, axis_id)) orelse continue;
                defer self.alloc.free(canonical_group);
                group_key = try token.canonicalTupleAlloc(self.alloc, &.{ first_component.payload, canonical_group });
            }
            errdefer self.alloc.free(group_key);
            try out.append(self.alloc, .{
                .group_key = group_key,
                .value = try self.alloc.dupe(u8, row.slots[0].value.?),
            });
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn scanAdaptiveEntriesFromExpression(self: *Index, store: *docstore_mod.DocStore, spec: AdaptiveMaterializationSpec) !?[]FoldEntry {
        const expr = adaptiveMaterializedExpression(spec) orelse return null;
        const law_id = law_mod.fromOp(spec.op);
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const prefix = try tensor_mod.expressionPrefixAlloc(self.alloc, self.name, expr_id);
        defer self.alloc.free(prefix);
        var out = std.ArrayListUnmanaged(FoldEntry).empty;
        errdefer {
            for (out.items) |*entry| entry.deinit(self.alloc);
            out.deinit(self.alloc);
        }

        var txn = try store.beginReadTxn();
        defer txn.abort();
        var symbols = SymbolCache{};
        defer symbols.deinit(self.alloc);
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            var row = try tensor_mod.rowFromBytesOrLayoutAlloc(self.alloc, entry.value, &.{law_id});
            defer row.deinit(self.alloc);
            if (row.slots.len == 0 or row.slots[0].value == null) continue;

            var group_key: []u8 = undefined;
            if (spec.time != null) {
                const bucket_component = token.componentAt(entry.key, prefix.len) catch continue;
                const axis_component = token.componentAt(entry.key, bucket_component.next) catch continue;
                if (axis_component.next != entry.key.len) continue;
                const axis_id = symbol.idFromTextAlloc(self.alloc, axis_component.payload) catch continue;
                defer self.alloc.free(axis_id);
                const canonical_group = (symbols.resolve(self, &txn, axis_id) catch |err| switch (err) {
                    error.InvalidSymbolId => null,
                    else => return err,
                }) orelse continue;
                group_key = try token.canonicalTupleAlloc(self.alloc, &.{ bucket_component.payload, canonical_group });
            } else {
                const axis_component = token.componentAt(entry.key, prefix.len) catch continue;
                if (axis_component.next != entry.key.len) continue;
                const axis_id = symbol.idFromTextAlloc(self.alloc, axis_component.payload) catch continue;
                defer self.alloc.free(axis_id);
                const canonical_group = (symbols.resolve(self, &txn, axis_id) catch |err| switch (err) {
                    error.InvalidSymbolId => null,
                    else => return err,
                }) orelse continue;
                group_key = try self.alloc.dupe(u8, canonical_group);
            }
            errdefer self.alloc.free(group_key);
            try out.append(self.alloc, .{
                .group_key = group_key,
                .value = try self.alloc.dupe(u8, row.slots[0].value.?),
            });
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn loadAdaptiveProgressForRecommendation(
        self: *Index,
        txn: anytype,
        recommendation: []const u8,
    ) !?PersistedAdaptiveProgress {
        const key = try adaptive_mod.progressKeyAlloc(self.alloc, self.name, recommendation);
        defer self.alloc.free(key);
        const payload = txn.get(key) catch |err| switch (err) {
            error.NotFound => return null,
            else => return err,
        };
        return try self.decodePersistedAdaptiveProgress(payload);
    }

    fn persistedMaterializationStateReady(
        self: *Index,
        txn: anytype,
        recommendation: []const u8,
    ) !bool {
        const key = try adaptive_mod.materializationStateKeyAlloc(self.alloc, self.name, recommendation);
        defer self.alloc.free(key);
        const payload = txn.get(key) catch |err| switch (err) {
            error.NotFound => return false,
            else => return err,
        };
        var state = self.decodePersistedMaterializationState(payload) catch return false;
        defer state.deinit(self.alloc);
        return state.lifecycle == .ready;
    }

    fn adaptiveProgressMatchesCurrentConfig(self: *const Index, progress: PersistedAdaptiveProgress) bool {
        const cfg = self.config();
        return progress.schema_version == cfg.schema_version and std.mem.eql(u8, progress.capability_fingerprint, cfg.capability_fingerprint);
    }

    pub fn config(self: *const Index) Config {
        return self.parsed.value;
    }

    pub fn hasErrors(self: *const Index) bool {
        return self.parse_error_count > 0;
    }

    pub fn status(self: *const Index) Status {
        return .{
            .parse_error_count = self.parse_error_count,
            .last_error_doc_key = self.last_error_doc_key,
            .last_error_reason = self.last_error_reason,
            .join_facts_scanned = self.join_facts_scanned,
            .join_facts_matched = self.join_facts_matched,
            .join_facts_pruned = self.join_facts_pruned,
            .accumulator_flush_count = self.accumulator_flush_count,
            .symbol_cache_hits = self.symbol_cache_hits,
            .symbol_cache_misses = self.symbol_cache_misses,
            .minmax_cache_hits = self.minmax_cache_hits,
            .minmax_cache_misses = self.minmax_cache_misses,
            .minmax_support_scans = self.minmax_support_scans,
            .planner_algebraic_selected = self.planner_algebraic_selected,
            .planner_fallback_count = self.planner_fallback_count,
            .planner_last_decision = if (self.planner_last_decision) |decision| decision.label() else null,
            .planner_last_fallback_reason = self.planner_last_fallback_reason,
            .planner_last_estimated_scan_rows = self.planner_last_estimated_scan_rows,
            .planner_last_estimated_result_buckets = self.planner_last_estimated_result_buckets,
            .planner_lifecycle_ready = self.plannerLifecycleReady(),
            .planner_lifecycle_blocking_reason = self.plannerLifecycleBlockingReason(),
            .observed_query_shape_count = self.observed_query_shape_count,
            .recommendation_count = self.recommendation_count,
            .last_observed_query_shape = self.last_observed_query_shape,
            .last_recommended_materialization = self.last_recommended_materialization,
            .doc_fact_write_count = self.doc_fact_write_count,
            .doc_fact_delete_count = self.doc_fact_delete_count,
            .doc_join_fact_ref_write_count = self.doc_join_fact_ref_write_count,
            .doc_join_fact_ref_delete_count = self.doc_join_fact_ref_delete_count,
            .dictionary_registry_claimed_count = self.dictionary_registry_claimed_count,
            .dictionary_registry_already_owned_count = self.dictionary_registry_already_owned_count,
            .dictionary_registry_owned_by_other_count = self.dictionary_registry_owned_by_other_count,
            .dictionary_registry_ready_hit_count = self.dictionary_registry_ready_hit_count,
            .dictionary_registry_ready_miss_count = self.dictionary_registry_ready_miss_count,
            .path_dictionary_fst_rebuild_count = self.path_dictionary_fst_rebuild_count,
            .distributed_partial_validation_proven_count = self.distributed_partial_validation_proven_count,
            .distributed_partial_validation_rejected_count = self.distributed_partial_validation_rejected_count,
            .distributed_partial_rows_exported_count = self.distributed_partial_rows_exported_count,
            .vector_filter_attempt_count = self.vector_filter_attempt_count,
            .vector_filter_resolved_count = self.vector_filter_resolved_count,
            .vector_filter_unsupported_count = self.vector_filter_unsupported_count,
            .vector_filter_fail_closed_count = self.vector_filter_fail_closed_count,
            .vector_filter_include_doc_id_count = self.vector_filter_include_doc_id_count,
            .vector_filter_exclude_doc_id_count = self.vector_filter_exclude_doc_id_count,
            .adaptive_maintenance_plan_build_count = self.adaptive_maintenance_plan_build_count,
            .adaptive_maintenance_cached_spec_count = self.adaptive_maintenance_cached_spec_count,
            .adaptive_maintenance_disabled_count = self.adaptive_maintenance_disabled_count,
        };
    }

    pub fn recordPlannerSelected(self: *Index, estimated_scan_rows: ?usize, estimated_result_buckets: ?usize) void {
        self.planner_algebraic_selected += 1;
        self.planner_last_decision = .selected;
        self.planner_last_estimated_scan_rows = estimated_scan_rows;
        self.planner_last_estimated_result_buckets = estimated_result_buckets;
    }

    pub fn recordPlannerFallback(self: *Index, reason: []const u8, estimated_scan_rows: ?usize, estimated_result_buckets: ?usize) void {
        self.planner_fallback_count += 1;
        self.planner_last_decision = .fallback;
        self.planner_last_estimated_scan_rows = estimated_scan_rows;
        self.planner_last_estimated_result_buckets = estimated_result_buckets;
        if (self.planner_last_fallback_reason) |old| self.alloc.free(old);
        self.planner_last_fallback_reason = self.alloc.dupe(u8, reason) catch null;
    }

    pub fn plannerLifecycleReady(self: *const Index) bool {
        const status_value = self.config().capability_lifecycle_status;
        return status_value.len == 0 or
            std.mem.eql(u8, status_value, "current") or
            std.mem.eql(u8, status_value, "compatible_additive");
    }

    pub fn plannerLifecycleBlockingReason(self: *const Index) ?[]const u8 {
        if (self.plannerLifecycleReady()) return null;
        return "capability_lifecycle_not_ready";
    }

    pub fn recordVectorFilterAttempt(self: *Index) void {
        self.vector_filter_attempt_count += 1;
    }

    pub fn recordVectorFilterResolved(self: *Index, include_count: usize, exclude_count: usize) void {
        self.vector_filter_resolved_count += 1;
        self.vector_filter_include_doc_id_count += @intCast(include_count);
        self.vector_filter_exclude_doc_id_count += @intCast(exclude_count);
    }

    pub fn recordVectorFilterUnsupported(self: *Index, fail_closed: bool) void {
        self.vector_filter_unsupported_count += 1;
        if (fail_closed) self.vector_filter_fail_closed_count += 1;
    }

    pub fn recordObservedQueryShape(self: *Index, query: ir.Query, reason: []const u8) void {
        const shape = adaptive_mod.shapeKeyAlloc(self.alloc, query) catch return;
        errdefer self.alloc.free(shape);
        if (self.last_observed_query_shape) |old| self.alloc.free(old);
        self.last_observed_query_shape = self.alloc.dupe(u8, shape) catch null;
        const gop = self.observed_query_shapes.getOrPut(self.alloc, shape) catch {
            self.alloc.free(shape);
            return;
        };
        if (gop.found_existing) {
            self.alloc.free(shape);
            gop.value_ptr.count += 1;
            self.alloc.free(gop.value_ptr.last_reason);
            gop.value_ptr.last_reason = self.alloc.dupe(u8, reason) catch return;
        } else {
            gop.key_ptr.* = shape;
            gop.value_ptr.* = .{
                .count = 1,
                .last_reason = self.alloc.dupe(u8, reason) catch {
                    _ = self.observed_query_shapes.remove(shape);
                    self.alloc.free(shape);
                    return;
                },
            };
        }
        self.observed_query_shape_count += 1;
        if (adaptive_mod.recommendationAlloc(self.alloc, query)) |recommendation| {
            self.recommendation_count += 1;
            if (self.last_recommended_materialization) |old| self.alloc.free(old);
            self.last_recommended_materialization = recommendation;
        } else |_| {}
    }

    pub fn recordObservedQueryShapeWithStore(self: *Index, store: *docstore_mod.DocStore, query: ir.Query, reason: []const u8) void {
        self.recordObservedQueryShape(query, reason);
        self.persistObservedQueryShape(store, query, reason) catch {};
    }

    pub fn loadPersistedObservations(self: *Index, store: *docstore_mod.DocStore) !void {
        self.clearObservedQueryState();
        const prefix = try adaptiveObservationPrefixAlloc(self.alloc, self.name);
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            var decoded = self.decodePersistedObservationFull(entry.value) catch continue;
            defer decoded.deinit(self.alloc);
            try self.loadObservedQueryShape(decoded);
        }
    }

    pub fn scanPersistedQueryObservations(self: *Index, store: *docstore_mod.DocStore) ![]PersistedQueryObservation {
        const prefix = try adaptiveObservationPrefixAlloc(self.alloc, self.name);
        defer self.alloc.free(prefix);
        var out = std.ArrayListUnmanaged(PersistedQueryObservation).empty;
        errdefer {
            for (out.items) |*observation| observation.deinit(self.alloc);
            out.deinit(self.alloc);
        }
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            var decoded = self.decodePersistedObservationFull(entry.value) catch continue;
            errdefer decoded.deinit(self.alloc);
            try out.append(self.alloc, decoded);
        }
        return try out.toOwnedSlice(self.alloc);
    }

