    fn shouldMaintainReadyAdaptiveMaterializations(self: *const Index) bool {
        return self.config().adaptive.lazy_materialization;
    }

    fn shouldMaintainPathProfiles(self: *const Index) bool {
        return self.config().adaptive.observe;
    }

    pub fn evaluateAdaptiveCandidates(self: *Index, store: *docstore_mod.DocStore, target_sequence: u64) !u64 {
        const policy = self.config().adaptive.policy();
        if (!policy.observe) return 0;

        var changed = try self.markMismatchedAdaptiveProgressRebuildRequired(store);

        const observations = try self.scanPersistedQueryObservations(store);
        defer {
            for (observations) |*observation| observation.deinit(self.alloc);
            if (observations.len > 0) self.alloc.free(observations);
        }
        const states = try self.scanPersistedMaterializationStates(store);
        defer {
            for (states) |*state| state.deinit(self.alloc);
            if (states.len > 0) self.alloc.free(states);
        }
        const prior_candidates = try self.scanPersistedAdaptiveCandidates(store);
        defer {
            for (prior_candidates) |*candidate| candidate.deinit(self.alloc);
            if (prior_candidates.len > 0) self.alloc.free(prior_candidates);
        }

        var active_materializations: u64 = 0;
        for (states) |state| {
            if (state.lifecycle == .backfilling or state.lifecycle == .ready) active_materializations += 1;
        }

        for (observations) |observation| {
            const recommendation = observation.recommendation orelse continue;
            const materialization_id = try adaptive_mod.materializationIdAlloc(self.alloc, recommendation);
            defer self.alloc.free(materialization_id);
            const current_state = findMaterializationState(states, recommendation) orelse continue;
            const prior_candidate = findAdaptiveCandidate(prior_candidates, recommendation);
            var lifecycle = current_state.lifecycle;
            var decision: []const u8 = "observed";
            var idle_miss_count: u64 = if (prior_candidate) |candidate| candidate.idle_miss_count else 0;
            const unchanged_observations = if (prior_candidate) |candidate| candidate.observation_count == observation.count else false;
            if (unchanged_observations and lifecycle != .backfilling) {
                idle_miss_count += 1;
            } else if (!unchanged_observations) {
                idle_miss_count = 0;
            }

            var effective_observation_count = observation.count;
            if (shouldDecayObservation(policy, idle_miss_count, lifecycle)) {
                effective_observation_count = decayObservationCount(policy, observation.count);
                try self.persistObservationCount(store, observation, effective_observation_count, lifecycle);
                changed += 1;
            }

            var spec = try self.adaptiveSpecFromRecommendationAlloc(materialization_id, recommendation);
            defer spec.deinit(self.alloc);
            const cost = try self.adaptiveCostInputs(store, spec, materialization_id);
            const estimated_scan_rows_saved = saturatedMul(effective_observation_count, @max(cost.doc_rows, @as(u64, 1)));
            const estimated_write_cost = adaptiveWriteCost(cost);
            const score: i128 = @as(i128, @intCast(estimated_scan_rows_saved)) - @as(i128, @intCast(estimated_write_cost));
            var started_backfill = false;

            if (lifecycle == .recommended) {
                if (!policy.lazy_materialization) {
                    decision = "lazy_materialization_disabled";
                } else if (effective_observation_count < policy.min_observations) {
                    decision = "below_min_observations";
                } else if (estimated_scan_rows_saved < policy.min_estimated_scan_rows_saved) {
                    decision = "below_scan_savings_threshold";
                } else if (active_materializations >= policy.max_auto_materializations_per_index) {
                    decision = "auto_materialization_budget_exhausted";
                } else {
                    try self.setPersistedMaterializationStateLifecycle(store, recommendation, .backfilling);
                    lifecycle = .backfilling;
                    active_materializations += 1;
                    changed += 1;
                    decision = "auto_backfill_started";
                    started_backfill = true;
                }
            } else if (lifecycle == .ready) {
                if (!policy.dematerialization) {
                    decision = "dematerialization_disabled";
                    idle_miss_count = 0;
                } else if (unchanged_observations) {
                    if (score <= 0) {
                        try self.setPersistedMaterializationStateLifecycle(store, recommendation, .dematerialize_recommended);
                        lifecycle = .dematerialize_recommended;
                        changed += 1;
                        decision = "auto_dematerialize_cost_exceeds_savings";
                    } else if (idle_miss_count >= policy.dematerialize_after_observation_misses) {
                        try self.setPersistedMaterializationStateLifecycle(store, recommendation, .dematerialize_recommended);
                        lifecycle = .dematerialize_recommended;
                        changed += 1;
                        decision = "auto_dematerialize_idle";
                    } else {
                        decision = "idle_window_recorded";
                    }
                } else {
                    idle_miss_count = 0;
                    decision = "ready_observed";
                }
            } else {
                decision = @tagName(lifecycle);
            }

            try self.persistAdaptiveCandidate(
                store,
                recommendation,
                materialization_id,
                lifecycle,
                effective_observation_count,
                estimated_scan_rows_saved,
                estimated_write_cost,
                cost,
                score,
                decision,
                idle_miss_count,
            );
            if (started_backfill) {
                try self.persistAdaptiveProgress(store, recommendation, materialization_id, lifecycle, target_sequence, 0, 0, 0, "");
            }
        }
        try self.loadPersistedObservations(store);
        return changed;
    }

    pub fn runAdaptiveWork(self: *Index, store: *docstore_mod.DocStore, target_sequence: u64) !u64 {
        const policy = self.config().adaptive.policy();
        if (!policy.observe or !policy.lazy_materialization) return 0;
        if (policy.max_backfill_rows_per_tick == 0) return 0;

        var changed = try self.markMismatchedAdaptiveProgressRebuildRequired(store);

        const progress_rows = try self.scanPersistedAdaptiveProgress(store);
        defer {
            for (progress_rows) |*progress| progress.deinit(self.alloc);
            if (progress_rows.len > 0) self.alloc.free(progress_rows);
        }
        const candidates = try self.scanPersistedAdaptiveCandidates(store);
        defer {
            for (candidates) |*candidate| candidate.deinit(self.alloc);
            if (candidates.len > 0) self.alloc.free(candidates);
        }

        for (progress_rows) |progress| {
            if (progress.lifecycle != .backfilling) continue;
            var spec = try self.adaptiveSpecFromRecommendationAlloc(progress.materialization_id, progress.recommendation);
            defer spec.deinit(self.alloc);

            var tick = try self.runAdaptiveBackfillTick(store, progress, spec, policy.max_backfill_rows_per_tick);
            defer tick.deinit(self.alloc);
            changed += tick.rows_processed;
            if (!tick.reached_end) continue;
            if (target_sequence < progress.target_sequence) continue;

            try self.setPersistedMaterializationStateLifecycle(store, progress.recommendation, .ready);
            try self.persistAdaptiveProgress(
                store,
                progress.recommendation,
                progress.materialization_id,
                .ready,
                progress.target_sequence,
                target_sequence,
                tick.total_rows_processed,
                tick.total_rows_processed,
                "",
            );
            if (findAdaptiveCandidate(candidates, progress.recommendation)) |candidate| {
                try self.persistAdaptiveCandidate(
                    store,
                    progress.recommendation,
                    progress.materialization_id,
                    .ready,
                    candidate.observation_count,
                    candidate.estimated_scan_rows_saved,
                    candidate.estimated_write_cost,
                    .{
                        .doc_rows = candidate.estimated_doc_rows,
                        .bucket_cardinality = candidate.estimated_bucket_cardinality,
                        .tensor_rows = candidate.estimated_tensor_rows,
                        .storage_bytes = candidate.estimated_storage_bytes,
                        .write_amplification = candidate.estimated_write_amplification,
                    },
                    candidate.score,
                    "backfill_ready",
                    0,
                );
            }
            if (try self.refreshReadyAdaptiveExpressionCache(store, progress.recommendation)) |rows| {
                changed += rows;
            }
            changed += 1;
        }
        for (candidates) |candidate| {
            if (candidate.lifecycle != .dematerialize_recommended) continue;
            try self.deleteAdaptiveMaterialization(store, candidate.recommendation, candidate.materialization_id);
            try self.setPersistedMaterializationStateLifecycle(store, candidate.recommendation, .stale);
            changed += 1;
        }
        return changed;
    }

    fn setPersistedMaterializationStateLifecycle(
        self: *Index,
        store: *docstore_mod.DocStore,
        recommendation: []const u8,
        lifecycle: adaptive_mod.Lifecycle,
    ) !void {
        const state_key = try adaptive_mod.materializationStateKeyAlloc(self.alloc, self.name, recommendation);
        defer self.alloc.free(state_key);

        var existing_state: PersistedMaterializationState = undefined;
        var updates = std.ArrayListUnmanaged(PersistedObservationUpdate).empty;
        errdefer {
            for (updates.items) |*update| update.deinit(self.alloc);
            updates.deinit(self.alloc);
        }

        {
            var txn = try store.beginReadTxn();
            defer txn.abort();

            const state_payload = try txn.get(state_key);
            existing_state = try self.decodePersistedMaterializationState(state_payload);
            errdefer existing_state.deinit(self.alloc);
            if (!adaptive_mod.validLifecycleTransition(existing_state.lifecycle, lifecycle)) return error.InvalidAlgebraicLifecycleTransition;

            const prefix = try adaptiveObservationPrefixAlloc(self.alloc, self.name);
            defer self.alloc.free(prefix);
            var cursor = try txn.openCursor();
            defer cursor.close();
            var entry_opt = try cursor.seekAtOrAfter(prefix);
            while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
                if (!std.mem.startsWith(u8, entry.key, prefix)) break;
                var decoded = self.decodePersistedObservationFull(entry.value) catch continue;
                var decoded_owned = true;
                defer if (decoded_owned) decoded.deinit(self.alloc);
                const matches = if (decoded.recommendation) |value| std.mem.eql(u8, value, recommendation) else false;
                if (!matches) continue;

                const key = try self.alloc.dupe(u8, entry.key);
                errdefer self.alloc.free(key);
                try updates.append(self.alloc, .{
                    .key = key,
                    .observation = decoded,
                });
                decoded_owned = false;
            }
        }
        defer existing_state.deinit(self.alloc);
        defer {
            for (updates.items) |*update| update.deinit(self.alloc);
            updates.deinit(self.alloc);
        }

        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        const state = try self.encodePersistedMaterializationStateAlloc(recommendation, lifecycle, existing_state.observation_count);
        defer self.alloc.free(state);
        try txn.put(state_key, state);
        for (updates.items) |update| {
            const observation_recommendation = update.observation.recommendation orelse continue;
            const encoded = try self.encodePersistedObservationAlloc(
                update.observation.shape,
                update.observation.count,
                update.observation.reason,
                observation_recommendation,
                lifecycle,
            );
            defer self.alloc.free(encoded);
            try txn.put(update.key, encoded);
        }
        try txn.commit();
        self.invalidateAdaptiveReadySpecCache();
    }

    fn loadObservedQueryShape(self: *Index, observation: PersistedQueryObservation) !void {
        const shape = try self.alloc.dupe(u8, observation.shape);
        errdefer self.alloc.free(shape);
        const reason = try self.alloc.dupe(u8, observation.reason);
        errdefer self.alloc.free(reason);
        const gop = try self.observed_query_shapes.getOrPut(self.alloc, shape);
        if (gop.found_existing) {
            self.alloc.free(shape);
            gop.value_ptr.count = observation.count;
            self.alloc.free(gop.value_ptr.last_reason);
            gop.value_ptr.last_reason = reason;
        } else {
            gop.key_ptr.* = shape;
            gop.value_ptr.* = .{
                .count = observation.count,
                .last_reason = reason,
            };
        }
        self.observed_query_shape_count += observation.count;
        if (self.last_observed_query_shape) |old| self.alloc.free(old);
        self.last_observed_query_shape = try self.alloc.dupe(u8, observation.shape);
        if (observation.recommendation) |recommendation| {
            self.recommendation_count += observation.count;
            if (self.last_recommended_materialization) |old| self.alloc.free(old);
            self.last_recommended_materialization = try self.alloc.dupe(u8, recommendation);
        }
    }

    fn persistObservedQueryShape(self: *Index, store: *docstore_mod.DocStore, query: ir.Query, reason: []const u8) !void {
        const shape = try adaptive_mod.shapeKeyAlloc(self.alloc, query);
        defer self.alloc.free(shape);
        const recommendation = try adaptive_mod.recommendationAlloc(self.alloc, query);
        defer self.alloc.free(recommendation);
        const key = try adaptive_mod.observationKeyAlloc(self.alloc, self.name, shape);
        defer self.alloc.free(key);

        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        const existing = txn.get(key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        const prior = if (existing) |payload|
            self.decodePersistedObservation(payload) catch PersistedObservationMeta{}
        else
            PersistedObservationMeta{};
        const next_count = prior.count + 1;
        const lifecycle = adaptive_mod.nextLifecycle(self.config().adaptive.policy(), next_count, prior.lifecycle);
        const encoded = try self.encodePersistedObservationAlloc(shape, next_count, reason, recommendation, lifecycle);
        defer self.alloc.free(encoded);
        try txn.put(key, encoded);
        if (lifecycle == .recommended or lifecycle == .backfilling or lifecycle == .ready) {
            const state_key = try adaptive_mod.materializationStateKeyAlloc(self.alloc, self.name, recommendation);
            defer self.alloc.free(state_key);
            const state = try self.encodePersistedMaterializationStateAlloc(recommendation, lifecycle, next_count);
            defer self.alloc.free(state);
            try txn.put(state_key, state);
        }
        try txn.commit();
        self.invalidateAdaptiveReadySpecCache();
    }

    fn persistObservationCount(
        self: *Index,
        store: *docstore_mod.DocStore,
        observation: PersistedQueryObservation,
        count: u64,
        lifecycle: adaptive_mod.Lifecycle,
    ) !void {
        const recommendation = observation.recommendation orelse return;
        const key = try adaptive_mod.observationKeyAlloc(self.alloc, self.name, observation.shape);
        defer self.alloc.free(key);
        const encoded = try self.encodePersistedObservationAlloc(observation.shape, count, observation.reason, recommendation, lifecycle);
        defer self.alloc.free(encoded);

        const state_key = try adaptive_mod.materializationStateKeyAlloc(self.alloc, self.name, recommendation);
        defer self.alloc.free(state_key);
        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        try txn.put(key, encoded);
        if (txn.get(state_key)) |existing| {
            var state = self.decodePersistedMaterializationState(existing) catch null;
            if (state) |*value| {
                defer value.deinit(self.alloc);
                const state_encoded = try self.encodePersistedMaterializationStateAlloc(recommendation, value.lifecycle, count);
                defer self.alloc.free(state_encoded);
                try txn.put(state_key, state_encoded);
            }
        } else |err| switch (err) {
            error.NotFound => {},
            else => return err,
        }
        try txn.commit();
    }

    fn adaptiveCostInputs(
        self: *Index,
        store: *docstore_mod.DocStore,
        spec: AdaptiveMaterializationSpec,
        materialization_id: []const u8,
    ) !AdaptiveCostInputs {
        const doc_rows = if (spec.path_promotion_path) |path| blk: {
            if (spec.path_promotion_kind) |kind| {
                break :blk try self.countRowsWithPrefix(store, try self.pathLookupKindPrefixAlloc(path, kind));
            }
            break :blk try self.countRowsWithPrefix(store, try self.pathLookupPathPrefixAlloc(path));
        } else if (spec.join) |join_name| blk: {
            const join_cfg = self.joinConfig(join_name) orelse return error.InvalidAlgebraicAdaptiveRecommendation;
            const left_rows = try self.countRowsWithPrefix(store, try self.joinSideFactPrefixAlloc(join_cfg, .left));
            const right_rows = try self.countRowsWithPrefix(store, try self.joinSideFactPrefixAlloc(join_cfg, .right));
            break :blk saturatedAdd(left_rows, right_rows);
        } else try self.countRowsWithPrefix(store, try self.docFactPrefixAlloc());

        const tensor_cost = try self.countRowsAndBytesWithPrefix(store, try self.adaptiveTensorPrefixAlloc(materialization_id));
        var tensor_rows = tensor_cost.rows;
        var storage_bytes = tensor_cost.bytes;

        if (adaptiveMaterializedExpression(spec)) |expr| {
            const law_id = law_mod.fromOp(spec.op);
            const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
            defer self.alloc.free(expr_id);
            const expression_cost = try self.countRowsAndBytesWithPrefix(store, try tensor_mod.expressionPrefixAlloc(self.alloc, self.name, expr_id));
            tensor_rows = saturatedAdd(tensor_rows, expression_cost.rows);
            storage_bytes = saturatedAdd(storage_bytes, expression_cost.bytes);
        }

        if (spec.path_promotion_path) |path| {
            const promoted_lookup_cost = try self.countRowsAndBytesWithPrefix(store, try self.promotedPathLookupMaterializationPrefixAlloc(materialization_id));
            tensor_rows = saturatedAdd(tensor_rows, promoted_lookup_cost.rows);
            storage_bytes = saturatedAdd(storage_bytes, promoted_lookup_cost.bytes);

            if (spec.path_promotion_kind) |kind| {
                const identity = lexical_mod.DictionaryIdentity.canonicalScalar(self.name, path, kind, "json-scalar-v1", "kind-qualified");
                if (try self.dictionaryRegistryOwnedByMaterialization(store, identity, materialization_id)) {
                    const lexicon_cost = try self.countRowsAndBytesWithPrefix(store, try self.pathDictionaryLexiconPrefixAlloc(identity));
                    const postings_cost = try self.countRowsAndBytesWithPrefix(store, try self.pathDictionaryPostingsDictionaryPrefixAlloc(identity));
                    const ordinal_postings_cost = try self.countRowsAndBytesWithPrefix(store, try self.pathDictionaryOrdinalPostingsDictionaryPrefixAlloc(identity));
                    tensor_rows = saturatedAdd(tensor_rows, saturatedAdd(lexicon_cost.rows, saturatedAdd(postings_cost.rows, ordinal_postings_cost.rows)));
                    storage_bytes = saturatedAdd(storage_bytes, saturatedAdd(lexicon_cost.bytes, saturatedAdd(postings_cost.bytes, ordinal_postings_cost.bytes)));

                    const fst_cost = try self.countRowsAndBytesWithPrefix(store, try self.pathDictionaryFstKeyAlloc(identity));
                    tensor_rows = saturatedAdd(tensor_rows, fst_cost.rows);
                    storage_bytes = saturatedAdd(storage_bytes, fst_cost.bytes);
                }
            }
        }

        const bucket_cardinality = if (tensor_rows > 0)
            tensor_rows
        else if (spec.group_by.len == 0 and spec.time == null)
            1
        else
            doc_rows;
        const write_amplification = if (spec.path_promotion_path != null)
            @as(u64, 1)
        else
            1 + @as(u64, @intCast(spec.group_by.len)) + @as(u64, @intFromBool(spec.measure != null)) + @as(u64, @intFromBool(spec.time != null)) + @as(u64, @intFromBool(spec.join != null));
        return .{
            .doc_rows = doc_rows,
            .bucket_cardinality = bucket_cardinality,
            .tensor_rows = tensor_rows,
            .storage_bytes = storage_bytes,
            .write_amplification = write_amplification,
        };
    }

    fn dictionaryRegistryOwnedByMaterialization(
        self: *Index,
        store: *docstore_mod.DocStore,
        identity: lexical_mod.DictionaryIdentity,
        materialization_id: []const u8,
    ) !bool {
        const registry_key = try identity.registryKeyAlloc(self.alloc);
        defer self.alloc.free(registry_key);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        const payload = txn.get(registry_key) catch |err| switch (err) {
            error.NotFound => return false,
            else => return err,
        };
        var entry = lexical_mod.RegistryEntry.decodeAlloc(self.alloc, payload) catch return false;
        defer entry.deinit(self.alloc);
        return std.mem.eql(u8, entry.owner, materialization_id);
    }

    fn countRowsAndBytesWithPrefix(self: *Index, store: *docstore_mod.DocStore, owned_prefix: []u8) !PrefixCost {
        defer self.alloc.free(owned_prefix);
        var cost: PrefixCost = .{};
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(owned_prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, owned_prefix)) break;
            cost.rows += 1;
            cost.bytes = saturatedAdd(cost.bytes, @intCast(entry.key.len + entry.value.len));
        }
        return cost;
    }

    fn countRowsWithPrefix(self: *Index, store: *docstore_mod.DocStore, owned_prefix: []u8) !u64 {
        return (try self.countRowsAndBytesWithPrefix(store, owned_prefix)).rows;
    }

    fn encodePersistedObservationAlloc(
        self: *Index,
        shape: []const u8,
        count: u64,
        reason: []const u8,
        recommendation: []const u8,
        lifecycle: adaptive_mod.Lifecycle,
    ) ![]u8 {
        const count_text = try std.fmt.allocPrint(self.alloc, "{d}", .{count});
        defer self.alloc.free(count_text);
        return try token.canonicalTupleAlloc(self.alloc, &.{ "observation:v1", shape, count_text, reason, recommendation, @tagName(lifecycle) });
    }

    fn encodePersistedMaterializationStateAlloc(
        self: *Index,
        recommendation: []const u8,
        lifecycle: adaptive_mod.Lifecycle,
        observation_count: u64,
    ) ![]u8 {
        const count_text = try std.fmt.allocPrint(self.alloc, "{d}", .{observation_count});
        defer self.alloc.free(count_text);
        return try token.canonicalTupleAlloc(self.alloc, &.{ "materialization-state:v1", recommendation, @tagName(lifecycle), count_text });
    }

    fn persistAdaptiveCandidate(
        self: *Index,
        store: *docstore_mod.DocStore,
        recommendation: []const u8,
        materialization_id: []const u8,
        lifecycle: adaptive_mod.Lifecycle,
        observation_count: u64,
        estimated_scan_rows_saved: u64,
        estimated_write_cost: u64,
        cost: AdaptiveCostInputs,
        score: i128,
        decision: []const u8,
        idle_miss_count: u64,
    ) !void {
        const key = try adaptive_mod.candidateKeyAlloc(self.alloc, self.name, recommendation);
        defer self.alloc.free(key);
        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        var prior_candidate: ?PersistedAdaptiveCandidate = null;
        const prior_payload = txn.get(key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        if (prior_payload) |payload| prior_candidate = self.decodePersistedAdaptiveCandidate(payload) catch null;
        defer if (prior_candidate) |*candidate| candidate.deinit(self.alloc);
        const generation = if (prior_candidate) |candidate| candidate.generation + 1 else 1;
        const previous_decision = if (prior_candidate) |candidate| candidate.decision else "";
        const previous_score = if (prior_candidate) |candidate| candidate.score else 0;
        const payload = try self.encodePersistedAdaptiveCandidateAlloc(recommendation, materialization_id, lifecycle, observation_count, estimated_scan_rows_saved, estimated_write_cost, cost, score, decision, idle_miss_count, generation);
        defer self.alloc.free(payload);
        const history_key = try adaptiveDecisionHistoryKeyAlloc(self.alloc, self.name, recommendation, generation);
        defer self.alloc.free(history_key);
        const history_payload = try self.encodePersistedAdaptiveDecisionAlloc(recommendation, materialization_id, lifecycle, previous_decision, decision, observation_count, estimated_scan_rows_saved, estimated_write_cost, score, score - previous_score, idle_miss_count, generation);
        defer self.alloc.free(history_payload);
        try txn.put(key, payload);
        try txn.put(history_key, history_payload);
        try txn.commit();
    }

    fn persistAdaptiveProgress(
        self: *Index,
        store: *docstore_mod.DocStore,
        recommendation: []const u8,
        materialization_id: []const u8,
        lifecycle: adaptive_mod.Lifecycle,
        target_sequence: u64,
        applied_sequence: u64,
        rows_processed: u64,
        target_rows: u64,
        cursor_key: []const u8,
    ) !void {
        const key = try adaptive_mod.progressKeyAlloc(self.alloc, self.name, recommendation);
        defer self.alloc.free(key);
        const payload = try self.encodePersistedAdaptiveProgressAlloc(recommendation, materialization_id, lifecycle, target_sequence, applied_sequence, rows_processed, target_rows, cursor_key);
        defer self.alloc.free(payload);
        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        try txn.put(key, payload);
        try txn.commit();
        self.invalidateAdaptiveReadySpecCache();
    }

