    fn markAdaptiveMaterializationStaleTxn(
        self: *Index,
        txn: anytype,
        recommendation: []const u8,
        materialization_id: []const u8,
    ) !void {
        const state_key = try adaptive_mod.materializationStateKeyAlloc(self.alloc, self.name, recommendation);
        defer self.alloc.free(state_key);
        const existing_state = txn.get(state_key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        const observation_count: u64 = if (existing_state) |payload| blk: {
            var state = self.decodePersistedMaterializationState(payload) catch break :blk 0;
            defer state.deinit(self.alloc);
            break :blk state.observation_count;
        } else 0;
        const state_payload = try self.encodePersistedMaterializationStateAlloc(recommendation, .stale, observation_count);
        defer self.alloc.free(state_payload);
        try txn.put(state_key, state_payload);

        const progress_key = try adaptive_mod.progressKeyAlloc(self.alloc, self.name, recommendation);
        defer self.alloc.free(progress_key);
        const existing_progress = txn.get(progress_key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        if (existing_progress) |payload| {
            var progress = self.decodePersistedAdaptiveProgress(payload) catch return;
            defer progress.deinit(self.alloc);
            try self.putAdaptiveProgressTxn(
                txn,
                recommendation,
                materialization_id,
                .stale,
                progress.target_sequence,
                progress.applied_sequence,
                progress.rows_processed,
                progress.target_rows,
                progress.cursor_key,
            );
        }
        self.invalidateAdaptiveReadySpecCache();
    }

    fn markMismatchedAdaptiveProgressRebuildRequired(self: *Index, store: *docstore_mod.DocStore) !u64 {
        const progress_rows = try self.scanPersistedAdaptiveProgress(store);
        defer {
            for (progress_rows) |*progress| progress.deinit(self.alloc);
            if (progress_rows.len > 0) self.alloc.free(progress_rows);
        }
        var changed: u64 = 0;
        for (progress_rows) |progress| {
            if (self.adaptiveProgressMatchesCurrentConfig(progress)) continue;
            if (progress.lifecycle == .rebuild_required) continue;
            var txn = try store.beginWriteTxn();
            errdefer txn.abort();
            try self.markAdaptiveMaterializationRebuildRequiredTxn(&txn, progress);
            try txn.commit();
            changed += 1;
        }
        return changed;
    }

    fn markAdaptiveMaterializationRebuildRequiredTxn(
        self: *Index,
        txn: anytype,
        progress: PersistedAdaptiveProgress,
    ) !void {
        const state_key = try adaptive_mod.materializationStateKeyAlloc(self.alloc, self.name, progress.recommendation);
        defer self.alloc.free(state_key);
        const existing_state = txn.get(state_key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        const observation_count: u64 = if (existing_state) |payload| blk: {
            var state = self.decodePersistedMaterializationState(payload) catch break :blk 0;
            defer state.deinit(self.alloc);
            break :blk state.observation_count;
        } else 0;
        const state_payload = try self.encodePersistedMaterializationStateAlloc(progress.recommendation, .rebuild_required, observation_count);
        defer self.alloc.free(state_payload);
        try txn.put(state_key, state_payload);
        try self.putAdaptiveProgressTxn(
            txn,
            progress.recommendation,
            progress.materialization_id,
            .rebuild_required,
            progress.target_sequence,
            progress.applied_sequence,
            progress.rows_processed,
            progress.target_rows,
            progress.cursor_key,
        );
        self.invalidateAdaptiveReadySpecCache();
    }

    fn readyAdaptiveJoinSpecsTxn(self: *Index, txn: anytype, join_name: []const u8) ![]AdaptiveMaterializationSpec {
        if (!self.shouldMaintainReadyAdaptiveMaterializations()) return &.{};
        const progress_rows = try self.scanPersistedAdaptiveProgressTxn(txn);
        defer {
            for (progress_rows) |*progress| progress.deinit(self.alloc);
            if (progress_rows.len > 0) self.alloc.free(progress_rows);
        }
        var out = std.ArrayListUnmanaged(AdaptiveMaterializationSpec).empty;
        errdefer {
            for (out.items) |*spec| spec.deinit(self.alloc);
            out.deinit(self.alloc);
        }
        for (progress_rows) |progress| {
            if (progress.lifecycle != .ready) continue;
            if (!self.adaptiveProgressMatchesCurrentConfig(progress)) continue;
            if (!(try self.persistedMaterializationStateReadyTxn(txn, progress.recommendation))) continue;
            var spec = try self.adaptiveSpecFromRecommendationAlloc(progress.materialization_id, progress.recommendation);
            var spec_owned = true;
            errdefer if (spec_owned) spec.deinit(self.alloc);
            if (spec.join) |value| {
                if (std.mem.eql(u8, value, join_name)) {
                    try out.append(self.alloc, spec);
                    spec_owned = false;
                    continue;
                }
            }
            spec.deinit(self.alloc);
            spec_owned = false;
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn persistedMaterializationStateReadyTxn(self: *Index, txn: anytype, recommendation: []const u8) !bool {
        const key = try adaptive_mod.materializationStateKeyAlloc(self.alloc, self.name, recommendation);
        defer self.alloc.free(key);
        const payload = txn.get(key) catch |err| switch (err) {
            error.NotFound => return false,
            else => return err,
        };
        var state = self.decodePersistedMaterializationState(payload) catch return false;
        defer state.deinit(self.alloc);
        return state.lifecycle == .ready;
    }

