        });
    }

    fn adaptiveSpecFromRecommendationAlloc(
        self: *Index,
        materialization_id: []const u8,
        recommendation: []const u8,
    ) !AdaptiveMaterializationSpec {
        const parts = try token.decodeTupleAlloc(self.alloc, recommendation);
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len == 4 and std.mem.eql(u8, parts[0], "path-recommendation:v1")) {
            const name = try self.alloc.dupe(u8, materialization_id);
            errdefer self.alloc.free(name);
            const recommendation_owned = try self.alloc.dupe(u8, recommendation);
            errdefer self.alloc.free(recommendation_owned);
            const path = try self.alloc.dupe(u8, parts[1]);
            errdefer self.alloc.free(path);
            const reason = try self.alloc.dupe(u8, parts[3]);
            errdefer self.alloc.free(reason);
            return .{
                .name = name,
                .recommendation = recommendation_owned,
                .op = .count,
                .path_promotion_path = path,
                .path_promotion_kind = if (parts[2].len == 0) null else std.meta.stringToEnum(pathfact_mod.Kind, parts[2]) orelse return error.InvalidAlgebraicAdaptiveRecommendation,
                .path_promotion_reason = reason,
            };
        }
        if (parts.len < 4 or !std.mem.eql(u8, parts[0], "recommendation:v1")) return error.InvalidAlgebraicAdaptiveRecommendation;
        const op = algebra.Op.parse(parts[2]) orelse return error.InvalidAlgebraicAdaptiveRecommendation;

        var group_fields = std.ArrayListUnmanaged([]u8).empty;
        errdefer {
            for (group_fields.items) |field| self.alloc.free(field);
            group_fields.deinit(self.alloc);
        }

        var time_field: ?[]u8 = null;
        errdefer if (time_field) |value| self.alloc.free(value);
        var bucket_name: ?[]u8 = null;
        errdefer if (bucket_name) |value| self.alloc.free(value);
        var join_name: ?[]u8 = null;
        errdefer if (join_name) |value| self.alloc.free(value);
        var group_side: ?[]u8 = null;
        errdefer if (group_side) |value| self.alloc.free(value);
        var measure_side: ?[]u8 = null;
        errdefer if (measure_side) |value| self.alloc.free(value);

        var pos: usize = 4;
        while (pos < parts.len) {
            if (std.mem.eql(u8, parts[pos], "group")) {
                if (pos + 1 >= parts.len) return error.InvalidAlgebraicAdaptiveRecommendation;
                try group_fields.append(self.alloc, try self.alloc.dupe(u8, parts[pos + 1]));
                pos += 2;
            } else if (std.mem.eql(u8, parts[pos], "time")) {
                if (pos + 2 >= parts.len) return error.InvalidAlgebraicAdaptiveRecommendation;
                if (time_field) |old| self.alloc.free(old);
                time_field = try self.alloc.dupe(u8, parts[pos + 1]);
                if (bucket_name) |old| self.alloc.free(old);
                bucket_name = if (parts[pos + 2].len == 0) null else try self.alloc.dupe(u8, parts[pos + 2]);
                pos += 3;
            } else if (std.mem.eql(u8, parts[pos], "join")) {
                if (pos + 4 >= parts.len) return error.InvalidAlgebraicAdaptiveRecommendation;
                if (join_name) |old| self.alloc.free(old);
                join_name = try self.alloc.dupe(u8, parts[pos + 1]);
                _ = std.meta.stringToEnum(join_mod.TemporalMode, parts[pos + 2]) orelse return error.InvalidAlgebraicAdaptiveRecommendation;
                if (group_side) |old| self.alloc.free(old);
                group_side = if (parts[pos + 3].len == 0) null else try self.alloc.dupe(u8, parts[pos + 3]);
                if (measure_side) |old| self.alloc.free(old);
                measure_side = if (parts[pos + 4].len == 0) null else try self.alloc.dupe(u8, parts[pos + 4]);
                pos += 5;
            } else {
                return error.InvalidAlgebraicAdaptiveRecommendation;
            }
        }

        const name = try self.alloc.dupe(u8, materialization_id);
        errdefer self.alloc.free(name);
        const recommendation_owned = try self.alloc.dupe(u8, recommendation);
        errdefer self.alloc.free(recommendation_owned);
        const measure = if (parts[3].len == 0) null else try self.alloc.dupe(u8, parts[3]);
        errdefer if (measure) |value| self.alloc.free(value);

        if (join_name != null) {
            if (group_side == null or measure_side == null) return error.InvalidAlgebraicAdaptiveRecommendation;
        } else if (group_side != null or measure_side != null) {
            return error.InvalidAlgebraicAdaptiveRecommendation;
        }

        return .{
            .name = name,
            .recommendation = recommendation_owned,
            .op = op,
            .measure = measure,
            .group_by = try group_fields.toOwnedSlice(self.alloc),
            .time = time_field,
            .bucket = bucket_name,
            .join = join_name,
            .group_side = group_side,
            .measure_side = measure_side,
        };
    }

    fn runAdaptiveBackfillTick(
        self: *Index,
        store: *docstore_mod.DocStore,
        progress: PersistedAdaptiveProgress,
        spec: AdaptiveMaterializationSpec,
        max_rows: u64,
    ) !AdaptiveBackfillTick {
        if (spec.path_promotion_path != null) return try self.runAdaptivePathPromotionBackfillTick(store, progress, spec, max_rows);
        if (spec.join != null) return try self.runAdaptiveJoinBackfillTick(store, progress, spec, max_rows);

        const prefix = try self.docFactPrefixAlloc();
        defer self.alloc.free(prefix);

        const BackfillItem = struct {
            key: []u8,
            payload: []u8,

            fn deinit(item: *@This(), alloc: Allocator) void {
                alloc.free(item.key);
                alloc.free(item.payload);
                item.* = undefined;
            }
        };
        var payloads = std.ArrayListUnmanaged(BackfillItem).empty;
        defer {
            for (payloads.items) |*item| item.deinit(self.alloc);
            payloads.deinit(self.alloc);
        }
        var reached_end = true;
        var next_cursor_key: []u8 = &.{};
        errdefer if (next_cursor_key.len > 0) self.alloc.free(next_cursor_key);

        {
            var read_txn = try store.beginReadTxn();
            defer read_txn.abort();
            var cursor = try read_txn.openCursor();
            defer cursor.close();

            const start_key = if (progress.cursor_key.len > 0) progress.cursor_key else prefix;
            var entry_opt = try cursor.seekAtOrAfter(start_key);
            if (progress.cursor_key.len > 0) {
                if (entry_opt) |entry| {
                    if (std.mem.eql(u8, entry.key, progress.cursor_key)) entry_opt = try cursor.next();
                }
            }
            while (entry_opt) |entry| {
                if (!std.mem.startsWith(u8, entry.key, prefix)) break;
                if (payloads.items.len >= max_rows) {
                    reached_end = false;
                    break;
                }
                try payloads.append(self.alloc, .{
                    .key = try self.alloc.dupe(u8, entry.key),
                    .payload = try self.alloc.dupe(u8, entry.value),
                });
                entry_opt = try cursor.next();
            }
        }

        const processed: u64 = @intCast(payloads.items.len);
        const total_processed = progress.rows_processed + processed;

        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        for (payloads.items) |item| {
            var facts = fact_mod.decodeListAlloc(self.alloc, item.payload) catch |err| switch (err) {
                error.InvalidAlgebraicFact => continue,
                else => return err,
            };
            defer facts.deinit(self.alloc);
            try self.updateAdaptiveTensorFromFacts(&txn, spec, facts.facts, 1);
            if (next_cursor_key.len > 0) self.alloc.free(next_cursor_key);
            next_cursor_key = try self.alloc.dupe(u8, item.key);
        }

        const applied_sequence = if (reached_end) progress.target_sequence else progress.applied_sequence;
        const target_rows = if (reached_end) total_processed else progress.target_rows;
        const cursor_key = if (reached_end) "" else next_cursor_key;
        try self.putAdaptiveProgressTxn(
            &txn,
            progress.recommendation,
            progress.materialization_id,
            .backfilling,
            progress.target_sequence,
            applied_sequence,
            total_processed,
            target_rows,
            cursor_key,
        );
        try txn.commit();
        if (reached_end and next_cursor_key.len > 0) {
            self.alloc.free(next_cursor_key);
            next_cursor_key = &.{};
        }
        return .{
            .rows_processed = processed,
            .total_rows_processed = total_processed,
            .cursor_key = if (reached_end or next_cursor_key.len == 0) &.{} else blk: {
                const owned = next_cursor_key;
                next_cursor_key = &.{};
                break :blk owned;
            },
            .reached_end = reached_end,
        };
    }

    fn runAdaptivePathPromotionBackfillTick(
        self: *Index,
        store: *docstore_mod.DocStore,
        progress: PersistedAdaptiveProgress,
        spec: AdaptiveMaterializationSpec,
        max_rows: u64,
    ) !AdaptiveBackfillTick {
        const path = spec.path_promotion_path orelse return error.InvalidAlgebraicAdaptiveRecommendation;
        const prefix = if (spec.path_promotion_kind) |kind|
            try self.pathLookupKindPrefixAlloc(path, kind)
        else
            try self.pathLookupPathPrefixAlloc(path);
        defer self.alloc.free(prefix);

        const BackfillItem = struct {
            key: []u8,
            kind: []u8,
            value: []u8,
            doc_key: []u8,

            fn deinit(item: *@This(), alloc: Allocator) void {
                alloc.free(item.key);
                alloc.free(item.kind);
                alloc.free(item.value);
                alloc.free(item.doc_key);
                item.* = undefined;
            }
        };
        var items = std.ArrayListUnmanaged(BackfillItem).empty;
        defer {
            for (items.items) |*item| item.deinit(self.alloc);
            items.deinit(self.alloc);
        }
        var reached_end = true;
        var next_cursor_key: []u8 = &.{};
        errdefer if (next_cursor_key.len > 0) self.alloc.free(next_cursor_key);

        {
            var read_txn = try store.beginReadTxn();
            defer read_txn.abort();
            var cursor = try read_txn.openCursor();
            defer cursor.close();

            const start_key = if (progress.cursor_key.len > 0) progress.cursor_key else prefix;
            var entry_opt = try cursor.seekAtOrAfter(start_key);
            if (progress.cursor_key.len > 0) {
                if (entry_opt) |entry| {
                    if (std.mem.eql(u8, entry.key, progress.cursor_key)) entry_opt = try cursor.next();
                }
            }
            while (entry_opt) |entry| {
                if (!std.mem.startsWith(u8, entry.key, prefix)) break;
                if (items.items.len >= max_rows) {
                    reached_end = false;
                    break;
                }
                if (spec.path_promotion_kind) |kind| {
                    const value_component = token.componentAt(entry.key, prefix.len) catch {
                        entry_opt = try cursor.next();
                        continue;
                    };
                    const doc_component = token.componentAt(entry.key, value_component.next) catch {
                        entry_opt = try cursor.next();
                        continue;
                    };
                    if (doc_component.next != entry.key.len) {
                        entry_opt = try cursor.next();
                        continue;
                    }
                    try items.append(self.alloc, .{
                        .key = try self.alloc.dupe(u8, entry.key),
                        .kind = try self.alloc.dupe(u8, @tagName(kind)),
                        .value = try self.alloc.dupe(u8, value_component.payload),
                        .doc_key = try self.alloc.dupe(u8, doc_component.payload),
                    });
                    entry_opt = try cursor.next();
                    continue;
                }
                const kind_component = token.componentAt(entry.key, prefix.len) catch {
                    entry_opt = try cursor.next();
                    continue;
                };
                const value_component = token.componentAt(entry.key, kind_component.next) catch {
                    entry_opt = try cursor.next();
                    continue;
                };
                const doc_component = token.componentAt(entry.key, value_component.next) catch {
                    entry_opt = try cursor.next();
                    continue;
                };
                if (doc_component.next != entry.key.len) {
                    entry_opt = try cursor.next();
                    continue;
                }
                try items.append(self.alloc, .{
                    .key = try self.alloc.dupe(u8, entry.key),
                    .kind = try self.alloc.dupe(u8, kind_component.payload),
                    .value = try self.alloc.dupe(u8, value_component.payload),
                    .doc_key = try self.alloc.dupe(u8, doc_component.payload),
                });
                entry_opt = try cursor.next();
            }
        }

        const processed: u64 = @intCast(items.items.len);
        const total_processed = progress.rows_processed + processed;
        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        const owns_dictionary = try self.putPathPromotionDictionaryRegistryTxn(&txn, spec, if (reached_end) "ready" else "building");
        for (items.items) |item| {
            const item_kind = std.meta.stringToEnum(pathfact_mod.Kind, item.kind) orelse continue;
            const axes_canonical = try token.canonicalTupleAlloc(self.alloc, &.{ item.kind, item.value });
            defer self.alloc.free(axes_canonical);
            const axes_id = try self.ensureSymbol(&txn, axes_canonical);
            self.alloc.free(axes_id);
            const delta = try algebra.encodeI64Alloc(self.alloc, 1);
            defer self.alloc.free(delta);
            const key = try tensor_mod.keyAlloc(self.alloc, self.name, .{
                .materialization = spec.name,
                .axes_canonical = axes_canonical,
                .bucket = null,
            });
            defer self.alloc.free(key);
            const existing = txn.get(key) catch |err| switch (err) {
                error.NotFound => null,
                else => return err,
            };
            const encoded = (try tensor_mod.applyRowSlotToBytesAlloc(self.alloc, existing, &.{.count}, 0, .count, delta, true)) orelse {
                txn.delete(key) catch |err| switch (err) {
                    error.NotFound => {},
                    else => return err,
                };
                continue;
            };
            defer self.alloc.free(encoded);
            try txn.put(key, encoded);
            const promoted_key = try self.promotedPathLookupKeyAlloc(spec.name, path, item_kind, item.value, item.doc_key);
            defer self.alloc.free(promoted_key);
            try txn.put(promoted_key, "");
            if (owns_dictionary) {
                const identity = lexical_mod.DictionaryIdentity.canonicalScalar(self.name, path, item_kind, "json-scalar-v1", "kind-qualified");
                const lexicon_key = try self.pathDictionaryLexiconKeyAlloc(identity, item.value);
                defer self.alloc.free(lexicon_key);
                try txn.put(lexicon_key, "");
                const posting_key = try self.pathDictionaryPostingsKeyAlloc(identity, item.value, item.doc_key);
                defer self.alloc.free(posting_key);
                try txn.put(posting_key, "");
                try self.writePathDictionaryOrdinalPostingIfAvailableTxn(&txn, identity, item.value, item.doc_key);
            }
            if (next_cursor_key.len > 0) self.alloc.free(next_cursor_key);
            next_cursor_key = try self.alloc.dupe(u8, item.key);
        }
        if (owns_dictionary and reached_end) try self.rebuildPathDictionaryFstTxn(&txn, spec);

        const applied_sequence = if (reached_end) progress.target_sequence else progress.applied_sequence;
        const target_rows = if (reached_end) total_processed else progress.target_rows;
        const cursor_key = if (reached_end) "" else next_cursor_key;
        try self.putAdaptiveProgressTxn(
            &txn,
            progress.recommendation,
            progress.materialization_id,
            .backfilling,
            progress.target_sequence,
            applied_sequence,
            total_processed,
            target_rows,
            cursor_key,
        );
        try txn.commit();
        if (reached_end and next_cursor_key.len > 0) {
            self.alloc.free(next_cursor_key);
            next_cursor_key = &.{};
        }
        return .{
            .rows_processed = processed,
            .total_rows_processed = total_processed,
            .cursor_key = if (reached_end or next_cursor_key.len == 0) &.{} else blk: {
                const owned = next_cursor_key;
                next_cursor_key = &.{};
                break :blk owned;
            },
            .reached_end = reached_end,
        };
    }

    fn putPathPromotionDictionaryRegistryTxn(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
        state: []const u8,
    ) !bool {
        const path = spec.path_promotion_path orelse return false;
        const kind = spec.path_promotion_kind orelse return false;
        const identity = lexical_mod.DictionaryIdentity.canonicalScalar(self.name, path, kind, "json-scalar-v1", "kind-qualified");
        switch (try lexical_mod.claimRegistryOwnerTxn(self.alloc, txn, identity, spec.name, .lexicon_postings_rows, state)) {
            .claimed => {
                self.dictionary_registry_claimed_count += 1;
                return true;
            },
            .already_owned => {
                self.dictionary_registry_already_owned_count += 1;
                return true;
            },
            .owned_by_other => {
                self.dictionary_registry_owned_by_other_count += 1;
                return false;
            },
        }
    }

    fn runAdaptiveJoinBackfillTick(
        self: *Index,
        store: *docstore_mod.DocStore,
        progress: PersistedAdaptiveProgress,
        spec: AdaptiveMaterializationSpec,
        max_rows: u64,
    ) !AdaptiveBackfillTick {
        const join_name = spec.join orelse return error.InvalidAlgebraicAdaptiveRecommendation;
        const join_cfg = self.joinConfig(join_name) orelse return error.InvalidAlgebraicAdaptiveRecommendation;
        const changed_side = if (spec.measure != null)
            try materializationSideRequired(spec.measure_side)
        else
            try materializationSideRequired(spec.group_side);
        const prefix = try self.joinSideFactPrefixAlloc(join_cfg, changed_side);
        defer self.alloc.free(prefix);

        const BackfillItem = struct {
            key: []u8,
            join_id: []u8,
            payload: []u8,

            fn deinit(item: *@This(), alloc: Allocator) void {
                alloc.free(item.key);
                alloc.free(item.join_id);
                alloc.free(item.payload);
                item.* = undefined;
            }
        };
        var payloads = std.ArrayListUnmanaged(BackfillItem).empty;
        defer {
            for (payloads.items) |*item| item.deinit(self.alloc);
            payloads.deinit(self.alloc);
        }
        var reached_end = true;
        var next_cursor_key: []u8 = &.{};
        errdefer if (next_cursor_key.len > 0) self.alloc.free(next_cursor_key);

        {
            var read_txn = try store.beginReadTxn();
            defer read_txn.abort();
            var cursor = try read_txn.openCursor();
            defer cursor.close();

            const start_key = if (progress.cursor_key.len > 0) progress.cursor_key else prefix;
            var entry_opt = try cursor.seekAtOrAfter(start_key);
            if (progress.cursor_key.len > 0) {
                if (entry_opt) |entry| {
                    if (std.mem.eql(u8, entry.key, progress.cursor_key)) entry_opt = try cursor.next();
                }
            }
            while (entry_opt) |entry| {
                if (!std.mem.startsWith(u8, entry.key, prefix)) break;
                if (payloads.items.len >= max_rows) {
                    reached_end = false;
                    break;
                }
                const join_component = token.componentAt(entry.key, prefix.len) catch {
                    entry_opt = try cursor.next();
                    continue;
                };
                try payloads.append(self.alloc, .{
                    .key = try self.alloc.dupe(u8, entry.key),
                    .join_id = try self.alloc.dupe(u8, join_component.payload),
                    .payload = try self.alloc.dupe(u8, entry.value),
                });
                entry_opt = try cursor.next();
            }
        }

        const processed: u64 = @intCast(payloads.items.len);
        const total_processed = progress.rows_processed + processed;

        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        for (payloads.items) |item| {
            var changed_fact = ProjectedFact.decode(self.alloc, item.payload) catch |err| switch (err) {
                error.InvalidAlgebraicFact => continue,
                else => return err,
            };
            defer changed_fact.deinit(self.alloc);
            try self.updateAdaptiveJoinTensorForChangedFact(&txn, join_cfg, changed_side, item.join_id, changed_fact, spec, 1);
            if (next_cursor_key.len > 0) self.alloc.free(next_cursor_key);
            next_cursor_key = try self.alloc.dupe(u8, item.key);
        }

        const applied_sequence = if (reached_end) progress.target_sequence else progress.applied_sequence;
        const target_rows = if (reached_end) total_processed else progress.target_rows;
        const cursor_key = if (reached_end) "" else next_cursor_key;
        try self.putAdaptiveProgressTxn(
            &txn,
            progress.recommendation,
            progress.materialization_id,
            .backfilling,
            progress.target_sequence,
            applied_sequence,
            total_processed,
            target_rows,
            cursor_key,
        );
        try txn.commit();
        if (reached_end and next_cursor_key.len > 0) {
            self.alloc.free(next_cursor_key);
            next_cursor_key = &.{};
        }
        return .{
            .rows_processed = processed,
            .total_rows_processed = total_processed,
            .cursor_key = if (reached_end or next_cursor_key.len == 0) &.{} else blk: {
                const owned = next_cursor_key;
                next_cursor_key = &.{};
                break :blk owned;
            },
            .reached_end = reached_end,
        };
    }

    fn deleteAdaptiveMaterialization(
        self: *Index,
        store: *docstore_mod.DocStore,
        recommendation: []const u8,
        materialization_id: []const u8,
    ) !void {
        const tensor_prefix = try self.adaptiveTensorPrefixAlloc(materialization_id);
        defer self.alloc.free(tensor_prefix);
        var keys = std.ArrayListUnmanaged([]u8).empty;
        defer {
            for (keys.items) |key| self.alloc.free(key);
            keys.deinit(self.alloc);
        }

        {
            var read_txn = try store.beginReadTxn();
            defer read_txn.abort();
            var cursor = try read_txn.openCursor();
            defer cursor.close();
            var entry_opt = try cursor.seekAtOrAfter(tensor_prefix);
            while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
                if (!std.mem.startsWith(u8, entry.key, tensor_prefix)) break;
                try keys.append(self.alloc, try self.alloc.dupe(u8, entry.key));
            }
            const promoted_prefix = try self.promotedPathLookupMaterializationPrefixAlloc(materialization_id);
            defer self.alloc.free(promoted_prefix);
            entry_opt = try cursor.seekAtOrAfter(promoted_prefix);
            while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
                if (!std.mem.startsWith(u8, entry.key, promoted_prefix)) break;
                try keys.append(self.alloc, try self.alloc.dupe(u8, entry.key));
            }
            if (self.adaptiveSpecFromRecommendationAlloc(materialization_id, recommendation)) |spec| {
                var owned_spec = spec;
                defer owned_spec.deinit(self.alloc);
                if (adaptiveMaterializedExpression(owned_spec)) |expr| {
                    const law_id = law_mod.fromOp(owned_spec.op);
                    const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
                    defer self.alloc.free(expr_id);
                    const expr_prefix = try tensor_mod.expressionPrefixAlloc(self.alloc, self.name, expr_id);
                    defer self.alloc.free(expr_prefix);
                    entry_opt = try cursor.seekAtOrAfter(expr_prefix);
                    while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
                        if (!std.mem.startsWith(u8, entry.key, expr_prefix)) break;
                        try keys.append(self.alloc, try self.alloc.dupe(u8, entry.key));
                    }
                }
            } else |_| {}
        }

        const progress_key = try adaptive_mod.progressKeyAlloc(self.alloc, self.name, recommendation);
        defer self.alloc.free(progress_key);
        const candidate_key = try adaptive_mod.candidateKeyAlloc(self.alloc, self.name, recommendation);
        defer self.alloc.free(candidate_key);

        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        for (keys.items) |key| txn.delete(key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
        txn.delete(progress_key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
        txn.delete(candidate_key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
        try self.deleteAdaptiveDictionaryIfOwnedTxn(&txn, recommendation, materialization_id);
        try txn.commit();
    }

    fn deleteAdaptiveDictionaryIfOwnedTxn(
        self: *Index,
        txn: anytype,
        recommendation: []const u8,
        materialization_id: []const u8,
    ) !void {
        var spec = self.adaptiveSpecFromRecommendationAlloc(materialization_id, recommendation) catch return;
        defer spec.deinit(self.alloc);
        const path = spec.path_promotion_path orelse return;
        const kind = spec.path_promotion_kind orelse return;
        const identity = lexical_mod.DictionaryIdentity.canonicalScalar(self.name, path, kind, "json-scalar-v1", "kind-qualified");
        const registry_key = try identity.registryKeyAlloc(self.alloc);
        defer self.alloc.free(registry_key);
        const payload = txn.get(registry_key) catch |err| switch (err) {
            error.NotFound => return,
            else => return err,
        };
        var entry = lexical_mod.RegistryEntry.decodeAlloc(self.alloc, payload) catch return;
        defer entry.deinit(self.alloc);
        if (!std.mem.eql(u8, entry.owner, materialization_id)) return;
        if (entry.layout != .lexicon_postings_rows) return;

        var keys = std.ArrayListUnmanaged([]u8).empty;
        defer {
            for (keys.items) |key| self.alloc.free(key);
            keys.deinit(self.alloc);
        }
        var cursor = try txn.openCursor();
        defer cursor.close();
        const lexicon_prefix = try self.pathDictionaryLexiconPrefixAlloc(identity);
        defer self.alloc.free(lexicon_prefix);
        var entry_opt = try cursor.seekAtOrAfter(lexicon_prefix);
        while (entry_opt) |row| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, row.key, lexicon_prefix)) break;
            try keys.append(self.alloc, try self.alloc.dupe(u8, row.key));
        }
        const postings_prefix = try self.pathDictionaryPostingsDictionaryPrefixAlloc(identity);
        defer self.alloc.free(postings_prefix);
        entry_opt = try cursor.seekAtOrAfter(postings_prefix);
        while (entry_opt) |row| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, row.key, postings_prefix)) break;
            try keys.append(self.alloc, try self.alloc.dupe(u8, row.key));
        }
        const ordinal_postings_prefix = try self.pathDictionaryOrdinalPostingsDictionaryPrefixAlloc(identity);
        defer self.alloc.free(ordinal_postings_prefix);
        entry_opt = try cursor.seekAtOrAfter(ordinal_postings_prefix);
        while (entry_opt) |row| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, row.key, ordinal_postings_prefix)) break;
            try keys.append(self.alloc, try self.alloc.dupe(u8, row.key));
        }
        const fst_key = try self.pathDictionaryFstKeyAlloc(identity);
        defer self.alloc.free(fst_key);
        try keys.append(self.alloc, try self.alloc.dupe(u8, fst_key));

        for (keys.items) |key| txn.delete(key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
        txn.delete(registry_key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
    }

    fn updateAdaptiveTensorFromFacts(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
        facts: []const fact_mod.Fact,
        sign: i8,
    ) !void {
        const axes_canonical = fact_mod.axisTupleAlloc(self.alloc, facts, spec.group_by) catch |err| switch (err) {
            error.MissingField => return,
            else => return err,
        };
        defer self.alloc.free(axes_canonical);
        const axes_id = try self.ensureSymbol(txn, axes_canonical);
        self.alloc.free(axes_id);

        const measure_value = if (spec.measure) |measure_name|
            try self.factMeasureAlloc(facts, measure_name)
        else
            null;
        defer if (measure_value) |value| value.deinit(self.alloc);

        var bucket_start: ?[]u8 = null;
        defer if (bucket_start) |value| self.alloc.free(value);
        if (spec.time) |time_name| {
            const bucket_name = spec.bucket orelse return;
            const bucket = cylinder.Bucket.parse(bucket_name) orelse return;
            const time_value = (try self.factTimeTextAlloc(facts, time_name)) orelse return;
            defer self.alloc.free(time_value);
            bucket_start = try cylinder.bucketStartAlloc(self.alloc, bucket, time_value);
        }

        const law_id = law_mod.fromOp(spec.op);
        const delta = try self.adaptiveTensorDeltaAlloc(spec.op, measure_value, sign);
        defer self.alloc.free(delta);
        const key = try tensor_mod.keyAlloc(self.alloc, self.name, .{
            .materialization = spec.name,
            .axes_canonical = axes_canonical,
            .bucket = bucket_start,
        });
        defer self.alloc.free(key);

        const existing = txn.get(key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        const encoded = try tensor_mod.applyRowSlotToBytesAlloc(self.alloc, existing, &.{law_id}, 0, law_id, delta, true);
        if (encoded) |bytes| {
            defer self.alloc.free(bytes);
            try txn.put(key, bytes);
        } else {
            txn.delete(key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
        }

        try self.applyAdaptiveExpressionDeltaTxn(txn, spec, axes_canonical, bucket_start, law_id, delta);
    }

