    fn updateAdaptiveJoinTensorForChangedFact(
        self: *Index,
        txn: anytype,
        join_cfg: JoinConfig,
        changed_side: join_mod.Side,
        join_id: []const u8,
        changed_fact: ProjectedFact,
        spec: AdaptiveMaterializationSpec,
        sign: i8,
    ) !void {
        const scan = try self.joinScanBoundsPreferOrdinalAlloc(txn, join_cfg, changed_side.opposite(), join_id, changed_fact, changed_side);
        defer scan.deinit(self.alloc);
        var cursor = try txn.openCursor();
        defer cursor.close();
        var fanout: usize = 0;
        var entry_opt = try cursor.seekAtOrAfter(scan.start);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, scan.prefix)) break;
            if (scan.max_time_key) |max_key| {
                const time_component = token.componentAt(entry.key, scan.prefix.len) catch {
                    self.join_facts_pruned += 1;
                    continue;
                };
                if (std.mem.order(u8, time_component.payload, max_key) == .gt) break;
            }
            self.join_facts_scanned += 1;
            var opposite_fact = ProjectedFact.decode(self.alloc, entry.value) catch continue;
            defer opposite_fact.deinit(self.alloc);
            if (!(try self.joinTemporalFactsMatch(join_cfg, changed_side, changed_fact, opposite_fact))) {
                self.join_facts_pruned += 1;
                continue;
            }
            self.join_facts_matched += 1;
            fanout += 1;
            if (join_cfg.max_fanout) |max| {
                if (fanout > max) return error.AlgebraicJoinFanoutExceeded;
            }
            const left_fact = if (changed_side == .left) changed_fact else opposite_fact;
            const right_fact = if (changed_side == .left) opposite_fact else changed_fact;
            try self.updateAdaptiveTensorFromJoinPair(txn, spec, left_fact, right_fact, sign);
        }
    }

    fn updateAdaptiveTensorFromJoinPair(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
        left_fact: ProjectedFact,
        right_fact: ProjectedFact,
        sign: i8,
    ) !void {
        const group_fact = try materializationSideFactRequired(spec.group_side, right_fact, left_fact);
        const measure_fact = try materializationSideFactRequired(spec.measure_side, right_fact, left_fact);
        const axes_canonical = group_fact.groupKeyAlloc(self.alloc, spec.group_by) catch |err| switch (err) {
            error.MissingField => return,
            else => return err,
        };
        defer self.alloc.free(axes_canonical);

        const measure_value = if (spec.measure) |measure_name|
            try measure_fact.measureAlloc(self.alloc, measure_name)
        else
            null;
        defer if (measure_value) |value| value.deinit(self.alloc);

        const law_id = law_mod.fromOp(spec.op);
        const delta = try self.adaptiveTensorDeltaAlloc(spec.op, measure_value, sign);
        defer self.alloc.free(delta);
        const key = try tensor_mod.keyAlloc(self.alloc, self.name, .{
            .materialization = spec.name,
            .axes_canonical = axes_canonical,
            .bucket = null,
        });
        defer self.alloc.free(key);

        const existing = txn.get(key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        const encoded = try tensor_mod.applyRowSlotToBytesAlloc(self.alloc, existing, &.{law_id}, 0, law_id, delta, true);
        if (encoded) |bytes| {
            defer self.alloc.free(bytes);
            try txn.put(key, bytes);
        } else {
            txn.delete(key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
        }

        try self.applyAdaptiveExpressionDeltaTxn(txn, spec, axes_canonical, null, law_id, delta);
    }

