    fn accumulateAdaptiveTensorDeltaAppendOnly(
        self: *Index,
        txn: anytype,
        accumulator: *AppendOnlyAccumulator,
        spec: AdaptiveMaterializationSpec,
        axes_canonical: []const u8,
        bucket: ?[]const u8,
        law_id: law_mod.Id,
        delta: []const u8,
    ) !void {
        const axes_id = try self.ensureSymbolAppendOnly(txn, axes_canonical);
        defer self.alloc.free(axes_id);

        const tensor_key = try tensor_mod.keyAlloc(self.alloc, self.name, .{
            .materialization = spec.name,
            .axes_canonical = axes_canonical,
            .bucket = bucket,
        });
        const tensor_row = try accumulator.expressionRow(self.alloc, tensor_key, &.{law_id});
        try tensor_row.applyDelta(self.alloc, 0, law_id, delta);

        const expr = adaptiveMaterializedExpression(spec) orelse return;
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const expr_key = try tensor_mod.expressionKeyAlloc(self.alloc, self.name, .{
            .expr_id = expr_id,
            .axes_canonical = axes_canonical,
            .bucket = bucket,
        });
        const expr_row = try accumulator.expressionRow(self.alloc, expr_key, &.{law_id});
        try expr_row.applyDelta(self.alloc, 0, law_id, delta);
    }

    fn accumulateAdaptiveTensorDelta(
        self: *Index,
        txn: anytype,
        accumulator: *AppendOnlyAccumulator,
        spec: AdaptiveMaterializationSpec,
        axes_canonical: []const u8,
        bucket: ?[]const u8,
        law_id: law_mod.Id,
        delta: []const u8,
    ) !void {
        const axes_id = try self.ensureSymbol(txn, axes_canonical);
        defer self.alloc.free(axes_id);

        const tensor_key = try tensor_mod.keyAlloc(self.alloc, self.name, .{
            .materialization = spec.name,
            .axes_canonical = axes_canonical,
            .bucket = bucket,
        });
        const tensor_row = try accumulator.expressionRow(self.alloc, tensor_key, &.{law_id});
        try tensor_row.applyDelta(self.alloc, 0, law_id, delta);

        const expr = adaptiveMaterializedExpression(spec) orelse return;
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const expr_key = try tensor_mod.expressionKeyAlloc(self.alloc, self.name, .{
            .expr_id = expr_id,
            .axes_canonical = axes_canonical,
            .bucket = bucket,
