    fn applyAdaptiveExpressionDeltaTxn(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
        axes_canonical: []const u8,
        bucket: ?[]const u8,
        law_id: law_mod.Id,
        delta: []const u8,
    ) !void {
        const expr = adaptiveMaterializedExpression(spec) orelse return;
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const expr_key = try tensor_mod.expressionKeyAlloc(self.alloc, self.name, .{
            .expr_id = expr_id,
            .axes_canonical = axes_canonical,
            .bucket = bucket,
        });
        defer self.alloc.free(expr_key);
        const expr_existing = txn.get(expr_key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        const expr_encoded = (try tensor_mod.applyRowSlotToBytesAlloc(self.alloc, expr_existing, &.{law_id}, 0, law_id, delta, true)) orelse {
            txn.delete(expr_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            return;
        };
        defer self.alloc.free(expr_encoded);
        try txn.put(expr_key, expr_encoded);
    }

    fn adaptiveTensorDeltaAlloc(self: *Index, op: algebra.Op, measure_value: ?MeasureValue, sign: i8) ![]u8 {
        return switch (op) {
            .count => try algebra.encodeI64Alloc(self.alloc, sign),
            .sum => blk: {
                const measure = measure_value orelse return error.MissingField;
                const delta = try algebra.parseF64(measure.raw) * @as(f64, @floatFromInt(sign));
                break :blk try algebra.encodeF64Alloc(self.alloc, delta);
            },
            .sumsquares => blk: {
                const measure = measure_value orelse return error.MissingField;
                const value = try algebra.parseF64(measure.raw);
                const delta = value * value * @as(f64, @floatFromInt(sign));
                break :blk try algebra.encodeF64Alloc(self.alloc, delta);
            },
            .avg => blk: {
                const measure = measure_value orelse return error.MissingField;
                const delta = try algebra.parseF64(measure.raw) * @as(f64, @floatFromInt(sign));
                break :blk try algebra.encodeAvgAlloc(self.alloc, .{ .sum = delta, .count = sign });
            },
            .min, .max => blk: {
                if (sign < 0) return error.AlgebraicLawNotInvertible;
                const measure = measure_value orelse return error.MissingField;
                break :blk try self.alloc.dupe(u8, measure.raw);
            },
        };
    }

    fn decodePersistedObservation(self: *Index, payload: []const u8) !PersistedObservationMeta {
        const parts = try token.decodeTupleAlloc(self.alloc, payload);
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 6 or !std.mem.eql(u8, parts[0], "observation:v1")) return error.InvalidAlgebraicObservation;
        return .{
            .count = try std.fmt.parseInt(u64, parts[2], 10),
            .lifecycle = std.meta.stringToEnum(adaptive_mod.Lifecycle, parts[5]) orelse return error.InvalidAlgebraicObservation,
        };
    }

    fn decodePersistedObservationFull(self: *Index, payload: []const u8) !PersistedQueryObservation {
        const parts = try token.decodeTupleAlloc(self.alloc, payload);
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 6 or !std.mem.eql(u8, parts[0], "observation:v1")) return error.InvalidAlgebraicObservation;
        const shape = try self.alloc.dupe(u8, parts[1]);
        errdefer self.alloc.free(shape);
        const reason = try self.alloc.dupe(u8, parts[3]);
        errdefer self.alloc.free(reason);
        const recommendation = if (parts[4].len == 0) null else try self.alloc.dupe(u8, parts[4]);
        errdefer if (recommendation) |value| self.alloc.free(value);
        return .{
            .shape = shape,
            .count = try std.fmt.parseInt(u64, parts[2], 10),
            .reason = reason,
            .recommendation = recommendation,
            .lifecycle = std.meta.stringToEnum(adaptive_mod.Lifecycle, parts[5]) orelse return error.InvalidAlgebraicObservation,
        };
    }

    fn decodePersistedMaterializationState(self: *Index, payload: []const u8) !PersistedMaterializationState {
        const parts = try token.decodeTupleAlloc(self.alloc, payload);
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 4 or !std.mem.eql(u8, parts[0], "materialization-state:v1")) return error.InvalidAlgebraicMaterializationState;
        const recommendation = try self.alloc.dupe(u8, parts[1]);
        errdefer self.alloc.free(recommendation);
        return .{
            .recommendation = recommendation,
            .lifecycle = std.meta.stringToEnum(adaptive_mod.Lifecycle, parts[2]) orelse return error.InvalidAlgebraicMaterializationState,
            .observation_count = try std.fmt.parseInt(u64, parts[3], 10),
        };
    }

    fn decodePersistedAdaptiveCandidate(self: *Index, payload: []const u8) !PersistedAdaptiveCandidate {
        const parts = try token.decodeTupleAlloc(self.alloc, payload);
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 16 or !std.mem.eql(u8, parts[0], "adaptive-candidate:v3")) return error.InvalidAlgebraicAdaptiveCandidate;
        const recommendation = try self.alloc.dupe(u8, parts[1]);
        errdefer self.alloc.free(recommendation);
        const materialization_id = try self.alloc.dupe(u8, parts[2]);
        errdefer self.alloc.free(materialization_id);
        const decision = try self.alloc.dupe(u8, parts[13]);
        errdefer self.alloc.free(decision);
        return .{
            .recommendation = recommendation,
            .materialization_id = materialization_id,
            .lifecycle = std.meta.stringToEnum(adaptive_mod.Lifecycle, parts[3]) orelse return error.InvalidAlgebraicAdaptiveCandidate,
            .observation_count = try std.fmt.parseInt(u64, parts[4], 10),
            .estimated_scan_rows_saved = try std.fmt.parseInt(u64, parts[5], 10),
            .estimated_write_cost = try std.fmt.parseInt(u64, parts[6], 10),
            .estimated_doc_rows = try std.fmt.parseInt(u64, parts[7], 10),
            .estimated_bucket_cardinality = try std.fmt.parseInt(u64, parts[8], 10),
            .estimated_tensor_rows = try std.fmt.parseInt(u64, parts[9], 10),
            .estimated_storage_bytes = try std.fmt.parseInt(u64, parts[10], 10),
            .estimated_write_amplification = try std.fmt.parseInt(u64, parts[11], 10),
            .score = try std.fmt.parseInt(i128, parts[12], 10),
            .decision = decision,
            .idle_miss_count = try std.fmt.parseInt(u64, parts[14], 10),
            .generation = try std.fmt.parseInt(u64, parts[15], 10),
        };
    }

    fn decodePersistedAdaptiveDecision(self: *Index, payload: []const u8) !PersistedAdaptiveDecision {
        const parts = try token.decodeTupleAlloc(self.alloc, payload);
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 13 or !std.mem.eql(u8, parts[0], "adaptive-decision:v1")) return error.InvalidAlgebraicAdaptiveDecision;
        const recommendation = try self.alloc.dupe(u8, parts[1]);
        errdefer self.alloc.free(recommendation);
        const materialization_id = try self.alloc.dupe(u8, parts[2]);
        errdefer self.alloc.free(materialization_id);
        const previous_decision = try self.alloc.dupe(u8, parts[4]);
        errdefer self.alloc.free(previous_decision);
        const decision = try self.alloc.dupe(u8, parts[5]);
        errdefer self.alloc.free(decision);
        return .{
            .recommendation = recommendation,
            .materialization_id = materialization_id,
            .lifecycle = std.meta.stringToEnum(adaptive_mod.Lifecycle, parts[3]) orelse return error.InvalidAlgebraicAdaptiveDecision,
            .previous_decision = previous_decision,
            .decision = decision,
            .observation_count = try std.fmt.parseInt(u64, parts[6], 10),
            .estimated_scan_rows_saved = try std.fmt.parseInt(u64, parts[7], 10),
            .estimated_write_cost = try std.fmt.parseInt(u64, parts[8], 10),
            .score = try std.fmt.parseInt(i128, parts[9], 10),
            .score_delta = try std.fmt.parseInt(i128, parts[10], 10),
            .idle_miss_count = try std.fmt.parseInt(u64, parts[11], 10),
            .generation = try std.fmt.parseInt(u64, parts[12], 10),
        };
    }

    fn decodePersistedAdaptiveProgress(self: *Index, payload: []const u8) !PersistedAdaptiveProgress {
        const parts = try token.decodeTupleAlloc(self.alloc, payload);
        defer {
            for (parts) |part| self.alloc.free(part);
            if (parts.len > 0) self.alloc.free(parts);
        }
        if (parts.len != 11 or !std.mem.eql(u8, parts[0], "adaptive-progress:v3")) return error.InvalidAlgebraicAdaptiveProgress;
        const recommendation = try self.alloc.dupe(u8, parts[1]);
        errdefer self.alloc.free(recommendation);
        const materialization_id = try self.alloc.dupe(u8, parts[2]);
        errdefer self.alloc.free(materialization_id);
        const capability_fingerprint: []u8 = if (parts[9].len == 0) &.{} else try self.alloc.dupe(u8, parts[9]);
        errdefer if (capability_fingerprint.len > 0) self.alloc.free(capability_fingerprint);
        const cursor_key: []u8 = if (parts[10].len == 0) &.{} else try self.alloc.dupe(u8, parts[10]);
        errdefer if (cursor_key.len > 0) self.alloc.free(cursor_key);
        return .{
            .recommendation = recommendation,
            .materialization_id = materialization_id,
            .lifecycle = std.meta.stringToEnum(adaptive_mod.Lifecycle, parts[3]) orelse return error.InvalidAlgebraicAdaptiveProgress,
            .target_sequence = try std.fmt.parseInt(u64, parts[4], 10),
            .applied_sequence = try std.fmt.parseInt(u64, parts[5], 10),
            .rows_processed = try std.fmt.parseInt(u64, parts[6], 10),
            .target_rows = try std.fmt.parseInt(u64, parts[7], 10),
            .schema_version = try std.fmt.parseInt(u32, parts[8], 10),
            .capability_fingerprint = capability_fingerprint,
            .cursor_key = cursor_key,
        };
    }

    pub fn constraintTokenAlloc(self: *const Index, alloc: Allocator, field_name: []const u8, value_text: []const u8) ![]u8 {
        const cfg = self.fieldConfig(field_name, .group) orelse return error.MissingField;
        return try token.scalarTokenFromFieldTextAlloc(alloc, cfg.type, value_text);
    }

    pub fn scalarTokenJsonAlloc(_: *const Index, alloc: Allocator, encoded: []const u8) ![]u8 {
        return try token.scalarTokenJsonAlloc(alloc, encoded);
    }

