        return try token.scalarTokenTextAlloc(alloc, encoded);
    }

    pub fn fieldConfig(self: *const Index, query_field: []const u8, class: FieldClass) ?FieldConfig {
        if (class == .group or class == .any) {
            for (self.config().group_fields) |field| {
                if (fieldMatchesQuery(field, query_field)) return field;
            }
        }
        if (class == .measure or class == .any) {
            for (self.config().measure_fields) |field| {
                if (fieldMatchesQuery(field, query_field)) return field;
            }
        }
        if (class == .time or class == .any) {
            for (self.config().time_fields) |field| {
                if (fieldMatchesQuery(field, query_field)) return field;
            }
        }
        return null;
    }

    pub fn resolveField(self: *const Index, query_field: []const u8, class: FieldClass) ?ResolvedField {
        if (class == .any) return self.resolveUniqueField(query_field);
        const cfg = self.fieldConfig(query_field, class) orelse return null;
        return .{
            .public = query_field,
            .name = cfg.name,
            .path = cfg.path,
            .role = class,
            .scalar_type = cfg.type,
        };
    }

    pub fn resolveMeasureField(self: *const Index, query_field: []const u8) ?ResolvedMeasureField {
        return .{ .field = self.resolveField(query_field, .measure) orelse return null };
    }

    fn joinConfig(self: *const Index, name: []const u8) ?JoinConfig {
        for (self.config().joins) |join_cfg| {
            if (std.mem.eql(u8, join_cfg.name, name)) return join_cfg;
        }
        return null;
    }

    fn keyAlloc(self: *Index, parts: []const []const u8) ![]u8 {
        var out = std.ArrayListUnmanaged(u8).empty;
        errdefer out.deinit(self.alloc);
        try out.appendSlice(self.alloc, namespace_prefix);
        try token.appendComponent(&out, self.alloc, self.name);
        try token.appendComponent(&out, self.alloc, "v4");
        for (parts) |part| try token.appendComponent(&out, self.alloc, part);
        return try out.toOwnedSlice(self.alloc);
    }

