    fn symbolKeyAlloc(self: *Index, id: []const u8) ![]u8 {
        if (id.len != symbol.id_len) return error.InvalidSymbolId;
        return try self.keyAlloc(&.{ "sym", id });
    }

    fn ensureSymbol(self: *Index, txn: anytype, canonical: []const u8) ![]u8 {
        const id = try symbol.idAlloc(self.alloc, canonical);
        errdefer self.alloc.free(id);
        const key = try self.symbolKeyAlloc(id);
        defer self.alloc.free(key);
        const existing = txn.get(key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        if (existing) |value| {
            if (!std.mem.eql(u8, value, canonical)) return error.AlgebraicSymbolCollision;
            return id;
        }
        try txn.put(key, canonical);
        return id;
    }

    fn ensureSymbolAppendOnly(self: *Index, txn: anytype, canonical: []const u8) ![]u8 {
        const id = try symbol.idAlloc(self.alloc, canonical);
        errdefer self.alloc.free(id);
        const key = try self.symbolKeyAlloc(id);
        defer self.alloc.free(key);
        const existing = txn.get(key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        if (existing) |value| {
            if (!std.mem.eql(u8, value, canonical)) return error.AlgebraicSymbolCollision;
            return id;
        }
        try txn.put(key, canonical);
        return id;
    }

    fn resolveSymbolAlloc(self: *Index, txn: anytype, id: []const u8) !?[]u8 {
        const key = try self.symbolKeyAlloc(id);
        defer self.alloc.free(key);
        const raw = txn.get(key) catch |err| switch (err) {
            error.NotFound => return null,
            else => return err,
        };
        return try self.alloc.dupe(u8, raw);
    }

    fn materializationIndex(self: *const Index, materialization: []const u8) ?usize {
        for (self.config().materializations, 0..) |mat, i| {
            if (std.mem.eql(u8, mat.name, materialization)) return i;
        }
        return null;
    }

    fn joinConfigByName(self: *const Index, name: []const u8) ?JoinConfig {
        for (self.config().joins) |join_cfg| {
            if (std.mem.eql(u8, join_cfg.name, name)) return join_cfg;
        }
        return null;
    }

    fn sameLayoutShape(a: MaterializationConfig, b: MaterializationConfig) bool {
        return stringSlicesEqual(a.group_by, b.group_by) and
            optionalStringEqual(a.time, b.time) and
            optionalStringEqual(a.bucket, b.bucket) and
            optionalStringEqual(a.join, b.join) and
            optionalStringEqual(a.group_side, b.group_side) and
            optionalStringEqual(a.measure_side, b.measure_side);
    }

    fn stringSlicesEqual(a: []const []const u8, b: []const []const u8) bool {
        if (a.len != b.len) return false;
        for (a, b) |lhs, rhs| {
            if (!std.mem.eql(u8, lhs, rhs)) return false;
        }
        return true;
    }

    fn optionalStringEqual(a: ?[]const u8, b: ?[]const u8) bool {
        if (a == null and b == null) return true;
        if (a == null or b == null) return false;
        return std.mem.eql(u8, a.?, b.?);
    }

    fn supportGroupKeyAlloc(self: *Index, kind: RowKind, group_key: []const u8, bucket_start: ?[]const u8) ![]u8 {
        return switch (kind) {
            .direct => try self.alloc.dupe(u8, group_key),
            .cylinder => try token.canonicalTupleAlloc(self.alloc, &.{ bucket_start orelse return error.InvalidAlgebraicConfig, group_key }),
        };
    }

    fn materializationExprIdAlloc(self: *Index, mat: MaterializationConfig, law_id: law_mod.Id) ![]u8 {
        const expr = materializationExpression(mat, law_id);
        return try self.materializedExpressionIdForLawAlloc(expr, law_id);
    }

    fn materializationLawId(self: *const Index, mat: MaterializationConfig, op: algebra.Op) law_mod.Id {
        if (mat.law) |law_name| {
            return lawConfigId(self.config(), law_name) orelse law_mod.fromOp(op);
        }
        return law_mod.fromOp(op);
    }

    fn distributedMaterializationOutputDims(mat: MaterializationConfig) []const ir.Dimension {
        if (mat.time != null) return &distributed_time_bucket_scalar_output_dims;
        if (mat.group_by.len > 0 or mat.axes.len > 0) return &distributed_bucket_scalar_output_dims;
        return &distributed_scalar_output_dims;
    }

    fn distributedMaterializationExportProven(mat: MaterializationConfig, law_id: law_mod.Id) bool {
        const law_ids = [_]law_mod.Id{law_id};
        const path = ir.PhysicalAccessPath{
            .owner = mat.name,
            .layout = .materialized_tensor,
            .fragments = if (mat.join != null) &distributed_join_materialized_tensor_fragments else &distributed_materialized_tensor_fragments,
            .output_dims = distributedMaterializationOutputDims(mat),
            .law_ids = law_ids[0..],
        };
        const reduce_expr = ir.TensorExpr{
            .fragment = .reduce,
            .owner = mat.name,
            .layout = .materialized_tensor,
            .output_dims = distributedMaterializationOutputDims(mat),
            .law_id = law_id,
        };
        if (!ir.accessPathCanSatisfy(path, reduce_expr).safe()) return false;
        const merge_expr = ir.TensorExpr{
            .fragment = .merge,
            .owner = mat.name,
            .layout = .materialized_tensor,
            .output_dims = distributedMaterializationOutputDims(mat),
            .law_id = law_id,
        };
        if (!ir.accessPathCanSatisfy(path, merge_expr).safe()) return false;
        if (mat.join != null) {
            const join_expr = ir.TensorExpr{
                .fragment = .join,
                .owner = mat.name,
                .layout = .materialized_tensor,
                .output_dims = distributedMaterializationOutputDims(mat),
                .law_id = law_id,
            };
            if (!ir.accessPathCanSatisfy(path, join_expr).safe()) return false;
        }
        return true;
    }

    fn distributedMaterializationLawIdsAlloc(self: *const Index, materializations: []const []const u8) ![]law_mod.Id {
        const law_ids = try self.alloc.alloc(law_mod.Id, materializations.len);
        errdefer self.alloc.free(law_ids);
        for (materializations, 0..) |materialization, i| {
            const mat_idx = self.materializationIndex(materialization) orelse return error.InvalidAlgebraicConfig;
            const mat = self.config().materializations[mat_idx];
            const op = algebra.Op.parse(mat.op) orelse return error.InvalidAlgebraicConfig;
            const law_id = self.materializationLawId(mat, op);
            if (!distributedMaterializationExportProven(mat, law_id)) return error.InvalidAlgebraicConfig;
            law_ids[i] = law_id;
        }
        return law_ids;
    }

    fn materializationDeltaAlloc(self: *Index, op: algebra.Op, measure_value: ?MeasureValue, sign: i64) ![]u8 {
        return switch (op) {
            .count => try algebra.encodeI64Alloc(self.alloc, sign),
            .sum => blk: {
                const measure = measure_value orelse return error.MissingField;
                const delta = try algebra.parseF64(measure.raw) * @as(f64, @floatFromInt(sign));
                break :blk try algebra.encodeF64Alloc(self.alloc, delta);
            },
            .sumsquares => blk: {
                const measure = measure_value orelse return error.MissingField;
                const value = try algebra.parseF64(measure.raw);
                const delta = value * value * @as(f64, @floatFromInt(sign));
                break :blk try algebra.encodeF64Alloc(self.alloc, delta);
            },
            .avg => blk: {
                const measure = measure_value orelse return error.MissingField;
                const delta = try algebra.parseF64(measure.raw) * @as(f64, @floatFromInt(sign));
                break :blk try algebra.encodeAvgAlloc(self.alloc, .{ .sum = delta, .count = sign });
            },
            .min, .max => error.AlgebraicLawNotInvertible,
        };
    }

    fn applyConfiguredExpressionMutationTxn(
        self: *Index,
        txn: anytype,
        mat: MaterializationConfig,
        op: algebra.Op,
        group_key: []const u8,
        measure_value: ?MeasureValue,
        sign: i8,
        kind: RowKind,
        bucket_start: ?[]const u8,
    ) !void {
        const law_id = self.materializationLawId(mat, op);

        switch (op) {
            .count, .sum, .sumsquares, .avg => {
                if (op != .count and measure_value == null) return;
                const delta = try self.materializationDeltaAlloc(op, measure_value, @as(i64, @intCast(sign)));
                defer self.alloc.free(delta);
                try self.applyConfiguredExpressionDeltaTxn(txn, mat, law_id, group_key, bucket_start, delta, true);
                return;
            },
            .min, .max => {},
        }

        const old_current = try self.expressionRawValueForMaterializationTxn(txn, mat.name, group_key, bucket_start);
        defer if (old_current) |value| self.alloc.free(value);

        const measure = measure_value orelse return;
        const expr_id = try self.materializationExprIdAlloc(mat, law_id);
        defer self.alloc.free(expr_id);
        const support_group_key = try self.supportGroupKeyAlloc(kind, group_key, bucket_start);
        defer self.alloc.free(support_group_key);
        const next_owned = try self.updateMinMaxExpressionCurrent(txn, expr_id, support_group_key, op, old_current, measure, sign);
        defer if (next_owned) |bytes| self.alloc.free(bytes);
        try self.replaceConfiguredExpressionValueTxn(txn, mat, law_id, group_key, bucket_start, next_owned);
    }

    fn applyConfiguredExpressionDeltaTxn(
        self: *Index,
        txn: anytype,
        mat: MaterializationConfig,
        law_id: law_mod.Id,
        group_key: []const u8,
        bucket_start: ?[]const u8,
        delta: []const u8,
        omit_empty: bool,
    ) !void {
        const axis_id = try self.ensureSymbol(txn, group_key);
        defer self.alloc.free(axis_id);
        const expr = materializationExpression(mat, law_id);
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const expr_key = try tensor_mod.expressionKeyAlloc(self.alloc, self.name, .{
            .expr_id = expr_id,
            .axes_canonical = group_key,
            .bucket = bucket_start,
        });
        defer self.alloc.free(expr_key);
        const existing = txn.get(expr_key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        const encoded = (try tensor_mod.applyRowSlotToBytesAlloc(self.alloc, existing, &.{law_id}, 0, law_id, delta, omit_empty)) orelse {
            txn.delete(expr_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            return;
        };
        defer self.alloc.free(encoded);
        try txn.put(expr_key, encoded);
    }

    fn replaceConfiguredExpressionValueTxn(
        self: *Index,
        txn: anytype,
        mat: MaterializationConfig,
        law_id: law_mod.Id,
        group_key: []const u8,
        bucket_start: ?[]const u8,
        next: ?[]const u8,
    ) !void {
        const axis_id = try self.ensureSymbol(txn, group_key);
        defer self.alloc.free(axis_id);
        const expr = materializationExpression(mat, law_id);
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const expr_key = try tensor_mod.expressionKeyAlloc(self.alloc, self.name, .{
            .expr_id = expr_id,
            .axes_canonical = group_key,
            .bucket = bucket_start,
        });
        defer self.alloc.free(expr_key);
        const existing = txn.get(expr_key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        const next_owned = if (next) |value| try self.alloc.dupe(u8, value) else null;
        const encoded = (try tensor_mod.replaceRowSlotToBytesAlloc(self.alloc, existing, &.{law_id}, 0, law_id, next_owned, true)) orelse {
            txn.delete(expr_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            return;
        };
        defer self.alloc.free(encoded);
        try txn.put(expr_key, encoded);
    }

    fn accumulateConfiguredExpressionAppendOnly(
        self: *Index,
        txn: anytype,
        accumulator: *AppendOnlyAccumulator,
        mat: MaterializationConfig,
        op: algebra.Op,
        group_key: []const u8,
        measure_value: ?MeasureValue,
        kind: RowKind,
        bucket_start: ?[]const u8,
    ) !void {
        const group_id = try self.ensureSymbolAppendOnly(txn, group_key);
        defer self.alloc.free(group_id);
        const law_id = self.materializationLawId(mat, op);
        const expr = materializationExpression(mat, law_id);
        const expr_id = try self.materializedExpressionIdForLawAlloc(expr, law_id);
        defer self.alloc.free(expr_id);
        const expr_key = try tensor_mod.expressionKeyAlloc(self.alloc, self.name, .{
            .expr_id = expr_id,
            .axes_canonical = group_key,
            .bucket = bucket_start,
        });
        const expression_row = try accumulator.expressionRow(self.alloc, expr_key, &.{law_id});

        switch (op) {
            .count => {
                const delta = try self.materializationDeltaAlloc(op, measure_value, 1);
                defer self.alloc.free(delta);
                try expression_row.applyDelta(self.alloc, 0, law_id, delta);
            },
            .sum, .sumsquares => {
                if (measure_value == null) return;
                const delta = try self.materializationDeltaAlloc(op, measure_value, 1);
                defer self.alloc.free(delta);
                try expression_row.applyDelta(self.alloc, 0, law_id, delta);
            },
            .avg => {
                if (measure_value == null) return;
                const delta = try self.materializationDeltaAlloc(op, measure_value, 1);
                defer self.alloc.free(delta);
                try expression_row.applyDelta(self.alloc, 0, law_id, delta);
            },
            .min, .max => {
                const measure = measure_value orelse return;
                try expression_row.applyDelta(self.alloc, 0, law_id, measure.raw);

                const support_group_key = try self.supportGroupKeyAlloc(kind, group_key, bucket_start);
                defer self.alloc.free(support_group_key);
                const support_group_id = try self.ensureSymbolAppendOnly(txn, support_group_key);
                defer self.alloc.free(support_group_id);
                const measure_id = try self.ensureSymbolAppendOnly(txn, measure.support_token);
                defer self.alloc.free(measure_id);
                const support_key = try self.keyAlloc(&.{ "minmax", expr_id, support_group_id, measure_id });
                try accumulator.addSupport(self.alloc, support_key, 1);
            },
        }
    }

    fn flushAppendOnlyAccumulator(self: *Index, txn: anytype, accumulator: *AppendOnlyAccumulator) !void {
        try self.flushAccumulator(txn, accumulator, false);
    }

    fn flushAccumulator(self: *Index, txn: anytype, accumulator: *AppendOnlyAccumulator, omit_empty_rows: bool) !void {
        var support_it = accumulator.support_counts.iterator();
        while (support_it.next()) |entry| {
            const pending = entry.value_ptr;
            const delta_count = try tensor_mod.countSupportValueAlloc(self.alloc, pending.row);
            if (delta_count == 0) continue;
            const delta = try algebra.encodeI64Alloc(self.alloc, delta_count);
            defer self.alloc.free(delta);
            const old_support = txn.get(pending.key) catch |err| switch (err) {
                error.NotFound => null,
                else => return err,
            };
            var support_mutation = try tensor_mod.applyCountSupportDeltaBytesAlloc(self.alloc, old_support, delta);
            defer support_mutation.deinit(self.alloc);
            if (support_mutation.encoded) |encoded_support| {
                try txn.put(pending.key, encoded_support);
            } else {
                txn.delete(pending.key) catch |err| switch (err) {
                    error.NotFound => {},
                    else => return err,
                };
            }
        }

        var expression_it = accumulator.expression_rows.iterator();
        while (expression_it.next()) |entry| {
            const pending = entry.value_ptr;
            const old_row = txn.get(pending.key) catch |err| switch (err) {
                error.NotFound => null,
                else => return err,
            };
            var deltas = std.ArrayListUnmanaged(tensor_mod.SlotDelta).empty;
            defer deltas.deinit(self.alloc);
            const pending_slots = try pending.slotDeltasAlloc(self.alloc);
            defer {
                for (pending_slots) |*slot| slot.deinit(self.alloc);
                if (pending_slots.len > 0) self.alloc.free(pending_slots);
            }
            for (pending_slots) |pending_slot| {
                try deltas.append(self.alloc, .{
                    .slot_idx = pending_slot.slot_idx,
                    .law_id = pending_slot.law_id,
                    .delta = pending_slot.delta,
                });
            }
            if (deltas.items.len == 0) continue;

            const encoded = try tensor_mod.applyRowSlotsToBytesAlloc(self.alloc, old_row, pending.law_ids, deltas.items, omit_empty_rows);
            if (encoded) |bytes| {
                defer self.alloc.free(bytes);
                try txn.put(pending.key, bytes);
            } else {
                txn.delete(pending.key) catch |err| switch (err) {
                    error.NotFound => {},
                    else => return err,
                };
            }
        }
    }

    fn minMaxCacheKeyAlloc(self: *Index, expr_id: []const u8, support_group_id: []const u8) ![]u8 {
        return try self.keyAlloc(&.{ "minmax_cache", expr_id, support_group_id });
    }

    fn readMinMaxCandidatesAlloc(self: *Index, txn: anytype, cache_key: []const u8) ![]MinMaxCandidate {
        const raw = txn.get(cache_key) catch |err| switch (err) {
            error.NotFound => return try self.alloc.alloc(MinMaxCandidate, 0),
            else => return err,
        };
        const decoded = try token.decodeTupleAlloc(self.alloc, raw);
        defer if (decoded.len > 0) self.alloc.free(decoded);
        var out = std.ArrayListUnmanaged(MinMaxCandidate).empty;
        errdefer {
            for (out.items) |*candidate| candidate.deinit(self.alloc);
            out.deinit(self.alloc);
        }
        for (decoded) |support_token| {
            const raw_text = token.scalarTokenTextAlloc(self.alloc, support_token) catch {
                self.alloc.free(support_token);
                continue;
            };
            const value = algebra.parseF64(raw_text) catch {
                self.alloc.free(raw_text);
                self.alloc.free(support_token);
                continue;
            };
            try out.append(self.alloc, .{
                .support_token = support_token,
                .raw = raw_text,
                .value = value,
            });
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn freeMinMaxCandidates(self: *Index, candidates: []MinMaxCandidate) void {
        for (candidates) |*candidate| candidate.deinit(self.alloc);
        if (candidates.len > 0) self.alloc.free(candidates);
    }

    fn writeMinMaxCandidates(self: *Index, txn: anytype, cache_key: []const u8, candidates: []const MinMaxCandidate, limit: usize) !void {
        if (limit == 0 or candidates.len == 0) return;
        const kept = @min(limit, candidates.len);
        const parts = try self.alloc.alloc([]const u8, kept);
        defer self.alloc.free(parts);
        for (parts, 0..) |*part, i| part.* = candidates[i].support_token;
        const encoded = try token.canonicalTupleAlloc(self.alloc, parts);
        defer self.alloc.free(encoded);
        try txn.put(cache_key, encoded);
    }

    fn sortMinMaxCandidates(_: *Index, candidates: []MinMaxCandidate, op: algebra.Op) void {
        std.mem.sort(MinMaxCandidate, candidates, op, struct {
            fn lessThan(ctx: algebra.Op, lhs: MinMaxCandidate, rhs: MinMaxCandidate) bool {
                if (lhs.value == rhs.value) return std.mem.order(u8, lhs.support_token, rhs.support_token) == .lt;
                return if (ctx == .min) lhs.value < rhs.value else lhs.value > rhs.value;
            }
        }.lessThan);
    }

    fn updateMinMaxCandidateCache(
        self: *Index,
        txn: anytype,
        expr_id: []const u8,
        support_group_id: []const u8,
        op: algebra.Op,
        measure: MeasureValue,
    ) !void {
        const limit = self.minMaxCandidateCacheSize();
        if (limit == 0) return;
        const cache_key = try self.minMaxCacheKeyAlloc(expr_id, support_group_id);
        defer self.alloc.free(cache_key);
        var candidates = try self.readMinMaxCandidatesAlloc(txn, cache_key);
        defer self.freeMinMaxCandidates(candidates);

        var exists = false;
        for (candidates) |candidate| {
            if (std.mem.eql(u8, candidate.support_token, measure.support_token)) {
                exists = true;
                break;
            }
        }
        if (!exists) {
            const next = try self.alloc.realloc(candidates, candidates.len + 1);
            candidates = next;
            candidates[candidates.len - 1] = .{
                .support_token = try self.alloc.dupe(u8, measure.support_token),
                .raw = try self.alloc.dupe(u8, measure.raw),
                .value = try algebra.parseF64(measure.raw),
            };
        }
        self.sortMinMaxCandidates(candidates, op);
        try self.writeMinMaxCandidates(txn, cache_key, candidates, limit);
    }

    fn cachedMinMaxCandidateAlloc(
        self: *Index,
        txn: anytype,
        expr_id: []const u8,
        support_group_id: []const u8,
        op: algebra.Op,
    ) !?[]u8 {
        const limit = self.minMaxCandidateCacheSize();
        if (limit == 0) {
            self.minmax_cache_misses += 1;
            return null;
        }
        const cache_key = try self.minMaxCacheKeyAlloc(expr_id, support_group_id);
        defer self.alloc.free(cache_key);
        const candidates = try self.readMinMaxCandidatesAlloc(txn, cache_key);
        defer self.freeMinMaxCandidates(candidates);
        self.sortMinMaxCandidates(candidates, op);
        for (candidates) |candidate| {
            const measure_id = try symbol.idAlloc(self.alloc, candidate.support_token);
            defer self.alloc.free(measure_id);
            const support_key = try self.keyAlloc(&.{ "minmax", expr_id, support_group_id, measure_id });
            defer self.alloc.free(support_key);
            const support = txn.get(support_key) catch |err| switch (err) {
                error.NotFound => continue,
                else => return err,
            };
            if ((try tensor_mod.countSupportValueAlloc(self.alloc, support)) <= 0) continue;
            self.minmax_cache_hits += 1;
            return try self.alloc.dupe(u8, candidate.raw);
        }
        self.minmax_cache_misses += 1;
        return null;
    }

    fn updateMinMaxExpressionCurrent(
        self: *Index,
        txn: anytype,
        expr_id: []const u8,
        support_group_key: []const u8,
        op: algebra.Op,
        old_current_raw: ?[]const u8,
        measure: MeasureValue,
        sign: i8,
    ) !?[]u8 {
        const support_group_id = try self.ensureSymbol(txn, support_group_key);
        defer self.alloc.free(support_group_id);
        const measure_id = try self.ensureSymbol(txn, measure.support_token);
        defer self.alloc.free(measure_id);
        const support_key = try self.keyAlloc(&.{ "minmax", expr_id, support_group_id, measure_id });
        defer self.alloc.free(support_key);
        const old_support = txn.get(support_key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        var support_mutation = try tensor_mod.applyCountSupportDeltaAlloc(self.alloc, old_support, sign);
        defer support_mutation.deinit(self.alloc);
        if (support_mutation.encoded) |encoded_support| {
            try txn.put(support_key, encoded_support);
        } else {
            txn.delete(support_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
        }
        if (sign > 0) try self.updateMinMaxCandidateCache(txn, expr_id, support_group_id, op, measure);

        const measure_f = try algebra.parseF64(measure.raw);
        if (sign > 0) {
            if (old_current_raw) |old_raw| {
                const old_f = try algebra.parseF64(old_raw);
                const replace = if (op == .min) measure_f < old_f else measure_f > old_f;
                return try self.alloc.dupe(u8, if (replace) measure.raw else old_raw);
            }
            return try self.alloc.dupe(u8, measure.raw);
        }

        const old_current = if (old_current_raw) |old_raw| try algebra.parseF64(old_raw) else return null;
        if (old_current != measure_f) return try self.alloc.dupe(u8, old_current_raw.?);
        if (support_mutation.next_count > 0) return try self.alloc.dupe(u8, old_current_raw.?);
        if (try self.cachedMinMaxCandidateAlloc(txn, expr_id, support_group_id, op)) |cached| return cached;
        return try self.scanMinMaxSupport(txn, expr_id, support_group_id, op);
    }

    fn scanMinMaxSupport(
        self: *Index,
        txn: anytype,
        expr_id: []const u8,
        support_group_id: []const u8,
        op: algebra.Op,
    ) !?[]u8 {
        self.minmax_support_scans += 1;
        const prefix = try self.keyAlloc(&.{ "minmax", expr_id, support_group_id });
        defer self.alloc.free(prefix);
        var cursor = try txn.openCursor();
        defer cursor.close();
        var symbols = SymbolCache{};
        defer symbols.deinit(self.alloc);
        var best_value: ?f64 = null;
        var best_raw: ?[]u8 = null;
        var candidates = std.ArrayListUnmanaged(MinMaxCandidate).empty;
        defer {
            for (candidates.items) |*candidate| candidate.deinit(self.alloc);
            candidates.deinit(self.alloc);
        }
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            if ((try tensor_mod.countSupportValueAlloc(self.alloc, entry.value)) <= 0) continue;
            const component = token.componentAt(entry.key, prefix.len) catch continue;
            if (component.next != entry.key.len) continue;
            const measure_token = (try symbols.resolve(self, txn, component.payload)) orelse continue;
            const value_bytes = token.scalarTokenTextAlloc(self.alloc, measure_token) catch continue;
            defer self.alloc.free(value_bytes);
            const value = algebra.parseF64(value_bytes) catch continue;
            if (self.minMaxCandidateCacheSize() > 0) {
                try candidates.append(self.alloc, .{
                    .support_token = try self.alloc.dupe(u8, measure_token),
                    .raw = try self.alloc.dupe(u8, value_bytes),
                    .value = value,
                });
            }
            const replace = if (best_value) |best|
                if (op == .min) value < best else value > best
            else
                true;
            if (replace) {
                if (best_raw) |raw| self.alloc.free(raw);
                best_raw = try self.alloc.dupe(u8, value_bytes);
                best_value = value;
            }
        }
        if (candidates.items.len > 0 and self.minMaxCandidateCacheSize() > 0) {
            self.sortMinMaxCandidates(candidates.items, op);
            const cache_key = try self.minMaxCacheKeyAlloc(expr_id, support_group_id);
            defer self.alloc.free(cache_key);
            try self.writeMinMaxCandidates(txn, cache_key, candidates.items, self.minMaxCandidateCacheSize());
        }
        return best_raw;
    }

    fn removeDoc(self: *Index, txn: anytype, doc_key: []const u8, maintenance_context: ?*BatchMaintenanceContext) !void {
        try self.deletePathFacts(txn, doc_key, maintenance_context);

        const fact_key = try self.docFactKey(doc_key);
        defer self.alloc.free(fact_key);
        const fact_payload = txn.get(fact_key) catch |err| switch (err) {
            error.NotFound => return,
            else => return err,
        };
        var facts = fact_mod.decodeListAlloc(self.alloc, fact_payload) catch {
            txn.delete(fact_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            return;
        };
        defer facts.deinit(self.alloc);

        try self.applyDocFactDelta(txn, doc_key, facts.facts, -1);
        try self.markHllCardinalitiesDirtyForFactsTxn(txn, facts.facts);
        try self.applyAdaptiveDocFactDelta(txn, facts.facts, -1, maintenance_context);
        if (self.config().joins.len > 0) {
            try self.applyStoredJoinFactsForDocDelta(txn, doc_key, -1, maintenance_context);
        }
        try self.deleteDocFactLookupRows(txn, doc_key, facts.facts);
        txn.delete(fact_key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
        self.doc_fact_delete_count += 1;
    }

    fn addDoc(self: *Index, txn: anytype, doc_key: []const u8, value: []const u8, maintenance_context: ?*BatchMaintenanceContext) !void {
        if (try self.tryUpdateDocCoalesced(txn, doc_key, value, maintenance_context)) return;
        try self.removeDoc(txn, doc_key, maintenance_context);
        try self.writeDocFacts(txn, doc_key, value, maintenance_context);
        try self.applyWrittenAdaptiveDocFactDelta(txn, doc_key, 1, maintenance_context);
        try self.applyDocDelta(txn, doc_key, value, 1, maintenance_context);
    }

    fn tryUpdateDocCoalesced(self: *Index, txn: anytype, doc_key: []const u8, value: []const u8, maintenance_context: ?*BatchMaintenanceContext) !bool {
        const fact_key = try self.docFactKey(doc_key);
        defer self.alloc.free(fact_key);
        const old_fact_payload = txn.get(fact_key) catch |err| switch (err) {
            error.NotFound => return false,
            else => return err,
        };
        var old_facts = fact_mod.decodeListAlloc(self.alloc, old_fact_payload) catch return false;
        defer old_facts.deinit(self.alloc);

        const path_key = try self.pathFactKey(doc_key);
        defer self.alloc.free(path_key);
        const old_path_payload = txn.get(path_key) catch |err| switch (err) {
            error.NotFound => return false,
            else => return err,
        };
        var old_projection = pathfact_mod.decodeProjectionAlloc(self.alloc, old_path_payload) catch return false;
        defer old_projection.deinit(self.alloc);

        var parsed = std.json.parseFromSlice(std.json.Value, self.alloc, value, .{}) catch return false;
        defer parsed.deinit();
        if (parsed.value != .object) return false;

        const specs = try self.factSpecsAlloc();
        defer self.alloc.free(specs);
        var new_facts = try fact_mod.projectDocumentAlloc(self.alloc, specs, parsed.value);
        defer new_facts.deinit(self.alloc);
        const new_fact_payload = try fact_mod.encodeListAlloc(self.alloc, new_facts.facts);
        defer self.alloc.free(new_fact_payload);

        var new_projection = try pathfact_mod.projectJsonValueAlloc(self.alloc, parsed.value);
        defer new_projection.deinit(self.alloc);
        const new_path_payload = try pathfact_mod.encodeProjectionAlloc(self.alloc, new_projection);
        defer self.alloc.free(new_path_payload);

        const doc_facts_changed = !std.mem.eql(u8, old_fact_payload, new_fact_payload);
        const path_facts_changed = !pathFactListsEqual(old_projection.facts, new_projection.facts);
        const path_profiles_changed = !pathProfileListsEqual(old_projection.profiles, new_projection.profiles);

        if (path_facts_changed) {
            try self.applyReadyPathPromotionRemovedDelta(txn, doc_key, old_projection.facts, new_projection.facts, maintenance_context);
        }
        try self.updateDocFactRowsCoalesced(txn, fact_key, old_fact_payload, old_facts.facts, new_fact_payload, new_facts.facts, doc_key);
        try self.updatePathFactRowsCoalesced(txn, path_key, old_path_payload, old_projection.facts, new_path_payload, new_projection.facts, doc_key);

        if (self.shouldMaintainPathProfiles() and path_profiles_changed) {
            try self.applyPathProfileDelta(txn, old_projection.profiles, -1);
        }
        if (doc_facts_changed) {
            try self.applyDocFactDelta(txn, doc_key, old_facts.facts, -1);
            // The old value cannot be subtracted from an HLL sketch, so mark a
            // materialization dirty when this update changed a field it reads;
            // the maintenance pass then rebuilds it exactly from surviving facts.
            // Unrelated field changes (e.g. a measure) leave the sketch alone.
            try self.markHllCardinalitiesDirtyForUpdateTxn(txn, old_facts.facts, new_facts.facts);
            try self.applyAdaptiveDocFactDelta(txn, old_facts.facts, -1, maintenance_context);
        }
        if (self.config().joins.len > 0) {
            try self.applyStoredJoinFactsForDocDelta(txn, doc_key, -1, maintenance_context);
        }

        if (self.shouldMaintainPathProfiles() and path_profiles_changed) {
            try self.applyPathProfileDelta(txn, new_projection.profiles, 1);
        }
        if (path_facts_changed) {
            try self.applyReadyPathPromotionAddedDelta(txn, doc_key, old_projection.facts, new_projection.facts, maintenance_context);
        }
        if (doc_facts_changed) {
            try self.applyAdaptiveDocFactDelta(txn, new_facts.facts, 1, maintenance_context);
            try self.applyDocFactDelta(txn, doc_key, new_facts.facts, 1);
            // Fold the new value into the sketches so warm reads stay close until
            // the dirty rebuild lands. Only materializations whose group/value
            // changed were marked dirty above; folding the others is harmless
            // (idempotent re-union of a value already present) but we skip it for
            // the unchanged ones via the same change check.
            try self.applyHllCardinalitiesForUpdatedFactsTxn(txn, old_facts.facts, new_facts.facts);
        }
        if (self.config().joins.len > 0) {
            try self.applyDocJoinDelta(txn, doc_key, parsed.value, 1, maintenance_context);
        }

        if (doc_facts_changed) {
            self.doc_fact_delete_count += 1;
            self.doc_fact_write_count += 1;
        }
        return true;
    }

    fn writeDocFacts(self: *Index, txn: anytype, doc_key: []const u8, value: []const u8, maintenance_context: ?*BatchMaintenanceContext) !void {
        var parsed = std.json.parseFromSlice(std.json.Value, self.alloc, value, .{}) catch return;
        defer parsed.deinit();
        if (parsed.value != .object) return;
        const specs = try self.factSpecsAlloc();
        defer self.alloc.free(specs);
        var facts = try fact_mod.projectDocumentAlloc(self.alloc, specs, parsed.value);
        defer facts.deinit(self.alloc);
        const encoded = try fact_mod.encodeListAlloc(self.alloc, facts.facts);
        defer self.alloc.free(encoded);
        const fact_key = try self.docFactKey(doc_key);
        defer self.alloc.free(fact_key);
        try txn.put(fact_key, encoded);
        try self.writeDocFactLookupRows(txn, doc_key, facts.facts);
        try self.writePathFacts(txn, doc_key, parsed.value, maintenance_context);
        // Fold the new document into the HLL cardinality sketches from its facts
        // (rather than the raw JSON), so this add path, the coalesced-update path,
        // and the delete-triggered rebuild all tokenize values identically. This
        // is the single add hook for every fresh-document path (plain ingest and
        // the append-only bulk path both route through writeDocFacts).
        try self.applyHllCardinalitiesForFactsTxn(txn, facts.facts);
        self.doc_fact_write_count += 1;
    }

    fn writeDocFactLookupRows(self: *Index, txn: anytype, doc_key: []const u8, facts: []const fact_mod.Fact) !void {
        for (facts) |fact| {
            const scalar_key = try self.docFactScalarKeyAlloc(fact.role, fact.field, fact.scalar, doc_key);
            defer self.alloc.free(scalar_key);
            try txn.put(scalar_key, "");
            try self.writeDocFactScalarOrdinalIfAvailableTxn(txn, fact.role, fact.field, fact.scalar, doc_key);

            const field_key = try self.docFactFieldKeyAlloc(fact.role, fact.field, doc_key);
            defer self.alloc.free(field_key);
            try txn.put(field_key, "");
            try self.writeDocFactFieldOrdinalIfAvailableTxn(txn, fact.role, fact.field, doc_key);
        }
    }

    fn updateDocFactRowsCoalesced(
        self: *Index,
        txn: anytype,
        fact_key: []const u8,
        old_payload: []const u8,
        old_facts: []const fact_mod.Fact,
        new_payload: []const u8,
        new_facts: []const fact_mod.Fact,
        doc_key: []const u8,
    ) !void {
        try self.updateDocFactLookupRowsCoalesced(txn, doc_key, old_facts, new_facts);
        if (!std.mem.eql(u8, old_payload, new_payload)) {
            try txn.put(fact_key, new_payload);
        }
    }

    fn updateDocFactLookupRowsCoalesced(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        old_facts: []const fact_mod.Fact,
        new_facts: []const fact_mod.Fact,
    ) !void {
        for (old_facts) |old_fact| {
            if (!docFactListContainsExact(new_facts, old_fact)) {
                const scalar_key = try self.docFactScalarKeyAlloc(old_fact.role, old_fact.field, old_fact.scalar, doc_key);
                defer self.alloc.free(scalar_key);
                txn.delete(scalar_key) catch |err| switch (err) {
                    error.NotFound => {},
                    else => return err,
                };
                try self.deleteDocFactScalarOrdinalIfAvailableTxn(txn, old_fact.role, old_fact.field, old_fact.scalar, doc_key);
            }
            if (!docFactListContainsField(new_facts, old_fact.role, old_fact.field)) {
                const field_key = try self.docFactFieldKeyAlloc(old_fact.role, old_fact.field, doc_key);
                defer self.alloc.free(field_key);
                txn.delete(field_key) catch |err| switch (err) {
                    error.NotFound => {},
                    else => return err,
                };
                try self.deleteDocFactFieldOrdinalIfAvailableTxn(txn, old_fact.role, old_fact.field, doc_key);
            }
        }
        for (new_facts) |new_fact| {
            if (!docFactListContainsExact(old_facts, new_fact)) {
                const scalar_key = try self.docFactScalarKeyAlloc(new_fact.role, new_fact.field, new_fact.scalar, doc_key);
                defer self.alloc.free(scalar_key);
                try txn.put(scalar_key, "");
                try self.writeDocFactScalarOrdinalIfAvailableTxn(txn, new_fact.role, new_fact.field, new_fact.scalar, doc_key);
            }
            if (!docFactListContainsField(old_facts, new_fact.role, new_fact.field)) {
                const field_key = try self.docFactFieldKeyAlloc(new_fact.role, new_fact.field, doc_key);
                defer self.alloc.free(field_key);
                try txn.put(field_key, "");
                try self.writeDocFactFieldOrdinalIfAvailableTxn(txn, new_fact.role, new_fact.field, doc_key);
            }
        }
    }

    fn deleteDocFactLookupRows(self: *Index, txn: anytype, doc_key: []const u8, facts: []const fact_mod.Fact) !void {
        for (facts) |fact| {
            const scalar_key = try self.docFactScalarKeyAlloc(fact.role, fact.field, fact.scalar, doc_key);
            defer self.alloc.free(scalar_key);
            txn.delete(scalar_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            try self.deleteDocFactScalarOrdinalIfAvailableTxn(txn, fact.role, fact.field, fact.scalar, doc_key);

            const field_key = try self.docFactFieldKeyAlloc(fact.role, fact.field, doc_key);
            defer self.alloc.free(field_key);
            txn.delete(field_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            try self.deleteDocFactFieldOrdinalIfAvailableTxn(txn, fact.role, fact.field, doc_key);
        }
    }

    fn writeDocFactScalarOrdinalIfAvailableTxn(
        self: *Index,
        txn: anytype,
        role: fact_mod.Role,
        field: []const u8,
        scalar: []const u8,
        doc_key: []const u8,
    ) !void {
        const ordinal = (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key)) orelse return;
        const key = try self.docFactScalarOrdinalKeyAlloc(role, field, scalar, ordinal);
        defer self.alloc.free(key);
        try txn.put(key, "");
    }

