    fn writePathFacts(self: *Index, txn: anytype, doc_key: []const u8, root: std.json.Value, maintenance_context: ?*BatchMaintenanceContext) !void {
        var projection = try pathfact_mod.projectJsonValueAlloc(self.alloc, root);
        defer projection.deinit(self.alloc);
        const encoded = try pathfact_mod.encodeProjectionAlloc(self.alloc, projection);
        defer self.alloc.free(encoded);
        const path_key = try self.pathFactKey(doc_key);
        defer self.alloc.free(path_key);
        try txn.put(path_key, encoded);
        try self.writePathFactOrdinalIfAvailableTxn(txn, doc_key, encoded);
        try self.writePathFactLookupRows(txn, doc_key, projection.facts);
        if (self.shouldMaintainPathProfiles()) {
            try self.applyPathProfileDelta(txn, projection.profiles, 1);
        }
        try self.applyReadyPathPromotionDelta(txn, doc_key, projection.facts, 1, maintenance_context);
    }

    fn writePathFactOrdinalIfAvailableTxn(self: *Index, txn: anytype, doc_key: []const u8, payload: []const u8) !void {
        const ordinal = (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key)) orelse return;
        const key = try self.pathFactOrdinalKey(ordinal);
        defer self.alloc.free(key);
        try txn.put(key, payload);
    }

    fn deletePathFactOrdinalIfAvailableTxn(self: *Index, txn: anytype, doc_key: []const u8) !void {
        const ordinal = (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key)) orelse return;
        const key = try self.pathFactOrdinalKey(ordinal);
        defer self.alloc.free(key);
        txn.delete(key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
    }

    fn writePathFactLookupRows(self: *Index, txn: anytype, doc_key: []const u8, facts: []const pathfact_mod.Fact) !void {
        const ordinal = try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key);
        for (facts) |fact| {
            const lookup_key = try self.pathLookupKeyAlloc(fact.path, fact.kind, fact.value, doc_key);
            defer self.alloc.free(lookup_key);
            try txn.put(lookup_key, "");
            if (ordinal) |doc_ordinal| {
                const ordinal_key = try self.pathLookupOrdinalKeyAlloc(fact.path, fact.kind, fact.value, doc_ordinal);
                defer self.alloc.free(ordinal_key);
                try txn.put(ordinal_key, "");
            }
        }
    }

    fn updatePathFactRowsCoalesced(
        self: *Index,
        txn: anytype,
        path_key: []const u8,
        old_payload: []const u8,
        old_facts: []const pathfact_mod.Fact,
        new_payload: []const u8,
        new_facts: []const pathfact_mod.Fact,
        doc_key: []const u8,
    ) !void {
        try self.updatePathFactLookupRowsCoalesced(txn, doc_key, old_facts, new_facts);
        if (!std.mem.eql(u8, old_payload, new_payload)) {
            try txn.put(path_key, new_payload);
            try self.writePathFactOrdinalIfAvailableTxn(txn, doc_key, new_payload);
        }
    }

    fn updatePathFactLookupRowsCoalesced(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        old_facts: []const pathfact_mod.Fact,
        new_facts: []const pathfact_mod.Fact,
    ) !void {
        const ordinal = try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key);
        for (old_facts) |old_fact| {
            if (pathFactListContainsExact(new_facts, old_fact)) continue;
            const lookup_key = try self.pathLookupKeyAlloc(old_fact.path, old_fact.kind, old_fact.value, doc_key);
            defer self.alloc.free(lookup_key);
            txn.delete(lookup_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            if (ordinal) |doc_ordinal| {
                const ordinal_key = try self.pathLookupOrdinalKeyAlloc(old_fact.path, old_fact.kind, old_fact.value, doc_ordinal);
                defer self.alloc.free(ordinal_key);
                txn.delete(ordinal_key) catch |err| switch (err) {
                    error.NotFound => {},
                    else => return err,
                };
            }
        }
        for (new_facts) |new_fact| {
            if (pathFactListContainsExact(old_facts, new_fact)) continue;
            const lookup_key = try self.pathLookupKeyAlloc(new_fact.path, new_fact.kind, new_fact.value, doc_key);
            defer self.alloc.free(lookup_key);
            try txn.put(lookup_key, "");
            if (ordinal) |doc_ordinal| {
                const ordinal_key = try self.pathLookupOrdinalKeyAlloc(new_fact.path, new_fact.kind, new_fact.value, doc_ordinal);
                defer self.alloc.free(ordinal_key);
                try txn.put(ordinal_key, "");
            }
        }
    }

    fn deletePathFacts(self: *Index, txn: anytype, doc_key: []const u8, maintenance_context: ?*BatchMaintenanceContext) !void {
        const path_key = try self.pathFactKey(doc_key);
        defer self.alloc.free(path_key);
        const payload = txn.get(path_key) catch |err| switch (err) {
            error.NotFound => return,
            else => return err,
        };
        var projection = pathfact_mod.decodeProjectionAlloc(self.alloc, payload) catch {
            txn.delete(path_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            try self.deletePathFactOrdinalIfAvailableTxn(txn, doc_key);
            return;
        };
        defer projection.deinit(self.alloc);
        try self.applyReadyPathPromotionDelta(txn, doc_key, projection.facts, -1, maintenance_context);
        try self.deletePathFactLookupRows(txn, doc_key, projection.facts);
        if (self.shouldMaintainPathProfiles()) {
            try self.applyPathProfileDelta(txn, projection.profiles, -1);
        }
        txn.delete(path_key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
        try self.deletePathFactOrdinalIfAvailableTxn(txn, doc_key);
    }

    fn deletePathFactLookupRows(self: *Index, txn: anytype, doc_key: []const u8, facts: []const pathfact_mod.Fact) !void {
        const ordinal = try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key);
        for (facts) |fact| {
            const lookup_key = try self.pathLookupKeyAlloc(fact.path, fact.kind, fact.value, doc_key);
            defer self.alloc.free(lookup_key);
            txn.delete(lookup_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            if (ordinal) |doc_ordinal| {
                const ordinal_key = try self.pathLookupOrdinalKeyAlloc(fact.path, fact.kind, fact.value, doc_ordinal);
                defer self.alloc.free(ordinal_key);
                txn.delete(ordinal_key) catch |err| switch (err) {
                    error.NotFound => {},
                    else => return err,
                };
            }
        }
    }

    fn applyReadyPathPromotionDelta(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        facts: []const pathfact_mod.Fact,
        sign: i8,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        if (!self.shouldMaintainReadyAdaptiveMaterializations()) return;
        if (maintenance_context) |ctx| {
            try self.applyReadyPathPromotionDeltaFromSpecs(txn, doc_key, facts, sign, ctx, ctx.ready_specs);
            return;
        }
        const progress_rows = try self.scanPersistedAdaptiveProgressTxn(txn);
        defer {
            for (progress_rows) |*progress| progress.deinit(self.alloc);
            if (progress_rows.len > 0) self.alloc.free(progress_rows);
        }
        for (progress_rows) |progress| {
            if (progress.lifecycle != .ready) continue;
            if (!self.adaptiveProgressMatchesCurrentConfig(progress)) continue;
            if (!(try self.persistedMaterializationStateReadyTxn(txn, progress.recommendation))) continue;
            var spec = self.adaptiveSpecFromRecommendationAlloc(progress.materialization_id, progress.recommendation) catch continue;
            defer spec.deinit(self.alloc);
            try self.applyReadyPathPromotionDeltaForSpec(txn, spec, doc_key, facts, sign, null);
        }
    }

    fn applyReadyPathPromotionRemovedDelta(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        old_facts: []const pathfact_mod.Fact,
        new_facts: []const pathfact_mod.Fact,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        const changed = try self.changedPathFactsAlloc(old_facts, new_facts);
        defer if (changed.len > 0) self.alloc.free(changed);
        if (changed.len == 0) return;
        try self.applyReadyPathPromotionDelta(txn, doc_key, changed, -1, maintenance_context);
    }

    fn applyReadyPathPromotionAddedDelta(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        old_facts: []const pathfact_mod.Fact,
        new_facts: []const pathfact_mod.Fact,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        const changed = try self.changedPathFactsAlloc(new_facts, old_facts);
        defer if (changed.len > 0) self.alloc.free(changed);
        if (changed.len == 0) return;
        try self.applyReadyPathPromotionDelta(txn, doc_key, changed, 1, maintenance_context);
    }

    fn changedPathFactsAlloc(self: *Index, source: []const pathfact_mod.Fact, comparison: []const pathfact_mod.Fact) ![]pathfact_mod.Fact {
        var out = std.ArrayListUnmanaged(pathfact_mod.Fact).empty;
        errdefer out.deinit(self.alloc);
        for (source) |fact| {
            if (pathFactListContainsExact(comparison, fact)) continue;
            try out.append(self.alloc, fact);
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn applyReadyPathPromotionDeltaFromSpecs(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        facts: []const pathfact_mod.Fact,
        sign: i8,
        maintenance_context: *BatchMaintenanceContext,
        specs: []const AdaptiveMaterializationSpec,
    ) !void {
        for (specs) |spec| {
            if (maintenance_context.isDisabled(spec.recommendation)) continue;
            if (spec.path_promotion_path == null) continue;
            try self.applyReadyPathPromotionDeltaForSpec(txn, spec, doc_key, facts, sign, maintenance_context);
        }
    }

    fn applyReadyPathPromotionDeltaForSpec(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
        doc_key: []const u8,
        facts: []const pathfact_mod.Fact,
        sign: i8,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        const path = spec.path_promotion_path orelse return;
        const promoted_kind = spec.path_promotion_kind;
        const owns_dictionary = try self.pathPromotionOwnsDictionaryTxn(txn, spec);
        var seen_facts = std.StringHashMapUnmanaged(void).empty;
        defer {
            var seen_it = seen_facts.keyIterator();
            while (seen_it.next()) |key| self.alloc.free(key.*);
            seen_facts.deinit(self.alloc);
        }
        for (facts) |fact| {
            if (!std.mem.eql(u8, fact.path, path)) continue;
            if (promoted_kind) |kind| {
                if (fact.kind != kind) continue;
            }
            const fact_key = try token.canonicalTupleAlloc(self.alloc, &.{ fact.path, fact.kind.tag(), fact.value });
            const gop = try seen_facts.getOrPut(self.alloc, fact_key);
            if (gop.found_existing) {
                self.alloc.free(fact_key);
                continue;
            }
            gop.key_ptr.* = fact_key;
            try self.applyReadyPathPromotionFactDelta(txn, spec, fact, doc_key, sign, owns_dictionary, maintenance_context);
        }
    }

    fn applyReadyPathPromotionFactDelta(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
        fact: pathfact_mod.Fact,
        doc_key: []const u8,
        sign: i8,
        owns_dictionary: bool,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        const axes_canonical = try token.canonicalTupleAlloc(self.alloc, &.{ fact.kind.tag(), fact.value });
        defer self.alloc.free(axes_canonical);
        const delta = try algebra.encodeI64Alloc(self.alloc, sign);
        defer self.alloc.free(delta);

        if (maintenance_context) |ctx| {
            if (ctx.coalesce_tensor_deltas) {
                try self.accumulateAdaptiveTensorDelta(txn, &ctx.tensor_accumulator, spec, axes_canonical, null, .count, delta);
            } else {
                try self.applyAdaptivePathPromotionTensorDeltaTxn(txn, spec, axes_canonical, delta);
            }
        } else {
            try self.applyAdaptivePathPromotionTensorDeltaTxn(txn, spec, axes_canonical, delta);
        }

        if (sign > 0) {
            try self.writeReadyPathPromotionLookupRows(txn, spec, fact, doc_key, owns_dictionary, maintenance_context);
        } else {
            try self.deleteReadyPathPromotionLookupRows(txn, spec, fact, doc_key, owns_dictionary, maintenance_context);
        }
    }

    fn applyAdaptivePathPromotionTensorDeltaTxn(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
        axes_canonical: []const u8,
        delta: []const u8,
    ) !void {
        const axes_id = try self.ensureSymbol(txn, axes_canonical);
        self.alloc.free(axes_id);
        const key = try tensor_mod.keyAlloc(self.alloc, self.name, .{
            .materialization = spec.name,
            .axes_canonical = axes_canonical,
            .bucket = null,
        });
        defer self.alloc.free(key);
        const existing = txn.get(key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        const encoded = try tensor_mod.applyRowSlotToBytesAlloc(self.alloc, existing, &.{.count}, 0, .count, delta, true);
        if (encoded) |bytes| {
            defer self.alloc.free(bytes);
            try txn.put(key, bytes);
        } else {
            txn.delete(key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
        }
        try self.applyAdaptiveExpressionDeltaTxn(txn, spec, axes_canonical, null, .count, delta);
    }

    fn writeReadyPathPromotionLookupRows(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
        fact: pathfact_mod.Fact,
        doc_key: []const u8,
        owns_dictionary: bool,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        const promoted_key = try self.promotedPathLookupKeyAlloc(spec.name, fact.path, fact.kind, fact.value, doc_key);
        defer self.alloc.free(promoted_key);
        try txn.put(promoted_key, "");
        if (owns_dictionary) {
            const identity = lexical_mod.DictionaryIdentity.canonicalScalar(self.name, fact.path, fact.kind, "json-scalar-v1", "kind-qualified");
            const lexicon_key = try self.pathDictionaryLexiconKeyAlloc(identity, fact.value);
            defer self.alloc.free(lexicon_key);
            try txn.put(lexicon_key, "");
            const posting_key = try self.pathDictionaryPostingsKeyAlloc(identity, fact.value, doc_key);
            defer self.alloc.free(posting_key);
            try txn.put(posting_key, "");
            try self.writePathDictionaryOrdinalPostingIfAvailableTxn(txn, identity, fact.value, doc_key);
            try self.rebuildOrDeferPathDictionaryFstTxn(txn, spec, maintenance_context);
        }
    }

    fn deleteReadyPathPromotionLookupRows(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
        fact: pathfact_mod.Fact,
        doc_key: []const u8,
        owns_dictionary: bool,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        const promoted_key = try self.promotedPathLookupKeyAlloc(spec.name, fact.path, fact.kind, fact.value, doc_key);
        defer self.alloc.free(promoted_key);
        txn.delete(promoted_key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
        if (owns_dictionary) {
            const identity = lexical_mod.DictionaryIdentity.canonicalScalar(self.name, fact.path, fact.kind, "json-scalar-v1", "kind-qualified");
            const posting_key = try self.pathDictionaryPostingsKeyAlloc(identity, fact.value, doc_key);
            defer self.alloc.free(posting_key);
            txn.delete(posting_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            try self.deletePathDictionaryOrdinalPostingIfAvailableTxn(txn, identity, fact.value, doc_key);
            const postings_prefix = try self.pathDictionaryPostingsPrefixAlloc(identity, fact.value);
            defer self.alloc.free(postings_prefix);
            if (!(try self.prefixHasAnyTxn(txn, postings_prefix))) {
                const lexicon_key = try self.pathDictionaryLexiconKeyAlloc(identity, fact.value);
                defer self.alloc.free(lexicon_key);
                txn.delete(lexicon_key) catch |err| switch (err) {
                    error.NotFound => {},
                    else => return err,
                };
            }
            try self.rebuildOrDeferPathDictionaryFstTxn(txn, spec, maintenance_context);
        }
    }

    fn writePathDictionaryOrdinalPostingIfAvailableTxn(
        self: *Index,
        txn: anytype,
        identity: lexical_mod.DictionaryIdentity,
        label: []const u8,
        doc_key: []const u8,
    ) !void {
        const ordinal = (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key)) orelse return;
        const key = try self.pathDictionaryOrdinalPostingsKeyAlloc(identity, label, ordinal);
        defer self.alloc.free(key);
        try txn.put(key, "");
    }

    fn deletePathDictionaryOrdinalPostingIfAvailableTxn(
        self: *Index,
        txn: anytype,
        identity: lexical_mod.DictionaryIdentity,
        label: []const u8,
        doc_key: []const u8,
    ) !void {
        const ordinal = (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key)) orelse return;
        const key = try self.pathDictionaryOrdinalPostingsKeyAlloc(identity, label, ordinal);
        defer self.alloc.free(key);
        txn.delete(key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
    }

    fn rebuildOrDeferPathDictionaryFstTxn(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        if (maintenance_context) |ctx| {
            try ctx.markPathPromotionDictionaryDirty(self.alloc, spec.name);
            return;
        }
        try self.rebuildPathDictionaryFstTxn(txn, spec);
    }

    fn rebuildPathDictionaryFstTxn(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
    ) !void {
        self.path_dictionary_fst_rebuild_count += 1;
        const path = spec.path_promotion_path orelse return;
        const kind = spec.path_promotion_kind orelse return;
        const identity = lexical_mod.DictionaryIdentity.canonicalScalar(self.name, path, kind, "json-scalar-v1", "kind-qualified");
        const lexicon_prefix = try self.pathDictionaryLexiconPrefixAlloc(identity);
        defer self.alloc.free(lexicon_prefix);
        const fst_key = try self.pathDictionaryFstKeyAlloc(identity);
        defer self.alloc.free(fst_key);

        var labels = std.ArrayListUnmanaged([]u8).empty;
        defer {
            for (labels.items) |label| self.alloc.free(label);
            labels.deinit(self.alloc);
        }
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(lexicon_prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, lexicon_prefix)) break;
            const label_component = token.componentAt(entry.key, lexicon_prefix.len) catch continue;
            if (label_component.next != entry.key.len) continue;
            try labels.append(self.alloc, try self.alloc.dupe(u8, label_component.payload));
        }
        if (labels.items.len == 0) {
            txn.delete(fst_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
            return;
        }
        const fst_bytes = try lexical_mod.buildFstAlloc(self.alloc, labels.items);
        defer self.alloc.free(fst_bytes);
        try txn.put(fst_key, fst_bytes);
    }

    fn pathPromotionOwnsDictionaryTxn(
        self: *Index,
        txn: anytype,
        spec: AdaptiveMaterializationSpec,
    ) !bool {
        const path = spec.path_promotion_path orelse return false;
        const kind = spec.path_promotion_kind orelse return false;
        const identity = lexical_mod.DictionaryIdentity.canonicalScalar(self.name, path, kind, "json-scalar-v1", "kind-qualified");
        const registry_key = try identity.registryKeyAlloc(self.alloc);
        defer self.alloc.free(registry_key);
        const payload = txn.get(registry_key) catch |err| switch (err) {
            error.NotFound => return false,
            else => return err,
        };
        var entry = lexical_mod.RegistryEntry.decodeAlloc(self.alloc, payload) catch return false;
        defer entry.deinit(self.alloc);
        return std.mem.eql(u8, entry.owner, spec.name) and
            entry.layout == .lexicon_postings_rows and
            std.mem.eql(u8, entry.state, "ready");
    }

    fn prefixHasAnyTxn(self: *Index, txn: anytype, prefix: []const u8) !bool {
        _ = self;
        var cursor = try txn.openCursor();
        defer cursor.close();
        const entry = try cursor.seekAtOrAfter(prefix);
        return if (entry) |found| std.mem.startsWith(u8, found.key, prefix) else false;
    }

    fn applyPathProfileDelta(self: *Index, txn: anytype, profiles: []const pathfact_mod.PathProfile, direction: i8) !void {
        for (profiles) |delta| {
            const key = try self.pathProfileKeyAlloc(delta.path);
            defer self.alloc.free(key);

            var current: pathfact_mod.PathProfile = if (txn.get(key)) |payload|
                try pathfact_mod.decodeProfileAlloc(self.alloc, delta.path, payload)
            else |err| switch (err) {
                error.NotFound => .{ .path = try self.alloc.dupe(u8, delta.path) },
                else => return err,
            };
            defer current.deinit(self.alloc);

            if (direction > 0) {
                current.null_count = try addU32(current.null_count, delta.null_count);
                current.bool_count = try addU32(current.bool_count, delta.bool_count);
                current.number_count = try addU32(current.number_count, delta.number_count);
                current.string_count = try addU32(current.string_count, delta.string_count);
                current.object_count = try addU32(current.object_count, delta.object_count);
                current.array_count = try addU32(current.array_count, delta.array_count);
                current.string_numeric_parse_success_count = try addU32(current.string_numeric_parse_success_count, delta.string_numeric_parse_success_count);
                current.string_numeric_parse_failure_count = try addU32(current.string_numeric_parse_failure_count, delta.string_numeric_parse_failure_count);
                current.string_datetime_parse_success_count = try addU32(current.string_datetime_parse_success_count, delta.string_datetime_parse_success_count);
                current.string_datetime_parse_failure_count = try addU32(current.string_datetime_parse_failure_count, delta.string_datetime_parse_failure_count);
                current.string_token_count = try addU32(current.string_token_count, delta.string_token_count);
                current.max_string_token_count = @max(current.max_string_token_count, delta.max_string_token_count);
            } else {
                const previous_max_string_token_count = current.max_string_token_count;
                current.null_count = try subU32(current.null_count, delta.null_count);
                current.bool_count = try subU32(current.bool_count, delta.bool_count);
                current.number_count = try subU32(current.number_count, delta.number_count);
                current.string_count = try subU32(current.string_count, delta.string_count);
                current.object_count = try subU32(current.object_count, delta.object_count);
                current.array_count = try subU32(current.array_count, delta.array_count);
                current.string_numeric_parse_success_count = try subU32(current.string_numeric_parse_success_count, delta.string_numeric_parse_success_count);
                current.string_numeric_parse_failure_count = try subU32(current.string_numeric_parse_failure_count, delta.string_numeric_parse_failure_count);
                current.string_datetime_parse_success_count = try subU32(current.string_datetime_parse_success_count, delta.string_datetime_parse_success_count);
                current.string_datetime_parse_failure_count = try subU32(current.string_datetime_parse_failure_count, delta.string_datetime_parse_failure_count);
                current.string_token_count = try subU32(current.string_token_count, delta.string_token_count);
                if (current.string_count == 0) {
                    current.max_string_token_count = 0;
                } else if (delta.max_string_token_count >= previous_max_string_token_count) {
                    current.max_string_token_count = try self.recomputePathProfileMaxStringTokenCountTxn(txn, delta.path);
                }
            }

            if (current.empty()) {
                txn.delete(key) catch |err| switch (err) {
                    error.NotFound => {},
                    else => return err,
                };
            } else {
                const encoded = try pathfact_mod.encodeProfileAlloc(self.alloc, current);
                defer self.alloc.free(encoded);
                try txn.put(key, encoded);
            }
        }
    }

    fn recomputePathProfileMaxStringTokenCountTxn(self: *Index, txn: anytype, path: []const u8) !u32 {
        const prefix = try self.pathLookupKindPrefixAlloc(path, .string);
        defer self.alloc.free(prefix);
        var max_tokens: u32 = 0;
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const value_component = token.componentAt(entry.key, prefix.len) catch continue;
            const doc_component = token.componentAt(entry.key, value_component.next) catch continue;
            if (doc_component.next != entry.key.len) continue;
            max_tokens = @max(max_tokens, pathfact_mod.countProfileTokens(value_component.payload));
        }
        return max_tokens;
    }

    fn addU32(a: u32, b: u32) !u32 {
        const result = @addWithOverflow(a, b);
        if (result[1] != 0) return error.PathProfileOverflow;
        return result[0];
    }

    fn subU32(a: u32, b: u32) !u32 {
        if (b > a) return error.PathProfileUnderflow;
        return a - b;
    }

    fn factSpecsAlloc(self: *Index) ![]fact_mod.FieldSpec {
        const cfg = self.config();
        const count = cfg.group_fields.len + cfg.measure_fields.len + cfg.time_fields.len;
        const specs = try self.alloc.alloc(fact_mod.FieldSpec, count);
        var i: usize = 0;
        for (cfg.group_fields) |field| {
            specs[i] = .{ .name = field.name, .path = field.path, .type = field.type, .role = .group };
            i += 1;
        }
        for (cfg.measure_fields) |field| {
            specs[i] = .{ .name = field.name, .path = field.path, .type = field.type, .role = .measure };
            i += 1;
        }
        for (cfg.time_fields) |field| {
            specs[i] = .{ .name = field.name, .path = field.path, .type = field.type, .role = .time };
            i += 1;
        }
        return specs;
    }

    fn applyDocDelta(self: *Index, txn: anytype, doc_key: []const u8, value: []const u8, sign: i8, maintenance_context: ?*BatchMaintenanceContext) !void {
        var parsed = std.json.parseFromSlice(std.json.Value, self.alloc, value, .{}) catch {
            try self.recordError(doc_key, "invalid_json");
            return;
        };
        defer parsed.deinit();
        if (parsed.value != .object) {
            try self.recordError(doc_key, "non_object_json");
            return;
        }

        for (self.config().materializations) |mat| {
            if (mat.join == null) {
                self.applyDirectMaterialization(txn, parsed.value, mat, sign) catch |err| switch (err) {
                    error.AlgebraicSymbolCollision => {
                        try self.recordError(doc_key, "symbol_collision");
                        return err;
                    },
                    else => return err,
                };
            }
        }
        // HLL cardinality sketches are maintained from the written facts in
        // writeDocFacts (add) / updateDocFactRowsCoalesced (update), not here, so
        // the incremental and rebuild tokenizations stay identical.
        try self.applyDocJoinDelta(txn, doc_key, parsed.value, sign, maintenance_context);
    }

    fn applyDocJoinDelta(self: *Index, txn: anytype, doc_key: []const u8, root: std.json.Value, sign: i8, maintenance_context: ?*BatchMaintenanceContext) !void {
        for (self.config().joins) |join_cfg| {
            self.applyJoinSide(txn, doc_key, root, join_cfg, true, sign, maintenance_context) catch |err| switch (err) {
                error.AlgebraicSymbolCollision => {
                    try self.recordError(doc_key, "symbol_collision");
                    return err;
                },
                error.AlgebraicJoinFanoutExceeded => {
                    try self.recordError(doc_key, "join_fanout_exceeded");
                    return err;
                },
                else => return err,
            };
            self.applyJoinSide(txn, doc_key, root, join_cfg, false, sign, maintenance_context) catch |err| switch (err) {
                error.AlgebraicSymbolCollision => {
                    try self.recordError(doc_key, "symbol_collision");
                    return err;
                },
                error.AlgebraicJoinFanoutExceeded => {
                    try self.recordError(doc_key, "join_fanout_exceeded");
                    return err;
                },
                else => return err,
            };
        }
    }

    fn applyDocFactDelta(self: *Index, txn: anytype, doc_key: []const u8, facts: []const fact_mod.Fact, sign: i8) !void {
        for (self.config().materializations) |mat| {
            if (mat.join != null) continue;
            self.applyDirectMaterializationFromFacts(txn, facts, mat, sign) catch |err| switch (err) {
                error.AlgebraicSymbolCollision => {
                    try self.recordError(doc_key, "symbol_collision");
                    return err;
                },
                else => return err,
            };
        }
    }

    fn applyWrittenAdaptiveDocFactDelta(self: *Index, txn: anytype, doc_key: []const u8, sign: i8, maintenance_context: ?*BatchMaintenanceContext) !void {
        const fact_key = try self.docFactKey(doc_key);
        defer self.alloc.free(fact_key);
        const fact_payload = txn.get(fact_key) catch |err| switch (err) {
            error.NotFound => return,
            else => return err,
        };
        var facts = fact_mod.decodeListAlloc(self.alloc, fact_payload) catch return;
        defer facts.deinit(self.alloc);
        try self.applyAdaptiveDocFactDelta(txn, facts.facts, sign, maintenance_context);
    }

    fn applyWrittenAdaptiveDocFactDeltaAppendOnly(
        self: *Index,
        txn: anytype,
        accumulator: *AppendOnlyAccumulator,
        doc_key: []const u8,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        if (!self.shouldMaintainReadyAdaptiveMaterializations()) return;
        const ctx = maintenance_context orelse {
            try self.applyWrittenAdaptiveDocFactDelta(txn, doc_key, 1, null);
            return;
        };
        const fact_key = try self.docFactKey(doc_key);
        defer self.alloc.free(fact_key);
        const fact_payload = txn.get(fact_key) catch |err| switch (err) {
            error.NotFound => return,
            else => return err,
        };
        var facts = fact_mod.decodeListAlloc(self.alloc, fact_payload) catch return;
        defer facts.deinit(self.alloc);
        try self.applyAdaptiveDocFactDeltaAppendOnly(txn, accumulator, facts.facts, ctx);
    }

    fn applyAdaptiveDocFactDelta(self: *Index, txn: anytype, facts: []const fact_mod.Fact, sign: i8, maintenance_context: ?*BatchMaintenanceContext) !void {
        if (!self.shouldMaintainReadyAdaptiveMaterializations()) return;
        if (maintenance_context) |ctx| {
            for (ctx.ready_specs) |spec| {
                if (ctx.isDisabled(spec.recommendation)) continue;
                if (spec.path_promotion_path != null) continue;
                if (spec.join != null) continue;
                const use_accumulator = ctx.coalesce_tensor_deltas;
                const update_result = if (use_accumulator)
                    self.updateAdaptiveTensorFromFactsCoalesced(txn, &ctx.tensor_accumulator, spec, facts, sign)
                else
                    self.updateAdaptiveTensorFromFacts(txn, spec, facts, sign);
                update_result catch |err| switch (err) {
                    error.AlgebraicLawNotInvertible => {
                        try self.markAdaptiveMaterializationStaleTxn(txn, spec.recommendation, spec.name);
                        try ctx.disable(self.alloc, spec.recommendation);
                        self.adaptive_maintenance_disabled_count += 1;
                        continue;
                    },
                    error.MissingField => continue,
                    else => return err,
                };
            }
            return;
        }
        const progress_rows = try self.scanPersistedAdaptiveProgressTxn(txn);
        defer {
            for (progress_rows) |*progress| progress.deinit(self.alloc);
            if (progress_rows.len > 0) self.alloc.free(progress_rows);
        }
        for (progress_rows) |progress| {
            if (progress.lifecycle != .ready) continue;
            if (!self.adaptiveProgressMatchesCurrentConfig(progress)) continue;
            if (!(try self.persistedMaterializationStateReadyTxn(txn, progress.recommendation))) continue;
            var spec = try self.adaptiveSpecFromRecommendationAlloc(progress.materialization_id, progress.recommendation);
            defer spec.deinit(self.alloc);
            if (spec.path_promotion_path != null) continue;
            if (spec.join != null) continue;
            self.updateAdaptiveTensorFromFacts(txn, spec, facts, sign) catch |err| switch (err) {
                error.AlgebraicLawNotInvertible => {
                    try self.markAdaptiveMaterializationStaleTxn(txn, progress.recommendation, progress.materialization_id);
                    continue;
                },
                error.MissingField => continue,
                else => return err,
            };
        }
    }

    fn applyAdaptiveDocFactDeltaAppendOnly(
        self: *Index,
        txn: anytype,
        accumulator: *AppendOnlyAccumulator,
        facts: []const fact_mod.Fact,
        maintenance_context: *BatchMaintenanceContext,
    ) !void {
        for (maintenance_context.ready_specs) |spec| {
            if (maintenance_context.isDisabled(spec.recommendation)) continue;
            if (spec.path_promotion_path != null) continue;
            if (spec.join != null) continue;
            self.updateAdaptiveTensorFromFactsAppendOnly(txn, accumulator, spec, facts) catch |err| switch (err) {
                error.AlgebraicLawNotInvertible => {
                    try self.markAdaptiveMaterializationStaleTxn(txn, spec.recommendation, spec.name);
                    try maintenance_context.disable(self.alloc, spec.recommendation);
                    self.adaptive_maintenance_disabled_count += 1;
                    continue;
                },
                error.MissingField => continue,
                else => return err,
            };
        }
    }

    fn applyStoredJoinFactsForDocDelta(self: *Index, txn: anytype, doc_key: []const u8, sign: i8, maintenance_context: ?*BatchMaintenanceContext) !void {
        for (self.config().joins) |join_cfg| {
            try self.applyStoredJoinSideFactsForDocDelta(txn, doc_key, join_cfg, .left, sign, maintenance_context);
            try self.applyStoredJoinSideFactsForDocDelta(txn, doc_key, join_cfg, .right, sign, maintenance_context);
        }
    }

    fn applyStoredJoinSideFactsForDocDelta(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        join_cfg: JoinConfig,
        side: join_mod.Side,
        sign: i8,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        const stored = try self.collectDocJoinSideFactRefsForDocPreferOrdinalAlloc(txn, doc_key, join_cfg, side);
        defer {
            for (stored) |*item| item.deinit(self.alloc);
            if (stored.len > 0) self.alloc.free(stored);
        }
        for (stored) |item| {
            var fact = try ProjectedFact.decode(self.alloc, item.payload);
            defer fact.deinit(self.alloc);
            try self.applyJoinFoldsForChangedFact(txn, join_cfg, side, item.join_id, fact, sign, maintenance_context);
            if (sign < 0) {
                try self.deleteJoinFactRowsForDoc(txn, doc_key, join_cfg, side, item.join_id, fact, item.key);
                try self.deleteDocJoinFactRef(txn, doc_key, join_cfg, side, item.key);
            }
        }
    }

    fn deleteJoinFactRowsForDoc(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        join_cfg: JoinConfig,
        side: join_mod.Side,
        join_id: []const u8,
        fact: ProjectedFact,
        legacy_key: []const u8,
    ) !void {
        txn.delete(legacy_key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
        const ordinal = (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key)) orelse return;
        const ordinal_key = try self.joinFactOrdinalKeyAlloc(join_cfg, side, join_id, fact, ordinal);
        defer self.alloc.free(ordinal_key);
        txn.delete(ordinal_key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
    }

    fn collectDocJoinSideFactRefsForDocPreferOrdinalAlloc(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        join_cfg: JoinConfig,
        side: join_mod.Side,
    ) ![]StoredJoinFact {
        const legacy = try self.collectDocJoinSideFactRefsForDocAlloc(txn, doc_key, join_cfg, side);
        errdefer {
            for (legacy) |*item| item.deinit(self.alloc);
            if (legacy.len > 0) self.alloc.free(legacy);
        }

        const ordinal = (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key)) orelse return legacy;
        const ordinal_refs = try self.collectDocJoinSideFactRefsForDocOrdinalAlloc(txn, ordinal, join_cfg, side);
        errdefer {
            for (ordinal_refs) |*item| item.deinit(self.alloc);
            if (ordinal_refs.len > 0) self.alloc.free(ordinal_refs);
        }

        if (storedJoinFactSlicesEquivalent(legacy, ordinal_refs)) {
            for (legacy) |*item| item.deinit(self.alloc);
            if (legacy.len > 0) self.alloc.free(legacy);
            return ordinal_refs;
        }

        for (ordinal_refs) |*item| item.deinit(self.alloc);
        if (ordinal_refs.len > 0) self.alloc.free(ordinal_refs);
        return legacy;
    }

    fn collectDocJoinSideFactRefsForDocAlloc(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        join_cfg: JoinConfig,
        side: join_mod.Side,
    ) ![]StoredJoinFact {
        const prefix = try self.docJoinFactRefPrefixAlloc(doc_key, join_cfg, side);
        defer self.alloc.free(prefix);
        return try self.collectDocJoinSideFactRefsWithPrefixAlloc(txn, prefix);
    }

    fn collectDocJoinSideFactRefsForDocOrdinalAlloc(
        self: *Index,
        txn: anytype,
        ordinal: doc_set.DocOrdinal,
        join_cfg: JoinConfig,
        side: join_mod.Side,
    ) ![]StoredJoinFact {
        const prefix = try self.docJoinFactOrdinalRefPrefixAlloc(ordinal, join_cfg, side);
        defer self.alloc.free(prefix);
        return try self.collectDocJoinSideFactRefsWithPrefixAlloc(txn, prefix);
    }

    fn collectDocJoinSideFactRefsWithPrefixAlloc(
        self: *Index,
        txn: anytype,
        prefix: []const u8,
    ) ![]StoredJoinFact {
        var out = std.ArrayListUnmanaged(StoredJoinFact).empty;
        errdefer {
            for (out.items) |*item| item.deinit(self.alloc);
            out.deinit(self.alloc);
        }
        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const decoded = token.decodeTupleAlloc(self.alloc, entry.value) catch continue;
            defer {
                for (decoded) |item| self.alloc.free(item);
                if (decoded.len > 0) self.alloc.free(decoded);
            }
            if (decoded.len != 4 or !std.mem.eql(u8, decoded[0], "jfr1")) continue;
            const ref_key_owned = try self.alloc.dupe(u8, entry.key);
            var ref_key_owned_live = true;
            errdefer if (ref_key_owned_live) self.alloc.free(ref_key_owned);
            const fact_key_owned = try self.alloc.dupe(u8, decoded[1]);
            var fact_key_owned_live = true;
            errdefer if (fact_key_owned_live) self.alloc.free(fact_key_owned);
            const join_id_owned = try self.alloc.dupe(u8, decoded[2]);
            var join_id_owned_live = true;
            errdefer if (join_id_owned_live) self.alloc.free(join_id_owned);
            const payload_owned = try self.alloc.dupe(u8, decoded[3]);
            var payload_owned_live = true;
            errdefer if (payload_owned_live) self.alloc.free(payload_owned);
            try out.append(self.alloc, .{
                .ref_key = ref_key_owned,
                .key = fact_key_owned,
                .join_id = join_id_owned,
                .payload = payload_owned,
            });
            ref_key_owned_live = false;
            fact_key_owned_live = false;
            join_id_owned_live = false;
            payload_owned_live = false;
        }
        return try out.toOwnedSlice(self.alloc);
    }

    fn applyDocDeltaAppendOnlyPreaggregated(
        self: *Index,
        txn: anytype,
        accumulator: *AppendOnlyAccumulator,
        doc_key: []const u8,
        value: []const u8,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        var parsed = std.json.parseFromSlice(std.json.Value, self.alloc, value, .{}) catch {
            try self.recordError(doc_key, "invalid_json");
            return;
        };
        defer parsed.deinit();
        if (parsed.value != .object) {
            try self.recordError(doc_key, "non_object_json");
            return;
        }

        for (self.config().materializations) |mat| {
            if (mat.join != null) continue;
            self.applyDirectMaterializationAppendOnlyPreaggregated(txn, accumulator, parsed.value, mat) catch |err| switch (err) {
                error.AlgebraicSymbolCollision => {
                    try self.recordError(doc_key, "symbol_collision");
                    return err;
                },
                else => return err,
            };
        }
        for (self.config().joins) |join_cfg| {
            self.applyJoinSideAppendOnlyPreaggregated(txn, accumulator, doc_key, parsed.value, join_cfg, true, maintenance_context) catch |err| switch (err) {
                error.AlgebraicSymbolCollision => {
                    try self.recordError(doc_key, "symbol_collision");
                    return err;
                },
                error.AlgebraicJoinFanoutExceeded => {
                    try self.recordError(doc_key, "join_fanout_exceeded");
                    return err;
                },
                else => return err,
            };
            self.applyJoinSideAppendOnlyPreaggregated(txn, accumulator, doc_key, parsed.value, join_cfg, false, maintenance_context) catch |err| switch (err) {
                error.AlgebraicSymbolCollision => {
                    try self.recordError(doc_key, "symbol_collision");
                    return err;
                },
                error.AlgebraicJoinFanoutExceeded => {
                    try self.recordError(doc_key, "join_fanout_exceeded");
                    return err;
                },
                else => return err,
            };
        }
    }

    fn applyDirectMaterialization(self: *Index, txn: anytype, root: std.json.Value, mat: MaterializationConfig, sign: i8) !void {
        const op = algebra.Op.parse(mat.op) orelse return;
        const group_key = self.groupKeyAlloc(root, mat.group_by) catch |err| switch (err) {
            error.MissingField => return,
            else => return err,
        };
        defer self.alloc.free(group_key);

        const measure_value = if (mat.measure) |measure_name|
            try self.fieldMeasureAlloc(root, measure_name)
        else
            null;
        defer if (measure_value) |value| value.deinit(self.alloc);

        if (mat.time == null) try self.applyConfiguredExpressionMutationTxn(txn, mat, op, group_key, measure_value, sign, .direct, null);

        if (mat.time) |time_name| {
            if (mat.bucket) |bucket_name| {
                const bucket = cylinder.Bucket.parse(bucket_name) orelse return;
                const time_value = (try self.fieldStringAlloc(root, time_name, .time)) orelse return;
                defer self.alloc.free(time_value);
                const bucket_start = try cylinder.bucketStartAlloc(self.alloc, bucket, time_value);
                defer self.alloc.free(bucket_start);
                try self.applyConfiguredExpressionMutationTxn(txn, mat, op, group_key, measure_value, sign, .cylinder, bucket_start);
            }
        }
    }

    fn applyDirectMaterializationFromFacts(
        self: *Index,
        txn: anytype,
        facts: []const fact_mod.Fact,
        mat: MaterializationConfig,
        sign: i8,
    ) !void {
        const op = algebra.Op.parse(mat.op) orelse return;
        const group_key = fact_mod.axisTupleAlloc(self.alloc, facts, mat.group_by) catch |err| switch (err) {
            error.MissingField => return,
            else => return err,
        };
        defer self.alloc.free(group_key);

        const measure_value = if (mat.measure) |measure_name|
            try self.factMeasureAlloc(facts, measure_name)
        else
            null;
        defer if (measure_value) |value| value.deinit(self.alloc);

        if (mat.time == null) try self.applyConfiguredExpressionMutationTxn(txn, mat, op, group_key, measure_value, sign, .direct, null);

        if (mat.time) |time_name| {
            if (mat.bucket) |bucket_name| {
                const bucket = cylinder.Bucket.parse(bucket_name) orelse return;
                const time_value = (try self.factTimeTextAlloc(facts, time_name)) orelse return;
                defer self.alloc.free(time_value);
                const bucket_start = try cylinder.bucketStartAlloc(self.alloc, bucket, time_value);
                defer self.alloc.free(bucket_start);
                try self.applyConfiguredExpressionMutationTxn(txn, mat, op, group_key, measure_value, sign, .cylinder, bucket_start);
            }
        }
    }

    const hll_default_precision: u6 = 12;

    fn hllCardinalityPrecision(hcfg: HllCardinalityConfig) u6 {
        if (hcfg.precision == 0) return hll_default_precision;
        return @intCast(std.math.clamp(hcfg.precision, @as(u8, hll.min_precision), @as(u8, hll.max_precision)));
    }

    fn hllCardinalityPrefixAlloc(self: *Index, name: []const u8) ![]u8 {
        return try self.keyAlloc(&.{ "hllcard", name });
    }

    fn hllCardinalityKeyAlloc(self: *Index, name: []const u8, group_key: []const u8) ![]u8 {
        return try self.keyAlloc(&.{ "hllcard", name, group_key });
    }

    // Folds a freshly-added document's value into the matching per-group HLL
    // sketches. Driven from the document facts (not the raw JSON) so the group
    // key and value token are byte-identical to what `rebuildHllCardinalityTxn`
    // derives from the stored facts — otherwise an incremental estimate and a
    // post-delete rebuilt estimate could disagree for the same data.
    fn applyHllCardinalitiesForFactsTxn(self: *Index, txn: anytype, facts: []const fact_mod.Fact) !void {
        for (self.config().hll_cardinalities) |hcfg| {
            try self.applyHllCardinalityForFactsTxn(txn, facts, hcfg);
        }
    }

    // Warm-folds the new value of an in-place update into only the sketches
    // whose group/value actually changed (the ones markHllCardinalitiesDirty-
    // ForUpdateTxn flagged), keeping the read estimate close until the rebuild.
    fn applyHllCardinalitiesForUpdatedFactsTxn(
        self: *Index,
        txn: anytype,
        old_facts: []const fact_mod.Fact,
        new_facts: []const fact_mod.Fact,
    ) !void {
        for (self.config().hll_cardinalities) |hcfg| {
            if (!hllCardinalityFactsChanged(hcfg, old_facts, new_facts)) continue;
            try self.applyHllCardinalityForFactsTxn(txn, new_facts, hcfg);
        }
    }

    fn applyHllCardinalityForFactsTxn(self: *Index, txn: anytype, facts: []const fact_mod.Fact, hcfg: HllCardinalityConfig) !void {
        const group_key = fact_mod.axisTupleAlloc(self.alloc, facts, hcfg.group_by) catch |err| switch (err) {
            error.MissingField => return,
            else => return err,
        };
        defer self.alloc.free(group_key);
        const value_scalar = fact_mod.findScalar(facts, .group, hcfg.value_field) orelse return;

        const singleton = try hll.singletonEncodedAlloc(self.alloc, hllCardinalityPrecision(hcfg), value_scalar);
        defer self.alloc.free(singleton);

        const key = try self.hllCardinalityKeyAlloc(hcfg.name, group_key);
        defer self.alloc.free(key);

        // `current` borrows txn-owned bytes (valid until the next txn write);
        // the union allocates a fresh buffer before we write it back.
        const current = txn.get(key) catch |err| switch (err) {
            error.NotFound => null,
            else => return err,
        };
        const merged = (try law_mod.combineAlloc(self.alloc, .hll, current, singleton)) orelse return;
        defer self.alloc.free(merged);
        try txn.put(key, merged);
    }

    fn hllCardinalityDirtyKeyAlloc(self: *Index, name: []const u8) ![]u8 {
        return try self.keyAlloc(&.{ "hllcard_dirty", name });
    }

    // Marks every HLL materialization the removed document contributed to as
    // needing a rebuild. Sketches cannot subtract a value, so a delete/overwrite
    // can only be reflected by recomputing the affected materialization.
    fn markHllCardinalitiesDirtyForFactsTxn(self: *Index, txn: anytype, facts: []const fact_mod.Fact) !void {
        for (self.config().hll_cardinalities) |hcfg| {
            if (fact_mod.findScalar(facts, .group, hcfg.value_field) == null) continue;
            try self.markHllCardinalityDirtyTxn(txn, hcfg);
        }
    }

    fn markHllCardinalityDirtyTxn(self: *Index, txn: anytype, hcfg: HllCardinalityConfig) !void {
        const dirty_key = try self.hllCardinalityDirtyKeyAlloc(hcfg.name);
        defer self.alloc.free(dirty_key);
        try txn.put(dirty_key, "1");
    }

    // True when `old_facts` and `new_facts` differ in any field the
    // materialization reads (its group_by axes or its value_field). Used by the
    // coalesced in-place update path to avoid forcing a full rebuild when a
    // re-upsert only touched fields the sketch does not depend on.
    fn hllCardinalityFactsChanged(
        hcfg: HllCardinalityConfig,
        old_facts: []const fact_mod.Fact,
        new_facts: []const fact_mod.Fact,
    ) bool {
        if (!scalarEqual(fact_mod.findScalar(old_facts, .group, hcfg.value_field), fact_mod.findScalar(new_facts, .group, hcfg.value_field))) return true;
        for (hcfg.group_by) |axis| {
            if (!scalarEqual(fact_mod.findScalar(old_facts, .group, axis), fact_mod.findScalar(new_facts, .group, axis))) return true;
        }
        return false;
    }

    fn scalarEqual(a: ?[]const u8, b: ?[]const u8) bool {
        if (a == null and b == null) return true;
        if (a == null or b == null) return false;
        return std.mem.eql(u8, a.?, b.?);
    }

    // Marks dirty only the materializations whose group_by/value_field actually
    // changed between the old and new facts of an in-place update.
    fn markHllCardinalitiesDirtyForUpdateTxn(
        self: *Index,
        txn: anytype,
        old_facts: []const fact_mod.Fact,
        new_facts: []const fact_mod.Fact,
    ) !void {
        for (self.config().hll_cardinalities) |hcfg| {
            // Only relevant if the old doc actually contributed a value to this
            // sketch; a pure add of the value is handled by the warm fold.
            if (fact_mod.findScalar(old_facts, .group, hcfg.value_field) == null) continue;
            if (!hllCardinalityFactsChanged(hcfg, old_facts, new_facts)) continue;
            try self.markHllCardinalityDirtyTxn(txn, hcfg);
        }
    }

    // Recomputes every per-group sketch for one materialization from the current
    // document facts, replacing any stale sketches and clearing the dirty marker.
    fn rebuildHllCardinalityTxn(self: *Index, txn: anytype, hcfg: HllCardinalityConfig) !void {
        const precision = hllCardinalityPrecision(hcfg);

        // Drop the existing sketches (a group emptied by deletes must disappear).
        {
            const prefix = try self.hllCardinalityPrefixAlloc(hcfg.name);
            defer self.alloc.free(prefix);
            var stale = std.ArrayListUnmanaged([]u8).empty;
            defer {
                for (stale.items) |key| self.alloc.free(key);
                stale.deinit(self.alloc);
            }
            var cursor = try txn.openCursor();
            defer cursor.close();
            var entry_opt = try cursor.seekAtOrAfter(prefix);
            while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
                if (!std.mem.startsWith(u8, entry.key, prefix)) break;
                try stale.append(self.alloc, try self.alloc.dupe(u8, entry.key));
            }
            for (stale.items) |key| txn.delete(key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
        }

        // Rebuild per-group sketches from the surviving document facts.
        var sketches = std.StringHashMapUnmanaged([]u8).empty;
        defer {
            var it = sketches.iterator();
            while (it.next()) |entry| {
                self.alloc.free(entry.key_ptr.*);
                self.alloc.free(entry.value_ptr.*);
            }
            sketches.deinit(self.alloc);
        }
        {
            const docfact_prefix = try self.keyAlloc(&.{"docfact"});
            defer self.alloc.free(docfact_prefix);
            var cursor = try txn.openCursor();
            defer cursor.close();
            var entry_opt = try cursor.seekAtOrAfter(docfact_prefix);
            while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
                if (!std.mem.startsWith(u8, entry.key, docfact_prefix)) break;
                var facts = fact_mod.decodeListAlloc(self.alloc, entry.value) catch continue;
                defer facts.deinit(self.alloc);
                const group_key = fact_mod.axisTupleAlloc(self.alloc, facts.facts, hcfg.group_by) catch |err| switch (err) {
                    error.MissingField => continue,
                    else => return err,
                };
                defer self.alloc.free(group_key);
                const value_scalar = fact_mod.findScalar(facts.facts, .group, hcfg.value_field) orelse continue;
                const singleton = try hll.singletonEncodedAlloc(self.alloc, precision, value_scalar);
                defer self.alloc.free(singleton);
                const gop = try sketches.getOrPut(self.alloc, group_key);
                if (!gop.found_existing) {
                    errdefer _ = sketches.remove(group_key);
                    gop.key_ptr.* = try self.alloc.dupe(u8, group_key);
                    gop.value_ptr.* = try self.alloc.dupe(u8, singleton);
                } else {
                    const merged = (try law_mod.combineAlloc(self.alloc, .hll, gop.value_ptr.*, singleton)) orelse continue;
                    self.alloc.free(gop.value_ptr.*);
                    gop.value_ptr.* = merged;
                }
            }
        }

        var write_it = sketches.iterator();
        while (write_it.next()) |entry| {
            const key = try self.hllCardinalityKeyAlloc(hcfg.name, entry.key_ptr.*);
            defer self.alloc.free(key);
            try txn.put(key, entry.value_ptr.*);
        }

        const dirty_key = try self.hllCardinalityDirtyKeyAlloc(hcfg.name);
        defer self.alloc.free(dirty_key);
        txn.delete(dirty_key) catch |err| switch (err) {
            error.NotFound => {},
            else => return err,
        };
    }

    fn anyHllCardinalityDirty(self: *Index, store: *docstore_mod.DocStore) !bool {
        var txn = try store.beginReadTxn();
        defer txn.abort();
        for (self.config().hll_cardinalities) |hcfg| {
            const dirty_key = try self.hllCardinalityDirtyKeyAlloc(hcfg.name);
            defer self.alloc.free(dirty_key);
            _ = txn.get(dirty_key) catch |err| switch (err) {
                error.NotFound => continue,
                else => return err,
            };
            return true;
        }
        return false;
    }

    fn runHllMaintenanceTxn(self: *Index, txn: anytype) !bool {
        var did_work = false;
        for (self.config().hll_cardinalities) |hcfg| {
            const dirty_key = try self.hllCardinalityDirtyKeyAlloc(hcfg.name);
            defer self.alloc.free(dirty_key);
            _ = txn.get(dirty_key) catch |err| switch (err) {
                error.NotFound => continue,
                else => return err,
            };
            try self.rebuildHllCardinalityTxn(txn, hcfg);
            did_work = true;
        }
        return did_work;
    }

    /// Rebuilds any HLL cardinality materialization marked dirty by a delete or
    /// overwrite. Safe to call repeatedly; a no-op when nothing is dirty. This is
    /// the unit of work the durable-job lane runs in the background.
    pub fn runHllMaintenance(self: *Index, store: *docstore_mod.DocStore) !bool {
        if (self.config().hll_cardinalities.len == 0) return false;
        if (!try self.anyHllCardinalityDirty(store)) return false;
        // Runs on a background thread; take the index write lock so the rebuild's
        // write txn never overlaps a foreground applyBatch write (single-writer
        // store). The dirty re-check inside the lock collapses redundant jobs.
        self.lockWrites();
        defer self.unlockWrites();
        if (!try self.anyHllCardinalityDirty(store)) return false;
        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        const did_work = try self.runHllMaintenanceTxn(&txn);
        try txn.commit();
        return did_work;
    }

    const HllMaintenanceJob = struct {
        index: *Index,
        store: *docstore_mod.DocStore,

        fn run(ptr: *anyopaque) anyerror!void {
            const self: *HllMaintenanceJob = @ptrCast(@alignCast(ptr));
            _ = self.index.runHllMaintenance(self.store) catch {};
        }

        fn deinitFn(ptr: *anyopaque) void {
            const self: *HllMaintenanceJob = @ptrCast(@alignCast(ptr));
            self.index.alloc.destroy(self);
        }
    };

    // Submits a background rebuild after a batch that may have invalidated
    // sketches. With the inline lane this runs synchronously once the batch txn
    // has committed; with a threaded lane it runs off the write path. When no
    // lane is attached, callers drive runHllMaintenance themselves.
    fn scheduleHllMaintenance(self: *Index, store: *docstore_mod.DocStore) void {
        const lane = self.hll_maintenance_lane orelse return;
        if (self.config().hll_cardinalities.len == 0) return;
        const job_ctx = self.alloc.create(HllMaintenanceJob) catch return;
        job_ctx.* = .{ .index = self, .store = store };
        lane.submit(.{
            .owner_id = self.hll_maintenance_owner_id,
            .class = .maintenance,
            .ptr = job_ctx,
            .run = HllMaintenanceJob.run,
            .deinit = HllMaintenanceJob.deinitFn,
        }) catch self.alloc.destroy(job_ctx);
    }

    // Schedules a rebuild iff the just-committed batch left a materialization
    // dirty. Keyed on the persisted dirty markers rather than the batch shape, so
    // it also catches in-place coalesced updates (which mark dirty without
    // appearing in deleted_keys/overwritten_doc_keys).
    //
    // Best-effort and infallible: it runs *after* the batch has durably
    // committed, so it must not turn a transient read-txn error into a failed
    // apply (a caller retrying would double-apply). If the dirtiness probe fails,
    // the persisted marker remains set and the next batch — or an explicit
    // runHllMaintenance — picks it up; meanwhile the dirty-aware read gate keeps
    // queries correct by falling back to the exact scan.
    fn scheduleHllMaintenanceIfDirty(self: *Index, store: *docstore_mod.DocStore) void {
        if (self.hll_maintenance_lane == null) return;
        if (self.config().hll_cardinalities.len == 0) return;
        const dirty = self.anyHllCardinalityDirty(store) catch return;
        if (!dirty) return;
        self.scheduleHllMaintenance(store);
    }

    pub const ApproxCardinalityEntry = struct {
        group_key: []u8,
        estimate: u64,

        pub fn deinit(self: *ApproxCardinalityEntry, alloc: Allocator) void {
            alloc.free(self.group_key);
            self.* = undefined;
        }
    };

    /// Reads one materialized HLL sketch per group and returns its estimated
    /// distinct count. O(groups) cursor reads with no per-document rescan.
    pub fn approxCardinalityEntriesAlloc(self: *Index, store: *docstore_mod.DocStore, name: []const u8) ![]ApproxCardinalityEntry {
        const prefix = try self.hllCardinalityPrefixAlloc(name);
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var out = std.ArrayListUnmanaged(ApproxCardinalityEntry).empty;
        errdefer {
            for (out.items) |*entry| entry.deinit(self.alloc);
            out.deinit(self.alloc);
        }
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const group_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (group_component.next != entry.key.len) continue;
            const estimate = hll.estimateEncoded(entry.value) catch continue;
            try out.append(self.alloc, .{
                .group_key = try self.alloc.dupe(u8, group_component.payload),
                .estimate = estimate,
            });
        }
        return try out.toOwnedSlice(self.alloc);
    }

    // Test helper: the estimate for one group of the (single) configured HLL
    // cardinality, or null if that group has no sketch. Keeps the regression
    // tests terse without duplicating entry iteration/cleanup.
    fn approxCardinalityEntriesForGroupTestEstimate(self: *Index, store: *docstore_mod.DocStore, group_key: []const u8) !?u64 {
        const name = self.config().hll_cardinalities[0].name;
        const entries = try self.approxCardinalityEntriesAlloc(store, name);
        defer {
            for (entries) |*entry| entry.deinit(self.alloc);
            self.alloc.free(entries);
        }
        for (entries) |entry| {
            if (std.mem.eql(u8, entry.group_key, group_key)) return entry.estimate;
        }
        return null;
    }

    /// Total distinct count across all groups of a materialized HLL cardinality,
    /// computed by merging the per-group sketches (an exact union, not a sum of
    /// per-group estimates).
    pub fn approxCardinalityTotalAlloc(self: *Index, store: *docstore_mod.DocStore, name: []const u8) !u64 {
        const prefix = try self.hllCardinalityPrefixAlloc(name);
        defer self.alloc.free(prefix);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        var cursor = try txn.openCursor();
        defer cursor.close();
        var merged: ?[]u8 = null;
        defer if (merged) |bytes| self.alloc.free(bytes);
        var entry_opt = try cursor.seekAtOrAfter(prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, prefix)) break;
            const group_component = token.componentAt(entry.key, prefix.len) catch continue;
            if (group_component.next != entry.key.len) continue;
            const next = (try law_mod.combineAlloc(self.alloc, .hll, merged, entry.value)) orelse continue;
            if (merged) |bytes| self.alloc.free(bytes);
            merged = next;
        }
        return if (merged) |bytes| try hll.estimateEncoded(bytes) else 0;
    }

    fn hllGroupByMatches(self: *const Index, mat_group: []const []const u8, query_group: []const []const u8) bool {
        if (mat_group.len != query_group.len) return false;
        for (mat_group, query_group) |mat_field, query_field| {
            const mat_resolved = self.resolveUniqueField(mat_field) orelse return false;
            const query_resolved = self.resolveUniqueField(query_field) orelse return false;
            if (!std.mem.eql(u8, mat_resolved.name, query_resolved.name)) return false;
        }
        return true;
    }

    // Name of an HLL cardinality materialization that can answer a distinct count
    // of `field_or_path` grouped exactly by `group_fields` (null = any grouping,
    // used for the merged total). Returns null when:
    //   - constraints or an MVCC read generation are present (sketches are
    //     maintained unconstrained and without per-generation visibility), or
    //   - the matching materialization is currently dirty (a delete/overwrite
    //     marked it stale and its background rebuild has not yet run) — the
    //     caller then falls back to the exact scan rather than reading a stale,
    //     over-counted sketch.
    fn hllCardinalityNameForField(
        self: *Index,
        store: *docstore_mod.DocStore,
        group_fields: ?[]const []const u8,
        field_or_path: []const u8,
        constraints: []const ir.Constraint,
        generation: ?u64,
    ) !?[]const u8 {
        if (constraints.len != 0 or generation != null) return null;
        const resolved = self.resolveUniqueField(field_or_path) orelse return null;
        if (resolved.role != .group) return null;
        for (self.config().hll_cardinalities) |hcfg| {
            if (!std.mem.eql(u8, hcfg.value_field, resolved.name)) continue;
            if (group_fields) |fields| {
                if (!self.hllGroupByMatches(hcfg.group_by, fields)) continue;
            }
            if (try self.hllCardinalityDirty(store, hcfg.name)) return null;
            return hcfg.name;
        }
        return null;
    }

    // Test helper: whether the (single) configured HLL cardinality is currently
    // marked dirty (i.e. a maintenance rebuild is pending).
    fn hllCardinalityDirtyTest(self: *Index, store: *docstore_mod.DocStore) !bool {
        return try self.hllCardinalityDirty(store, self.config().hll_cardinalities[0].name);
    }

    fn hllCardinalityDirty(self: *Index, store: *docstore_mod.DocStore, name: []const u8) !bool {
        const dirty_key = try self.hllCardinalityDirtyKeyAlloc(name);
        defer self.alloc.free(dirty_key);
        var txn = try store.beginReadTxn();
        defer txn.abort();
        _ = txn.get(dirty_key) catch |err| switch (err) {
            error.NotFound => return false,
            else => return err,
        };
        return true;
    }

    /// Total distinct-count estimate for `field_or_path` from a matching HLL
    /// materialization (the union of every group's sketch), or null when none
    /// applies. Used to answer a root `cardinality` aggregation.
    pub fn approxCardinalityTotalForFieldAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        field_or_path: []const u8,
        constraints: []const ir.Constraint,
        generation: ?u64,
    ) !?u64 {
        const name = (try self.hllCardinalityNameForField(store, null, field_or_path, constraints, generation)) orelse return null;
        return try self.approxCardinalityTotalAlloc(store, name);
    }

    /// Per-group distinct-count estimates for a `terms(group_fields) ->
    /// cardinality(field)` query, keyed by the materialized group key, or null
    /// when no HLL materialization matches the group layout and value field.
    pub fn approxCardinalityEntriesForGroupAlloc(
        self: *Index,
        store: *docstore_mod.DocStore,
        group_fields: []const []const u8,
        field_or_path: []const u8,
        constraints: []const ir.Constraint,
        generation: ?u64,
    ) !?[]ApproxCardinalityEntry {
        const name = (try self.hllCardinalityNameForField(store, group_fields, field_or_path, constraints, generation)) orelse return null;
        return try self.approxCardinalityEntriesAlloc(store, name);
    }

    /// The materialized group key for a single-field terms bucket whose value
    /// scalar token is `scalar` — i.e. what groupKeyAlloc produces for that field
    /// — so callers can look up the bucket's estimate in the entries above.
    pub fn approxCardinalityGroupKeyForScalarAlloc(self: *Index, scalar: []const u8) ![]u8 {
        return try token.canonicalTupleAlloc(self.alloc, &.{scalar});
    }

    fn applyDirectMaterializationAppendOnlyPreaggregated(
        self: *Index,
        txn: anytype,
        accumulator: *AppendOnlyAccumulator,
        root: std.json.Value,
        mat: MaterializationConfig,
    ) !void {
        const op = algebra.Op.parse(mat.op) orelse return;
        const group_key = self.groupKeyAlloc(root, mat.group_by) catch |err| switch (err) {
            error.MissingField => return,
            else => return err,
        };
        defer self.alloc.free(group_key);

        const measure_value = if (mat.measure) |measure_name|
            try self.fieldMeasureAlloc(root, measure_name)
        else
            null;
        defer if (measure_value) |value| value.deinit(self.alloc);

        if (mat.time == null) try self.accumulateConfiguredExpressionAppendOnly(txn, accumulator, mat, op, group_key, measure_value, .direct, null);

        if (mat.time) |time_name| {
            if (mat.bucket) |bucket_name| {
                const bucket = cylinder.Bucket.parse(bucket_name) orelse return;
                const time_value = (try self.fieldStringAlloc(root, time_name, .time)) orelse return;
                defer self.alloc.free(time_value);
                const bucket_start = try cylinder.bucketStartAlloc(self.alloc, bucket, time_value);
                defer self.alloc.free(bucket_start);
                try self.accumulateConfiguredExpressionAppendOnly(txn, accumulator, mat, op, group_key, measure_value, .cylinder, bucket_start);
            }
        }
    }

    fn applyJoinSide(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        root: std.json.Value,
        join_cfg: JoinConfig,
        comptime left: bool,
        sign: i8,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        const side: join_mod.Side = if (left) .left else .right;
        var prepared = (try self.prepareJoinFact(txn, root, join_cfg, side, doc_key)) orelse return;
        defer prepared.deinit(self.alloc);
        var fact = try ProjectedFact.decode(self.alloc, prepared.payload);
        defer fact.deinit(self.alloc);

        if (sign > 0) {
            try txn.put(prepared.key, prepared.payload);
            if (prepared.ordinal_key) |ordinal_key| try txn.put(ordinal_key, prepared.payload);
            try self.putDocJoinFactRef(txn, doc_key, join_cfg, side, prepared);
            try self.applyJoinFoldsForChangedFact(txn, join_cfg, side, prepared.join_id, fact, 1, maintenance_context);
        } else {
            try self.applyJoinFoldsForChangedFact(txn, join_cfg, side, prepared.join_id, fact, -1, maintenance_context);
            try txn.delete(prepared.key);
            if (prepared.ordinal_key) |ordinal_key| {
                txn.delete(ordinal_key) catch |err| switch (err) {
                    error.NotFound => {},
                    else => return err,
                };
            }
            try self.deleteDocJoinFactRef(txn, doc_key, join_cfg, side, prepared.key);
        }
    }

    const PreparedJoinFact = struct {
        join_id: []u8,
        key: []u8,
        payload: []u8,
        ordinal_key: ?[]u8 = null,

        fn deinit(self: *PreparedJoinFact, alloc: Allocator) void {
            alloc.free(self.join_id);
            alloc.free(self.key);
            alloc.free(self.payload);
            if (self.ordinal_key) |key| alloc.free(key);
            self.* = undefined;
        }
    };

    fn prepareJoinFact(
        self: *Index,
        txn: anytype,
        root: std.json.Value,
        join_cfg: JoinConfig,
        side: join_mod.Side,
        doc_key: []const u8,
    ) !?PreparedJoinFact {
        if (!(try self.joinSideMatches(root, join_cfg, side == .left))) return null;
        const fields = if (side == .left) join_cfg.left_fields else join_cfg.right_fields;
        const join_key = self.groupKeyAlloc(root, fields) catch |err| switch (err) {
            error.MissingField => return null,
            else => return err,
        };
        defer self.alloc.free(join_key);
        const join_id = try self.ensureSymbol(txn, join_key);
        errdefer self.alloc.free(join_id);
        const payload = try self.projectJoinFactAlloc(root, join_cfg, side);
        errdefer self.alloc.free(payload);
        var fact = try ProjectedFact.decode(self.alloc, payload);
        defer fact.deinit(self.alloc);
        const key = self.joinFactKeyAlloc(join_cfg, side, join_id, fact, doc_key) catch |err| switch (err) {
            error.MissingField => {
                self.alloc.free(join_id);
                self.alloc.free(payload);
                return null;
            },
            else => return err,
        };
        errdefer self.alloc.free(key);
        const ordinal_key = if (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key)) |ordinal|
            try self.joinFactOrdinalKeyAlloc(join_cfg, side, join_id, fact, ordinal)
        else
            null;
        errdefer if (ordinal_key) |owned| self.alloc.free(owned);
        return .{ .join_id = join_id, .key = key, .payload = payload, .ordinal_key = ordinal_key };
    }

    fn applyJoinSideAppendOnlyPreaggregated(
        self: *Index,
        txn: anytype,
        accumulator: *AppendOnlyAccumulator,
        doc_key: []const u8,
        root: std.json.Value,
        join_cfg: JoinConfig,
        comptime left: bool,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        const side: join_mod.Side = if (left) .left else .right;
        var prepared = (try self.prepareJoinFactAppendOnly(txn, root, join_cfg, side, doc_key)) orelse return;
        defer prepared.deinit(self.alloc);
        var fact = try ProjectedFact.decode(self.alloc, prepared.payload);
        defer fact.deinit(self.alloc);
        try txn.put(prepared.key, prepared.payload);
        if (prepared.ordinal_key) |ordinal_key| try txn.put(ordinal_key, prepared.payload);
        try self.putDocJoinFactRef(txn, doc_key, join_cfg, side, prepared);
        try self.applyJoinFoldsForChangedFactAppendOnly(txn, accumulator, join_cfg, side, prepared.join_id, fact, maintenance_context);
    }

    fn putDocJoinFactRef(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        join_cfg: JoinConfig,
        side: join_mod.Side,
        prepared: PreparedJoinFact,
    ) !void {
        const ref_key = try self.docJoinFactRefKeyAlloc(doc_key, join_cfg, side, prepared.key);
        defer self.alloc.free(ref_key);
        const encoded = try token.canonicalTupleAlloc(self.alloc, &.{ "jfr1", prepared.key, prepared.join_id, prepared.payload });
        defer self.alloc.free(encoded);
        try txn.put(ref_key, encoded);
        if (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key)) |ordinal| {
            const ordinal_ref_key = try self.docJoinFactOrdinalRefKeyAlloc(ordinal, join_cfg, side, prepared.key);
            defer self.alloc.free(ordinal_ref_key);
            try txn.put(ordinal_ref_key, encoded);
        }
        self.doc_join_fact_ref_write_count += 1;
    }

    fn deleteDocJoinFactRef(
        self: *Index,
        txn: anytype,
        doc_key: []const u8,
        join_cfg: JoinConfig,
        side: join_mod.Side,
        fact_key: []const u8,
    ) !void {
        const ref_key = try self.docJoinFactRefKeyAlloc(doc_key, join_cfg, side, fact_key);
        defer self.alloc.free(ref_key);
        var deleted_ref = true;
        txn.delete(ref_key) catch |err| switch (err) {
            error.NotFound => deleted_ref = false,
            else => return err,
        };
        if (deleted_ref) self.doc_join_fact_ref_delete_count += 1;
        if (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key)) |ordinal| {
            const ordinal_ref_key = try self.docJoinFactOrdinalRefKeyAlloc(ordinal, join_cfg, side, fact_key);
            defer self.alloc.free(ordinal_ref_key);
            txn.delete(ordinal_ref_key) catch |err| switch (err) {
                error.NotFound => {},
                else => return err,
            };
        }
    }

    fn prepareJoinFactAppendOnly(
        self: *Index,
        txn: anytype,
        root: std.json.Value,
        join_cfg: JoinConfig,
        side: join_mod.Side,
        doc_key: []const u8,
    ) !?PreparedJoinFact {
        if (!(try self.joinSideMatches(root, join_cfg, side == .left))) return null;
        const fields = if (side == .left) join_cfg.left_fields else join_cfg.right_fields;
        const join_key = self.groupKeyAlloc(root, fields) catch |err| switch (err) {
            error.MissingField => return null,
            else => return err,
        };
        defer self.alloc.free(join_key);
        const join_id = try self.ensureSymbolAppendOnly(txn, join_key);
        errdefer self.alloc.free(join_id);
        const payload = try self.projectJoinFactAlloc(root, join_cfg, side);
        errdefer self.alloc.free(payload);
        var fact = try ProjectedFact.decode(self.alloc, payload);
        defer fact.deinit(self.alloc);
        const key = self.joinFactKeyAlloc(join_cfg, side, join_id, fact, doc_key) catch |err| switch (err) {
            error.MissingField => {
                self.alloc.free(join_id);
                self.alloc.free(payload);
                return null;
            },
            else => return err,
        };
        errdefer self.alloc.free(key);
        const ordinal_key = if (try doc_identity.lookupOrdinalTxn(self.alloc, txn, doc_key)) |ordinal|
            try self.joinFactOrdinalKeyAlloc(join_cfg, side, join_id, fact, ordinal)
        else
            null;
        errdefer if (ordinal_key) |owned| self.alloc.free(owned);
        return .{ .join_id = join_id, .key = key, .payload = payload, .ordinal_key = ordinal_key };
    }

    fn applyJoinFoldsForChangedFact(
        self: *Index,
        txn: anytype,
        join_cfg: JoinConfig,
        changed_side: join_mod.Side,
        join_id: []const u8,
        changed_fact: ProjectedFact,
        sign: i8,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        const scan = try self.joinScanBoundsPreferOrdinalAlloc(txn, join_cfg, changed_side.opposite(), join_id, changed_fact, changed_side);
        defer scan.deinit(self.alloc);
        var adaptive_specs: []AdaptiveMaterializationSpec = &.{};
        if (maintenance_context == null) {
            adaptive_specs = try self.readyAdaptiveJoinSpecsTxn(txn, join_cfg.name);
        }
        defer if (maintenance_context == null) {
            for (adaptive_specs) |*spec| spec.deinit(self.alloc);
            if (adaptive_specs.len > 0) self.alloc.free(adaptive_specs);
        };
        var opposite_facts = std.ArrayListUnmanaged(ProjectedFact).empty;
        defer {
            for (opposite_facts.items) |*fact| fact.deinit(self.alloc);
            opposite_facts.deinit(self.alloc);
        }
        {
            var cursor = try txn.openCursor();
            defer cursor.close();
            var fanout: usize = 0;
            var entry_opt = try cursor.seekAtOrAfter(scan.start);
            while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
                if (!std.mem.startsWith(u8, entry.key, scan.prefix)) break;
                if (scan.max_time_key) |max_key| {
                    const time_component = token.componentAt(entry.key, scan.prefix.len) catch {
                        self.join_facts_pruned += 1;
                        continue;
                    };
                    if (std.mem.order(u8, time_component.payload, max_key) == .gt) break;
                }
                self.join_facts_scanned += 1;
                var opposite_fact = ProjectedFact.decode(self.alloc, entry.value) catch continue;
                const temporal_match = self.joinTemporalFactsMatch(join_cfg, changed_side, changed_fact, opposite_fact) catch |err| {
                    opposite_fact.deinit(self.alloc);
                    return err;
                };
                if (!temporal_match) {
                    self.join_facts_pruned += 1;
                    opposite_fact.deinit(self.alloc);
                    continue;
                }
                self.join_facts_matched += 1;
                fanout += 1;
                if (join_cfg.max_fanout) |max| {
                    if (fanout > max) {
                        opposite_fact.deinit(self.alloc);
                        return error.AlgebraicJoinFanoutExceeded;
                    }
                }
                opposite_facts.append(self.alloc, opposite_fact) catch |err| {
                    opposite_fact.deinit(self.alloc);
                    return err;
                };
            }
        }
        for (opposite_facts.items) |opposite_fact| {
            const left_fact = if (changed_side == .left) changed_fact else opposite_fact;
            const right_fact = if (changed_side == .left) opposite_fact else changed_fact;
            for (self.config().materializations) |mat| {
                const mat_join = mat.join orelse continue;
                if (!std.mem.eql(u8, mat_join, join_cfg.name)) continue;
                const op = algebra.Op.parse(mat.op) orelse continue;
                const group_fact = try materializationSideFactRequired(mat.group_side, right_fact, left_fact);
                const measure_fact = try materializationSideFactRequired(mat.measure_side, right_fact, left_fact);
                const group_key = group_fact.groupKeyAlloc(self.alloc, mat.group_by) catch |err| switch (err) {
                    error.MissingField => continue,
                    else => return err,
                };
                defer self.alloc.free(group_key);
                const measure_value = if (mat.measure) |measure_name|
                    try measure_fact.measureAlloc(self.alloc, measure_name)
                else
                    null;
                defer if (measure_value) |value| value.deinit(self.alloc);
                try self.applyConfiguredExpressionMutationTxn(txn, mat, op, group_key, measure_value, sign, .direct, null);
            }
            const specs = if (maintenance_context) |ctx| ctx.ready_specs else adaptive_specs;
            for (specs) |spec| {
                if (maintenance_context) |ctx| {
                    if (ctx.isDisabled(spec.recommendation)) continue;
                }
                if (spec.join) |join_name| {
                    if (!std.mem.eql(u8, join_name, join_cfg.name)) continue;
                } else continue;
                const use_accumulator = if (maintenance_context) |ctx| ctx.coalesce_tensor_deltas else false;
                const update_result = if (use_accumulator)
                    self.updateAdaptiveTensorFromJoinPairCoalesced(txn, &maintenance_context.?.tensor_accumulator, spec, left_fact, right_fact, sign)
                else
                    self.updateAdaptiveTensorFromJoinPair(txn, spec, left_fact, right_fact, sign);
                update_result catch |err| switch (err) {
                    error.AlgebraicLawNotInvertible => {
                        try self.markAdaptiveMaterializationStaleTxn(txn, spec.recommendation, spec.name);
                        if (maintenance_context) |ctx| {
                            try ctx.disable(self.alloc, spec.recommendation);
                            self.adaptive_maintenance_disabled_count += 1;
                        }
                    },
                    else => return err,
                };
            }
        }
    }

    fn applyJoinFoldsForChangedFactAppendOnly(
        self: *Index,
        txn: anytype,
        accumulator: *AppendOnlyAccumulator,
        join_cfg: JoinConfig,
        changed_side: join_mod.Side,
        join_id: []const u8,
        changed_fact: ProjectedFact,
        maintenance_context: ?*BatchMaintenanceContext,
    ) !void {
        const scan = try self.joinScanBoundsPreferOrdinalAlloc(txn, join_cfg, changed_side.opposite(), join_id, changed_fact, changed_side);
        defer scan.deinit(self.alloc);
        var adaptive_specs: []AdaptiveMaterializationSpec = &.{};
        if (maintenance_context == null) {
            adaptive_specs = try self.readyAdaptiveJoinSpecsTxn(txn, join_cfg.name);
        }
        defer if (maintenance_context == null) {
            for (adaptive_specs) |*spec| spec.deinit(self.alloc);
            if (adaptive_specs.len > 0) self.alloc.free(adaptive_specs);
        };
        var cursor = try txn.openCursor();
        defer cursor.close();
        var fanout: usize = 0;
        var entry_opt = try cursor.seekAtOrAfter(scan.start);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, scan.prefix)) break;
            if (scan.max_time_key) |max_key| {
                const time_component = token.componentAt(entry.key, scan.prefix.len) catch {
                    self.join_facts_pruned += 1;
                    continue;
                };
                if (std.mem.order(u8, time_component.payload, max_key) == .gt) break;
            }
            self.join_facts_scanned += 1;
            var opposite_fact = ProjectedFact.decode(self.alloc, entry.value) catch continue;
            defer opposite_fact.deinit(self.alloc);
            if (!(try self.joinTemporalFactsMatch(join_cfg, changed_side, changed_fact, opposite_fact))) {
                self.join_facts_pruned += 1;
                continue;
            }
            self.join_facts_matched += 1;
            fanout += 1;
            if (join_cfg.max_fanout) |max| {
                if (fanout > max) return error.AlgebraicJoinFanoutExceeded;
            }
            const left_fact = if (changed_side == .left) changed_fact else opposite_fact;
            const right_fact = if (changed_side == .left) opposite_fact else changed_fact;
            for (self.config().materializations) |mat| {
                const mat_join = mat.join orelse continue;
                if (!std.mem.eql(u8, mat_join, join_cfg.name)) continue;
                const op = algebra.Op.parse(mat.op) orelse continue;
                const group_fact = try materializationSideFactRequired(mat.group_side, right_fact, left_fact);
                const measure_fact = try materializationSideFactRequired(mat.measure_side, right_fact, left_fact);
                const group_key = group_fact.groupKeyAlloc(self.alloc, mat.group_by) catch |err| switch (err) {
                    error.MissingField => continue,
                    else => return err,
                };
                defer self.alloc.free(group_key);
                const measure_value = if (mat.measure) |measure_name|
                    try measure_fact.measureAlloc(self.alloc, measure_name)
                else
                    null;
                defer if (measure_value) |value| value.deinit(self.alloc);
                try self.accumulateConfiguredExpressionAppendOnly(txn, accumulator, mat, op, group_key, measure_value, .direct, null);
            }
            const specs = if (maintenance_context) |ctx| ctx.ready_specs else adaptive_specs;
            for (specs) |spec| {
                if (maintenance_context) |ctx| {
                    if (ctx.isDisabled(spec.recommendation)) continue;
                }
                if (spec.join) |join_name| {
                    if (!std.mem.eql(u8, join_name, join_cfg.name)) continue;
                } else continue;
                self.updateAdaptiveTensorFromJoinPairAppendOnly(txn, accumulator, spec, left_fact, right_fact) catch |err| switch (err) {
                    error.AlgebraicLawNotInvertible => {
                        try self.markAdaptiveMaterializationStaleTxn(txn, spec.recommendation, spec.name);
                        if (maintenance_context) |ctx| {
                            try ctx.disable(self.alloc, spec.recommendation);
                            self.adaptive_maintenance_disabled_count += 1;
                        }
                    },
                    else => return err,
                };
            }
        }
    }

    fn scanDerivedJoinFoldEntriesTxn(
        self: *Index,
        txn: anytype,
        join_cfg: JoinConfig,
        request: DerivedJoinFoldRequest,
        law_id: law_mod.Id,
        generation: ?u64,
    ) ![]FoldEntry {
        var encoded_constraints = std.ArrayListUnmanaged(EncodedDerivedConstraint).empty;
        defer {
            for (encoded_constraints.items) |*constraint| constraint.deinit(self.alloc);
            encoded_constraints.deinit(self.alloc);
        }
        for (request.constraints) |constraint| {
            const field = self.fieldConfig(constraint.field, .group) orelse return try self.alloc.alloc(FoldEntry, 0);
            try encoded_constraints.append(self.alloc, .{
                .field = field.name,
                .scalar = try self.constraintTokenAlloc(self.alloc, field.name, constraint.value),
            });
        }

        const left_prefix = try self.joinSideFactPrefixPreferOrdinalAlloc(txn, join_cfg, .left);
        defer self.alloc.free(left_prefix);
        var accumulator = DerivedJoinFoldAccumulator{};
        defer accumulator.deinit(self.alloc);

        var cursor = try txn.openCursor();
        defer cursor.close();
        var entry_opt = try cursor.seekAtOrAfter(left_prefix);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, left_prefix)) break;
            if (!try self.joinFactKeyVisibleAtGenerationTxn(txn, entry.key, generation)) continue;
            const join_id_component = token.componentAt(entry.key, left_prefix.len) catch continue;
            var left_fact = ProjectedFact.decode(self.alloc, entry.value) catch continue;
            defer left_fact.deinit(self.alloc);
            try self.scanDerivedJoinFoldMatchesTxn(txn, join_cfg, request, law_id, encoded_constraints.items, join_id_component.payload, left_fact, generation, &accumulator);
        }

        return try accumulator.entriesAlloc(self.alloc);
    }

    fn scanDerivedJoinFoldMatchesTxn(
        self: *Index,
        txn: anytype,
        join_cfg: JoinConfig,
        request: DerivedJoinFoldRequest,
        law_id: law_mod.Id,
        constraints: []const EncodedDerivedConstraint,
        join_id: []const u8,
        left_fact: ProjectedFact,
        generation: ?u64,
        accumulator: *DerivedJoinFoldAccumulator,
    ) !void {
        const scan = try self.joinScanBoundsPreferOrdinalAlloc(txn, join_cfg, .right, join_id, left_fact, .left);
        defer scan.deinit(self.alloc);
        var cursor = try txn.openCursor();
        defer cursor.close();
        var fanout: usize = 0;
        var entry_opt = try cursor.seekAtOrAfter(scan.start);
        while (entry_opt) |entry| : (entry_opt = try cursor.next()) {
            if (!std.mem.startsWith(u8, entry.key, scan.prefix)) break;
            if (!try self.joinFactKeyVisibleAtGenerationTxn(txn, entry.key, generation)) continue;
            if (scan.max_time_key) |max_key| {
                const time_component = token.componentAt(entry.key, scan.prefix.len) catch continue;
                if (std.mem.order(u8, time_component.payload, max_key) == .gt) break;
            }
            var right_fact = ProjectedFact.decode(self.alloc, entry.value) catch continue;
            defer right_fact.deinit(self.alloc);
            if (!(try self.joinTemporalFactsMatch(join_cfg, .left, left_fact, right_fact))) continue;
            fanout += 1;
            if (join_cfg.max_fanout) |max| {
                if (fanout > max) return error.AlgebraicJoinFanoutExceeded;
            }
            try self.applyDerivedJoinFoldPair(request, law_id, constraints, left_fact, right_fact, accumulator);
        }
    }

    fn applyDerivedJoinFoldPair(
        self: *Index,
        request: DerivedJoinFoldRequest,
        law_id: law_mod.Id,
        constraints: []const EncodedDerivedConstraint,
        left_fact: ProjectedFact,
        right_fact: ProjectedFact,
        accumulator: *DerivedJoinFoldAccumulator,
    ) !void {
        if (!(try derivedJoinConstraintsMatch(left_fact, right_fact, constraints))) return;
        const group_fact = try materializationSideFactRequired(request.join.group_side, right_fact, left_fact);
        const measure_fact = try materializationSideFactRequired(request.join.measure_side, right_fact, left_fact);
        const base_group_key = group_fact.groupKeyAlloc(self.alloc, request.group_by) catch |err| switch (err) {
            error.MissingField => return,
            else => return err,
        };
        defer self.alloc.free(base_group_key);
        const group_key = self.derivedJoinGroupKeyAlloc(request, group_fact, measure_fact, base_group_key) catch |err| switch (err) {
            error.MissingField => return,
            else => return err,
        };
        defer self.alloc.free(group_key);
        const measure_value = if (request.measure) |measure_name|
            try measure_fact.measureAlloc(self.alloc, measure_name)
        else
            null;
        defer if (measure_value) |value| value.deinit(self.alloc);
        const contribution = self.derivedJoinContributionAlloc(request.op, measure_value) catch |err| switch (err) {
            error.MissingField => return,
            else => return err,
        };
        defer self.alloc.free(contribution);
        try accumulator.add(self.alloc, group_key, law_id, contribution);
    }

    fn derivedJoinGroupKeyAlloc(
        self: *Index,
        request: DerivedJoinFoldRequest,
        group_fact: ProjectedFact,
        measure_fact: ProjectedFact,
        base_group_key: []const u8,
    ) ![]u8 {
        if (request.range_field) |field_name| {
            if (!(try self.derivedJoinRangeMatches(request, group_fact, measure_fact, field_name))) return error.MissingField;
            const range_axis = try token.canonicalTupleAlloc(self.alloc, &.{ request.range_start orelse "", request.range_end orelse "" });
            errdefer self.alloc.free(range_axis);
            if (base_group_key.len == 0) return range_axis;
            defer self.alloc.free(range_axis);
            return try token.canonicalTupleAlloc(self.alloc, &.{ range_axis, base_group_key });
        }
        if (request.histogram_field) |field_name| {
            const role = request.histogram_role orelse return error.InvalidAlgebraicConfig;
            if (request.histogram_interval <= 0) return error.InvalidAlgebraicConfig;
            return try self.derivedJoinHistogramGroupKeyAlloc(request, group_fact, measure_fact, field_name, role);
        }
        const time_field = request.time_field orelse return try self.alloc.dupe(u8, base_group_key);
        const bucket_name = request.time_bucket orelse return error.InvalidAlgebraicConfig;
        const bucket = cylinder.Bucket.parse(bucket_name) orelse return error.InvalidAlgebraicConfig;
        const time_text = (try group_fact.timeText(time_field)) orelse (try measure_fact.timeText(time_field)) orelse return error.MissingField;
        const bucket_start = try cylinder.bucketStartAlloc(self.alloc, bucket, time_text);
        defer self.alloc.free(bucket_start);
        return try token.canonicalTupleAlloc(self.alloc, &.{ bucket_start, base_group_key });
    }

    fn derivedJoinHistogramGroupKeyAlloc(
        self: *Index,
        request: DerivedJoinFoldRequest,
        group_fact: ProjectedFact,
        measure_fact: ProjectedFact,
        field_name: []const u8,
        role: fact_mod.Role,
    ) ![]u8 {
        const numeric = switch (role) {
            .measure => blk: {
                const measure = (try measure_fact.measureAlloc(self.alloc, field_name)) orelse return error.MissingField;
                defer measure.deinit(self.alloc);
                break :blk try algebra.parseF64(measure.raw);
            },
            .group => blk: {
                const encoded = group_fact.findGroupToken(field_name) orelse return error.MissingField;
                const scalar = try value_mod.parseScalarAlloc(self.alloc, encoded);
                defer value_mod.deinitScalar(self.alloc, scalar);
                if (scalar.kind != .number and scalar.kind != .integer) return error.MissingField;
                break :blk try std.fmt.parseFloat(f64, scalar.canonical);
            },
            .time, .vector_constraint => return error.MissingField,
        };
        const bucket_index: i64 = @intFromFloat(@floor(numeric / request.histogram_interval));
        return try std.fmt.allocPrint(self.alloc, "{d}", .{bucket_index});
    }

    fn derivedJoinRangeMatches(
        self: *Index,
        request: DerivedJoinFoldRequest,
        group_fact: ProjectedFact,
        measure_fact: ProjectedFact,
        field_name: []const u8,
    ) !bool {
        const kind = request.range_kind orelse return error.InvalidAlgebraicConfig;
        return switch (kind) {
            .numeric => blk: {
                const value = try self.derivedJoinRangeNumericValue(request, group_fact, measure_fact, field_name);
                const min = if (request.range_start) |start| try std.fmt.parseFloat(f64, start) else null;
                const max = if (request.range_end) |end| try std.fmt.parseFloat(f64, end) else null;
                break :blk scalarInNumberRange(value, min, max, request.range_inclusive_start, request.range_inclusive_end);
            },
            .date => blk: {
                const timestamp_ns = try self.derivedJoinRangeDateValue(request, group_fact, measure_fact, field_name);
                const start_ns = if (request.range_start) |start| (try parseDateTimeOptionalToNs(start)) orelse return error.MissingField else null;
                const end_ns = if (request.range_end) |end| (try parseDateTimeOptionalToNs(end)) orelse return error.MissingField else null;
                break :blk scalarInDateRange(timestamp_ns, start_ns, end_ns, request.range_inclusive_start, request.range_inclusive_end);
            },
        };
    }

    fn derivedJoinRangeNumericValue(
        self: *Index,
        request: DerivedJoinFoldRequest,
        group_fact: ProjectedFact,
        measure_fact: ProjectedFact,
        field_name: []const u8,
    ) !f64 {
        const role = request.range_role orelse return error.InvalidAlgebraicConfig;
        return switch (role) {
            .measure => blk: {
                const measure = (try measure_fact.measureAlloc(self.alloc, field_name)) orelse return error.MissingField;
                defer measure.deinit(self.alloc);
                break :blk try algebra.parseF64(measure.raw);
            },
            .group => blk: {
                const encoded = group_fact.findGroupToken(field_name) orelse return error.MissingField;
                const scalar = try value_mod.parseScalarAlloc(self.alloc, encoded);
                defer value_mod.deinitScalar(self.alloc, scalar);
                if (scalar.kind != .number and scalar.kind != .integer) return error.MissingField;
                break :blk try std.fmt.parseFloat(f64, scalar.canonical);
            },
            .time, .vector_constraint => return error.MissingField,
        };
    }

    fn derivedJoinRangeDateValue(
        self: *Index,
        request: DerivedJoinFoldRequest,
        group_fact: ProjectedFact,
        measure_fact: ProjectedFact,
        field_name: []const u8,
    ) !u64 {
        const role = request.range_role orelse return error.InvalidAlgebraicConfig;
        return switch (role) {
            .time => blk: {
                const time_text = (try group_fact.timeText(field_name)) orelse (try measure_fact.timeText(field_name)) orelse return error.MissingField;
                break :blk (try parseDateTimeOptionalToNs(time_text)) orelse return error.MissingField;
            },
            .group => blk: {
                const encoded = group_fact.findGroupToken(field_name) orelse return error.MissingField;
                const scalar_text = try token.scalarTokenTextAlloc(self.alloc, encoded);
                defer self.alloc.free(scalar_text);
                break :blk (try parseDateTimeOptionalToNs(scalar_text)) orelse return error.MissingField;
            },
            .measure, .vector_constraint => return error.MissingField,
        };
    }

    fn derivedJoinContributionAlloc(self: *Index, op: algebra.Op, measure_value: ?MeasureValue) ![]u8 {
        return switch (op) {
            .count => try algebra.encodeI64Alloc(self.alloc, 1),
            .sum, .min, .max => blk: {
                const measure = measure_value orelse return error.MissingField;
                break :blk try self.alloc.dupe(u8, measure.raw);
            },
            .sumsquares => blk: {
                const measure = measure_value orelse return error.MissingField;
                const value = try algebra.parseF64(measure.raw);
                break :blk try algebra.encodeF64Alloc(self.alloc, value * value);
            },
            .avg => blk: {
                const measure = measure_value orelse return error.MissingField;
                break :blk try algebra.encodeAvgAlloc(self.alloc, .{
                    .sum = try algebra.parseF64(measure.raw),
                    .count = 1,
                });
            },
        };
    }

    fn derivedJoinConstraintsMatch(
        left_fact: ProjectedFact,
        right_fact: ProjectedFact,
        constraints: []const EncodedDerivedConstraint,
    ) !bool {
        for (constraints) |constraint| {
            const left_match = try left_fact.groupTokenConstraintMatch(constraint.field, constraint.scalar);
            const right_match = try right_fact.groupTokenConstraintMatch(constraint.field, constraint.scalar);
            if (left_match == null and right_match == null) return false;
            if (left_match) |matches| {
                if (!matches) return false;
            }
            if (right_match) |matches| {
                if (!matches) return false;
            }
        }
        return true;
    }

    fn projectJoinFactAlloc(self: *Index, root: std.json.Value, join_cfg: JoinConfig, side: join_mod.Side) ![]u8 {
        var parts = std.ArrayListUnmanaged([]const u8).empty;
        defer parts.deinit(self.alloc);
        var owned = std.ArrayListUnmanaged([]u8).empty;
        defer {
            for (owned.items) |item| self.alloc.free(item);
            owned.deinit(self.alloc);
        }

        try parts.append(self.alloc, "f1");
        for (self.config().group_fields) |field| {
            if (!self.joinFactNeedsGroupField(join_cfg, side, field.name)) continue;
            const value = (try self.fieldScalarTokenAlloc(root, field.name)) orelse continue;
            owned.append(self.alloc, value) catch |err| {
                self.alloc.free(value);
                return err;
            };
            try parts.appendSlice(self.alloc, &.{ "g", field.name, value });
        }
        for (self.config().measure_fields) |field| {
            if (!self.joinFactNeedsMeasureField(join_cfg, side, field.name)) continue;
            const value = (try self.fieldMeasureAlloc(root, field.name)) orelse continue;
            owned.append(self.alloc, value.raw) catch |err| {
                value.deinit(self.alloc);
                return err;
            };
            owned.append(self.alloc, value.support_token) catch |err| {
                self.alloc.free(value.support_token);
                return err;
            };
            try parts.appendSlice(self.alloc, &.{ "m", field.name, value.raw, value.support_token });
        }
        for (self.config().time_fields) |field| {
            if (!self.joinFactNeedsTimeField(join_cfg, side, field.name)) continue;
            const value = (try self.fieldStringAlloc(root, field.name, .time)) orelse continue;
            owned.append(self.alloc, value) catch |err| {
                self.alloc.free(value);
                return err;
            };
            try parts.appendSlice(self.alloc, &.{ "t", field.name, value });
        }
        return try token.canonicalTupleAlloc(self.alloc, parts.items);
    }

    fn joinFactNeedsGroupField(self: *Index, join_cfg: JoinConfig, side: join_mod.Side, field_name: []const u8) bool {
        _ = self;
        const key_fields = if (side == .left) join_cfg.left_fields else join_cfg.right_fields;
        if (stringSliceContains(key_fields, field_name)) return true;
        // Join facts are the durable substrate for both configured join
        // tensors and derived bounded join folds. Keep scalar group fields on
        // the side fact when present so future exact-law query rewrites do not
        // need to rescan source documents.
        return true;
    }

    fn joinFactNeedsMeasureField(self: *Index, join_cfg: JoinConfig, side: join_mod.Side, field_name: []const u8) bool {
        _ = self;
        _ = join_cfg;
        _ = side;
        _ = field_name;
        // As with group fields, measure facts are retained for derived
        // distributive joins. Missing measures are skipped during projection,
        // so this only expands facts for documents that actually carry the
        // measure.
        return true;
    }

    fn joinFactNeedsTimeField(_: *Index, join_cfg: JoinConfig, side: join_mod.Side, field_name: []const u8) bool {
        _ = join_cfg;
        _ = side;
        _ = field_name;
        // Derived date-histogram folds need side-local time facts in the same
        // durable join-fact substrate as scalar groups and measures.
        return true;
    }

    fn joinFactKeyAlloc(
        self: *Index,
        join_cfg: JoinConfig,
        side: join_mod.Side,
        join_id: []const u8,
        fact: ProjectedFact,
        doc_key: []const u8,
    ) ![]u8 {
        const mode = join_mod.temporalMode(join_cfg.temporal_bucket, join_cfg.temporal_window_seconds);
        return switch (mode) {
            .none => try self.keyAlloc(&.{ "jf", join_cfg.name, side.tag(), join_id, "e", doc_key }),
            .bucket => blk: {
                const bucket_start = try self.joinFactBucketAlloc(join_cfg, side, fact);
                defer self.alloc.free(bucket_start);
                break :blk try self.keyAlloc(&.{ "jf", join_cfg.name, side.tag(), join_id, "b", bucket_start, doc_key });
            },
            .window => blk: {
                const time_key = try self.joinFactTimeKeyAlloc(join_cfg, side, fact);
                defer self.alloc.free(time_key);
                break :blk try self.keyAlloc(&.{ "jf", join_cfg.name, side.tag(), join_id, "w", time_key, doc_key });
            },
            .bucket_window => blk: {
                const bucket_start = try self.joinFactBucketAlloc(join_cfg, side, fact);
                defer self.alloc.free(bucket_start);
                const time_key = try self.joinFactTimeKeyAlloc(join_cfg, side, fact);
                defer self.alloc.free(time_key);
                break :blk try self.keyAlloc(&.{ "jf", join_cfg.name, side.tag(), join_id, "bw", bucket_start, time_key, doc_key });
            },
        };
    }

    fn joinFactOrdinalKeyAlloc(
        self: *Index,
        join_cfg: JoinConfig,
        side: join_mod.Side,
        join_id: []const u8,
        fact: ProjectedFact,
        ordinal: doc_set.DocOrdinal,
    ) ![]u8 {
        const ordinal_component = ordinalComponent(ordinal);
        const mode = join_mod.temporalMode(join_cfg.temporal_bucket, join_cfg.temporal_window_seconds);
        return switch (mode) {
            .none => try self.keyAlloc(&.{ "jf_ord", join_cfg.name, side.tag(), join_id, "e", ordinal_component[0..] }),
            .bucket => blk: {
                const bucket_start = try self.joinFactBucketAlloc(join_cfg, side, fact);
                defer self.alloc.free(bucket_start);
                break :blk try self.keyAlloc(&.{ "jf_ord", join_cfg.name, side.tag(), join_id, "b", bucket_start, ordinal_component[0..] });
            },
            .window => blk: {
                const time_key = try self.joinFactTimeKeyAlloc(join_cfg, side, fact);
                defer self.alloc.free(time_key);
                break :blk try self.keyAlloc(&.{ "jf_ord", join_cfg.name, side.tag(), join_id, "w", time_key, ordinal_component[0..] });
            },
            .bucket_window => blk: {
                const bucket_start = try self.joinFactBucketAlloc(join_cfg, side, fact);
                defer self.alloc.free(bucket_start);
                const time_key = try self.joinFactTimeKeyAlloc(join_cfg, side, fact);
                defer self.alloc.free(time_key);
                break :blk try self.keyAlloc(&.{ "jf_ord", join_cfg.name, side.tag(), join_id, "bw", bucket_start, time_key, ordinal_component[0..] });
            },
        };
    }

    fn joinScanBoundsAlloc(
        self: *Index,
        join_cfg: JoinConfig,
        scan_side: join_mod.Side,
        join_id: []const u8,
        changed_fact: ProjectedFact,
        changed_side: join_mod.Side,
    ) !JoinScanBounds {
        return try self.joinScanBoundsForNamespaceAlloc("jf", join_cfg, scan_side, join_id, changed_fact, changed_side);
    }

    fn joinScanBoundsPreferOrdinalAlloc(
        self: *Index,
        txn: anytype,
        join_cfg: JoinConfig,
        scan_side: join_mod.Side,
        join_id: []const u8,
        changed_fact: ProjectedFact,
        changed_side: join_mod.Side,
    ) !JoinScanBounds {
        var legacy = try self.joinScanBoundsForNamespaceAlloc("jf", join_cfg, scan_side, join_id, changed_fact, changed_side);
        errdefer legacy.deinit(self.alloc);
        var ordinal = try self.joinScanBoundsForNamespaceAlloc("jf_ord", join_cfg, scan_side, join_id, changed_fact, changed_side);
        errdefer ordinal.deinit(self.alloc);
        const legacy_count = try self.countRowsWithPrefixTxn(txn, legacy.prefix);
        const ordinal_count = try self.countRowsWithPrefixTxn(txn, ordinal.prefix);
        if (legacy_count == ordinal_count) {
            legacy.deinit(self.alloc);
            return ordinal;
        }
        ordinal.deinit(self.alloc);
        return legacy;
    }

    fn joinScanBoundsForNamespaceAlloc(
        self: *Index,
        namespace: []const u8,
        join_cfg: JoinConfig,
        scan_side: join_mod.Side,
        join_id: []const u8,
        changed_fact: ProjectedFact,
        changed_side: join_mod.Side,
    ) !JoinScanBounds {
        const prefix = try self.joinMatchPrefixForNamespaceAlloc(namespace, join_cfg, scan_side, join_id, changed_fact, changed_side);
        errdefer self.alloc.free(prefix);

        const mode = join_mod.temporalMode(join_cfg.temporal_bucket, join_cfg.temporal_window_seconds);
        if (!self.config().enable_temporal_range_pruning or join_cfg.temporal_window_seconds == null or (mode != .window and mode != .bucket_window)) {
            return .{ .prefix = prefix, .start = try self.alloc.dupe(u8, prefix) };
        }

        const changed_time = try self.joinFactTimeText(join_cfg, changed_side, changed_fact);
        const changed_seconds = try cylinder.unixSeconds(changed_time);
        const window = join_cfg.temporal_window_seconds.?;
        const min_seconds = clampedAddI64(changed_seconds, -window);
        const max_seconds = clampedAddI64(changed_seconds, window);
        const min_key = try sortableI64Alloc(self.alloc, min_seconds);
        defer self.alloc.free(min_key);
        const max_key = try sortableI64Alloc(self.alloc, max_seconds);
        errdefer self.alloc.free(max_key);
        const start = try appendKeyComponentAlloc(self.alloc, prefix, min_key);
        return .{ .prefix = prefix, .start = start, .max_time_key = max_key };
    }

    fn joinMatchPrefixAlloc(
        self: *Index,
        join_cfg: JoinConfig,
        scan_side: join_mod.Side,
        join_id: []const u8,
        changed_fact: ProjectedFact,
        changed_side: join_mod.Side,
    ) ![]u8 {
        return try self.joinMatchPrefixForNamespaceAlloc("jf", join_cfg, scan_side, join_id, changed_fact, changed_side);
    }

    fn joinMatchPrefixForNamespaceAlloc(
        self: *Index,
        namespace: []const u8,
        join_cfg: JoinConfig,
        scan_side: join_mod.Side,
        join_id: []const u8,
        changed_fact: ProjectedFact,
        changed_side: join_mod.Side,
    ) ![]u8 {
        const mode = join_mod.temporalMode(join_cfg.temporal_bucket, join_cfg.temporal_window_seconds);
        return switch (mode) {
            .none => try self.keyAlloc(&.{ namespace, join_cfg.name, scan_side.tag(), join_id, "e" }),
            .bucket => blk: {
                const bucket_start = try self.joinFactBucketAlloc(join_cfg, changed_side, changed_fact);
                defer self.alloc.free(bucket_start);
                break :blk try self.keyAlloc(&.{ namespace, join_cfg.name, scan_side.tag(), join_id, "b", bucket_start });
            },
            .window => try self.keyAlloc(&.{ namespace, join_cfg.name, scan_side.tag(), join_id, "w" }),
            .bucket_window => blk: {
                const bucket_start = try self.joinFactBucketAlloc(join_cfg, changed_side, changed_fact);
                defer self.alloc.free(bucket_start);
                break :blk try self.keyAlloc(&.{ namespace, join_cfg.name, scan_side.tag(), join_id, "bw", bucket_start });
            },
        };
    }

    fn joinTemporalFactsMatch(
        self: *Index,
        join_cfg: JoinConfig,
        changed_side: join_mod.Side,
        changed_fact: ProjectedFact,
        opposite_fact: ProjectedFact,
    ) !bool {
        const window = join_cfg.temporal_window_seconds orelse return true;
        const opposite_side = changed_side.opposite();
        const changed_time = try self.joinFactTimeText(join_cfg, changed_side, changed_fact);
        const opposite_time = try self.joinFactTimeText(join_cfg, opposite_side, opposite_fact);
        const changed_seconds = try cylinder.unixSeconds(changed_time);
        const opposite_seconds = try cylinder.unixSeconds(opposite_time);
        const delta = if (changed_seconds >= opposite_seconds) changed_seconds - opposite_seconds else opposite_seconds - changed_seconds;
        return delta <= window;
    }

    fn joinFactBucketAlloc(self: *Index, join_cfg: JoinConfig, side: join_mod.Side, fact: ProjectedFact) ![]u8 {
        const bucket = cylinder.Bucket.parse(join_cfg.temporal_bucket orelse return error.InvalidAlgebraicConfig) orelse return error.InvalidAlgebraicConfig;
        const time_text = try self.joinFactTimeText(join_cfg, side, fact);
        return try cylinder.bucketStartAlloc(self.alloc, bucket, time_text);
    }

    fn joinFactTimeText(_: *Index, join_cfg: JoinConfig, side: join_mod.Side, fact: ProjectedFact) ![]const u8 {
        const field_name = switch (side) {
            .left => join_cfg.left_time_field,
            .right => join_cfg.right_time_field,
        } orelse return error.MissingField;
        return (try fact.timeText(field_name)) orelse return error.MissingField;
    }

    fn joinFactTimeKeyAlloc(self: *Index, join_cfg: JoinConfig, side: join_mod.Side, fact: ProjectedFact) ![]u8 {
        const time_text = try self.joinFactTimeText(join_cfg, side, fact);
        return try sortableI64Alloc(self.alloc, try cylinder.unixSeconds(time_text));
    }

    fn groupKeyAlloc(self: *Index, root: std.json.Value, fields: []const []const u8) ![]u8 {
        var values = try self.alloc.alloc([]const u8, fields.len);
        defer self.alloc.free(values);
        var owned = std.ArrayListUnmanaged([]u8).empty;
        defer {
            for (owned.items) |item| self.alloc.free(item);
            owned.deinit(self.alloc);
        }
        for (fields, 0..) |field_name, i| {
            const value = (try self.fieldScalarTokenAlloc(root, field_name)) orelse return error.MissingField;
            try owned.append(self.alloc, value);
            values[i] = value;
        }
        return try token.canonicalTupleAlloc(self.alloc, values);
    }

    fn fieldScalarTokenAlloc(self: *Index, root: std.json.Value, field_name: []const u8) !?[]u8 {
        const cfg = self.fieldConfig(field_name, .group) orelse return null;
        const value = valueAtPath(root, cfg.path) orelse return null;
        return try token.scalarTokenFromFieldValueAlloc(self.alloc, cfg.type, value);
    }

    fn fieldStringAlloc(self: *Index, root: std.json.Value, field_name: []const u8, class: FieldClass) !?[]u8 {
        const cfg = self.fieldConfig(field_name, class) orelse return null;
        const value = valueAtPath(root, cfg.path) orelse return null;
        return try jsonScalarToStringAlloc(self.alloc, value);
    }

    fn fieldMeasureAlloc(self: *Index, root: std.json.Value, field_name: []const u8) !?MeasureValue {
        const cfg = self.fieldConfig(field_name, .measure) orelse return null;
        const value = valueAtPath(root, cfg.path) orelse return null;
        const support_token = switch (value) {
            .string => |text| token.scalarTokenFromFieldTextAlloc(self.alloc, cfg.type, text) catch |err| switch (err) {
                error.OutOfMemory => return err,
                else => return null,
            },
            else => (try token.scalarTokenFromFieldValueAlloc(self.alloc, cfg.type, value)) orelse return null,
        };
        errdefer self.alloc.free(support_token);
        const raw = try token.scalarTokenTextAlloc(self.alloc, support_token);
        return .{ .raw = raw, .support_token = support_token };
    }

    fn factMeasureAlloc(self: *Index, facts: []const fact_mod.Fact, field_name: []const u8) !?MeasureValue {
        const scalar = fact_mod.findScalar(facts, .measure, field_name) orelse return null;
        const raw = try token.scalarTokenTextAlloc(self.alloc, scalar);
        errdefer self.alloc.free(raw);
        const support_token = try self.alloc.dupe(u8, scalar);
        return .{ .raw = raw, .support_token = support_token };
    }

    fn factTimeTextAlloc(self: *Index, facts: []const fact_mod.Fact, field_name: []const u8) !?[]u8 {
        const scalar = fact_mod.findScalar(facts, .time, field_name) orelse return null;
        return try token.scalarTokenTextAlloc(self.alloc, scalar);
    }

    fn joinSideMatches(self: *Index, root: std.json.Value, join_cfg: JoinConfig, left: bool) !bool {
        const field_name_opt = if (left) join_cfg.left_type_field else join_cfg.right_type_field;
        const expected_opt = if (left) join_cfg.left_type_value else join_cfg.right_type_value;
        if (field_name_opt == null and expected_opt == null) return true;
        const field_name = field_name_opt orelse return false;
        const expected = expected_opt orelse return false;
        const actual = (try self.fieldStringAlloc(root, field_name, .any)) orelse return false;
        defer self.alloc.free(actual);
        return std.mem.eql(u8, actual, expected);
    }

    fn recordError(self: *Index, doc_key: []const u8, reason: []const u8) !void {
        self.parse_error_count += 1;
        if (self.last_error_doc_key) |value| self.alloc.free(value);
        if (self.last_error_reason) |value| self.alloc.free(value);
        self.last_error_doc_key = null;
        self.last_error_reason = null;
        self.last_error_doc_key = try self.alloc.dupe(u8, doc_key);
        errdefer {
            if (self.last_error_doc_key) |value| self.alloc.free(value);
            self.last_error_doc_key = null;
        }
        self.last_error_reason = try self.alloc.dupe(u8, reason);
    }
};

fn materializationSideRoot(side_name: ?[]const u8, right_root: std.json.Value, left_root: std.json.Value, default_left: bool) std.json.Value {
    if (side_name) |side| {
        if (std.mem.eql(u8, side, "left")) return left_root;
        if (std.mem.eql(u8, side, "right")) return right_root;
    }
    return if (default_left) left_root else right_root;
}

fn materializationSideFactRequired(side_name: ?[]const u8, right_fact: ProjectedFact, left_fact: ProjectedFact) !ProjectedFact {
    return switch (try materializationSideRequired(side_name)) {
        .left => left_fact,
        .right => right_fact,
    };
}

fn materializationSideRequired(side_name: ?[]const u8) !join_mod.Side {
    const side = side_name orelse return error.InvalidAlgebraicConfig;
    if (std.mem.eql(u8, side, "left")) return .left;
    if (std.mem.eql(u8, side, "right")) return .right;
    return error.InvalidAlgebraicConfig;
}

fn adaptiveObservationPrefixAlloc(alloc: Allocator, index_name: []const u8) ![]u8 {
    return try token.canonicalTupleAlloc(alloc, &.{ "\x00\x00__algebraic__", index_name, "v4", "observe" });
}

fn adaptiveMaterializationStatePrefixAlloc(alloc: Allocator, index_name: []const u8) ![]u8 {
    return try token.canonicalTupleAlloc(alloc, &.{ "\x00\x00__algebraic__", index_name, "v4", "materialization-state" });
}

fn adaptiveCandidatePrefixAlloc(alloc: Allocator, index_name: []const u8) ![]u8 {
    return try token.canonicalTupleAlloc(alloc, &.{ "\x00\x00__algebraic__", index_name, "v4", "adaptive-candidate" });
}

fn adaptiveDecisionHistoryPrefixAlloc(alloc: Allocator, index_name: []const u8) ![]u8 {
    return try token.canonicalTupleAlloc(alloc, &.{ "\x00\x00__algebraic__", index_name, "v4", "adaptive-decision-history" });
}

fn adaptiveDecisionHistoryKeyAlloc(alloc: Allocator, index_name: []const u8, recommendation: []const u8, generation: u64) ![]u8 {
    const generation_text = try std.fmt.allocPrint(alloc, "{d:0>20}", .{generation});
    defer alloc.free(generation_text);
    return try token.canonicalTupleAlloc(alloc, &.{ "\x00\x00__algebraic__", index_name, "v4", "adaptive-decision-history", recommendation, generation_text });
}

fn adaptiveProgressPrefixAlloc(alloc: Allocator, index_name: []const u8) ![]u8 {
    return try token.canonicalTupleAlloc(alloc, &.{ "\x00\x00__algebraic__", index_name, "v4", "adaptive-progress" });
}

fn findMaterializationState(states: []const PersistedMaterializationState, recommendation: []const u8) ?PersistedMaterializationState {
    for (states) |state| {
        if (std.mem.eql(u8, state.recommendation, recommendation)) return state;
    }
    return null;
}

fn findAdaptiveCandidate(candidates: []const PersistedAdaptiveCandidate, recommendation: []const u8) ?PersistedAdaptiveCandidate {
    for (candidates) |candidate| {
        if (std.mem.eql(u8, candidate.recommendation, recommendation)) return candidate;
    }
    return null;
}

fn shouldDecayObservation(policy: adaptive_mod.Policy, idle_miss_count: u64, lifecycle: adaptive_mod.Lifecycle) bool {
    if (policy.observation_decay_after_misses == 0) return false;
    if (policy.observation_decay_retain_percent >= 100) return false;
    if (idle_miss_count < policy.observation_decay_after_misses) return false;
    return lifecycle != .backfilling;
}

fn decayObservationCount(policy: adaptive_mod.Policy, count: u64) u64 {
    if (count == 0) return 0;
    const retained = saturatedMul(count, policy.observation_decay_retain_percent) / 100;
    return if (retained < count) retained else count - 1;
}

fn adaptiveWriteCost(cost: AdaptiveCostInputs) u64 {
    const row_cost = saturatedMul(@max(cost.doc_rows, @as(u64, 1)), @max(cost.write_amplification, @as(u64, 1)));
    const tensor_cost = saturatedAdd(cost.tensor_rows, cost.bucket_cardinality);
    return saturatedAdd(saturatedAdd(row_cost, tensor_cost), cost.storage_bytes / 256);
}

fn saturatedMul(a: u64, b: u64) u64 {
    return std.math.mul(u64, a, b) catch std.math.maxInt(u64);
}

fn saturatedAdd(a: u64, b: u64) u64 {
    return std.math.add(u64, a, b) catch std.math.maxInt(u64);
}

fn stringSliceContains(values: []const []const u8, needle: []const u8) bool {
    for (values) |value| {
        if (std.mem.eql(u8, value, needle)) return true;
    }
    return false;
}

fn appendKeyComponentAlloc(alloc: Allocator, prefix: []const u8, component: []const u8) ![]u8 {
    var out = std.ArrayListUnmanaged(u8).empty;
    errdefer out.deinit(alloc);
    try out.appendSlice(alloc, prefix);
    try token.appendComponent(&out, alloc, component);
    return try out.toOwnedSlice(alloc);
}

fn sortableI64Alloc(alloc: Allocator, value: i64) ![]u8 {
    const biased: u64 = @bitCast(value ^ std.math.minInt(i64));
    const out = try alloc.alloc(u8, 8);
    std.mem.writeInt(u64, out[0..8], biased, .big);
    return out;
}

fn sortableU64TextAlloc(alloc: Allocator, value: u64) ![]u8 {
    return try std.fmt.allocPrint(alloc, "{d:0>20}", .{value});
}

fn clampedAddI64(value: i64, delta: i64) i64 {
    const sum = @as(i128, value) + @as(i128, delta);
    if (sum > std.math.maxInt(i64)) return std.math.maxInt(i64);
    if (sum < std.math.minInt(i64)) return std.math.minInt(i64);
    return @intCast(sum);
}

fn valueAtPath(root: std.json.Value, path: []const u8) ?std.json.Value {
    var current = root;
    var it = std.mem.splitScalar(u8, path, '.');
    while (it.next()) |part| {
        if (part.len == 0) return null;
        if (current != .object) return null;
        current = current.object.get(part) orelse return null;
    }
    return current;
}

fn rangeSpecMatchesScalar(alloc: Allocator, spec: RangeSpec, encoded: []const u8) !bool {
    const scalar = try value_mod.parseScalarAlloc(alloc, encoded);
    defer value_mod.deinitScalar(alloc, scalar);
    return switch (spec.kind) {
        .numeric => blk: {
            if (scalar.kind != .integer and scalar.kind != .number) break :blk false;
            const parsed = std.fmt.parseFloat(f64, scalar.canonical) catch break :blk false;
            break :blk scalarInNumberRange(parsed, spec.min_number, spec.max_number, spec.inclusive_min, spec.inclusive_max);
        },
        .term => blk: {
            if (scalar.kind != .string and scalar.kind != .bytes) break :blk false;
            break :blk scalarInTermRange(scalar.canonical, spec.min_term, spec.max_term, spec.inclusive_min, spec.inclusive_max);
        },
        .date => blk: {
            if (scalar.kind != .datetime) break :blk false;
            const parsed = parseDateTimeOptionalToNs(scalar.canonical) catch break :blk false;
            const timestamp_ns = parsed orelse break :blk false;
            break :blk scalarInDateRange(timestamp_ns, spec.start_ns, spec.end_ns, spec.inclusive_min, spec.inclusive_max);
        },
    };
}

fn scalarInNumberRange(value: f64, min: ?f64, max: ?f64, inclusive_min: bool, inclusive_max: bool) bool {
    if (min) |lower| {
        if (value < lower or (!inclusive_min and value == lower)) return false;
    }
    if (max) |upper| {
        if (value > upper or (!inclusive_max and value == upper)) return false;
    }
    return true;
}

fn scalarInTermRange(value: []const u8, min: ?[]const u8, max: ?[]const u8, inclusive_min: bool, inclusive_max: bool) bool {
    if (min) |lower| {
        const order = std.mem.order(u8, value, lower);
        if (order == .lt or (!inclusive_min and order == .eq)) return false;
    }
    if (max) |upper| {
        const order = std.mem.order(u8, value, upper);
        if (order == .gt or (!inclusive_max and order == .eq)) return false;
    }
    return true;
}

fn scalarInDateRange(value_ns: u64, start_ns: ?u64, end_ns: ?u64, inclusive_start: bool, inclusive_end: bool) bool {
    if (start_ns) |lower| {
        if (value_ns < lower or (!inclusive_start and value_ns == lower)) return false;
    }
    if (end_ns) |upper| {
        if (value_ns > upper or (!inclusive_end and value_ns == upper)) return false;
    }
    return true;
}

fn rangeFieldAcceptsNumeric(field_type: []const u8) bool {
    return switch (value_mod.kindFromFieldType(field_type)) {
        .integer, .number => true,
        else => false,
    };
}

fn rangeFieldAcceptsTerm(field_type: []const u8) bool {
    return switch (value_mod.kindFromFieldType(field_type)) {
        .string, .bytes => true,
        else => false,
    };
}

fn rangeFieldAcceptsKind(field_type: []const u8, kind: RangeKind) bool {
    return switch (kind) {
        .numeric => rangeFieldAcceptsNumeric(field_type),
        .term => rangeFieldAcceptsTerm(field_type),
        .date => value_mod.kindFromFieldType(field_type) == .datetime,
    };
}

fn wildcardLiteralPrefix(pattern: []const u8) []const u8 {
    for (pattern, 0..) |ch, i| {
        if (ch == '*' or ch == '?') return pattern[0..i];
    }
    return pattern;
}

fn wildcardPatternHasMeta(pattern: []const u8) bool {
    return std.mem.indexOfAny(u8, pattern, "*?") != null;
}

fn wildcardMatch(pattern: []const u8, text: []const u8) bool {
    var pi: usize = 0;
    var ti: usize = 0;
    var star_pi: ?usize = null;
    var star_ti: usize = 0;

    while (ti < text.len) {
        if (pi < pattern.len and (pattern[pi] == '?' or pattern[pi] == text[ti])) {
            pi += 1;
            ti += 1;
        } else if (pi < pattern.len and pattern[pi] == '*') {
            star_pi = pi;
            star_ti = ti;
            pi += 1;
        } else if (star_pi) |sp| {
            pi = sp + 1;
            star_ti += 1;
            ti = star_ti;
        } else {
            return false;
        }
    }

    while (pi < pattern.len and pattern[pi] == '*') pi += 1;
    return pi == pattern.len;
}

fn regexpLiteralPrefix(pattern: []const u8) []const u8 {
    for (pattern, 0..) |ch, i| {
        switch (ch) {
            '.', '^', '$', '*', '+', '?', '(', ')', '[', ']', '{', '}', '|', '\\' => return pattern[0..i],
            else => {},
        }
    }
    return pattern;
}

fn parseFuzzyQuery(value: std.json.Value) ?FuzzyQuery {
    switch (value) {
        .string => |text| return .{ .term = text, .max_edits = 1, .prefix_len = 0 },
        .object => |object| {
            var out = FuzzyQuery{
                .term = jsonStringValue(object.get("query") orelse return null) orelse return null,
                .max_edits = 1,
                .prefix_len = 0,
            };
            if (!parseFuzzyOptions(object, &out)) return null;
            return out;
        },
        else => return null,
    }
}

fn parseFuzzyOptions(object: anytype, out: *FuzzyQuery) bool {
    if (object.get("max_edits")) |edits| {
        out.max_edits = jsonU8Value(edits) orelse return false;
    }
    if (object.get("prefix_length")) |prefix| {
        out.prefix_len = jsonU8Value(prefix) orelse return false;
    }
    if (object.get("auto_fuzzy")) |auto| {
        if (auto != .bool) return false;
        if (auto.bool) out.max_edits = if (out.term.len > 5) 2 else if (out.term.len > 2) 1 else 0;
    }
    return true;
}

fn jsonU8Value(value: std.json.Value) ?u8 {
    return switch (value) {
        .integer => |number| std.math.cast(u8, number),
        .float => |number| blk: {
            if (!std.math.isFinite(number) or @round(number) != number) break :blk null;
            const parsed: i64 = @intFromFloat(number);
            break :blk std.math.cast(u8, parsed);
        },
        else => null,
    };
}

fn fuzzyMatchesScalar(alloc: Allocator, candidate: []const u8, folded_term: []const u8, max_edits: u8) !bool {
    if (candidate.len == 0 or folded_term.len == 0) return std.mem.eql(u8, candidate, folded_term);
    const folded_candidate = try asciiLowerAlloc(alloc, candidate);
    defer alloc.free(folded_candidate);

    var automaton = levenshtein_mod.LevenshteinAutomaton{
        .term = folded_term,
        .max_distance = max_edits,
        .alloc = alloc,
    };
    defer automaton.deinit();

    var state = automaton.automaton().start();
    for (folded_candidate) |byte| {
        state = automaton.automaton().accept(state, byte);
        if (!automaton.automaton().canMatch(state)) return false;
    }
    return automaton.automaton().isMatch(state);
}

fn asciiLowerAlloc(alloc: Allocator, input: []const u8) ![]u8 {
    const out = try alloc.dupe(u8, input);
    for (out) |*byte| byte.* = std.ascii.toLower(byte.*);
    return out;
}

fn containsCaseInsensitive(haystack: []const u8, needle: []const u8) bool {
    if (needle.len == 0) return true;
    if (haystack.len < needle.len) return false;
    var i: usize = 0;
    while (i + needle.len <= haystack.len) : (i += 1) {
        if (asciiEqualIgnoreCase(haystack[i .. i + needle.len], needle)) return true;
    }
    return false;
}

fn asciiEqualIgnoreCase(left: []const u8, right: []const u8) bool {
    if (left.len != right.len) return false;
    for (left, right) |l, r| {
        if (std.ascii.toLower(l) != std.ascii.toLower(r)) return false;
    }
    return true;
}

const IpCidr = struct {
    network: [4]u8,
    prefix_len: u8,
};

const IpRangeQuery = struct {
    cidr: ?IpCidr = null,
    exact_ip: ?[4]u8 = null,
};

fn ipRangeQuery(text: []const u8) ?IpRangeQuery {
    if (parseIpCidr(text)) |cidr| return .{ .cidr = cidr };
    if (parseIPv4(text)) |exact_ip| return .{ .exact_ip = exact_ip };
    return null;
}

fn ipRangeQueryMatches(query: IpRangeQuery, text: []const u8) bool {
    const candidate = parseIPv4(text) orelse return false;
    if (query.cidr) |cidr| return ipInRange(candidate, cidr.network, cidr.prefix_len);
    if (query.exact_ip) |wanted| return std.mem.eql(u8, wanted[0..], candidate[0..]);
    return false;
}

fn parseIpCidr(cidr: []const u8) ?IpCidr {
    const slash_pos = std.mem.indexOfScalar(u8, cidr, '/') orelse return null;
    const ip = parseIPv4(cidr[0..slash_pos]) orelse return null;
    const prefix_len = std.fmt.parseInt(u8, cidr[slash_pos + 1 ..], 10) catch return null;
    if (prefix_len > 32) return null;
    const mask = ipMask(prefix_len);
    return .{
        .network = .{ ip[0] & mask[0], ip[1] & mask[1], ip[2] & mask[2], ip[3] & mask[3] },
        .prefix_len = prefix_len,
    };
}

fn parseIPv4(text: []const u8) ?[4]u8 {
    var parts = std.mem.splitScalar(u8, text, '.');
    var out: [4]u8 = undefined;
    var i: usize = 0;
    while (parts.next()) |part| {
        if (i >= 4 or part.len == 0) return null;
        out[i] = std.fmt.parseInt(u8, part, 10) catch return null;
        i += 1;
    }
    if (i != 4) return null;
    return out;
}

fn ipMask(prefix_len: u8) [4]u8 {
    var mask = [_]u8{ 0, 0, 0, 0 };
    var remaining = prefix_len;
    for (&mask) |*byte| {
        if (remaining >= 8) {
            byte.* = 0xff;
            remaining -= 8;
        } else if (remaining > 0) {
            byte.* = @as(u8, 0xff) << @intCast(8 - remaining);
            remaining = 0;
        }
    }
    return mask;
}

fn ipInRange(ip: [4]u8, network: [4]u8, prefix_len: u8) bool {
    const mask = ipMask(prefix_len);
    return (ip[0] & mask[0]) == network[0] and
        (ip[1] & mask[1]) == network[1] and
        (ip[2] & mask[2]) == network[2] and
        (ip[3] & mask[3]) == network[3];
}

fn rangeKindForFieldType(field_type: []const u8) ?RangeKind {
    return switch (value_mod.kindFromFieldType(field_type)) {
        .integer, .number => .numeric,
        .string, .bytes => .term,
        .datetime => .date,
        else => null,
    };
}

const JsonRangeBound = struct {
    value: std.json.Value,
    inclusive: bool,
};

const FuzzyQuery = struct {
    term: []const u8,
    max_edits: u8,
    prefix_len: u8,
};

fn standardRangeSpecFromObject(field: anytype, object: anytype) !?RangeSpec {
    const kind = rangeKindForFieldType(field.type) orelse return null;
    const lower = try standardRangeLowerBound(object);
    const upper = try standardRangeUpperBound(object);
    if (lower == null and upper == null) return null;
    return switch (kind) {
        .numeric => RangeSpec{
            .field = field.field,
            .role = field.role,
            .kind = .numeric,
            .min_number = if (lower) |bound| try jsonOptionalF64Strict(bound.value) else null,
            .max_number = if (upper) |bound| try jsonOptionalF64Strict(bound.value) else null,
            .inclusive_min = if (lower) |bound| bound.inclusive else true,
            .inclusive_max = if (upper) |bound| bound.inclusive else false,
        },
        .term => RangeSpec{
            .field = field.field,
            .role = field.role,
            .kind = .term,
            .min_term = if (lower) |bound| try jsonOptionalStringStrict(bound.value) else null,
            .max_term = if (upper) |bound| try jsonOptionalStringStrict(bound.value) else null,
            .inclusive_min = if (lower) |bound| bound.inclusive else true,
            .inclusive_max = if (upper) |bound| bound.inclusive else false,
        },
        .date => RangeSpec{
            .field = field.field,
            .role = field.role,
            .kind = .date,
            .start_ns = if (lower) |bound| try jsonOptionalDateOrNsStrict(bound.value) else null,
            .end_ns = if (upper) |bound| try jsonOptionalDateOrNsStrict(bound.value) else null,
            .inclusive_min = if (lower) |bound| bound.inclusive else true,
            .inclusive_max = if (upper) |bound| bound.inclusive else false,
        },
    };
}

fn standardRangeLowerBound(object: anytype) !?JsonRangeBound {
    var found: ?JsonRangeBound = null;
    if (object.get("gte")) |value| try setJsonRangeBound(&found, value, true);
    if (object.get("gt")) |value| try setJsonRangeBound(&found, value, false);
    if (object.get("from")) |value| try setJsonRangeBound(&found, value, (try jsonOptionalBoolStrict(object.get("include_lower"))) orelse true);
    if (object.get("min")) |value| try setJsonRangeBound(&found, value, (try jsonOptionalBoolStrict(object.get("inclusive_min"))) orelse true);
    return found;
}

fn standardRangeUpperBound(object: anytype) !?JsonRangeBound {
    var found: ?JsonRangeBound = null;
    if (object.get("lte")) |value| try setJsonRangeBound(&found, value, true);
    if (object.get("lt")) |value| try setJsonRangeBound(&found, value, false);
    if (object.get("to")) |value| try setJsonRangeBound(&found, value, (try jsonOptionalBoolStrict(object.get("include_upper"))) orelse true);
    if (object.get("max")) |value| try setJsonRangeBound(&found, value, (try jsonOptionalBoolStrict(object.get("inclusive_max"))) orelse false);
    return found;
}

fn setJsonRangeBound(found: *?JsonRangeBound, value: std.json.Value, inclusive: bool) !void {
    if (found.* != null) return error.InvalidAlgebraicRange;
    found.* = .{ .value = value, .inclusive = inclusive };
}

fn jsonStringValue(value: std.json.Value) ?[]const u8 {
    return switch (value) {
        .string => |v| v,
        .null => null,
        else => null,
    };
}

pub fn isExplicitJsonPointerPath(path: []const u8) bool {
    return path.len == 0 or std.mem.startsWith(u8, path, "/");
}

fn pathFromPathPredicateObject(object: anytype) ?[]const u8 {
    if (object.get("path")) |path_value| {
        const path = jsonStringValue(path_value) orelse return null;
        if (!isExplicitJsonPointerPath(path)) return null;
        return path;
    }
    return null;
}

fn pathFromExistsFilter(value: std.json.Value) ?[]const u8 {
    return switch (value) {
        .string => |field_or_path| if (isExplicitJsonPointerPath(field_or_path)) field_or_path else null,
        .object => |object| blk: {
            if (object.get("path")) |path_value| {
                const path = jsonStringValue(path_value) orelse break :blk null;
                break :blk if (isExplicitJsonPointerPath(path)) path else null;
            }
            if (object.get("role") == null) {
                if (object.get("field")) |field_value| {
                    const field = jsonStringValue(field_value) orelse break :blk null;
                    break :blk if (isExplicitJsonPointerPath(field)) field else null;
                }
            }
            break :blk null;
        },
        else => null,
    };
}

const PathPrefixPredicate = struct {
    path: []const u8,
    prefix: []const u8,
};

const PathTextPredicate = struct {
    path: []const u8,
    text: []const u8,
};

const PathFuzzyPredicate = struct {
    path: []const u8,
    query: FuzzyQuery,
};

fn pathPrefixPredicate(prefix_value: std.json.Value, sibling_field_value: ?std.json.Value) ?PathPrefixPredicate {
    return switch (prefix_value) {
        .object => |object| blk: {
            if (pathFromPathPredicateObject(object)) |path| {
                const prefix = jsonStringValue(object.get("value") orelse object.get("prefix") orelse break :blk null) orelse break :blk null;
                break :blk .{ .path = path, .prefix = prefix };
            }
            if (object.get("role") == null) {
                if (object.get("field")) |field_value| {
                    const field = jsonStringValue(field_value) orelse break :blk null;
                    if (isExplicitJsonPointerPath(field)) {
                        const prefix = jsonStringValue(object.get("value") orelse object.get("prefix") orelse break :blk null) orelse break :blk null;
                        break :blk .{ .path = field, .prefix = prefix };
                    }
                }
            }
            if (object.count() == 1) {
                var it = object.iterator();
                const entry = it.next() orelse break :blk null;
                if (isExplicitJsonPointerPath(entry.key_ptr.*)) {
                    const prefix = jsonStringValue(entry.value_ptr.*) orelse break :blk null;
                    break :blk .{ .path = entry.key_ptr.*, .prefix = prefix };
                }
            }
            break :blk null;
        },
        .string => |prefix| blk: {
            const field = jsonStringValue(sibling_field_value orelse break :blk null) orelse break :blk null;
            break :blk if (isExplicitJsonPointerPath(field)) .{ .path = field, .prefix = prefix } else null;
        },
        else => null,
    };
}

fn pathPatternPredicate(object: anytype, pattern_field: []const u8) ?PathTextPredicate {
    if (pathFromPathPredicateObject(object)) |path| {
        const text = jsonStringValue(object.get(pattern_field) orelse object.get("value") orelse return null) orelse return null;
        return .{ .path = path, .text = text };
    }
    if (object.get("role") == null) {
        if (object.get("field")) |field_value| {
            const field = jsonStringValue(field_value) orelse return null;
            if (isExplicitJsonPointerPath(field)) {
                const text = jsonStringValue(object.get(pattern_field) orelse object.get("value") orelse return null) orelse return null;
                return .{ .path = field, .text = text };
            }
        }
    }
    if (object.count() == 1) {
        var it = object.iterator();
        const entry = it.next() orelse return null;
        if (isExplicitJsonPointerPath(entry.key_ptr.*)) {
            const text = jsonStringValue(entry.value_ptr.*) orelse return null;
            return .{ .path = entry.key_ptr.*, .text = text };
        }
    }
    return null;
}

fn pathFuzzyPredicate(object: anytype) ?PathFuzzyPredicate {
    if (pathFromPathPredicateObject(object)) |path| {
        var query = FuzzyQuery{
            .term = jsonStringValue(object.get("query") orelse object.get("value") orelse return null) orelse return null,
            .max_edits = 1,
            .prefix_len = 0,
        };
        if (!parseFuzzyOptions(object, &query)) return null;
        return .{ .path = path, .query = query };
    }
    if (object.get("role") == null) {
        if (object.get("field")) |field_value| {
            const field = jsonStringValue(field_value) orelse return null;
            if (isExplicitJsonPointerPath(field)) {
                var query = FuzzyQuery{
                    .term = jsonStringValue(object.get("query") orelse object.get("value") orelse return null) orelse return null,
                    .max_edits = 1,
                    .prefix_len = 0,
                };
                if (!parseFuzzyOptions(object, &query)) return null;
                return .{ .path = field, .query = query };
            }
        }
    }
    if (object.count() == 1) {
        var it = object.iterator();
        const entry = it.next() orelse return null;
        if (isExplicitJsonPointerPath(entry.key_ptr.*)) {
            const query = parseFuzzyQuery(entry.value_ptr.*) orelse return null;
            return .{ .path = entry.key_ptr.*, .query = query };
        }
    }
    return null;
}

fn pathRangePredicateFromObject(path: []const u8, object: anytype, kind: RangeKind) !?PathRangePredicate {
    if (!isExplicitJsonPointerPath(path)) return null;
    return switch (kind) {
        .numeric => PathRangePredicate{
            .path = path,
            .kind = .numeric,
            .min_number = jsonOptionalF64Strict(object.get("min")) catch return null,
            .max_number = jsonOptionalF64Strict(object.get("max")) catch return null,
            .inclusive_min = (jsonOptionalBoolStrict(object.get("inclusive_min")) catch return null) orelse true,
            .inclusive_max = (jsonOptionalBoolStrict(object.get("inclusive_max")) catch return null) orelse false,
        },
        .term => PathRangePredicate{
            .path = path,
            .kind = .term,
            .min_term = jsonOptionalStringStrict(object.get("min")) catch return null,
            .max_term = jsonOptionalStringStrict(object.get("max")) catch return null,
            .inclusive_min = (jsonOptionalBoolStrict(object.get("inclusive_min")) catch return null) orelse true,
            .inclusive_max = (jsonOptionalBoolStrict(object.get("inclusive_max")) catch return null) orelse false,
        },
        .date => PathRangePredicate{
            .path = path,
            .kind = .date,
            .start_ns = if (object.get("start_ns") != null)
                jsonOptionalU64Strict(object.get("start_ns")) catch return null
            else
                jsonOptionalDateTimeNsStrict(object.get("start")) catch return null,
            .end_ns = if (object.get("end_ns") != null)
                jsonOptionalU64Strict(object.get("end_ns")) catch return null
            else
                jsonOptionalDateTimeNsStrict(object.get("end")) catch return null,
            .inclusive_min = (jsonOptionalBoolStrict(object.get("inclusive_start")) catch return null) orelse true,
            .inclusive_max = (jsonOptionalBoolStrict(object.get("inclusive_end")) catch return null) orelse false,
        },
    };
}

fn pathStandardRangePredicateFromObject(path: []const u8, object: anytype) !?PathRangePredicate {
    if (!isExplicitJsonPointerPath(path)) return null;
    const lower = try standardRangeLowerBound(object);
    const upper = try standardRangeUpperBound(object);
    if (lower == null and upper == null) return null;
    const numeric_bounds = lower != null and numericJsonValue(lower.?.value) or upper != null and numericJsonValue(upper.?.value);
    if (numeric_bounds) {
        return .{
            .path = path,
            .kind = .numeric,
            .min_number = if (lower) |bound| try jsonOptionalF64Strict(bound.value) else null,
            .max_number = if (upper) |bound| try jsonOptionalF64Strict(bound.value) else null,
            .inclusive_min = if (lower) |bound| bound.inclusive else true,
            .inclusive_max = if (upper) |bound| bound.inclusive else false,
        };
    }
    const date_bounds = (lower != null and dateJsonValue(lower.?.value)) or (upper != null and dateJsonValue(upper.?.value));
    if (date_bounds and
        (lower == null or dateJsonValue(lower.?.value)) and
        (upper == null or dateJsonValue(upper.?.value)))
    {
        return .{
            .path = path,
            .kind = .date,
            .start_ns = if (lower) |bound| try jsonOptionalDateTimeNsStrict(bound.value) else null,
            .end_ns = if (upper) |bound| try jsonOptionalDateTimeNsStrict(bound.value) else null,
            .inclusive_min = if (lower) |bound| bound.inclusive else true,
            .inclusive_max = if (upper) |bound| bound.inclusive else false,
        };
    }
    return .{
        .path = path,
        .kind = .term,
        .min_term = if (lower) |bound| try jsonOptionalStringStrict(bound.value) else null,
        .max_term = if (upper) |bound| try jsonOptionalStringStrict(bound.value) else null,
        .inclusive_min = if (lower) |bound| bound.inclusive else true,
        .inclusive_max = if (upper) |bound| bound.inclusive else false,
    };
}

fn numericJsonValue(value: std.json.Value) bool {
    return switch (value) {
        .integer, .float, .number_string => true,
        else => false,
    };
}

fn dateJsonValue(value: std.json.Value) bool {
    return switch (value) {
        .string => |text| (parseDateTimeOptionalToNs(text) catch null) != null,
        else => false,
    };
}

fn jsonOptionalStringStrict(value: ?std.json.Value) !?[]const u8 {
    const actual = value orelse return null;
    return switch (actual) {
        .string => |v| v,
        .null => null,
        else => error.InvalidAlgebraicRange,
    };
}

fn jsonOptionalF64Strict(value: ?std.json.Value) !?f64 {
    const actual = value orelse return null;
    return switch (actual) {
        .integer => |v| @floatFromInt(v),
        .float => |v| v,
        .null => null,
        else => error.InvalidAlgebraicRange,
    };
}

fn jsonOptionalU64Strict(value: ?std.json.Value) !?u64 {
    const actual = value orelse return null;
    return switch (actual) {
        .integer => |v| if (v >= 0) @intCast(v) else error.InvalidAlgebraicRange,
        .null => null,
        else => error.InvalidAlgebraicRange,
    };
}

fn jsonOptionalDateTimeNsStrict(value: ?std.json.Value) !?u64 {
    const actual = value orelse return null;
    return switch (actual) {
        .string => |v| (try parseDateTimeOptionalToNs(v)) orelse error.InvalidAlgebraicRange,
        .null => null,
        else => error.InvalidAlgebraicRange,
    };
}

fn jsonOptionalDateOrNsStrict(value: ?std.json.Value) !?u64 {
    const actual = value orelse return null;
    return switch (actual) {
        .integer => |v| if (v >= 0) @intCast(v) else error.InvalidAlgebraicRange,
        .string => |v| (try parseDateTimeOptionalToNs(v)) orelse error.InvalidAlgebraicRange,
        .null => null,
        else => error.InvalidAlgebraicRange,
    };
}

fn jsonOptionalBoolStrict(value: ?std.json.Value) !?bool {
    const actual = value orelse return null;
    return switch (actual) {
        .bool => |v| v,
        .null => null,
        else => error.InvalidAlgebraicRange,
    };
}

fn parseDateTimeOptionalToNs(text: []const u8) !?u64 {
    if (try parseRfc3339ToNs(text)) |ts| return ts;
    if (text.len != 10 or text[4] != '-' or text[7] != '-') return null;
    const year = std.fmt.parseInt(i64, text[0..4], 10) catch return null;
    const month = std.fmt.parseInt(i64, text[5..7], 10) catch return null;
    const day = std.fmt.parseInt(i64, text[8..10], 10) catch return null;
    return civilDateTimeToNs(year, month, day, 0, 0, 0, 0);
}

fn parseDateOrNsOptionalToNs(text: []const u8) !?u64 {
    if (try parseDateTimeOptionalToNs(text)) |ts| return ts;
    if (text.len == 0) return null;
    for (text) |ch| {
        if (ch < '0' or ch > '9') return null;
    }
    return std.fmt.parseUnsigned(u64, text, 10) catch null;
}

fn parseRfc3339ToNs(text: []const u8) !?u64 {
    if (text.len < 20) return null;
    if (text[4] != '-' or text[7] != '-' or text[10] != 'T' or text[13] != ':' or text[16] != ':') return null;

    const year = std.fmt.parseInt(i64, text[0..4], 10) catch return null;
    const month = std.fmt.parseInt(i64, text[5..7], 10) catch return null;
    const day = std.fmt.parseInt(i64, text[8..10], 10) catch return null;
    const hour = std.fmt.parseInt(i64, text[11..13], 10) catch return null;
    const minute = std.fmt.parseInt(i64, text[14..16], 10) catch return null;
    const second = std.fmt.parseInt(i64, text[17..19], 10) catch return null;

    var idx: usize = 19;
    var nanos: u64 = 0;
    if (idx < text.len and text[idx] == '.') {
        idx += 1;
        const frac_start = idx;
        while (idx < text.len and text[idx] >= '0' and text[idx] <= '9') : (idx += 1) {}
        const frac = text[frac_start..idx];
        if (frac.len == 0 or frac.len > 9) return null;
        var frac_ns = std.fmt.parseInt(u64, frac, 10) catch return null;
        var scale: usize = frac.len;
        while (scale < 9) : (scale += 1) frac_ns *= 10;
        nanos = frac_ns;
    }
    if (idx >= text.len or text[idx] != 'Z' or idx + 1 != text.len) return null;

    return civilDateTimeToNs(year, month, day, hour, minute, second, nanos);
}

fn civilDateTimeToNs(year: i64, month: i64, day: i64, hour: i64, minute: i64, second: i64, nanos: u64) ?u64 {
    if (month < 1 or month > 12 or day < 1 or day > 31 or hour < 0 or hour > 23 or minute < 0 or minute > 59 or second < 0 or second > 60) return null;
    const days = daysFromCivil(year, month, day);
    if (days < 0) return null;
    const secs = days * 86_400 + hour * 3_600 + minute * 60 + second;
    if (secs < 0) return null;
    return @as(u64, @intCast(secs)) * std.time.ns_per_s + nanos;
}

fn daysFromCivil(year: i64, month: i64, day: i64) i64 {
    var y = year;
    y -= if (month <= 2) @as(i64, 1) else @as(i64, 0);
    const era = @divFloor(if (y >= 0) y else y - 399, 400);
    const yoe = y - era * 400;
    const mp = month + (if (month > 2) @as(i64, -3) else @as(i64, 9));
    const doy = @divFloor(153 * mp + 2, 5) + day - 1;
    const doe = yoe * 365 + @divFloor(yoe, 4) - @divFloor(yoe, 100) + doy;
    return era * 146_097 + doe - 719_468;
}

fn jsonScalarToStringAlloc(alloc: Allocator, value: std.json.Value) Allocator.Error!?[]u8 {
    return switch (value) {
        .string => |v| try alloc.dupe(u8, v),
        .integer => |v| try std.fmt.allocPrint(alloc, "{d}", .{v}),
        .float => |v| try std.fmt.allocPrint(alloc, "{d}", .{v}),
        .bool => |v| try alloc.dupe(u8, if (v) "true" else "false"),
        else => null,
    };
}

fn fieldMatchesQuery(field: FieldConfig, query_field: []const u8) bool {
    return std.mem.eql(u8, field.name, query_field) or std.mem.eql(u8, field.path, query_field);
}

fn docFactListContainsExact(facts: []const fact_mod.Fact, needle: fact_mod.Fact) bool {
    for (facts) |item| {
        if (item.role == needle.role and
            std.mem.eql(u8, item.field, needle.field) and
            std.mem.eql(u8, item.scalar, needle.scalar))
        {
            return true;
        }
    }
    return false;
}

fn docFactListContainsField(facts: []const fact_mod.Fact, role: fact_mod.Role, field: []const u8) bool {
    for (facts) |item| {
        if (item.role == role and std.mem.eql(u8, item.field, field)) return true;
    }
    return false;
}

fn pathFactListContainsExact(facts: []const pathfact_mod.Fact, needle: pathfact_mod.Fact) bool {
    for (facts) |item| {
        if (item.kind == needle.kind and
            std.mem.eql(u8, item.path, needle.path) and
            std.mem.eql(u8, item.value, needle.value))
        {
            return true;
        }
    }
    return false;
}

fn pathFactListsEqual(a: []const pathfact_mod.Fact, b: []const pathfact_mod.Fact) bool {
    if (a.len != b.len) return false;
    for (a) |item| {
        if (!pathFactListContainsExact(b, item)) return false;
    }
    return true;
}

fn pathProfileListsEqual(a: []const pathfact_mod.PathProfile, b: []const pathfact_mod.PathProfile) bool {
    if (a.len != b.len) return false;
    for (a) |item| {
        if (!pathProfileListContainsExact(b, item)) return false;
    }
    return true;
}

fn pathProfileListContainsExact(profiles: []const pathfact_mod.PathProfile, needle: pathfact_mod.PathProfile) bool {
    for (profiles) |item| {
        if (pathProfilesEqual(item, needle)) return true;
    }
    return false;
}

fn pathProfilesEqual(a: pathfact_mod.PathProfile, b: pathfact_mod.PathProfile) bool {
    return std.mem.eql(u8, a.path, b.path) and
        a.null_count == b.null_count and
        a.bool_count == b.bool_count and
        a.number_count == b.number_count and
        a.string_count == b.string_count and
        a.object_count == b.object_count and
        a.array_count == b.array_count and
        a.string_numeric_parse_success_count == b.string_numeric_parse_success_count and
        a.string_numeric_parse_failure_count == b.string_numeric_parse_failure_count and
        a.string_datetime_parse_success_count == b.string_datetime_parse_success_count and
        a.string_datetime_parse_failure_count == b.string_datetime_parse_failure_count and
        a.string_token_count == b.string_token_count and
        a.max_string_token_count == b.max_string_token_count;
}

fn stableScalarKind(profile: pathfact_mod.PathProfile) ?pathfact_mod.Kind {
    var found: ?pathfact_mod.Kind = null;
    if (profile.null_count > 0) found = .null;
    if (profile.bool_count > 0) {
        if (found != null) return null;
        found = .bool;
    }
    if (profile.number_count > 0) {
        if (found != null) return null;
        found = .number;
    }
    if (profile.string_count > 0) {
        if (found != null) return null;
        found = .string;
    }
    return found;
}

fn fieldClassFromFactRoleText(role_text: []const u8) ?FieldClass {
    if (std.mem.eql(u8, role_text, "group")) return .group;
    if (std.mem.eql(u8, role_text, "measure")) return .measure;
    if (std.mem.eql(u8, role_text, "time")) return .time;
    return null;
}

fn factRoleFromFieldClass(class: FieldClass) ?fact_mod.Role {
    return switch (class) {
        .group => .group,
        .measure => .measure,
        .time => .time,
        .any => null,
    };
}

test "algebraic config validation rejects ambiguous or malformed plans" {
    const alloc = std.testing.allocator;

    try std.testing.expectError(error.InvalidAlgebraicConfig, Index.open(alloc, "bad",
        \\{
        \\  "version": 2,
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "materializations": [{"name":"count_by_customer","op":"count","group_by":["customer"]}]
        \\}
    ));

    try std.testing.expectError(error.InvalidAlgebraicConfig, Index.open(alloc, "bad",
        \\{
        \\  "version": 1,
        \\  "group_fields": [
        \\    {"name":"customer","path":"customer","type":"string"},
        \\    {"name":"customer","path":"customer_id","type":"string"}
        \\  ],
        \\  "materializations": [{"name":"count_by_customer","op":"count","group_by":["customer"]}]
        \\}
    ));

    try std.testing.expectError(error.InvalidAlgebraicConfig, Index.open(alloc, "bad",
        \\{
        \\  "version": 1,
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "materializations": [
        \\    {"name":"sum_by_customer","op":"sum","group_by":["customer"],"measure":"amount"},
        \\    {"name":"sum_by_customer","op":"sum","group_by":["customer"],"measure":"amount"}
        \\  ]
        \\}
    ));

    try std.testing.expectError(error.InvalidAlgebraicConfig, Index.open(alloc, "bad",
        \\{
        \\  "version": 1,
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "joins": [{"name":"orders_customers","left_fields":["customer"],"right_fields":["missing"]}],
        \\  "materializations": [{"name":"count_by_customer","op":"count","join":"orders_customers","group_by":["customer"]}]
