    try std.testing.expectError(error.InvalidAlgebraicConfig, Index.open(alloc, "bad",
        \\{
        \\  "version": 1,
        \\  "group_fields": [
        \\    {"name":"customer","path":"customer","type":"string"},
        \\    {"name":"kind","path":"kind","type":"string"}
        \\  ],
        \\  "measure_fields": [{"name":"kind","path":"kind_score","type":"number"}],
        \\  "joins": [{"name":"orders_customers","left_fields":["customer"],"right_fields":["customer"],"left_type_field":"kind","left_type_value":"order"}],
        \\  "materializations": [{"name":"count_by_customer","op":"count","join":"orders_customers","group_by":["customer"]}]
        \\}
    ));

    try std.testing.expectError(error.InvalidAlgebraicConfig, Index.open(alloc, "bad",
        \\{
        \\  "version": 1,
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "materializations": [{"name":"count_by_customer","op":"count","group_by":["customer"],"group_side":"left"}]
        \\}
    ));

    try std.testing.expectError(error.InvalidAlgebraicConfig, Index.open(alloc, "bad",
        \\{
        \\  "version": 1,
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "time_fields": [{"name":"created_at","path":"created_at","type":"datetime"}],
        \\  "joins": [{"name":"bad_temporal","left_fields":["customer"],"right_fields":["customer"],"left_time_field":"created_at","temporal_window_seconds":60}],
        \\  "materializations": [{"name":"count_by_customer","op":"count","join":"bad_temporal","group_by":["customer"]}]
        \\}
    ));

    try std.testing.expectError(error.InvalidAlgebraicConfig, Index.open(alloc, "bad",
        \\{
        \\  "version": 1,
        \\  "group_fields": [
        \\    {"name":"kind","path":"kind","type":"string"},
        \\    {"name":"customer","path":"customer","type":"integer"},
        \\    {"name":"segment","path":"segment","type":"string"}
        \\  ],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "joins": [
        \\    {"name":"orders_customers","left_fields":["customer"],"right_fields":["customer"],"left_type_field":"kind","left_type_value":"order","right_type_field":"kind","right_type_value":"customer"}
        \\  ],
        \\  "materializations": [
        \\    {"name":"unsafe_explicit_join","op":"sum","join":"orders_customers","group_by":["segment"],"measure":"amount","group_side":"right"}
        \\  ]
        \\}
    ));

    try std.testing.expectError(error.InvalidAlgebraicConfig, Index.open(alloc, "bad",
        \\{
        \\  "version": 1,
        \\  "group_fields": [
        \\    {"name":"kind","path":"kind","type":"string"},
        \\    {"name":"customer","path":"customer","type":"integer"},
        \\    {"name":"segment","path":"segment","type":"string"}
        \\  ],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "joins": [
        \\    {"name":"orders_customers","left_fields":["customer"],"right_fields":["customer"],"left_type_field":"kind","left_type_value":"order"}
        \\  ],
        \\  "materializations": [
        \\    {"name":"unsafe_implicit_join","op":"sum","join":"orders_customers","group_by":["segment"],"measure":"amount","group_side":"right","measure_side":"left","implicit_query":true}
        \\  ]
        \\}
    ));

    try std.testing.expectError(error.InvalidAlgebraicConfig, Index.open(alloc, "bad",
        \\{
        \\  "version": 1,
        \\  "group_fields": [
        \\    {"name":"kind","path":"kind","type":"string"},
        \\    {"name":"customer","path":"customer","type":"integer"},
        \\    {"name":"segment","path":"segment","type":"string"}
        \\  ],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "joins": [
        \\    {"name":"orders_customers","left_fields":["customer"],"right_fields":["customer"],"left_type_field":"kind","left_type_value":"order","right_type_field":"kind","right_type_value":"customer"}
        \\  ],
        \\  "materializations": [
        \\    {"name":"unsafe_implicit_join","op":"sum","join":"orders_customers","group_by":["segment"],"measure":"amount","group_side":"right","implicit_query":true}
        \\  ]
        \\}
    ));
}

test "algebraic index maintains direct count sum avg min max" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "materializations": [
        \\    {"name":"count_by_customer","op":"count","group_by":["customer"]},
        \\    {"name":"sum_by_customer","op":"sum","group_by":["customer"],"measure":"amount"},
        \\    {"name":"avg_by_customer","op":"avg","group_by":["customer"],"measure":"amount"},
        \\    {"name":"min_by_customer","op":"min","group_by":["customer"],"measure":"amount"},
        \\    {"name":"max_by_customer","op":"max","group_by":["customer"],"measure":"amount"}
        \\  ]
        \\}
    ;
    var idx = try Index.open(alloc, "alg", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"amount\":10}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"amount\":20}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });
    const customer_token = try idx.constraintTokenAlloc(alloc, "customer", "alice");
    defer alloc.free(customer_token);
    const group = try token.canonicalTupleAlloc(alloc, &.{customer_token});
    defer alloc.free(group);
    const stored_symbol = (try idx.symbolValueAlloc(&store, group)).?;
    defer alloc.free(stored_symbol);
    try std.testing.expectEqualStrings(group, stored_symbol);
    const fact_key = try idx.docFactKey("o1");
    defer alloc.free(fact_key);
    var fact_txn = try store.beginReadTxn();
    const fact_payload = try fact_txn.get(fact_key);
    var fact_list = try fact_mod.decodeListAlloc(alloc, fact_payload);
    defer fact_list.deinit(alloc);
    fact_txn.abort();
    try std.testing.expect(fact_mod.findScalar(fact_list.facts, .group, "customer") != null);
    try std.testing.expect(fact_mod.findScalar(fact_list.facts, .measure, "amount") != null);
    try std.testing.expectEqual(@as(u64, 2), idx.status().doc_fact_write_count);
    const group_id = try symbol.idAlloc(alloc, group);
    defer alloc.free(group_id);
    try std.testing.expectEqual(@as(i64, 2), try idx.countValue(&store, "count_by_customer", group));
    try std.testing.expectEqual(@as(f64, 30), (try idx.numericValue(&store, "sum_by_customer", group)).?);
    var sum_expr_raw = (try idx.materializedExpressionRawValueForMaterializationAlloc(&store, "sum_by_customer", group, null)).?;
    defer sum_expr_raw.deinit(idx.alloc);
    try std.testing.expectEqualStrings("30", sum_expr_raw.raw.?);
    const avg_raw = (try idx.rawValueAlloc(&store, "avg_by_customer", group)).?;
    defer alloc.free(avg_raw);
    const avg = try algebra.parseAvg(avg_raw);
    try std.testing.expectEqual(@as(f64, 30), avg.sum);
    try std.testing.expectEqual(@as(i64, 2), avg.count);
    try std.testing.expectEqual(@as(f64, 10), (try idx.numericValue(&store, "min_by_customer", group)).?);
    try std.testing.expectEqual(@as(f64, 20), (try idx.numericValue(&store, "max_by_customer", group)).?);
    var min_expr_raw = (try idx.materializedExpressionRawValueForMaterializationAlloc(&store, "min_by_customer", group, null)).?;
    defer min_expr_raw.deinit(idx.alloc);
    try std.testing.expectEqualStrings("10", min_expr_raw.raw.?);
    var max_expr_raw = (try idx.materializedExpressionRawValueForMaterializationAlloc(&store, "max_by_customer", group, null)).?;
    defer max_expr_raw.deinit(idx.alloc);
    try std.testing.expectEqualStrings("20", max_expr_raw.raw.?);
    const min_mat = idx.config().materializations[idx.materializationIndex("min_by_customer").?];
    const min_law_id = idx.materializationLawId(min_mat, .min);
    const min_expr_id = try idx.materializationExprIdAlloc(min_mat, min_law_id);
    defer alloc.free(min_expr_id);
    const amount_10_token = try token.scalarTokenFromFieldTextAlloc(alloc, "number", "10");
    defer alloc.free(amount_10_token);
    const amount_10_id = try symbol.idAlloc(alloc, amount_10_token);
    defer alloc.free(amount_10_id);
    const min_support_key = try idx.keyAlloc(&.{ "minmax", min_expr_id, group_id, amount_10_id });
    defer alloc.free(min_support_key);
    var minmax_txn = try store.beginReadTxn();
    const min_support = try minmax_txn.get(min_support_key);
    try std.testing.expectEqual(@as(i64, 1), try tensor_mod.countSupportValueAlloc(alloc, min_support));
    minmax_txn.abort();
    const row_names = [_][]const u8{
        "count_by_customer",
        "sum_by_customer",
        "min_by_customer",
        "max_by_customer",
    };
    const rows = (try idx.scanMaterializedExpressionRows(&store, row_names[0..])).?;
    defer {
        for (rows) |*row| row.deinit(alloc);
        if (rows.len > 0) alloc.free(rows);
    }
    try std.testing.expectEqual(@as(usize, 1), rows.len);
    try std.testing.expectEqualStrings(group, rows[0].group_key);
    try std.testing.expectEqualStrings("2", rows[0].values[0].?);
    try std.testing.expectEqualStrings("30", rows[0].values[1].?);
    try std.testing.expectEqualStrings("10", rows[0].values[2].?);
    try std.testing.expectEqualStrings("20", rows[0].values[3].?);

    const distributed_names = [_][]const u8{
        "count_by_customer",
        "sum_by_customer",
    };
    const partials = try idx.scanDistributedPartials(&store, distributed_names[0..]);
    defer distributed_mod.freePartials(alloc, partials);
    try std.testing.expectEqual(@as(usize, 2), partials.len);
    var merged_partials = try distributed_mod.mergePartialsAlloc(alloc, partials);
    defer merged_partials.deinit(alloc);
    try std.testing.expectEqual(@as(usize, 2), merged_partials.rows.len);
    try std.testing.expectEqualStrings(group, merged_partials.rows[0].canonical_axis);
    try std.testing.expectEqualStrings("count_by_customer", merged_partials.rows[0].metric);
    try std.testing.expectEqualStrings("2", merged_partials.rows[0].value);
    try std.testing.expectEqualStrings(group, merged_partials.rows[1].canonical_axis);
    try std.testing.expectEqualStrings("sum_by_customer", merged_partials.rows[1].metric);
    try std.testing.expectEqualStrings("30", merged_partials.rows[1].value);
    const invalid_distributed_names = [_][]const u8{"missing_by_customer"};
    try std.testing.expectError(error.InvalidAlgebraicConfig, idx.scanDistributedPartials(&store, invalid_distributed_names[0..]));

    const deletes = [_][]const u8{"o2"};
    try idx.applyBatch(&store, .{ .deleted_keys = deletes[0..] });
    try std.testing.expectEqual(@as(i64, 1), try idx.countValue(&store, "count_by_customer", group));
    try std.testing.expectEqual(@as(f64, 10), (try idx.numericValue(&store, "min_by_customer", group)).?);
    try std.testing.expectEqual(@as(f64, 10), (try idx.numericValue(&store, "max_by_customer", group)).?);
    var max_expr_after_delete = (try idx.materializedExpressionRawValueForMaterializationAlloc(&store, "max_by_customer", group, null)).?;
    defer max_expr_after_delete.deinit(idx.alloc);
    try std.testing.expectEqualStrings("10", max_expr_after_delete.raw.?);

    const overwrite = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"amount\":15}" },
    };
    try idx.applyBatch(&store, .{ .documents = overwrite[0..] });
    try std.testing.expectEqual(@as(i64, 1), try idx.countValue(&store, "count_by_customer", group));
    try std.testing.expectEqual(@as(f64, 15), (try idx.numericValue(&store, "sum_by_customer", group)).?);
    try std.testing.expectEqual(@as(f64, 15), (try idx.numericValue(&store, "min_by_customer", group)).?);
    try std.testing.expectEqual(@as(f64, 15), (try idx.numericValue(&store, "max_by_customer", group)).?);
    var sum_expr_after_overwrite = (try idx.materializedExpressionRawValueForMaterializationAlloc(&store, "sum_by_customer", group, null)).?;
    defer sum_expr_after_overwrite.deinit(idx.alloc);
    try std.testing.expectEqualStrings("15", sum_expr_after_overwrite.raw.?);

    const duplicate_extrema = [_]derived_types.DerivedDocument{
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"amount\":15}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"amount\":30}" },
    };
    try idx.applyBatch(&store, .{ .documents = duplicate_extrema[0..] });
    try std.testing.expectEqual(@as(i64, 3), try idx.countValue(&store, "count_by_customer", group));
    try std.testing.expectEqual(@as(f64, 15), (try idx.numericValue(&store, "min_by_customer", group)).?);
    try std.testing.expectEqual(@as(f64, 30), (try idx.numericValue(&store, "max_by_customer", group)).?);

    const delete_one_duplicate_min = [_][]const u8{"o1"};
    try idx.applyBatch(&store, .{ .deleted_keys = delete_one_duplicate_min[0..] });
    try std.testing.expectEqual(@as(i64, 2), try idx.countValue(&store, "count_by_customer", group));
    try std.testing.expectEqual(@as(f64, 15), (try idx.numericValue(&store, "min_by_customer", group)).?);
    try std.testing.expectEqual(@as(f64, 30), (try idx.numericValue(&store, "max_by_customer", group)).?);

    const delete_remaining = [_][]const u8{ "o2", "o3" };
    try idx.applyBatch(&store, .{ .deleted_keys = delete_remaining[0..] });
    try std.testing.expectEqual(@as(i64, 0), try idx.countValue(&store, "count_by_customer", group));
    try std.testing.expect((try idx.numericValue(&store, "sum_by_customer", group)) == null);
    try std.testing.expect((try idx.rawValueAlloc(&store, "avg_by_customer", group)) == null);
    try std.testing.expect((try idx.numericValue(&store, "min_by_customer", group)) == null);
    try std.testing.expect((try idx.numericValue(&store, "max_by_customer", group)) == null);
    try std.testing.expect((try idx.materializedExpressionRawValueForMaterializationAlloc(&store, "sum_by_customer", group, null)) == null);
    try std.testing.expect((try idx.materializedExpressionRawValueForMaterializationAlloc(&store, "min_by_customer", group, null)) == null);
    try std.testing.expect((try idx.materializedExpressionRawValueForMaterializationAlloc(&store, "max_by_customer", group, null)) == null);
}

test "algebraic index materializes approximate per-group cardinality" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [{"name":"region","path":"region","type":"string"},{"name":"customer","path":"customer","type":"string"}],
        \\  "hll_cardinalities": [{"name":"customers_by_region","group_by":["region"],"value_field":"customer"}]
        \\}
    ;
    var idx = try Index.open(alloc, "alg", cfg);
    defer idx.close();

    // west has 3 distinct customers (a1 repeated), east has 2.
    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"a1\"}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"a2\"}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"a3\"}" },
        .{ .key = "o4", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"a1\"}" },
        .{ .key = "o5", .action = .upsert, .cleaned_value = "{\"region\":\"east\",\"customer\":\"b1\"}" },
        .{ .key = "o6", .action = .upsert, .cleaned_value = "{\"region\":\"east\",\"customer\":\"b2\"}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });

    const entries = try idx.approxCardinalityEntriesAlloc(&store, "customers_by_region");
    defer {
        for (entries) |*entry| entry.deinit(alloc);
        alloc.free(entries);
    }
    try std.testing.expectEqual(@as(usize, 2), entries.len);

    const west_token = try idx.constraintTokenAlloc(alloc, "region", "west");
    defer alloc.free(west_token);
    const west_group = try token.canonicalTupleAlloc(alloc, &.{west_token});
    defer alloc.free(west_group);
    const east_token = try idx.constraintTokenAlloc(alloc, "region", "east");
    defer alloc.free(east_token);
    const east_group = try token.canonicalTupleAlloc(alloc, &.{east_token});
    defer alloc.free(east_group);

    var west_estimate: ?u64 = null;
    var east_estimate: ?u64 = null;
    for (entries) |entry| {
        if (std.mem.eql(u8, entry.group_key, west_group)) west_estimate = entry.estimate;
        if (std.mem.eql(u8, entry.group_key, east_group)) east_estimate = entry.estimate;
    }
    // Small cardinalities land within one of the truth (linear counting regime).
    try std.testing.expect(west_estimate != null and east_estimate != null);
    try std.testing.expect(@max(west_estimate.?, 3) - @min(west_estimate.?, 3) <= 1);
    try std.testing.expect(@max(east_estimate.?, 2) - @min(east_estimate.?, 2) <= 1);

    // The grand total is the union of the per-group sketches: 5 distinct customers.
    const total = try idx.approxCardinalityTotalAlloc(&store, "customers_by_region");
    try std.testing.expect(@max(total, 5) - @min(total, 5) <= 1);
}

test "algebraic HLL cardinality rebuilds after deletes via maintenance lane" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    // A manual-backend runtime runs durable jobs inline (synchronously on submit),
    // so the post-batch maintenance rebuild completes before applyBatch returns.
    var runtime = try background_runtime.BackendRuntime.init(alloc, .{ .backend = .manual });
    defer runtime.deinit();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [
        \\    {"name":"region","path":"region","type":"string"},
        \\    {"name":"customer","path":"customer","type":"string"}
        \\  ],
        \\  "hll_cardinalities": [
        \\    {"name":"customers_by_region","group_by":["region"],"value_field":"customer","precision":14}
        \\  ]
        \\}
    ;
    var idx = try Index.open(alloc, "alg", cfg);
    defer idx.close();
    idx.attachHllMaintenanceLane(runtime.durable_jobs, runtime.allocOwnerId());

    const west_token = try idx.constraintTokenAlloc(alloc, "region", "west");
    defer alloc.free(west_token);
    const west_group = try token.canonicalTupleAlloc(alloc, &.{west_token});
    defer alloc.free(west_group);

    const westEstimate = struct {
        fn read(index: *Index, doc_store: *docstore_mod.DocStore, group: []const u8, allocator: Allocator) !?u64 {
            const entries = try index.approxCardinalityEntriesAlloc(doc_store, "customers_by_region");
            defer {
                for (entries) |*entry| entry.deinit(allocator);
                allocator.free(entries);
            }
            for (entries) |entry| {
                if (std.mem.eql(u8, entry.group_key, group)) return entry.estimate;
            }
            return null;
        }
    }.read;

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"a\"}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"b\"}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"c\"}" },
        .{ .key = "o4", .action = .upsert, .cleaned_value = "{\"region\":\"east\",\"customer\":\"a\"}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });
    try std.testing.expectEqual(@as(?u64, 3), try westEstimate(&idx, &store, west_group, alloc));

    // Delete customers b and c from west; the inline lane rebuilds the sketch so
    // west collapses to a single distinct customer (a).
    const deletes = [_][]const u8{ "o2", "o3" };
    try idx.applyBatch(&store, .{ .deleted_keys = deletes[0..] });
    try std.testing.expectEqual(@as(?u64, 1), try westEstimate(&idx, &store, west_group, alloc));
}

test "algebraic HLL cardinality stays correct under a concurrent threaded maintenance lane" {
    if (builtin.os.tag == .freestanding) return error.SkipZigTest;
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    // Real threaded lane: maintenance rebuilds run on a background thread,
    // concurrently with the foreground applyBatch writes below. The index write
    // lock must serialize them so neither a lost update nor a torn read occurs.
    var runtime = try background_runtime.BackendRuntime.init(alloc, .{ .backend = .io_threaded });
    defer runtime.deinit();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [
        \\    {"name":"region","path":"region","type":"string"},
        \\    {"name":"customer","path":"customer","type":"string"}
        \\  ],
        \\  "hll_cardinalities": [
        \\    {"name":"customers_by_region","group_by":["region"],"value_field":"customer","precision":14}
        \\  ]
        \\}
    ;
    var idx = try Index.open(alloc, "alg", cfg);
    defer idx.close();
    idx.attachHllMaintenanceLane(runtime.durable_jobs, runtime.allocOwnerId());

    const west_token = try idx.constraintTokenAlloc(alloc, "region", "west");
    defer alloc.free(west_token);
    const west_group = try token.canonicalTupleAlloc(alloc, &.{west_token});
    defer alloc.free(west_group);

    // Insert 200 distinct west customers across many small batches, deleting the
    // previous batch's docs each round. Every delete schedules a background
    // rebuild that races the next round's insert.
    var round: usize = 0;
    while (round < 40) : (round += 1) {
        var docs: [5]derived_types.DerivedDocument = undefined;
        var bufs: [5][64]u8 = undefined;
        for (0..5) |i| {
            const n = round * 5 + i;
            const key = try std.fmt.bufPrint(&bufs[i], "k{d}", .{n});
            // Reuse the buffer tail for the value via a second format into a dup.
            const value = try std.fmt.allocPrint(alloc, "{{\"region\":\"west\",\"customer\":\"c{d}\"}}", .{n});
            docs[i] = .{ .key = try alloc.dupe(u8, key), .action = .upsert, .cleaned_value = value };
        }
        defer for (docs) |d| {
            alloc.free(@constCast(d.key));
            if (d.cleaned_value) |v| alloc.free(@constCast(v));
        };
        try idx.applyBatch(&store, .{ .documents = docs[0..] });
    }

    // Drain all background rebuilds, then run one final maintenance pass so any
    // outstanding dirty marker is resolved deterministically before asserting.
    runtime.durable_jobs.drainOwner(idx.hll_maintenance_owner_id);
    _ = try idx.runHllMaintenance(&store);

    // All 200 customers are distinct and all in west; the estimate must be close
    // to 200 (HLL error), and must not be corrupted by a lost update or a torn
    // read from the concurrent rebuilds.
    const entries = try idx.approxCardinalityEntriesAlloc(&store, "customers_by_region");
    defer {
        for (entries) |*entry| entry.deinit(alloc);
        alloc.free(entries);
    }
    var west_estimate: ?u64 = null;
    for (entries) |entry| {
        if (std.mem.eql(u8, entry.group_key, west_group)) west_estimate = entry.estimate;
    }
    try std.testing.expect(west_estimate != null);
    const est = west_estimate.?;
    // Generous bound: p=14 standard error is ~0.8%, allow well beyond that. The
    // point is to catch corruption (estimate near 0, or far off), not precision.
    try std.testing.expect(est >= 180 and est <= 220);
}

test "algebraic HLL cardinality is corrected after an in-place value change" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();
    var runtime = try background_runtime.BackendRuntime.init(alloc, .{ .backend = .manual });
    defer runtime.deinit();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [
        \\    {"name":"region","path":"region","type":"string"},
        \\    {"name":"customer","path":"customer","type":"string"}
        \\  ],
        \\  "hll_cardinalities": [
        \\    {"name":"customers_by_region","group_by":["region"],"value_field":"customer","precision":14}
        \\  ]
        \\}
    ;
    var idx = try Index.open(alloc, "alg", cfg);
    defer idx.close();
    idx.attachHllMaintenanceLane(runtime.durable_jobs, runtime.allocOwnerId());

    const west_token = try idx.constraintTokenAlloc(alloc, "region", "west");
    defer alloc.free(west_token);
    const west_group = try token.canonicalTupleAlloc(alloc, &.{west_token});
    defer alloc.free(west_group);

    // Three distinct customers in west.
    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"a\"}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"b\"}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"c\"}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });
    try std.testing.expectEqual(@as(?u64, 3), try idx.approxCardinalityEntriesForGroupTestEstimate(&store, west_group));

    // Re-upsert o1/o2/o3 so every west document shares one customer. This goes
    // through the in-place coalesced update path (no deleted/overwritten keys);
    // the rebuild must collapse west to a single distinct customer.
    const collapsed = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"z\"}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"z\"}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"region\":\"west\",\"customer\":\"z\"}" },
    };
    try idx.applyBatch(&store, .{ .documents = collapsed[0..] });
    try std.testing.expectEqual(@as(?u64, 1), try idx.approxCardinalityEntriesForGroupTestEstimate(&store, west_group));
}

