    defer idx.freeDocIds(stale_path_term_ids);
    try std.testing.expectEqual(@as(usize, 0), stale_path_term_ids.len);
    const updated_path_term_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"term":{"path":"/meta/tier","value":"silver"}}
    )).?;
    defer idx.freeDocIds(updated_path_term_ids);
    try std.testing.expectEqual(@as(usize, 1), updated_path_term_ids.len);
    try std.testing.expectEqualStrings("o1", updated_path_term_ids[0]);

    const deletes = [_][]const u8{"o1"};
    try idx.applyBatch(&store, .{ .deleted_keys = deletes[0..] });
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.pathLookupPrefixAlloc("/customer", .string, "bob")));
    const deleted_path_exists_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"exists":{"path":"/meta/tier"}}
    )).?;
    defer idx.freeDocIds(deleted_path_exists_ids);
    try std.testing.expectEqual(@as(usize, 0), deleted_path_exists_ids.len);
    var deleted_txn = try store.beginReadTxn();
    _ = deleted_txn.get(path_key) catch |err| switch (err) {
        error.NotFound => {},
        else => return err,
    };
    _ = deleted_txn.get(profile_key) catch |err| switch (err) {
        error.NotFound => {},
        else => return err,
    };
    deleted_txn.abort();
}

test "algebraic path profile recomputes max string token count after deleting max row" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_path_profile_max_recompute", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"meta\":{\"label\":\"short name\"}}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"meta\":{\"label\":\"one two three four\"}}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"meta\":{\"label\":\"medium name here\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });

    var initial = (try idx.pathProfileStatsAlloc(&store, "/meta/label")).?;
    defer initial.deinit(alloc);
    try std.testing.expectEqual(@as(u32, 3), initial.profile.string_count);
    try std.testing.expectEqual(@as(u32, 9), initial.profile.string_token_count);
    try std.testing.expectEqual(@as(u32, 4), initial.profile.max_string_token_count);

    const delete_max = [_][]const u8{"o2"};
    try idx.applyBatch(&store, .{ .deleted_keys = delete_max[0..] });

    var after_delete = (try idx.pathProfileStatsAlloc(&store, "/meta/label")).?;
    defer after_delete.deinit(alloc);
    try std.testing.expectEqual(@as(u32, 2), after_delete.profile.string_count);
    try std.testing.expectEqual(@as(u32, 5), after_delete.profile.string_token_count);
    try std.testing.expectEqual(@as(u32, 3), after_delete.profile.max_string_token_count);

    const overwrite_max = [_]derived_types.DerivedDocument{
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"meta\":{\"label\":\"tiny\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = overwrite_max[0..] });

    var after_overwrite = (try idx.pathProfileStatsAlloc(&store, "/meta/label")).?;
    defer after_overwrite.deinit(alloc);
    try std.testing.expectEqual(@as(u32, 2), after_overwrite.profile.string_count);
    try std.testing.expectEqual(@as(u32, 3), after_overwrite.profile.string_token_count);
    try std.testing.expectEqual(@as(u32, 2), after_overwrite.profile.max_string_token_count);
}

test "algebraic path profile stats expose selectivity for promotion decisions" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "adaptive": {"observe": true, "path_profile_history_retention": 2},
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "materializations": [{"name":"count_by_customer","op":"count","group_by":["customer"]}]
        \\}
    ;
    var idx = try Index.open(alloc, "alg_path_profile_stats", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"meta\":{\"tier\":\"gold\",\"score_text\":\"10.5\",\"published\":\"2026-05-10T14:03:00Z\"}}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"customer\":\"bob\",\"meta\":{\"tier\":\"gold\",\"score_text\":\"11.5\",\"published\":\"2026-05-10T15:03:00Z\"}}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"customer\":\"carol\",\"meta\":{\"tier\":\"silver\",\"score_text\":\"12.5\",\"published\":\"2026-05-10T16:03:00Z\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });

    var tier_stats = (try idx.pathProfileStatsAlloc(&store, "/meta/tier")).?;
    defer tier_stats.deinit(alloc);
    try std.testing.expectEqual(@as(u32, 3), tier_stats.profile.string_count);
    try std.testing.expectEqual(@as(u64, 3), tier_stats.doc_count);
    try std.testing.expectEqual(@as(u64, 3), tier_stats.lookup_row_count);
    try std.testing.expectEqual(@as(u64, 2), tier_stats.unique_scalar_values);
    try std.testing.expectEqual(@as(u64, 2), tier_stats.max_value_doc_frequency);
    try std.testing.expectEqual(@as(u32, 0), tier_stats.profile.string_numeric_parse_success_count);
    try std.testing.expectEqual(@as(u32, 3), tier_stats.profile.string_numeric_parse_failure_count);
    try std.testing.expectEqual(@as(u32, 3), tier_stats.profile.string_token_count);
    try std.testing.expectEqual(@as(u32, 1), tier_stats.profile.max_string_token_count);

    const tier_recommendation = try idx.pathPromotionRecommendationAlloc(&store, "/meta/tier");
    try std.testing.expectEqual(pathfact_mod.Kind.string, tier_recommendation.stable_kind.?);
    try std.testing.expect(tier_recommendation.typed_projection);
    try std.testing.expect(tier_recommendation.lexical_dictionary);
    try std.testing.expect(!tier_recommendation.aggregate_materialization);
    try std.testing.expectEqualStrings("stable_lexical_path", tier_recommendation.reason);

    var score_stats = (try idx.pathProfileStatsAlloc(&store, "/meta/score_text")).?;
    defer score_stats.deinit(alloc);
    try std.testing.expectEqual(@as(u32, 3), score_stats.profile.string_numeric_parse_success_count);
    try std.testing.expectEqual(@as(u32, 0), score_stats.profile.string_numeric_parse_failure_count);
    try std.testing.expectEqual(@as(u32, 6), score_stats.profile.string_token_count);
    const score_recommendation = try idx.pathPromotionRecommendationAlloc(&store, "/meta/score_text");
    try std.testing.expect(score_recommendation.typed_projection);
    try std.testing.expect(score_recommendation.numeric_projection);
    try std.testing.expectEqualStrings("stable_numeric_string_path", score_recommendation.reason);

    var published_stats = (try idx.pathProfileStatsAlloc(&store, "/meta/published")).?;
    defer published_stats.deinit(alloc);
    try std.testing.expectEqual(@as(u32, 3), published_stats.profile.string_datetime_parse_success_count);
    try std.testing.expectEqual(@as(u32, 0), published_stats.profile.string_datetime_parse_failure_count);
    const published_recommendation = try idx.pathPromotionRecommendationAlloc(&store, "/meta/published");
    try std.testing.expect(published_recommendation.typed_projection);
    try std.testing.expect(published_recommendation.datetime_projection);
    try std.testing.expectEqualStrings("stable_datetime_string_path", published_recommendation.reason);

    const deletes = [_][]const u8{"o2"};
    try idx.applyBatch(&store, .{ .deleted_keys = deletes[0..] });
    var updated_stats = (try idx.pathProfileStatsAlloc(&store, "/meta/tier")).?;
    defer updated_stats.deinit(alloc);
    try std.testing.expectEqual(@as(u32, 2), updated_stats.profile.string_count);
    try std.testing.expectEqual(@as(u64, 2), updated_stats.doc_count);
    try std.testing.expectEqual(@as(u64, 2), updated_stats.lookup_row_count);
    try std.testing.expectEqual(@as(u64, 2), updated_stats.unique_scalar_values);
    try std.testing.expectEqual(@as(u64, 1), updated_stats.max_value_doc_frequency);

    const tag_docs = [_]derived_types.DerivedDocument{
        .{ .key = "o6", .action = .upsert, .cleaned_value = "{\"customer\":\"frank\",\"tags\":[\"new\",\"vip\",\"new\"]}" },
        .{ .key = "o7", .action = .upsert, .cleaned_value = "{\"customer\":\"grace\",\"tags\":[\"vip\"]}" },
    };
    try idx.applyBatch(&store, .{ .documents = tag_docs[0..] });
    var tag_stats = (try idx.pathProfileStatsAlloc(&store, "/tags")).?;
    defer tag_stats.deinit(alloc);
    try std.testing.expectEqual(@as(u32, 2), tag_stats.profile.array_count);
    try std.testing.expectEqual(@as(u32, 4), tag_stats.profile.string_count);
    try std.testing.expectEqual(@as(u64, 2), tag_stats.doc_count);
    try std.testing.expectEqual(@as(u64, 5), tag_stats.lookup_row_count);
    try std.testing.expectEqual(@as(u64, 2), tag_stats.unique_scalar_values);
    try std.testing.expectEqual(@as(u64, 2), tag_stats.max_value_doc_frequency);
    const tag_recommendation = try idx.pathPromotionRecommendationAlloc(&store, "/tags");
    try std.testing.expectEqual(pathfact_mod.Kind.string, tag_recommendation.stable_kind.?);
    try std.testing.expect(tag_recommendation.lexical_dictionary);

    try std.testing.expect((try idx.pathProfileStatsAlloc(&store, "/missing")) == null);
    const missing_recommendation = try idx.pathPromotionRecommendationAlloc(&store, "/missing");
    try std.testing.expect(!missing_recommendation.typed_projection);
    try std.testing.expectEqualStrings("missing_path", missing_recommendation.reason);

    const mixed_doc = [_]derived_types.DerivedDocument{
        .{ .key = "o4", .action = .upsert, .cleaned_value = "{\"customer\":\"dave\",\"mixed\":\"one\"}" },
        .{ .key = "o5", .action = .upsert, .cleaned_value = "{\"customer\":\"erin\",\"mixed\":2}" },
    };
    try idx.applyBatch(&store, .{ .documents = mixed_doc[0..] });
    const mixed_recommendation = try idx.pathPromotionRecommendationAlloc(&store, "/mixed");
    try std.testing.expect(mixed_recommendation.stable_kind == null);
    try std.testing.expect(!mixed_recommendation.typed_projection);
    try std.testing.expectEqualStrings("mixed_scalar_kinds", mixed_recommendation.reason);

    const all_recommendations = try idx.pathPromotionRecommendationsAlloc(&store);
    defer idx.freePathPromotionRecommendations(all_recommendations);
    try std.testing.expect(all_recommendations.len >= 3);
    var saw_tier = false;
    var saw_mixed = false;
    for (all_recommendations) |recommendation| {
        if (std.mem.eql(u8, recommendation.path, "/meta/tier")) {
            saw_tier = true;
            try std.testing.expect(recommendation.typed_projection);
        } else if (std.mem.eql(u8, recommendation.path, "/mixed")) {
            saw_mixed = true;
            try std.testing.expectEqualStrings("mixed_scalar_kinds", recommendation.reason);
        }
    }
    try std.testing.expect(saw_tier);
    try std.testing.expect(saw_mixed);

    try std.testing.expect((try idx.persistSchemalessPathPromotionRecommendations(&store)) >= 3);
    const score_path_recommendation = try adaptive_mod.pathPromotionRecommendationAlloc(alloc, "/meta/score_text", "string", "stable_numeric_string_path");
    defer alloc.free(score_path_recommendation);
    const materialization_states = try idx.scanPersistedMaterializationStates(&store);
    defer {
        for (materialization_states) |*state| state.deinit(alloc);
        alloc.free(materialization_states);
    }
    var saw_score_state = false;
    for (materialization_states) |state| {
        if (std.mem.eql(u8, state.recommendation, score_path_recommendation)) {
            saw_score_state = true;
            try std.testing.expectEqual(adaptive_mod.Lifecycle.recommended, state.lifecycle);
            try std.testing.expectEqual(@as(u64, 2), state.observation_count);
        }
    }
    try std.testing.expect(saw_score_state);

    const candidates = try idx.scanPersistedAdaptiveCandidates(&store);
    defer {
        for (candidates) |*candidate| candidate.deinit(alloc);
        alloc.free(candidates);
    }
    var saw_score_candidate = false;
    for (candidates) |candidate| {
        if (std.mem.eql(u8, candidate.recommendation, score_path_recommendation)) {
            saw_score_candidate = true;
            try std.testing.expectEqualStrings("schemaless_numeric_path_recommended", candidate.decision);
            try std.testing.expect(candidate.estimated_scan_rows_saved >= 2);
            try std.testing.expect(candidate.estimated_write_cost > 0);
        }
    }
    try std.testing.expect(saw_score_candidate);

    const score_history = try idx.scanPathProfileHistoryAlloc(&store, "/meta/score_text");
    defer {
        for (score_history) |*entry| entry.deinit(alloc);
        alloc.free(score_history);
    }
    try std.testing.expectEqual(@as(usize, 1), score_history.len);
    try std.testing.expectEqual(@as(u64, 1), score_history[0].sequence);
    try std.testing.expectEqual(@as(u64, 2), score_history[0].doc_count);
    try std.testing.expectEqual(@as(u64, 2), score_history[0].unique_scalar_values);
    try std.testing.expectEqualStrings("stable_numeric_string_path", score_history[0].reason);

    const cardinality_doc = [_]derived_types.DerivedDocument{
        .{ .key = "o6", .action = .upsert, .cleaned_value = "{\"customer\":\"frank\",\"meta\":{\"score_text\":\"13.5\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = cardinality_doc[0..] });
    _ = try idx.persistSchemalessPathPromotionRecommendations(&store);
    const updated_score_history = try idx.scanPathProfileHistoryAlloc(&store, "/meta/score_text");
    defer {
        for (updated_score_history) |*entry| entry.deinit(alloc);
        alloc.free(updated_score_history);
    }
    try std.testing.expectEqual(@as(usize, 2), updated_score_history.len);
    try std.testing.expectEqual(@as(u64, 2), updated_score_history[1].sequence);
    try std.testing.expectEqual(@as(u64, 3), updated_score_history[1].doc_count);
    try std.testing.expectEqual(@as(u64, 3), updated_score_history[1].unique_scalar_values);

    const retained_cardinality_doc = [_]derived_types.DerivedDocument{
        .{ .key = "o7", .action = .upsert, .cleaned_value = "{\"customer\":\"grace\",\"meta\":{\"score_text\":\"14.5\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = retained_cardinality_doc[0..] });
    _ = try idx.persistSchemalessPathPromotionRecommendations(&store);
    const retained_score_history = try idx.scanPathProfileHistoryAlloc(&store, "/meta/score_text");
    defer {
        for (retained_score_history) |*entry| entry.deinit(alloc);
        alloc.free(retained_score_history);
    }
    try std.testing.expectEqual(@as(usize, 2), retained_score_history.len);
    try std.testing.expectEqual(@as(u64, 2), retained_score_history[0].sequence);
    try std.testing.expectEqual(@as(u64, 3), retained_score_history[1].sequence);
    try std.testing.expectEqual(@as(u64, 4), retained_score_history[1].doc_count);
    try std.testing.expectEqual(@as(u64, 4), retained_score_history[1].unique_scalar_values);
}

test "algebraic adaptive backfill materializes schemaless path recommendations" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "adaptive": {"observe": true, "lazy_materialization": true, "min_observations": 1, "max_backfill_rows_per_tick": 10, "min_estimated_scan_rows_saved": 1},
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_path_adaptive_backfill", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"10.5\"}}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"10.5\"}}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"12.5\"}}" },
    };
    const doc_keys = [_][]const u8{ "o1", "o2", "o3" };
    var identity_writes = std.ArrayListUnmanaged(docstore_mod.KVPair).empty;
    defer {
        for (identity_writes.items) |item| {
            alloc.free(@constCast(item.key));
            alloc.free(@constCast(item.value));
        }
        identity_writes.deinit(alloc);
    }
    try doc_identity.appendBatchIdentityMetadataAlloc(
        alloc,
        &store,
        0,
        0,
        1,
        &identity_writes,
        doc_keys[0..],
        &.{},
    );
    try store.putBatchWithReplay(null, identity_writes.items, &.{}, null);

    try idx.applyBatch(&store, .{ .documents = docs[0..] });

    try std.testing.expect(try idx.persistSchemalessPathPromotionRecommendations(&store) > 0);
    const recommendation = try adaptive_mod.pathPromotionRecommendationAlloc(alloc, "/meta/score_text", "string", "stable_numeric_string_path");
    defer alloc.free(recommendation);
    const materialization_id = try adaptive_mod.materializationIdAlloc(alloc, recommendation);
    defer alloc.free(materialization_id);

    const candidates = try idx.scanPersistedAdaptiveCandidates(&store);
    defer {
        for (candidates) |*candidate| candidate.deinit(alloc);
        alloc.free(candidates);
    }
    var saw_backfill_candidate = false;
    for (candidates) |candidate| {
        if (std.mem.eql(u8, candidate.recommendation, recommendation)) {
            saw_backfill_candidate = true;
            try std.testing.expectEqual(adaptive_mod.Lifecycle.backfilling, candidate.lifecycle);
            try std.testing.expectEqualStrings("schemaless_path_backfill_started", candidate.decision);
        }
    }
    try std.testing.expect(saw_backfill_candidate);

    try std.testing.expect(try idx.runAdaptiveWork(&store, 0) > 0);
    const ready_id = (try idx.readyAdaptiveMaterializationIdAlloc(&store, recommendation)).?;
    defer alloc.free(ready_id);
    try std.testing.expectEqualStrings(materialization_id, ready_id);

    const axes = try token.canonicalTupleAlloc(alloc, &.{ "string", "10.5" });
    defer alloc.free(axes);
    const raw = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, axes, null)).?;
    defer alloc.free(raw);
    try std.testing.expectEqual(@as(i64, 2), try algebra.parseI64(raw));
    var expr_raw = (try idx.adaptiveMaterializedExpressionRawValueForRecommendationAlloc(&store, recommendation, axes, null)).?;
    defer expr_raw.deinit(idx.alloc);
    try std.testing.expectEqual(@as(i64, 2), try algebra.parseI64(expr_raw.raw.?));
    try std.testing.expectEqual(@as(u64, 2), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "10.5")));
    const identity = lexical_mod.DictionaryIdentity.canonicalScalar(idx.name, "/meta/score_text", .string, "json-scalar-v1", "kind-qualified");
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryLexiconKeyAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 2), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 2), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryOrdinalPostingsPrefixAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryFstKeyAlloc(identity)));
    var resolved_term_filter = (try idx.resolvedDocFilterForFilterJsonAlloc(&store,
        \\{"term":{"path":"/meta/score_text","value":"10.5"}}
    )).?;
    defer resolved_term_filter.deinit(idx.alloc);
    switch (resolved_term_filter.include) {
        .ordinals => |ordinals| {
            try std.testing.expectEqual(@as(usize, 2), ordinals.len);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 1), ordinals[0]);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 2), ordinals[1]);
        },
        else => return error.ExpectedOrdinalDocSet,
    }
    var resolved_term_range_filter = (try idx.resolvedDocFilterForFilterJsonAlloc(&store,
        \\{"term_range":{"path":"/meta/score_text","min":"10","max":"11","inclusive_min":true,"inclusive_max":false}}
    )).?;
    defer resolved_term_range_filter.deinit(idx.alloc);
    switch (resolved_term_range_filter.include) {
