        else => return error.ExpectedOrdinalDocSet,
    }
    var resolved_regexp_filter = (try idx.resolvedDocFilterForFilterJsonAlloc(&store,
        \\{"regexp":{"path":"/meta/score_text","pattern":"10.*"}}
    )).?;
    defer resolved_regexp_filter.deinit(idx.alloc);
    switch (resolved_regexp_filter.include) {
        .ordinals => |ordinals| {
            try std.testing.expectEqual(@as(usize, 2), ordinals.len);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 1), ordinals[0]);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 2), ordinals[1]);
        },
        else => return error.ExpectedOrdinalDocSet,
    }
    var resolved_fuzzy_filter = (try idx.resolvedDocFilterForFilterJsonAlloc(&store,
        \\{"fuzzy":{"path":"/meta/score_text","query":"10.6","prefix_length":2,"max_edits":1}}
    )).?;
    defer resolved_fuzzy_filter.deinit(idx.alloc);
    switch (resolved_fuzzy_filter.include) {
        .ordinals => |ordinals| {
            try std.testing.expectEqual(@as(usize, 2), ordinals.len);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 1), ordinals[0]);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 2), ordinals[1]);
        },
        else => return error.ExpectedOrdinalDocSet,
    }
    var resolved_exists_filter = (try idx.resolvedDocFilterForFilterJsonAlloc(&store,
        \\{"exists":{"path":"/meta/score_text"}}
    )).?;
    defer resolved_exists_filter.deinit(idx.alloc);
    switch (resolved_exists_filter.include) {
        .ordinals => |ordinals| {
            try std.testing.expectEqual(@as(usize, 3), ordinals.len);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 1), ordinals[0]);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 2), ordinals[1]);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 3), ordinals[2]);
        },
        else => return error.ExpectedOrdinalDocSet,
    }

    const term_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"term":{"path":"/meta/score_text","value":"10.5"}}
    )).?;
    defer idx.freeDocIds(term_ids);
    try std.testing.expectEqual(@as(usize, 2), term_ids.len);
    const prefix_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"prefix":{"path":"/meta/score_text","value":"10"}}
    )).?;
    defer idx.freeDocIds(prefix_ids);
    try std.testing.expectEqual(@as(usize, 2), prefix_ids.len);

    const registry_key = try identity.registryKeyAlloc(alloc);
    defer alloc.free(registry_key);
    var read_txn = try store.beginReadTxn();
    const registry_payload = try read_txn.get(registry_key);
    var registry_entry = try lexical_mod.RegistryEntry.decodeAlloc(alloc, registry_payload);
    defer registry_entry.deinit(alloc);
    read_txn.abort();
    try std.testing.expectEqual(lexical_mod.DictionaryLayoutKind.lexicon_postings_rows, registry_entry.layout);
    try std.testing.expectEqualStrings(materialization_id, registry_entry.owner);

    var ready_spec = try idx.adaptiveSpecFromRecommendationAlloc(materialization_id, recommendation);
    defer ready_spec.deinit(alloc);
    const path_expr = Index.adaptiveMaterializedExpression(ready_spec) orelse return error.TestUnexpectedResult;
    const path_expr_id = try idx.materializedExpressionIdForLawAlloc(path_expr, .count);
    defer alloc.free(path_expr_id);
    const ready_cost = try idx.adaptiveCostInputs(&store, ready_spec, materialization_id);
    try std.testing.expect(ready_cost.tensor_rows >= 8);
    try std.testing.expect(ready_cost.storage_bytes > 0);

    const incremental_doc = [_]derived_types.DerivedDocument{
        .{ .key = "o4", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"10.5\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = incremental_doc[0..] });
    const raw_after_add = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, axes, null)).?;
    defer alloc.free(raw_after_add);
    try std.testing.expectEqual(@as(i64, 3), try algebra.parseI64(raw_after_add));
    var expr_after_add = (try idx.adaptiveMaterializedExpressionRawValueForRecommendationAlloc(&store, recommendation, axes, null)).?;
    defer expr_after_add.deinit(idx.alloc);
    try std.testing.expectEqual(@as(i64, 3), try algebra.parseI64(expr_after_add.raw.?));
    try std.testing.expectEqual(@as(u64, 3), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "10.5")));
    try std.testing.expectEqual(@as(u64, 3), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "10.5")));
    const term_ids_after_add = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"term":{"path":"/meta/score_text","value":"10.5"}}
    )).?;
    defer idx.freeDocIds(term_ids_after_add);
    try std.testing.expectEqual(@as(usize, 3), term_ids_after_add.len);

    const rebuilds_before_bulk = idx.path_dictionary_fst_rebuild_count;
    const bulk_incremental_doc = [_]derived_types.DerivedDocument{
        .{ .key = "o5", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"10.5\"}}" },
        .{ .key = "o6", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"12.5\"}}" },
    };
    try idx.applyBatchWithOptions(&store, .{ .documents = bulk_incremental_doc[0..] }, .{ .batch_options = .{ .mode = .bulk_ingest } });
    try std.testing.expectEqual(rebuilds_before_bulk + 1, idx.path_dictionary_fst_rebuild_count);
    const raw_after_bulk_add = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, axes, null)).?;
    defer alloc.free(raw_after_bulk_add);
    try std.testing.expectEqual(@as(i64, 4), try algebra.parseI64(raw_after_bulk_add));
    var expr_after_bulk_add = (try idx.adaptiveMaterializedExpressionRawValueForRecommendationAlloc(&store, recommendation, axes, null)).?;
    defer expr_after_bulk_add.deinit(idx.alloc);
    try std.testing.expectEqual(@as(i64, 4), try algebra.parseI64(expr_after_bulk_add.raw.?));
    try std.testing.expectEqual(@as(u64, 4), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "10.5")));
    try std.testing.expectEqual(@as(u64, 4), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "10.5")));
    const term_ids_after_bulk_add = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"term":{"path":"/meta/score_text","value":"10.5"}}
    )).?;
    defer idx.freeDocIds(term_ids_after_bulk_add);
    try std.testing.expectEqual(@as(usize, 4), term_ids_after_bulk_add.len);

    const rebuilds_before_session = idx.path_dictionary_fst_rebuild_count;
    try idx.beginBulkIngestSession();
    var algebraic_bulk_session_open = true;
    errdefer if (algebraic_bulk_session_open) idx.abortBulkIngestSession();
    const session_first = [_]derived_types.DerivedDocument{
        .{ .key = "o7", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"13.5\"}}" },
    };
    const session_second = [_]derived_types.DerivedDocument{
        .{ .key = "o8", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"14.5\"}}" },
    };
    try idx.applyBatchWithOptions(&store, .{ .documents = session_first[0..] }, .{ .batch_options = .{ .mode = .bulk_ingest } });
    try std.testing.expectEqual(rebuilds_before_session, idx.path_dictionary_fst_rebuild_count);
    try idx.applyBatchWithOptions(&store, .{ .documents = session_second[0..] }, .{ .batch_options = .{ .mode = .bulk_ingest } });
    try std.testing.expectEqual(rebuilds_before_session, idx.path_dictionary_fst_rebuild_count);
    try idx.finishBulkIngestSessionWithOptions(&store, .{});
    algebraic_bulk_session_open = false;
    try std.testing.expectEqual(rebuilds_before_session + 1, idx.path_dictionary_fst_rebuild_count);
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "13.5")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "14.5")));

    const rebuilds_before_unrelated_path_update = idx.path_dictionary_fst_rebuild_count;
    const unrelated_path_update = [_]derived_types.DerivedDocument{
        .{ .key = "o7", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"13.5\",\"other\":\"unchanged-dictionary\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = unrelated_path_update[0..] });
    try std.testing.expectEqual(rebuilds_before_unrelated_path_update, idx.path_dictionary_fst_rebuild_count);
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "13.5")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "13.5")));

    const delete_one = [_][]const u8{"o1"};
    try idx.applyBatch(&store, .{ .deleted_keys = delete_one[0..] });
    const raw_after_delete = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, axes, null)).?;
    defer alloc.free(raw_after_delete);
    try std.testing.expectEqual(@as(i64, 3), try algebra.parseI64(raw_after_delete));
    var expr_after_delete = (try idx.adaptiveMaterializedExpressionRawValueForRecommendationAlloc(&store, recommendation, axes, null)).?;
    defer expr_after_delete.deinit(idx.alloc);
    try std.testing.expectEqual(@as(i64, 3), try algebra.parseI64(expr_after_delete.raw.?));
    try std.testing.expectEqual(@as(u64, 3), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "10.5")));
    try std.testing.expectEqual(@as(u64, 3), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "10.5")));
    const term_ids_after_delete = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"term":{"path":"/meta/score_text","value":"10.5"}}
    )).?;
    defer idx.freeDocIds(term_ids_after_delete);
    try std.testing.expectEqual(@as(usize, 3), term_ids_after_delete.len);

    const delete_remaining = [_][]const u8{ "o2", "o4", "o5" };
    try idx.applyBatch(&store, .{ .deleted_keys = delete_remaining[0..] });
    const raw_after_delete_remaining = try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, axes, null);
    defer if (raw_after_delete_remaining) |bytes| alloc.free(bytes);
    try std.testing.expect(raw_after_delete_remaining == null);
    try std.testing.expect((try idx.adaptiveMaterializedExpressionRawValueForRecommendationAlloc(&store, recommendation, axes, null)) == null);
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "10.5")));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryLexiconKeyAlloc(identity, "10.5")));

    try idx.deleteAdaptiveMaterialization(&store, recommendation, materialization_id);
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "10.5")));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryLexiconKeyAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryFstKeyAlloc(identity)));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try tensor_mod.expressionPrefixAlloc(alloc, idx.name, path_expr_id)));
    var deleted_registry_txn = try store.beginReadTxn();
    _ = deleted_registry_txn.get(registry_key) catch |err| switch (err) {
        error.NotFound => {},
        else => return err,
    };
    deleted_registry_txn.abort();
}

test "algebraic resolved doc filters honor identity generation for explicit ids" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_generation_ids", cfg);
    defer idx.close();

    var create_identity = std.ArrayListUnmanaged(docstore_mod.KVPair).empty;
    defer {
        for (create_identity.items) |item| {
            alloc.free(@constCast(item.key));
            alloc.free(@constCast(item.value));
        }
        create_identity.deinit(alloc);
    }
    try doc_identity.appendBatchIdentityMetadataAlloc(
        alloc,
        &store,
        0,
        0,
        1,
        &create_identity,
        &.{"doc:a"},
        &.{},
    );
    try store.putBatchWithReplay(null, create_identity.items, &.{}, null);

    try idx.applyBatch(&store, .{ .documents = &.{.{
        .key = "doc:a",
        .action = .upsert,
        .cleaned_value = "{\"name\":\"alpha\"}",
    }} });

    var delete_identity = std.ArrayListUnmanaged(docstore_mod.KVPair).empty;
    defer {
        for (delete_identity.items) |item| {
            alloc.free(@constCast(item.key));
            alloc.free(@constCast(item.value));
        }
        delete_identity.deinit(alloc);
    }
    try doc_identity.appendBatchIdentityMetadataAlloc(
        alloc,
        &store,
        0,
        0,
        2,
        &delete_identity,
        &.{},
        &.{"doc:a"},
    );
    try store.putBatchWithReplay(null, delete_identity.items, &.{}, null);

    var visible_at_create = (try idx.resolvedDocFilterForFilterJsonAtGenerationAlloc(&store,
        \\{"ids":["doc:a"]}
    , 1)).?;
    defer visible_at_create.deinit(idx.alloc);
    switch (visible_at_create.include) {
        .ordinals => |ordinals| {
            try std.testing.expectEqual(@as(usize, 1), ordinals.len);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 1), ordinals[0]);
        },
        else => return error.ExpectedOrdinalDocSet,
    }

    var hidden_at_delete = (try idx.resolvedDocFilterForFilterJsonAtGenerationAlloc(&store,
        \\{"ids":["doc:a"]}
    , 2)).?;
    defer hidden_at_delete.deinit(idx.alloc);
    try std.testing.expectEqual(@as(?usize, 0), hidden_at_delete.include.estimatedCardinality());
}

test "algebraic adaptive path promotion defers fst rebuild until backfill completion" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "adaptive": {"observe": true, "lazy_materialization": true, "min_observations": 1, "max_backfill_rows_per_tick": 1, "min_estimated_scan_rows_saved": 1},
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_path_dictionary_deferred_fst", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"10.5\"}}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"12.5\"}}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"15.5\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });
    try std.testing.expect(try idx.persistSchemalessPathPromotionRecommendations(&store) > 0);

    const recommendation = try adaptive_mod.pathPromotionRecommendationAlloc(alloc, "/meta/score_text", "string", "stable_numeric_string_path");
    defer alloc.free(recommendation);
    const materialization_id = try adaptive_mod.materializationIdAlloc(alloc, recommendation);
    defer alloc.free(materialization_id);
    const identity = lexical_mod.DictionaryIdentity.canonicalScalar(idx.name, "/meta/score_text", .string, "json-scalar-v1", "kind-qualified");
    const registry_key = try identity.registryKeyAlloc(alloc);
    defer alloc.free(registry_key);

    try std.testing.expect(try idx.runAdaptiveWork(&store, 0) > 0);
    try std.testing.expect((try idx.readyAdaptiveMaterializationIdAlloc(&store, recommendation)) == null);
    try std.testing.expectEqual(@as(u64, 0), idx.path_dictionary_fst_rebuild_count);
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryFstKeyAlloc(identity)));

    {
        var read_txn = try store.beginReadTxn();
        defer read_txn.abort();
        var entry = try lexical_mod.RegistryEntry.decodeAlloc(alloc, try read_txn.get(registry_key));
        defer entry.deinit(alloc);
        try std.testing.expectEqualStrings(materialization_id, entry.owner);
        try std.testing.expectEqual(lexical_mod.DictionaryLayoutKind.lexicon_postings_rows, entry.layout);
        try std.testing.expectEqualStrings("building", entry.state);
    }

    while (try idx.runAdaptiveWork(&store, 0) != 0) {}
    const ready_id = (try idx.readyAdaptiveMaterializationIdAlloc(&store, recommendation)).?;
    defer alloc.free(ready_id);
    try std.testing.expectEqualStrings(materialization_id, ready_id);
    try std.testing.expectEqual(@as(u64, 1), idx.path_dictionary_fst_rebuild_count);
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryFstKeyAlloc(identity)));

    {
        var read_txn = try store.beginReadTxn();
        defer read_txn.abort();
        var entry = try lexical_mod.RegistryEntry.decodeAlloc(alloc, try read_txn.get(registry_key));
        defer entry.deinit(alloc);
        try std.testing.expectEqualStrings(materialization_id, entry.owner);
        try std.testing.expectEqual(lexical_mod.DictionaryLayoutKind.lexicon_postings_rows, entry.layout);
        try std.testing.expectEqualStrings("ready", entry.state);
    }

    const prefix_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"prefix":{"path":"/meta/score_text","value":"1"}}
    )).?;
    defer idx.freeDocIds(prefix_ids);
    try std.testing.expectEqual(@as(usize, 3), prefix_ids.len);
}

test "algebraic adaptive path promotion honors existing dictionary owner" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "adaptive": {"observe": true, "lazy_materialization": true, "min_observations": 1, "max_backfill_rows_per_tick": 10, "min_estimated_scan_rows_saved": 1},
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_path_dictionary_conflict", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"10.5\"}}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"10.5\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });
    try std.testing.expect(try idx.persistSchemalessPathPromotionRecommendations(&store) > 0);

    const recommendation = try adaptive_mod.pathPromotionRecommendationAlloc(alloc, "/meta/score_text", "string", "stable_numeric_string_path");
    defer alloc.free(recommendation);
    const materialization_id = try adaptive_mod.materializationIdAlloc(alloc, recommendation);
    defer alloc.free(materialization_id);
    const identity = lexical_mod.DictionaryIdentity.canonicalScalar(idx.name, "/meta/score_text", .string, "json-scalar-v1", "kind-qualified");
    const registry_key = try identity.registryKeyAlloc(alloc);
    defer alloc.free(registry_key);

    {
        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        try std.testing.expectEqual(lexical_mod.RegistryClaim.claimed, try lexical_mod.claimRegistryOwnerTxn(
            alloc,
            &txn,
            identity,
            "lexical-owner",
            .fst_postings,
            "ready",
        ));
        try txn.commit();
    }

    try std.testing.expect(try idx.runAdaptiveWork(&store, 0) > 0);
    try std.testing.expectEqual(@as(u64, 1), idx.dictionary_registry_owned_by_other_count);

    const axes = try token.canonicalTupleAlloc(alloc, &.{ "string", "10.5" });
    defer alloc.free(axes);
    const raw = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, axes, null)).?;
    defer alloc.free(raw);
    try std.testing.expectEqual(@as(i64, 2), try algebra.parseI64(raw));
    try std.testing.expectEqual(@as(u64, 2), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "10.5")));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryLexiconKeyAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryFstKeyAlloc(identity)));

    try idx.deleteAdaptiveMaterialization(&store, recommendation, materialization_id);
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "10.5")));

    var read_txn = try store.beginReadTxn();
    const registry_payload = try read_txn.get(registry_key);
    var registry_entry = try lexical_mod.RegistryEntry.decodeAlloc(alloc, registry_payload);
    defer registry_entry.deinit(alloc);
    read_txn.abort();
    try std.testing.expectEqual(lexical_mod.DictionaryLayoutKind.fst_postings, registry_entry.layout);
    try std.testing.expectEqualStrings("lexical-owner", registry_entry.owner);
}

test "algebraic adaptive backfill promotes scalar array parent paths without duplicate value deltas" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "adaptive": {"observe": true, "lazy_materialization": true, "min_observations": 1, "max_backfill_rows_per_tick": 20, "min_estimated_scan_rows_saved": 1},
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_path_array_adaptive_backfill", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"tags\":[\"new\",\"vip\",\"new\"]}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"tags\":[\"vip\"]}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"tags\":[\"sale\"]}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });

    const tag_recommendation = try idx.pathPromotionRecommendationAlloc(&store, "/tags");
    try std.testing.expectEqual(pathfact_mod.Kind.string, tag_recommendation.stable_kind.?);
    try std.testing.expect(tag_recommendation.lexical_dictionary);
    try std.testing.expectEqualStrings("stable_lexical_path", tag_recommendation.reason);

    try std.testing.expect(try idx.persistSchemalessPathPromotionRecommendations(&store) > 0);
    const recommendation = try adaptive_mod.pathPromotionRecommendationAlloc(alloc, "/tags", "string", "stable_lexical_path");
    defer alloc.free(recommendation);
    const materialization_id = try adaptive_mod.materializationIdAlloc(alloc, recommendation);
    defer alloc.free(materialization_id);

    while (try idx.runAdaptiveWork(&store, 0) != 0) {}
    const ready_id = (try idx.readyAdaptiveMaterializationIdAlloc(&store, recommendation)).?;
    defer alloc.free(ready_id);
    try std.testing.expectEqualStrings(materialization_id, ready_id);

    const vip_axes = try token.canonicalTupleAlloc(alloc, &.{ "string", "vip" });
    defer alloc.free(vip_axes);
    const new_axes = try token.canonicalTupleAlloc(alloc, &.{ "string", "new" });
    defer alloc.free(new_axes);
    const sale_axes = try token.canonicalTupleAlloc(alloc, &.{ "string", "sale" });
    defer alloc.free(sale_axes);
    const clearance_axes = try token.canonicalTupleAlloc(alloc, &.{ "string", "clearance" });
    defer alloc.free(clearance_axes);

    const vip_raw = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, vip_axes, null)).?;
    defer alloc.free(vip_raw);
    try std.testing.expectEqual(@as(i64, 2), try algebra.parseI64(vip_raw));
    const new_raw = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, new_axes, null)).?;
    defer alloc.free(new_raw);
    try std.testing.expectEqual(@as(i64, 1), try algebra.parseI64(new_raw));
    const sale_raw = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, sale_axes, null)).?;
    defer alloc.free(sale_raw);
    try std.testing.expectEqual(@as(i64, 1), try algebra.parseI64(sale_raw));
    var vip_expr = (try idx.adaptiveMaterializedExpressionRawValueForRecommendationAlloc(&store, recommendation, vip_axes, null)).?;
    defer vip_expr.deinit(idx.alloc);
    try std.testing.expectEqual(@as(i64, 2), try algebra.parseI64(vip_expr.raw.?));

    const identity = lexical_mod.DictionaryIdentity.canonicalScalar(idx.name, "/tags", .string, "json-scalar-v1", "kind-qualified");
    try std.testing.expectEqual(@as(u64, 2), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/tags", .string, "vip")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/tags", .string, "new")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/tags", .string, "sale")));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/tags", .array, "")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryLexiconKeyAlloc(identity, "vip")));
    try std.testing.expectEqual(@as(u64, 2), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "vip")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryFstKeyAlloc(identity)));

    const term_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"term":{"path":"/tags","value":"vip"}}
    )).?;
    defer idx.freeDocIds(term_ids);
    try std.testing.expectEqual(@as(usize, 2), term_ids.len);
    const prefix_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"prefix":{"path":"/tags","value":"v"}}
    )).?;
    defer idx.freeDocIds(prefix_ids);
    try std.testing.expectEqual(@as(usize, 2), prefix_ids.len);

    const duplicate_increment = [_]derived_types.DerivedDocument{
        .{ .key = "o4", .action = .upsert, .cleaned_value = "{\"tags\":[\"vip\",\"clearance\",\"vip\"]}" },
    };
    try idx.applyBatch(&store, .{ .documents = duplicate_increment[0..] });
    const vip_after_add = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, vip_axes, null)).?;
    defer alloc.free(vip_after_add);
    try std.testing.expectEqual(@as(i64, 3), try algebra.parseI64(vip_after_add));
    const clearance_after_add = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, clearance_axes, null)).?;
    defer alloc.free(clearance_after_add);
    try std.testing.expectEqual(@as(i64, 1), try algebra.parseI64(clearance_after_add));
    try std.testing.expectEqual(@as(u64, 3), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "vip")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "clearance")));

    const delete_o4 = [_][]const u8{"o4"};
    try idx.applyBatch(&store, .{ .deleted_keys = delete_o4[0..] });
    const vip_after_delete_o4 = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, vip_axes, null)).?;
    defer alloc.free(vip_after_delete_o4);
    try std.testing.expectEqual(@as(i64, 2), try algebra.parseI64(vip_after_delete_o4));
    const clearance_after_delete_o4 = try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, clearance_axes, null);
    defer if (clearance_after_delete_o4) |bytes| alloc.free(bytes);
    try std.testing.expect(clearance_after_delete_o4 == null);
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "clearance")));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/tags", .array, "")));

    const delete_o1 = [_][]const u8{"o1"};
    try idx.applyBatch(&store, .{ .deleted_keys = delete_o1[0..] });
    const new_after_delete_o1 = try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, new_axes, null);
    defer if (new_after_delete_o1) |bytes| alloc.free(bytes);
    try std.testing.expect(new_after_delete_o1 == null);
    const vip_after_delete_o1 = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, vip_axes, null)).?;
    defer alloc.free(vip_after_delete_o1);
    try std.testing.expectEqual(@as(i64, 1), try algebra.parseI64(vip_after_delete_o1));
}

test "algebraic promoted datetime path dictionary supports date ranges" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "events",
        \\  "adaptive": {"observe": true, "lazy_materialization": true, "min_observations": 1, "max_backfill_rows_per_tick": 10, "min_estimated_scan_rows_saved": 1},
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_path_datetime_dictionary", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "e1", .action = .upsert, .cleaned_value = "{\"published_at\":\"2026-01-02T12:00:00Z\"}" },
        .{ .key = "e2", .action = .upsert, .cleaned_value = "{\"published_at\":\"2026-01-03T12:00:00Z\"}" },
        .{ .key = "e3", .action = .upsert, .cleaned_value = "{\"published_at\":\"2026-01-05T12:00:00Z\"}" },
    };
    const doc_keys = [_][]const u8{ "e1", "e2", "e3" };
    var identity_writes = std.ArrayListUnmanaged(docstore_mod.KVPair).empty;
    defer {
        for (identity_writes.items) |item| {
            alloc.free(@constCast(item.key));
            alloc.free(@constCast(item.value));
        }
        identity_writes.deinit(alloc);
    }
    try doc_identity.appendBatchIdentityMetadataAlloc(
        alloc,
        &store,
        0,
        0,
        1,
        &identity_writes,
        doc_keys[0..],
        &.{},
    );
    try store.putBatchWithReplay(null, identity_writes.items, &.{}, null);
    try idx.applyBatch(&store, .{ .documents = docs[0..] });
    try std.testing.expect(try idx.persistSchemalessPathPromotionRecommendations(&store) > 0);
    const recommendation = try adaptive_mod.pathPromotionRecommendationAlloc(alloc, "/published_at", "string", "stable_datetime_string_path");
    defer alloc.free(recommendation);
    while (try idx.runAdaptiveWork(&store, 0) != 0) {}
    const materialization_id = (try idx.readyAdaptiveMaterializationIdAlloc(&store, recommendation)).?;
    defer alloc.free(materialization_id);

    const identity = lexical_mod.DictionaryIdentity.canonicalScalar(idx.name, "/published_at", .string, "json-scalar-v1", "kind-qualified");
    const status_value = idx.status();
    try std.testing.expect(status_value.dictionary_registry_claimed_count >= 1);
    try std.testing.expectEqual(@as(u64, 0), status_value.dictionary_registry_owned_by_other_count);
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryFstKeyAlloc(identity)));

    var resolved_date_filter = (try idx.resolvedDocFilterForFilterJsonAlloc(&store,
        \\{"date_range":{"path":"/published_at","start":"2026-01-03T00:00:00Z","end":"2026-01-05T00:00:00Z","inclusive_start":true,"inclusive_end":false}}
    )).?;
    defer resolved_date_filter.deinit(idx.alloc);
    switch (resolved_date_filter.include) {
        .ordinals => |ordinals| {
            try std.testing.expectEqual(@as(usize, 1), ordinals.len);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 2), ordinals[0]);
        },
        else => return error.ExpectedOrdinalDocSet,
    }

    const date_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"date_range":{"path":"/published_at","start":"2026-01-03T00:00:00Z","end":"2026-01-05T00:00:00Z","inclusive_start":true,"inclusive_end":false}}
    )).?;
    defer idx.freeDocIds(date_ids);
    try std.testing.expectEqual(@as(usize, 1), date_ids.len);
    try std.testing.expectEqualStrings("e2", date_ids[0]);

    var resolved_standard_filter = (try idx.resolvedDocFilterForFilterJsonAlloc(&store,
        \\{"range":{"/published_at":{"gte":"2026-01-03","lt":"2026-01-05"}}}
    )).?;
    defer resolved_standard_filter.deinit(idx.alloc);
    switch (resolved_standard_filter.include) {
        .ordinals => |ordinals| {
            try std.testing.expectEqual(@as(usize, 1), ordinals.len);
            try std.testing.expectEqual(@as(doc_set.DocOrdinal, 2), ordinals[0]);
        },
        else => return error.ExpectedOrdinalDocSet,
    }

    const standard_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"range":{"/published_at":{"gte":"2026-01-03","lt":"2026-01-05"}}}
    )).?;
    defer idx.freeDocIds(standard_ids);
    try std.testing.expectEqual(@as(usize, 1), standard_ids.len);
    try std.testing.expectEqualStrings("e2", standard_ids[0]);
}

test "algebraic dictionary registry preserves an existing shared owner" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "adaptive": {"observe": true, "lazy_materialization": true, "min_observations": 1, "max_backfill_rows_per_tick": 10, "min_estimated_scan_rows_saved": 1},
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_path_registry_owner", cfg);
    defer idx.close();

    const identity = lexical_mod.DictionaryIdentity.canonicalScalar(idx.name, "/meta/score_text", .string, "json-scalar-v1", "kind-qualified");
    const registry_key = try identity.registryKeyAlloc(alloc);
    defer alloc.free(registry_key);
    const existing_payload = try (lexical_mod.RegistryEntry{
        .owner = "shared-canonical-scalar-dictionary",
        .layout = .fst_postings,
        .state = "ready",
    }).encodeAlloc(alloc);
    defer alloc.free(existing_payload);
    {
        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        try txn.put(registry_key, existing_payload);
        const lexicon_key = try idx.pathDictionaryLexiconKeyAlloc(identity, "10.5");
        defer alloc.free(lexicon_key);
        const postings_key_1 = try idx.pathDictionaryPostingsKeyAlloc(identity, "10.5", "o1");
        defer alloc.free(postings_key_1);
        const postings_key_2 = try idx.pathDictionaryPostingsKeyAlloc(identity, "10.5", "o2");
        defer alloc.free(postings_key_2);
        const fst_key = try idx.pathDictionaryFstKeyAlloc(identity);
        defer alloc.free(fst_key);
        const labels = [_][]const u8{"10.5"};
        const fst_bytes = try lexical_mod.buildFstAlloc(alloc, labels[0..]);
        defer alloc.free(fst_bytes);
        try txn.put(lexicon_key, "shared-lexicon-row");
        try txn.put(postings_key_1, "shared-posting-row");
        try txn.put(postings_key_2, "shared-posting-row");
        try txn.put(fst_key, fst_bytes);
        try txn.commit();
    }

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"10.5\"}}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"10.5\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });
    try std.testing.expect(try idx.persistSchemalessPathPromotionRecommendations(&store) > 0);
    const recommendation = try adaptive_mod.pathPromotionRecommendationAlloc(alloc, "/meta/score_text", "string", "stable_numeric_string_path");
    defer alloc.free(recommendation);
    const materialization_id = try adaptive_mod.materializationIdAlloc(alloc, recommendation);
    defer alloc.free(materialization_id);
    try std.testing.expect(try idx.runAdaptiveWork(&store, 0) > 0);
    try std.testing.expect(idx.status().dictionary_registry_owned_by_other_count >= 1);

    const axes = try token.canonicalTupleAlloc(alloc, &.{ "string", "10.5" });
    defer alloc.free(axes);
    const raw = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, axes, null)).?;
    defer alloc.free(raw);
    try std.testing.expectEqual(@as(i64, 2), try algebra.parseI64(raw));
    try std.testing.expectEqual(@as(u64, 2), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "10.5")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryLexiconKeyAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 2), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryFstKeyAlloc(identity)));

    const term_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"term":{"path":"/meta/score_text","value":"10.5"}}
    )).?;
    defer idx.freeDocIds(term_ids);
    try std.testing.expectEqual(@as(usize, 2), term_ids.len);

    {
        var txn = try store.beginReadTxn();
        defer txn.abort();
        const registry_payload = try txn.get(registry_key);
        var registry_entry = try lexical_mod.RegistryEntry.decodeAlloc(alloc, registry_payload);
        defer registry_entry.deinit(alloc);
        try std.testing.expectEqualStrings("shared-canonical-scalar-dictionary", registry_entry.owner);
        try std.testing.expectEqual(lexical_mod.DictionaryLayoutKind.fst_postings, registry_entry.layout);
    }

    try idx.deleteAdaptiveMaterialization(&store, recommendation, materialization_id);
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.promotedPathLookupPrefixAlloc(materialization_id, "/meta/score_text", .string, "10.5")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryLexiconKeyAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 2), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryPostingsPrefixAlloc(identity, "10.5")));
    try std.testing.expectEqual(@as(u64, 1), try idx.countRowsWithPrefix(&store, try idx.pathDictionaryFstKeyAlloc(identity)));
    {
        var txn = try store.beginReadTxn();
        defer txn.abort();
        const registry_payload = try txn.get(registry_key);
        var registry_entry = try lexical_mod.RegistryEntry.decodeAlloc(alloc, registry_payload);
        defer registry_entry.deinit(alloc);
        try std.testing.expectEqualStrings("shared-canonical-scalar-dictionary", registry_entry.owner);
        try std.testing.expectEqual(lexical_mod.DictionaryLayoutKind.fst_postings, registry_entry.layout);
    }
}

test "algebraic path dictionary reads require ready registry owner" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "adaptive": {"observe": true, "lazy_materialization": true, "min_observations": 1, "max_backfill_rows_per_tick": 10, "min_estimated_scan_rows_saved": 1},
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_path_registry_ready_gate", cfg);
    defer idx.close();

    const identity = lexical_mod.DictionaryIdentity.canonicalScalar(idx.name, "/meta/score_text", .string, "json-scalar-v1", "kind-qualified");
    const registry_key = try identity.registryKeyAlloc(alloc);
    defer alloc.free(registry_key);
    const building_payload = try (lexical_mod.RegistryEntry{
        .owner = "shared-canonical-scalar-dictionary",
        .layout = .fst_postings,
        .state = "building",
    }).encodeAlloc(alloc);
    defer alloc.free(building_payload);
    {
        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        try txn.put(registry_key, building_payload);
        const lexicon_key = try idx.pathDictionaryLexiconKeyAlloc(identity, "10.5");
        defer alloc.free(lexicon_key);
        const postings_key = try idx.pathDictionaryPostingsKeyAlloc(identity, "10.5", "stale-doc");
        defer alloc.free(postings_key);
        const fst_key = try idx.pathDictionaryFstKeyAlloc(identity);
        defer alloc.free(fst_key);
        try txn.put(lexicon_key, "stale-lexicon-row");
        try txn.put(postings_key, "stale-posting-row");
        try txn.put(fst_key, "not-a-valid-fst");
        try txn.commit();
    }

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"10.5\"}}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"meta\":{\"score_text\":\"10.5\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });
    try std.testing.expect(try idx.persistSchemalessPathPromotionRecommendations(&store) > 0);
    while (try idx.runAdaptiveWork(&store, 0) != 0) {}
    try std.testing.expect(idx.status().dictionary_registry_owned_by_other_count >= 1);

    const term_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"term":{"path":"/meta/score_text","value":"10.5"}}
    )).?;
    defer idx.freeDocIds(term_ids);
    try std.testing.expectEqual(@as(usize, 2), term_ids.len);
    try std.testing.expect(containsDocId(term_ids, "o1"));
    try std.testing.expect(containsDocId(term_ids, "o2"));
    try std.testing.expect(!containsDocId(term_ids, "stale-doc"));

    const incompatible_ready_payload = try (lexical_mod.RegistryEntry{
        .owner = "shared-canonical-scalar-dictionary",
        .layout = .fst_postings,
        .state = "ready",
    }).encodeAlloc(alloc);
    defer alloc.free(incompatible_ready_payload);
    {
        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        try txn.put(registry_key, incompatible_ready_payload);
        try txn.commit();
    }
    const layout_gated_ids = (try idx.docIdsForFilterJsonAlloc(&store,
        \\{"term":{"path":"/meta/score_text","value":"10.5"}}
    )).?;
    defer idx.freeDocIds(layout_gated_ids);
    try std.testing.expectEqual(@as(usize, 2), layout_gated_ids.len);
    try std.testing.expect(containsDocId(layout_gated_ids, "o1"));
    try std.testing.expect(containsDocId(layout_gated_ids, "o2"));
    try std.testing.expect(!containsDocId(layout_gated_ids, "stale-doc"));
    try std.testing.expect(idx.status().dictionary_registry_ready_miss_count >= 1);
}

test "algebraic dictionary registry does not duplicate analyzed text ownership" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const analyzed_identity = lexical_mod.DictionaryIdentity.analyzedText("full_text_index_v0", "body", "default");
    const canonical_identity = lexical_mod.DictionaryIdentity.canonicalScalar("full_text_index_v0", "body", .string, "json-scalar-v1", "kind-qualified");
    {
        var txn = try store.beginWriteTxn();
        errdefer txn.abort();
        try std.testing.expectEqual(
            lexical_mod.RegistryClaim.claimed,
            try lexical_mod.claimRegistryOwnerTxn(alloc, &txn, analyzed_identity, "full_text_index_v0", .fst_postings, "ready"),
        );
        try std.testing.expectEqual(
            lexical_mod.RegistryClaim.owned_by_other,
            try lexical_mod.claimRegistryOwnerTxn(alloc, &txn, analyzed_identity, "algebraic", .lexicon_postings_rows, "ready"),
        );
        try std.testing.expectEqual(
            lexical_mod.RegistryClaim.owned_by_other,
            try lexical_mod.claimRegistryOwnerTxn(alloc, &txn, analyzed_identity, "full_text_index_v0", .lexicon_postings_rows, "ready"),
        );
        try std.testing.expectEqual(
            lexical_mod.RegistryClaim.claimed,
            try lexical_mod.claimRegistryOwnerTxn(alloc, &txn, canonical_identity, "algebraic", .lexicon_postings_rows, "ready"),
        );
        try txn.commit();
    }

    const analyzed_registry_key = try analyzed_identity.registryKeyAlloc(alloc);
    defer alloc.free(analyzed_registry_key);
    const canonical_registry_key = try canonical_identity.registryKeyAlloc(alloc);
    defer alloc.free(canonical_registry_key);
    var txn = try store.beginReadTxn();
    defer txn.abort();

    const analyzed_payload = try txn.get(analyzed_registry_key);
    var analyzed_entry = try lexical_mod.RegistryEntry.decodeAlloc(alloc, analyzed_payload);
    defer analyzed_entry.deinit(alloc);
    try std.testing.expectEqualStrings("full_text_index_v0", analyzed_entry.owner);
    try std.testing.expectEqual(lexical_mod.DictionaryLayoutKind.fst_postings, analyzed_entry.layout);

    const canonical_payload = try txn.get(canonical_registry_key);
    var canonical_entry = try lexical_mod.RegistryEntry.decodeAlloc(alloc, canonical_payload);
    defer canonical_entry.deinit(alloc);
    try std.testing.expectEqualStrings("algebraic", canonical_entry.owner);
    try std.testing.expectEqual(lexical_mod.DictionaryLayoutKind.lexicon_postings_rows, canonical_entry.layout);
}

