    ;
    var idx = try Index.open(alloc, "alg_expr_cache", cfg);
    defer idx.close();

    const axes = try token.canonicalTupleAlloc(alloc, &.{ "customer", "alice" });
    defer alloc.free(axes);
    const expr = ir.TensorExpr{
        .fragment = .reduce,
        .input_dims = &.{ .doc, .scalar },
        .output_dims = &.{.bucket},
        .layout = .materialized_expr,
        .law_id = .sum,
    };

    try idx.applyMaterializedExpressionDelta(&store, expr, axes, "2026-05-15", .sum, "2.5");
    try idx.applyMaterializedExpressionDelta(&store, expr, axes, "2026-05-15", .sum, "1.5");
    const raw = (try idx.materializedExpressionRawValueAlloc(&store, expr, axes, "2026-05-15", .sum)).?;
    defer alloc.free(raw);
    try std.testing.expectEqualStrings("4", raw);

    var count_expr = expr;
    count_expr.law_id = .count;
    try std.testing.expect((try idx.materializedExpressionRawValueAlloc(&store, count_expr, axes, "2026-05-15", .count)) == null);
    try std.testing.expectError(error.InvalidAlgebraicTensorExpr, idx.applyMaterializedExpressionDelta(&store, expr, axes, null, .count, "1"));
}

test "algebraic index rebuilds materialized expression cache from aggregate materialization" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "time_fields": [{"name":"created","path":"created_at","type":"timestamp"}],
        \\  "materializations": [
        \\    {"name":"sum_by_customer","op":"sum","group_by":["customer"],"measure":"amount"},
        \\    {"name":"orders_by_day","op":"count","time":"created","bucket":"day"}
        \\  ]
        \\}
    ;
    var idx = try Index.open(alloc, "alg_expr_rebuild", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"created_at\":\"2026-05-01T10:00:00Z\",\"amount\":10}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"created_at\":\"2026-05-01T11:00:00Z\",\"amount\":5}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"customer\":\"bob\",\"created_at\":\"2026-05-02T09:00:00Z\",\"amount\":4}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });

    const expr = ir.TensorExpr{
        .fragment = .reduce,
        .input_dims = &.{ .doc, .scalar },
        .output_dims = &.{.bucket},
        .layout = .materialized_expr,
        .law_id = .sum,
    };
    try std.testing.expectEqual(@as(usize, 2), try idx.rebuildMaterializedExpressionFromMaterialization(&store, expr, "sum_by_customer"));

    const alice_token = try idx.constraintTokenAlloc(alloc, "customer", "alice");
    defer alloc.free(alice_token);
    const alice_axes = try token.canonicalTupleAlloc(alloc, &.{alice_token});
    defer alloc.free(alice_axes);
    const alice_raw = (try idx.materializedExpressionRawValueAlloc(&store, expr, alice_axes, null, .sum)).?;
    defer alloc.free(alice_raw);
    try std.testing.expectEqualStrings("15", alice_raw);

    const day_expr = ir.TensorExpr{
        .fragment = .reduce,
        .input_dims = &.{ .doc, .time },
        .output_dims = &.{ .time, .bucket, .scalar },
        .layout = .materialized_expr,
        .law_id = .count,
    };
    const empty_axes = try token.canonicalTupleAlloc(alloc, &.{});
    defer alloc.free(empty_axes);
    const may_first = try cylinder.bucketStartAlloc(alloc, .day, "2026-05-01T10:00:00Z");
    defer alloc.free(may_first);
    try std.testing.expectEqual(@as(usize, 2), try idx.rebuildMaterializedExpressionFromMaterialization(&store, day_expr, "orders_by_day"));
    const day_raw = (try idx.materializedExpressionRawValueAlloc(&store, day_expr, empty_axes, may_first, .count)).?;
    defer alloc.free(day_raw);
    try std.testing.expectEqualStrings("2", day_raw);
    const day_entries = try idx.scanMaterializedExpressionEntries(&store, day_expr, .count);
    defer {
        for (day_entries) |*entry| entry.deinit(alloc);
        if (day_entries.len > 0) alloc.free(day_entries);
    }
    try std.testing.expectEqual(@as(usize, 2), day_entries.len);
    var saw_may_first = false;
    for (day_entries) |entry| {
        const bucket_component = try token.componentAt(entry.group_key, 0);
        if (std.mem.eql(u8, bucket_component.payload, may_first)) saw_may_first = true;
    }
    try std.testing.expect(saw_may_first);
    const expression_partials = try idx.scanDistributedPartialsForExpressions(&store, &.{day_expr});
    defer distributed_mod.freePartials(alloc, expression_partials);
    try std.testing.expectEqual(@as(usize, 2), expression_partials.len);
    var saw_expression_partial = false;
    for (expression_partials) |partial| {
        try std.testing.expectEqual(law_mod.Id.count, partial.law_id);
        const bucket_component = try token.componentAt(partial.canonical_axis, 0);
        if (std.mem.eql(u8, bucket_component.payload, may_first)) {
            try std.testing.expectEqualStrings("2", partial.value);
            saw_expression_partial = true;
        }
    }
    try std.testing.expect(saw_expression_partial);

    const incremental = [_]derived_types.DerivedDocument{
        .{ .key = "o4", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"created_at\":\"2026-05-01T12:00:00Z\",\"amount\":2}" },
    };
    try idx.applyBatch(&store, .{ .documents = incremental[0..] });
    try std.testing.expectEqual(@as(usize, 2), try idx.rebuildMaterializedExpressionFromMaterialization(&store, expr, "sum_by_customer"));
    const rebuilt_alice_raw = (try idx.materializedExpressionRawValueAlloc(&store, expr, alice_axes, null, .sum)).?;
    defer alloc.free(rebuilt_alice_raw);
    try std.testing.expectEqualStrings("17", rebuilt_alice_raw);
    try std.testing.expectEqual(@as(usize, 2), try idx.rebuildMaterializedExpressionFromMaterialization(&store, day_expr, "orders_by_day"));
    const rebuilt_day_raw = (try idx.materializedExpressionRawValueAlloc(&store, day_expr, empty_axes, may_first, .count)).?;
    defer alloc.free(rebuilt_day_raw);
    try std.testing.expectEqualStrings("3", rebuilt_day_raw);

    var count_expr = expr;
    count_expr.law_id = .count;
    try std.testing.expectError(error.InvalidAlgebraicTensorExpr, idx.rebuildMaterializedExpressionFromMaterialization(&store, count_expr, "sum_by_customer"));
}

test "algebraic bulk ingest existing doc falls back through docfact compensation" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "materializations": [
        \\    {"name":"count_by_customer","op":"count","group_by":["customer"]},
        \\    {"name":"sum_by_customer","op":"sum","group_by":["customer"],"measure":"amount"}
        \\  ]
        \\}
    ;
    var idx = try Index.open(alloc, "alg_bulk_docfact_guard", cfg);
    defer idx.close();

    const first = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"amount\":10}" },
    };
    try idx.applyBatchWithOptions(&store, .{ .documents = first[0..] }, .{ .batch_options = .{ .mode = .bulk_ingest } });

    const first_customer_token = try idx.constraintTokenAlloc(alloc, "customer", "alice");
    defer alloc.free(first_customer_token);
    const first_group = try token.canonicalTupleAlloc(alloc, &.{first_customer_token});
    defer alloc.free(first_group);
    var first_sum_expr_raw = (try idx.materializedExpressionRawValueForMaterializationAlloc(&store, "sum_by_customer", first_group, null)).?;
    defer first_sum_expr_raw.deinit(idx.alloc);
    try std.testing.expectEqualStrings("10", first_sum_expr_raw.raw.?);

    const second = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"amount\":20}" },
    };
    try idx.applyBatchWithOptions(&store, .{ .documents = second[0..] }, .{ .batch_options = .{ .mode = .bulk_ingest } });

    const customer_token = try idx.constraintTokenAlloc(alloc, "customer", "alice");
    defer alloc.free(customer_token);
    const group = try token.canonicalTupleAlloc(alloc, &.{customer_token});
    defer alloc.free(group);
    try std.testing.expectEqual(@as(i64, 1), try idx.countValue(&store, "count_by_customer", group));
    try std.testing.expectEqual(@as(f64, 20), (try idx.numericValue(&store, "sum_by_customer", group)).?);
    var sum_expr_raw = (try idx.materializedExpressionRawValueForMaterializationAlloc(&store, "sum_by_customer", group, null)).?;
    defer sum_expr_raw.deinit(idx.alloc);
    try std.testing.expectEqualStrings("20", sum_expr_raw.raw.?);
    try std.testing.expectEqual(@as(u64, 2), idx.status().doc_fact_write_count);
    try std.testing.expectEqual(@as(u64, 1), idx.status().doc_fact_delete_count);
}

