    const delete_o2 = [_][]const u8{"o2"};
    try idx.applyBatch(&store, .{ .deleted_keys = delete_o2[0..] });
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.docFactScalarPrefixAlloc(.measure, "amount", amount_lookup_token)));
    try std.testing.expectEqual(@as(u64, 2), try idx.countRowsWithPrefix(&store, try idx.docFactScalarFieldPrefixAlloc(.measure, "amount")));
    try std.testing.expectEqual(@as(u64, 2), try idx.countRowsWithPrefix(&store, try idx.docFactFieldPrefixAlloc(.time, "event_time")));
}

test "algebraic index uses bounded exact min max candidate cache" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "min_max_candidate_cache_size": 2,
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "materializations": [
        \\    {"name":"count_by_customer","op":"count","group_by":["customer"]},
        \\    {"name":"max_by_customer","op":"max","group_by":["customer"],"measure":"amount"}
        \\  ]
        \\}
    ;
    var idx = try Index.open(alloc, "alg_minmax_cache", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"amount\":10}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"amount\":20}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"amount\":30}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });

    const customer_token = try idx.constraintTokenAlloc(alloc, "customer", "alice");
    defer alloc.free(customer_token);
    const group = try token.canonicalTupleAlloc(alloc, &.{customer_token});
    defer alloc.free(group);
    try std.testing.expectEqual(@as(f64, 30), (try idx.numericValue(&store, "max_by_customer", group)).?);

    const delete_current_cached = [_][]const u8{"o3"};
    try idx.applyBatch(&store, .{ .deleted_keys = delete_current_cached[0..] });
    try std.testing.expectEqual(@as(f64, 20), (try idx.numericValue(&store, "max_by_customer", group)).?);
    var status_value = idx.status();
    try std.testing.expectEqual(@as(u64, 1), status_value.minmax_cache_hits);
    try std.testing.expectEqual(@as(u64, 0), status_value.minmax_support_scans);

    const delete_current_uncached = [_][]const u8{"o2"};
    try idx.applyBatch(&store, .{ .deleted_keys = delete_current_uncached[0..] });
    try std.testing.expectEqual(@as(f64, 10), (try idx.numericValue(&store, "max_by_customer", group)).?);
    status_value = idx.status();
    try std.testing.expectEqual(@as(u64, 1), status_value.minmax_cache_misses);
    try std.testing.expectEqual(@as(u64, 1), status_value.minmax_support_scans);
}

test "algebraic index fails fast on symbol id collision" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "materializations": [{"name":"count_by_customer","op":"count","group_by":["customer"]}]
        \\}
    ;
    var idx = try Index.open(alloc, "alg_collision", cfg);
    defer idx.close();

    const customer_token = try idx.constraintTokenAlloc(alloc, "customer", "alice");
    defer alloc.free(customer_token);
    const group = try token.canonicalTupleAlloc(alloc, &.{customer_token});
    defer alloc.free(group);
    const group_id = try symbol.idAlloc(alloc, group);
    defer alloc.free(group_id);
    const sym_key = try idx.symbolKeyAlloc(group_id);
    defer alloc.free(sym_key);

    var txn = try store.beginWriteTxn();
    errdefer txn.abort();
    try txn.put(sym_key, "different canonical bytes");
    try txn.commit();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\"}" },
    };
    try std.testing.expectError(error.AlgebraicSymbolCollision, idx.applyBatch(&store, .{ .documents = docs[0..] }));
    try std.testing.expect(idx.hasErrors());
    const status = idx.status();
    try std.testing.expectEqual(@as(u64, 1), status.parse_error_count);
    try std.testing.expectEqualStrings("o1", status.last_error_doc_key.?);
    try std.testing.expectEqualStrings("symbol_collision", status.last_error_reason.?);
}

test "algebraic index maintains composite equi join aggregate" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "mixed",
        \\  "group_fields": [
        \\    {"name":"kind","path":"kind","type":"string"},
        \\    {"name":"tenant","path":"tenant_id","type":"string"},
        \\    {"name":"customer_id","path":"customer_id","type":"string"},
        \\    {"name":"id","path":"id","type":"string"},
        \\    {"name":"region","path":"region","type":"string"}
        \\  ],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "joins": [
        \\    {"name":"orders_customers","left_fields":["tenant","customer_id"],"right_fields":["tenant","id"],"left_type_field":"kind","left_type_value":"order","right_type_field":"kind","right_type_value":"customer"}
        \\  ],
        \\  "materializations": [
        \\    {"name":"sum_by_region","op":"sum","join":"orders_customers","group_by":["region"],"measure":"amount","group_side":"right","measure_side":"left"}
        \\  ]
        \\}
    ;
    var idx = try Index.open(alloc, "alg_join", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "cust1", .action = .upsert, .cleaned_value = "{\"kind\":\"customer\",\"tenant_id\":\"t1\",\"id\":\"c1\",\"region\":\"west\"}" },
        .{ .key = "order1", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"tenant_id\":\"t1\",\"customer_id\":\"c1\",\"amount\":25}" },
        .{ .key = "order2", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"tenant_id\":\"t1\",\"customer_id\":\"c1\",\"amount\":5}" },
        .{ .key = "both_shape", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"tenant_id\":\"t1\",\"customer_id\":\"c1\",\"id\":\"c1\",\"region\":\"east\",\"amount\":100}" },
    };
    const doc_keys = [_][]const u8{ "cust1", "order1", "order2", "both_shape" };
    var identity_writes = std.ArrayListUnmanaged(docstore_mod.KVPair).empty;
    defer {
        for (identity_writes.items) |item| {
            alloc.free(@constCast(item.key));
            alloc.free(@constCast(item.value));
        }
        identity_writes.deinit(alloc);
    }
    try doc_identity.appendBatchIdentityMetadataAlloc(
        alloc,
        &store,
        0,
        0,
        1,
        &identity_writes,
        doc_keys[0..],
        &.{},
    );
    try store.putBatchWithReplay(null, identity_writes.items, &.{}, null);

    try idx.applyBatch(&store, .{ .documents = docs[0..] });
    const region_token = try idx.constraintTokenAlloc(alloc, "region", "west");
    defer alloc.free(region_token);
    const group = try token.canonicalTupleAlloc(alloc, &.{region_token});
    defer alloc.free(group);
    try std.testing.expectEqual(@as(f64, 130), (try idx.numericValue(&store, "sum_by_region", group)).?);
    var expr_raw = (try idx.materializedExpressionRawValueForMaterializationAlloc(&store, "sum_by_region", group, null)).?;
    defer expr_raw.deinit(idx.alloc);
    try std.testing.expectEqualStrings("130", expr_raw.raw.?);

    const mat_idx = idx.materializationIndex("sum_by_region").?;
    const expr = Index.materializationExpression(idx.config().materializations[mat_idx], .sum);
    try std.testing.expectEqual(@as(usize, 1), try idx.rebuildMaterializedExpressionFromMaterialization(&store, expr, "sum_by_region"));
    try std.testing.expectEqual(@as(f64, 130), (try idx.numericValue(&store, "sum_by_region", group)).?);
    try std.testing.expectEqual(
        try idx.countRowsWithPrefix(&store, try idx.joinSideFactPrefixAlloc(idx.config().joins[0], .left)),
        try idx.countRowsWithPrefix(&store, try idx.joinSideFactOrdinalPrefixAlloc(idx.config().joins[0], .left)),
    );
    try std.testing.expectEqual(
        try idx.countRowsWithPrefix(&store, try idx.joinSideFactPrefixAlloc(idx.config().joins[0], .right)),
        try idx.countRowsWithPrefix(&store, try idx.joinSideFactOrdinalPrefixAlloc(idx.config().joins[0], .right)),
    );

    var ref_read_txn = try store.beginReadTxn();
    var ref_cursor = try ref_read_txn.openCursor();
    const docjf_prefix = try idx.keyAlloc(&.{ "docjf", "cust1", "orders_customers", "r" });
    defer alloc.free(docjf_prefix);
    const docjf_before = try ref_cursor.seekAtOrAfter(docjf_prefix);
    try std.testing.expect(docjf_before != null and std.mem.startsWith(u8, docjf_before.?.key, docjf_prefix));
    const cust1_ordinal = (try doc_identity.lookupOrdinalTxn(alloc, &ref_read_txn, "cust1")) orelse return error.TestUnexpectedResult;
    const docjf_ord_prefix = try idx.docJoinFactOrdinalRefPrefixAlloc(cust1_ordinal, idx.config().joins[0], .right);
    defer alloc.free(docjf_ord_prefix);
    const docjf_ord_before = try ref_cursor.seekAtOrAfter(docjf_ord_prefix);
    try std.testing.expect(docjf_ord_before != null and std.mem.startsWith(u8, docjf_ord_before.?.key, docjf_ord_prefix));
    ref_cursor.close();
    ref_read_txn.abort();

    const deletes = [_][]const u8{"cust1"};
    try idx.applyBatch(&store, .{ .deleted_keys = deletes[0..] });
    try std.testing.expect((try idx.numericValue(&store, "sum_by_region", group)) == null);
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.joinSideFactPrefixAlloc(idx.config().joins[0], .right)));
    try std.testing.expectEqual(@as(u64, 0), try idx.countRowsWithPrefix(&store, try idx.joinSideFactOrdinalPrefixAlloc(idx.config().joins[0], .right)));

    ref_read_txn = try store.beginReadTxn();
    ref_cursor = try ref_read_txn.openCursor();
    const docjf_after = try ref_cursor.seekAtOrAfter(docjf_prefix);
    try std.testing.expect(docjf_after == null or !std.mem.startsWith(u8, docjf_after.?.key, docjf_prefix));
    const docjf_ord_after = try ref_cursor.seekAtOrAfter(docjf_ord_prefix);
    try std.testing.expect(docjf_ord_after == null or !std.mem.startsWith(u8, docjf_ord_after.?.key, docjf_ord_prefix));
    ref_cursor.close();
    ref_read_txn.abort();
}

test "algebraic index executes proven docfact bucket fold tensor program" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [{"name":"tenant","path":"tenant","type":"string"}],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_docfact_program", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"tenant\":\"t1\",\"amount\":7,\"meta\":{\"tier\":\"gold\"},\"tags\":[\"new\"]}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"tenant\":\"t1\",\"amount\":20,\"meta\":{\"tier\":\"gold\"}}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"tenant\":\"t1\",\"amount\":25,\"tags\":[\"returning\"]}" },
        .{ .key = "o4", .action = .upsert, .cleaned_value = "{\"tenant\":\"t2\",\"amount\":21,\"meta\":{\"tier\":\"silver\"},\"tags\":[\"new\",\"vip\"]}" },
        .{ .key = "o5", .action = .upsert, .cleaned_value = "{\"tenant\":null,\"amount\":30}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });

    const constraints = [_]ir.Constraint{.{ .field = "tenant", .value = "t1" }};
    const fold = DocFactBucketFoldRequest{
        .kind = .histogram,
        .op = .count,
        .bucket_field = "amount",
        .bucket_role = .measure,
        .histogram_interval = 10,
        .constraints = constraints[0..],
    };
    const metadata = try docFactBucketFoldMetadataAlloc(alloc, fold);
    defer alloc.free(metadata);

    const access_paths = [_]ir.PhysicalAccessPath{ir.docFactAccessPath(idx.name)};
    const steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = &.{ .doc, .field, .scalar },
            .owner = idx.name,
            .layout = .docfact_rows,
        } },
        .{
            .expr = .{
                .fragment = .reduce,
                .input_dims = &.{ .doc, .field, .scalar },
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "amount_histogram",
                .law_id = .count,
                .metadata = metadata,
            },
            .inputs = &.{.{ .step = 0 }},
        },
    };
    const program = ir.TensorProgram{
        .steps = steps[0..],
        .output = .{ .step = 1 },
    };
    const entries = (try idx.scanDocFactBucketFoldEntriesWithTensorProgram(&store, fold, access_paths[0..], program, .{ .step = 1 })) orelse return error.TestUnexpectedResult;
    defer {
        for (entries) |*entry| entry.deinit(alloc);
        alloc.free(entries);
    }
    try std.testing.expectEqual(@as(usize, 2), entries.len);
    var bucket0: ?[]const u8 = null;
    var bucket2: ?[]const u8 = null;
    for (entries) |entry| {
        if (std.mem.eql(u8, entry.group_key, "0")) bucket0 = entry.value;
        if (std.mem.eql(u8, entry.group_key, "2")) bucket2 = entry.value;
    }
    try std.testing.expectEqualStrings("1", bucket0 orelse return error.TestUnexpectedResult);
    try std.testing.expectEqualStrings("2", bucket2 orelse return error.TestUnexpectedResult);

    const partials = (try idx.scanDistributedPartialsForTensorProgram(&store, access_paths[0..], program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, partials);
    try std.testing.expectEqual(@as(usize, 2), partials.len);
    var partial_bucket0: ?[]const u8 = null;
    var partial_bucket2: ?[]const u8 = null;
    for (partials) |partial| {
        try std.testing.expectEqual(law_mod.Id.count, partial.law_id);
        try std.testing.expectEqualStrings("amount_histogram", partial.metric);
        if (std.mem.eql(u8, partial.canonical_axis, "0")) partial_bucket0 = partial.value;
        if (std.mem.eql(u8, partial.canonical_axis, "2")) partial_bucket2 = partial.value;
    }
    try std.testing.expectEqualStrings("1", partial_bucket0 orelse return error.TestUnexpectedResult);
    try std.testing.expectEqualStrings("2", partial_bucket2 orelse return error.TestUnexpectedResult);

    const envelopes = (try idx.scanDistributedPartialEnvelopesForTensorProgram(&store, access_paths[0..], program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartialEnvelopes(alloc, envelopes);
    try std.testing.expectEqual(@as(usize, 2), envelopes.len);
    const program_id = try ir.tensorProgramIdAlloc(alloc, program);
    defer alloc.free(program_id);
    const expression_id = try ir.tensorExprIdAlloc(alloc, steps[1].expr);
    defer alloc.free(expression_id);
    const expected_protocol = distributed_mod.PartialProtocol{
        .owner = idx.name,
        .layout = .docfact_rows,
        .fragment = .reduce,
        .output_dims = &distributed_bucket_scalar_output_dims,
        .law_id = .count,
        .metric = "amount_histogram",
        .program_id = program_id,
        .expression_id = expression_id,
    };
    var envelope_merge = try distributed_mod.mergeValidatedPartialsAlloc(alloc, expected_protocol, envelopes);
    defer envelope_merge.deinit(alloc);
    try std.testing.expectEqual(@as(usize, 2), envelope_merge.rows.len);
    var envelope_bucket0: ?[]const u8 = null;
    var envelope_bucket2: ?[]const u8 = null;
    for (envelope_merge.rows) |row| {
        try std.testing.expectEqual(law_mod.Id.count, row.law_id);
        try std.testing.expectEqualStrings("amount_histogram", row.metric);
        if (std.mem.eql(u8, row.canonical_axis, "0")) envelope_bucket0 = row.value;
        if (std.mem.eql(u8, row.canonical_axis, "2")) envelope_bucket2 = row.value;
    }
    try std.testing.expectEqualStrings("1", envelope_bucket0 orelse return error.TestUnexpectedResult);
    try std.testing.expectEqualStrings("2", envelope_bucket2 orelse return error.TestUnexpectedResult);

    var status_value = idx.status();
    try std.testing.expectEqual(@as(u64, 2), status_value.distributed_partial_validation_proven_count);
    try std.testing.expectEqual(@as(u64, 0), status_value.distributed_partial_validation_rejected_count);
    try std.testing.expectEqual(@as(u64, 4), status_value.distributed_partial_rows_exported_count);

    const rejected_access_paths = [_]ir.PhysicalAccessPath{ir.docFactAccessPath("other_index")};
    try std.testing.expect((try idx.scanDistributedPartialsForTensorProgram(&store, rejected_access_paths[0..], program)) == null);
    status_value = idx.status();
    try std.testing.expectEqual(@as(u64, 2), status_value.distributed_partial_validation_proven_count);
    try std.testing.expectEqual(@as(u64, 1), status_value.distributed_partial_validation_rejected_count);
    try std.testing.expectEqual(@as(u64, 4), status_value.distributed_partial_rows_exported_count);

    var tampered_steps = steps;
    tampered_steps[1].expr.metadata = "wrong";
    const tampered_program = ir.TensorProgram{
        .steps = tampered_steps[0..],
        .output = .{ .step = 1 },
    };
    try std.testing.expect((try idx.scanDocFactBucketFoldEntriesWithTensorProgram(&store, fold, access_paths[0..], tampered_program, .{ .step = 1 })) == null);
}

test "algebraic index executes cardinality partial tensor programs" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [
        \\    {"name":"tenant","path":"tenant","type":"string"},
        \\    {"name":"product","path":"product","type":"string"}
        \\  ],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_cardinality_program", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"tenant\":\"t1\",\"product\":\"p1\",\"amount\":7,\"meta\":{\"tier\":\"gold\"}}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"tenant\":\"t1\",\"product\":\"p2\",\"amount\":20,\"meta\":{\"tier\":\"gold\"}}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"tenant\":\"t1\",\"product\":\"p1\",\"amount\":25,\"meta\":{\"tier\":\"silver\"}}" },
        .{ .key = "o4", .action = .upsert, .cleaned_value = "{\"tenant\":\"t2\",\"product\":\"p3\",\"amount\":21,\"meta\":{\"tier\":\"gold\"}}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });

    const constraints = [_]ir.Constraint{.{ .field = "tenant", .value = "t1" }};
    const doc_request = CardinalityPartialsRequest{
        .aggregation_name = "product_cardinality",
        .field_or_path = "product",
        .constraints = constraints[0..],
    };
    const doc_metadata = try cardinalityPartialsMetadataAlloc(alloc, doc_request);
    defer alloc.free(doc_metadata);
    const doc_access_paths = [_]ir.PhysicalAccessPath{ir.docFactAccessPath(idx.name)};
    const doc_steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = &.{ .doc, .field, .scalar },
            .owner = idx.name,
            .layout = .docfact_rows,
        } },
        .{
            .expr = .{
                .fragment = .reduce,
                .input_dims = &.{ .doc, .field, .scalar },
                .output_dims = &distributed_scalar_output_dims,
                .semantic_id = "product_cardinality",
                .law_id = .count,
                .metadata = doc_metadata,
            },
            .inputs = &.{.{ .step = 0 }},
        },
    };
    const doc_program = ir.TensorProgram{
        .steps = doc_steps[0..],
        .output = .{ .step = 1 },
    };
    const doc_partials = (try idx.scanDistributedPartialsForTensorProgram(&store, doc_access_paths[0..], doc_program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, doc_partials);
    try std.testing.expectEqual(@as(usize, 2), doc_partials.len);

    const empty_axis = try token.canonicalTupleAlloc(alloc, &.{});
    defer alloc.free(empty_axis);
    const p1_token = try idx.constraintTokenAlloc(alloc, "product", "p1");
    defer alloc.free(p1_token);
    const p2_token = try idx.constraintTokenAlloc(alloc, "product", "p2");
    defer alloc.free(p2_token);
    const p1_metric = try token.canonicalTupleAlloc(alloc, &.{ "cardinality:v1", "product_cardinality", p1_token });
    defer alloc.free(p1_metric);
    const p2_metric = try token.canonicalTupleAlloc(alloc, &.{ "cardinality:v1", "product_cardinality", p2_token });
    defer alloc.free(p2_metric);
    var saw_p1 = false;
    var saw_p2 = false;
    for (doc_partials) |partial| {
        try std.testing.expectEqualStrings(empty_axis, partial.canonical_axis);
        try std.testing.expectEqual(law_mod.Id.count, partial.law_id);
        try std.testing.expectEqualStrings("1", partial.value);
        if (std.mem.eql(u8, partial.metric, p1_metric)) saw_p1 = true;
        if (std.mem.eql(u8, partial.metric, p2_metric)) saw_p2 = true;
    }
    try std.testing.expect(saw_p1);
    try std.testing.expect(saw_p2);

    const path_request = CardinalityPartialsRequest{
        .aggregation_name = "tier_cardinality",
        .field_or_path = "/meta/tier",
        .constraints = constraints[0..],
    };
    const path_metadata = try cardinalityPartialsMetadataAlloc(alloc, path_request);
    defer alloc.free(path_metadata);
    const path_access_paths = [_]ir.PhysicalAccessPath{ir.pathFactAccessPath(idx.name)};
    const path_steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = &.{ .doc, .path, .kind, .scalar },
            .owner = idx.name,
            .layout = .pathfact_rows,
        } },
        .{
            .expr = .{
                .fragment = .reduce,
                .input_dims = &.{ .doc, .path, .kind, .scalar },
                .output_dims = &distributed_scalar_output_dims,
                .semantic_id = "tier_cardinality",
                .law_id = .count,
                .metadata = path_metadata,
            },
            .inputs = &.{.{ .step = 0 }},
        },
    };
    const path_program = ir.TensorProgram{
        .steps = path_steps[0..],
        .output = .{ .step = 1 },
    };
    const path_partials = (try idx.scanDistributedPartialsForTensorProgram(&store, path_access_paths[0..], path_program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, path_partials);
    try std.testing.expectEqual(@as(usize, 2), path_partials.len);

    const gold_value = try token.canonicalTupleAlloc(alloc, &.{ "string", "gold" });
    defer alloc.free(gold_value);
    const silver_value = try token.canonicalTupleAlloc(alloc, &.{ "string", "silver" });
    defer alloc.free(silver_value);
    const gold_metric = try token.canonicalTupleAlloc(alloc, &.{ "cardinality:v1", "tier_cardinality", gold_value });
    defer alloc.free(gold_metric);
    const silver_metric = try token.canonicalTupleAlloc(alloc, &.{ "cardinality:v1", "tier_cardinality", silver_value });
    defer alloc.free(silver_metric);
    var saw_gold = false;
    var saw_silver = false;
    for (path_partials) |partial| {
        try std.testing.expectEqualStrings(empty_axis, partial.canonical_axis);
        try std.testing.expectEqual(law_mod.Id.count, partial.law_id);
        try std.testing.expectEqualStrings("1", partial.value);
        if (std.mem.eql(u8, partial.metric, gold_metric)) saw_gold = true;
        if (std.mem.eql(u8, partial.metric, silver_metric)) saw_silver = true;
    }
    try std.testing.expect(saw_gold);
    try std.testing.expect(saw_silver);

    const terms_children = [_]CardinalityChildRequest{.{ .name = "product_cardinality", .field = "product" }};
    const terms_request = TermsCardinalityPartialsRequest{
        .aggregation_name = "by_tier",
        .bucket_field_or_path = "/meta/tier",
        .children = terms_children[0..],
        .constraints = constraints[0..],
    };
    const terms_metadata = try termsCardinalityPartialsMetadataAlloc(alloc, terms_request);
    defer alloc.free(terms_metadata);
    const terms_access_paths = [_]ir.PhysicalAccessPath{ ir.pathFactAccessPath(idx.name), ir.docFactAccessPath(idx.name) };
    const terms_steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = &.{ .doc, .path, .kind, .scalar },
            .owner = idx.name,
            .layout = .pathfact_rows,
        } },
        .{
            .expr = .{
                .fragment = .reduce,
                .input_dims = &.{ .doc, .path, .kind, .scalar },
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "by_tier",
                .law_id = .count,
                .metadata = terms_metadata,
            },
            .inputs = &.{.{ .step = 0 }},
        },
    };
    const terms_program = ir.TensorProgram{
        .steps = terms_steps[0..],
        .output = .{ .step = 1 },
    };
    const terms_partials = (try idx.scanDistributedPartialsForTensorProgram(&store, terms_access_paths[0..], terms_program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, terms_partials);
    try std.testing.expectEqual(@as(usize, 5), terms_partials.len);
    var gold_count: ?[]const u8 = null;
    var silver_count: ?[]const u8 = null;
    var gold_products: usize = 0;
    var silver_products: usize = 0;
    for (terms_partials) |partial| {
        if (std.mem.eql(u8, partial.canonical_axis, gold_value)) {
            if (std.mem.eql(u8, partial.metric, "by_tier")) gold_count = partial.value else gold_products += 1;
        }
        if (std.mem.eql(u8, partial.canonical_axis, silver_value)) {
            if (std.mem.eql(u8, partial.metric, "by_tier")) silver_count = partial.value else silver_products += 1;
        }
    }
    try std.testing.expectEqualStrings("2", gold_count orelse return error.TestUnexpectedResult);
    try std.testing.expectEqualStrings("1", silver_count orelse return error.TestUnexpectedResult);
    try std.testing.expectEqual(@as(usize, 2), gold_products);
    try std.testing.expectEqual(@as(usize, 1), silver_products);

    const range_requests = [_]CardinalityRangeRequest{
        .{ .name = "low", .start = "0", .end = "20" },
        .{ .name = "high", .start = "20", .end = "30" },
    };
    const range_request = RangeCardinalityPartialsRequest{
        .aggregation_name = "amount_ranges",
        .field_or_path = "amount",
        .kind = .numeric,
        .ranges = range_requests[0..],
        .children = terms_children[0..],
        .constraints = constraints[0..],
    };
    const range_metadata = try rangeCardinalityPartialsMetadataAlloc(alloc, range_request);
    defer alloc.free(range_metadata);
    const range_access_paths = [_]ir.PhysicalAccessPath{ir.docFactAccessPath(idx.name)};
    const range_steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = &.{ .doc, .field, .scalar },
            .owner = idx.name,
            .layout = .docfact_rows,
        } },
        .{
            .expr = .{
                .fragment = .reduce,
                .input_dims = &.{ .doc, .field, .scalar },
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "amount_ranges",
                .law_id = .count,
                .metadata = range_metadata,
            },
            .inputs = &.{.{ .step = 0 }},
        },
    };
    const range_program = ir.TensorProgram{
        .steps = range_steps[0..],
        .output = .{ .step = 1 },
    };
    const range_partials = (try idx.scanDistributedPartialsForTensorProgram(&store, range_access_paths[0..], range_program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, range_partials);
    try std.testing.expectEqual(@as(usize, 5), range_partials.len);

    const low_inner_axis = try token.canonicalTupleAlloc(alloc, &.{ "0", "20" });
    defer alloc.free(low_inner_axis);
    const high_inner_axis = try token.canonicalTupleAlloc(alloc, &.{ "20", "30" });
    defer alloc.free(high_inner_axis);
    const low_axis = try token.canonicalTupleAlloc(alloc, &.{low_inner_axis});
    defer alloc.free(low_axis);
    const high_axis = try token.canonicalTupleAlloc(alloc, &.{high_inner_axis});
    defer alloc.free(high_axis);
    var low_count: ?[]const u8 = null;
    var high_count: ?[]const u8 = null;
    var low_products: usize = 0;
    var high_products: usize = 0;
    for (range_partials) |partial| {
        try std.testing.expectEqual(law_mod.Id.count, partial.law_id);
        if (std.mem.eql(u8, partial.canonical_axis, low_axis)) {
            if (std.mem.eql(u8, partial.metric, "amount_ranges")) low_count = partial.value else low_products += 1;
        }
        if (std.mem.eql(u8, partial.canonical_axis, high_axis)) {
            if (std.mem.eql(u8, partial.metric, "amount_ranges")) high_count = partial.value else high_products += 1;
        }
    }
    try std.testing.expectEqualStrings("1", low_count orelse return error.TestUnexpectedResult);
    try std.testing.expectEqualStrings("2", high_count orelse return error.TestUnexpectedResult);
    try std.testing.expectEqual(@as(usize, 1), low_products);
    try std.testing.expectEqual(@as(usize, 2), high_products);

    const histogram_request = HistogramCardinalityPartialsRequest{
        .aggregation_name = "amount_histogram",
        .field_or_path = "amount",
        .kind = .numeric,
        .numeric_interval = 10,
        .children = terms_children[0..],
        .constraints = constraints[0..],
    };
    const histogram_metadata = try histogramCardinalityPartialsMetadataAlloc(alloc, histogram_request);
    defer alloc.free(histogram_metadata);
    const histogram_steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = &.{ .doc, .field, .scalar },
            .owner = idx.name,
            .layout = .docfact_rows,
        } },
        .{
            .expr = .{
                .fragment = .reduce,
                .input_dims = &.{ .doc, .field, .scalar },
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "amount_histogram",
                .law_id = .count,
                .metadata = histogram_metadata,
            },
            .inputs = &.{.{ .step = 0 }},
        },
    };
    const histogram_program = ir.TensorProgram{
        .steps = histogram_steps[0..],
        .output = .{ .step = 1 },
    };
    const histogram_partials = (try idx.scanDistributedPartialsForTensorProgram(&store, range_access_paths[0..], histogram_program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, histogram_partials);
    try std.testing.expectEqual(@as(usize, 5), histogram_partials.len);

    const bucket0_axis = try token.canonicalTupleAlloc(alloc, &.{"0"});
    defer alloc.free(bucket0_axis);
    const bucket2_axis = try token.canonicalTupleAlloc(alloc, &.{"2"});
    defer alloc.free(bucket2_axis);
    var bucket0_count: ?[]const u8 = null;
    var bucket2_count: ?[]const u8 = null;
    var bucket0_products: usize = 0;
    var bucket2_products: usize = 0;
    for (histogram_partials) |partial| {
        try std.testing.expectEqual(law_mod.Id.count, partial.law_id);
        if (std.mem.eql(u8, partial.canonical_axis, bucket0_axis)) {
            if (std.mem.eql(u8, partial.metric, "amount_histogram")) bucket0_count = partial.value else bucket0_products += 1;
        }
        if (std.mem.eql(u8, partial.canonical_axis, bucket2_axis)) {
            if (std.mem.eql(u8, partial.metric, "amount_histogram")) bucket2_count = partial.value else bucket2_products += 1;
        }
    }
    try std.testing.expectEqualStrings("1", bucket0_count orelse return error.TestUnexpectedResult);
    try std.testing.expectEqualStrings("2", bucket2_count orelse return error.TestUnexpectedResult);
    try std.testing.expectEqual(@as(usize, 1), bucket0_products);
    try std.testing.expectEqual(@as(usize, 2), bucket2_products);

    try std.testing.expect((try idx.scanDistributedPartialsForTensorProgram(&store, doc_access_paths[0..], path_program)) == null);
}

test "algebraic index can execute pathfact bucket fold tensor program" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    var idx = try Index.open(alloc, "alg_pathfact_program",
        \\{"version":1,"table":"docs","materializations":[]}
    );
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"tenant\":\"t1\",\"amount\":7,\"meta\":{\"tier\":\"gold\"},\"tags\":[\"new\"]}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"tenant\":\"t1\",\"amount\":20,\"meta\":{\"tier\":\"gold\"}}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"tenant\":\"t1\",\"amount\":25,\"tags\":[\"returning\"]}" },
        .{ .key = "o4", .action = .upsert, .cleaned_value = "{\"tenant\":\"t2\",\"amount\":21,\"meta\":{\"tier\":\"silver\"},\"tags\":[\"new\",\"vip\"]}" },
        .{ .key = "o5", .action = .upsert, .cleaned_value = "{\"tenant\":null,\"amount\":30}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });

    {
        var read_txn = try store.beginReadTxn();
        defer read_txn.abort();
        const object_doc_path_key = try idx.pathFactKey("o1");
        defer alloc.free(object_doc_path_key);
        var object_projection = try pathfact_mod.decodeProjectionAlloc(alloc, try read_txn.get(object_doc_path_key));
        defer object_projection.deinit(alloc);
        try expectProjectionFact(object_projection, "/meta", .object, "");
        try expectProjectionFact(object_projection, "/tags", .array, "");

        const null_doc_path_key = try idx.pathFactKey("o5");
        defer alloc.free(null_doc_path_key);
        var projection = try pathfact_mod.decodeProjectionAlloc(alloc, try read_txn.get(null_doc_path_key));
        defer projection.deinit(alloc);
        try expectProjectionFact(projection, "/tenant", .null, "");
    }

    const constraints = [_]ir.Constraint{.{ .field = "/tenant", .value = "t1" }};
    const fold = PathFactBucketFoldRequest{
        .kind = .histogram,
        .op = .sum,
        .bucket_path = "/amount",
        .bucket_kind = .number,
        .histogram_interval = 10,
        .measure_path = "/amount",
        .measure_kind = .number,
        .constraints = constraints[0..],
    };
    const metadata = try pathFactBucketFoldMetadataAlloc(alloc, fold);
    defer alloc.free(metadata);

    const access_paths = [_]ir.PhysicalAccessPath{ir.pathFactAccessPath(idx.name)};
    const steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = &.{ .doc, .path, .kind, .scalar },
            .owner = idx.name,
            .layout = .pathfact_rows,
        } },
        .{
            .expr = .{
                .fragment = .reduce,
                .input_dims = &.{ .doc, .path, .kind, .scalar },
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "amount_sum",
                .law_id = .sum,
                .metadata = metadata,
            },
            .inputs = &.{.{ .step = 0 }},
        },
    };
    const program = ir.TensorProgram{
        .steps = steps[0..],
        .output = .{ .step = 1 },
    };
    const entries = (try idx.scanPathFactBucketFoldEntriesWithTensorProgram(&store, fold, access_paths[0..], program, .{ .step = 1 })) orelse return error.TestUnexpectedResult;
    defer {
        for (entries) |*entry| entry.deinit(alloc);
        alloc.free(entries);
    }
    try std.testing.expectEqual(@as(usize, 2), entries.len);
    var bucket0: ?[]const u8 = null;
    var bucket2: ?[]const u8 = null;
    for (entries) |entry| {
        if (std.mem.eql(u8, entry.group_key, "0")) bucket0 = entry.value;
        if (std.mem.eql(u8, entry.group_key, "2")) bucket2 = entry.value;
    }
    try std.testing.expectEqualStrings("7", bucket0 orelse return error.TestUnexpectedResult);
    try std.testing.expectEqualStrings("45", bucket2 orelse return error.TestUnexpectedResult);

    const partials = (try idx.scanDistributedPartialsForTensorProgram(&store, access_paths[0..], program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, partials);
    try std.testing.expectEqual(@as(usize, 2), partials.len);
    var partial_bucket0: ?[]const u8 = null;
    var partial_bucket2: ?[]const u8 = null;
    for (partials) |partial| {
        try std.testing.expectEqual(law_mod.Id.sum, partial.law_id);
        try std.testing.expectEqualStrings("amount_sum", partial.metric);
        if (std.mem.eql(u8, partial.canonical_axis, "0")) partial_bucket0 = partial.value;
        if (std.mem.eql(u8, partial.canonical_axis, "2")) partial_bucket2 = partial.value;
    }
    try std.testing.expectEqualStrings("7", partial_bucket0 orelse return error.TestUnexpectedResult);
    try std.testing.expectEqualStrings("45", partial_bucket2 orelse return error.TestUnexpectedResult);

    const terms_fold = PathFactBucketFoldRequest{
        .kind = .terms,
        .op = .count,
        .bucket_path = "/tenant",
        .bucket_kind = .string,
    };
    const terms_metadata = try pathFactBucketFoldMetadataAlloc(alloc, terms_fold);
    defer alloc.free(terms_metadata);
    const terms_steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = &.{ .doc, .path, .kind, .scalar },
            .owner = idx.name,
            .layout = .pathfact_rows,
        } },
        .{
            .expr = .{
                .fragment = .reduce,
                .input_dims = &.{ .doc, .path, .kind, .scalar },
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "tenant_terms",
                .law_id = .count,
                .metadata = terms_metadata,
            },
            .inputs = &.{.{ .step = 0 }},
        },
    };
    const terms_program = ir.TensorProgram{
        .steps = terms_steps[0..],
        .output = .{ .step = 1 },
    };
    const terms_partials = (try idx.scanDistributedPartialsForTensorProgram(&store, access_paths[0..], terms_program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, terms_partials);
    const t1_axis = try token.canonicalTupleAlloc(alloc, &.{ "string", "t1" });
    defer alloc.free(t1_axis);
    const t2_axis = try token.canonicalTupleAlloc(alloc, &.{ "string", "t2" });
    defer alloc.free(t2_axis);
    var partial_t1: ?[]const u8 = null;
    var partial_t2: ?[]const u8 = null;
    for (terms_partials) |partial| {
        try std.testing.expectEqual(law_mod.Id.count, partial.law_id);
        try std.testing.expectEqualStrings("tenant_terms", partial.metric);
        if (std.mem.eql(u8, partial.canonical_axis, t1_axis)) partial_t1 = partial.value;
        if (std.mem.eql(u8, partial.canonical_axis, t2_axis)) partial_t2 = partial.value;
    }
    try std.testing.expectEqualStrings("3", partial_t1 orelse return error.TestUnexpectedResult);
    try std.testing.expectEqualStrings("1", partial_t2 orelse return error.TestUnexpectedResult);

    const null_terms_fold = PathFactBucketFoldRequest{
        .kind = .terms,
        .op = .count,
        .bucket_path = "/tenant",
        .bucket_kind = .null,
    };
    const null_terms_metadata = try pathFactBucketFoldMetadataAlloc(alloc, null_terms_fold);
    defer alloc.free(null_terms_metadata);
    const null_terms_steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = &.{ .doc, .path, .kind, .scalar },
            .owner = idx.name,
            .layout = .pathfact_rows,
        } },
        .{
            .expr = .{
                .fragment = .reduce,
                .input_dims = &.{ .doc, .path, .kind, .scalar },
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "tenant_null_terms",
                .law_id = .count,
                .metadata = null_terms_metadata,
            },
            .inputs = &.{.{ .step = 0 }},
        },
    };
    const null_terms_program = ir.TensorProgram{
        .steps = null_terms_steps[0..],
        .output = .{ .step = 1 },
    };
    const null_terms_partials = (try idx.scanDistributedPartialsForTensorProgram(&store, access_paths[0..], null_terms_program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, null_terms_partials);
    const null_axis = try token.canonicalTupleAlloc(alloc, &.{ "null", "" });
    defer alloc.free(null_axis);
    try std.testing.expectEqual(@as(usize, 1), null_terms_partials.len);
    try std.testing.expectEqualStrings(null_axis, null_terms_partials[0].canonical_axis);
    try std.testing.expectEqualStrings("tenant_null_terms", null_terms_partials[0].metric);
    try std.testing.expectEqual(law_mod.Id.count, null_terms_partials[0].law_id);
    try std.testing.expectEqualStrings("1", null_terms_partials[0].value);

    const object_terms_fold = PathFactBucketFoldRequest{
        .kind = .terms,
        .op = .count,
        .bucket_path = "/meta",
        .bucket_kind = .object,
    };
    const object_terms_metadata = try pathFactBucketFoldMetadataAlloc(alloc, object_terms_fold);
    defer alloc.free(object_terms_metadata);
    const object_terms_steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = &.{ .doc, .path, .kind, .scalar },
            .owner = idx.name,
            .layout = .pathfact_rows,
        } },
        .{
            .expr = .{
                .fragment = .reduce,
                .input_dims = &.{ .doc, .path, .kind, .scalar },
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "meta_object_terms",
                .law_id = .count,
                .metadata = object_terms_metadata,
            },
            .inputs = &.{.{ .step = 0 }},
        },
    };
    const object_terms_program = ir.TensorProgram{
        .steps = object_terms_steps[0..],
        .output = .{ .step = 1 },
    };
    const object_terms_partials = (try idx.scanDistributedPartialsForTensorProgram(&store, access_paths[0..], object_terms_program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, object_terms_partials);
    const object_axis = try token.canonicalTupleAlloc(alloc, &.{ "object", "" });
    defer alloc.free(object_axis);
    try std.testing.expectEqual(@as(usize, 1), object_terms_partials.len);
    try std.testing.expectEqualStrings(object_axis, object_terms_partials[0].canonical_axis);
    try std.testing.expectEqualStrings("meta_object_terms", object_terms_partials[0].metric);
    try std.testing.expectEqual(law_mod.Id.count, object_terms_partials[0].law_id);
    try std.testing.expectEqualStrings("3", object_terms_partials[0].value);

    const array_terms_fold = PathFactBucketFoldRequest{
        .kind = .terms,
        .op = .count,
        .bucket_path = "/tags",
        .bucket_kind = .array,
    };
    const array_terms_metadata = try pathFactBucketFoldMetadataAlloc(alloc, array_terms_fold);
    defer alloc.free(array_terms_metadata);
    const array_terms_steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = &.{ .doc, .path, .kind, .scalar },
            .owner = idx.name,
            .layout = .pathfact_rows,
        } },
        .{
            .expr = .{
                .fragment = .reduce,
                .input_dims = &.{ .doc, .path, .kind, .scalar },
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "tags_array_terms",
                .law_id = .count,
                .metadata = array_terms_metadata,
            },
            .inputs = &.{.{ .step = 0 }},
        },
    };
    const array_terms_program = ir.TensorProgram{
        .steps = array_terms_steps[0..],
        .output = .{ .step = 1 },
    };
    const array_terms_partials = (try idx.scanDistributedPartialsForTensorProgram(&store, access_paths[0..], array_terms_program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, array_terms_partials);
    const array_axis = try token.canonicalTupleAlloc(alloc, &.{ "array", "" });
    defer alloc.free(array_axis);
    try std.testing.expectEqual(@as(usize, 1), array_terms_partials.len);
    try std.testing.expectEqualStrings(array_axis, array_terms_partials[0].canonical_axis);
    try std.testing.expectEqualStrings("tags_array_terms", array_terms_partials[0].metric);
    try std.testing.expectEqual(law_mod.Id.count, array_terms_partials[0].law_id);
    try std.testing.expectEqualStrings("3", array_terms_partials[0].value);
}

test "algebraic pathfact fold constraints preserve scalar kind" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    var idx = try Index.open(alloc, "alg_pathfact_typed_constraint",
        \\{"version":1,"table":"docs","materializations":[]}
    );
    defer idx.close();

