test "algebraic index maintains temporal bucket window join aggregate" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "mixed",
        \\  "group_fields": [
        \\    {"name":"kind","path":"kind","type":"string"},
        \\    {"name":"customer_id","path":"customer_id","type":"string"},
        \\    {"name":"id","path":"id","type":"string"},
        \\    {"name":"region","path":"region","type":"string"}
        \\  ],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "time_fields": [
        \\    {"name":"order_time","path":"order_time","type":"datetime"},
        \\    {"name":"profile_time","path":"profile_time","type":"datetime"}
        \\  ],
        \\  "joins": [
        \\    {"name":"orders_profiles","left_fields":["customer_id"],"right_fields":["id"],"left_type_field":"kind","left_type_value":"order","right_type_field":"kind","right_type_value":"profile","left_time_field":"order_time","right_time_field":"profile_time","temporal_bucket":"hour","temporal_window_seconds":1800}
        \\  ],
        \\  "materializations": [
        \\    {"name":"sum_by_region","op":"sum","join":"orders_profiles","group_by":["region"],"measure":"amount","group_side":"right","measure_side":"left"}
        \\  ]
        \\}
    ;
    var idx = try Index.open(alloc, "alg_temporal_join", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "profile1", .action = .upsert, .cleaned_value = "{\"kind\":\"profile\",\"id\":\"c1\",\"region\":\"west\",\"profile_time\":\"2026-05-10T10:30:00Z\"}" },
        .{ .key = "order1", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer_id\":\"c1\",\"amount\":25,\"order_time\":\"2026-05-10T10:00:00Z\"}" },
        .{ .key = "order2", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer_id\":\"c1\",\"amount\":50,\"order_time\":\"2026-05-10T10:31:00Z\"}" },
        .{ .key = "order3", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer_id\":\"c1\",\"amount\":75,\"order_time\":\"2026-05-10T09:59:00Z\"}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });
    const region_token = try idx.constraintTokenAlloc(alloc, "region", "west");
    defer alloc.free(region_token);
    const group = try token.canonicalTupleAlloc(alloc, &.{region_token});
    defer alloc.free(group);
    try std.testing.expectEqual(@as(f64, 75), (try idx.numericValue(&store, "sum_by_region", group)).?);

    var status_value = idx.status();
    try std.testing.expect(status_value.doc_join_fact_ref_write_count >= 4);

    var ref_read_txn = try store.beginReadTxn();
    var ref_cursor = try ref_read_txn.openCursor();
    const docjf_prefix = try idx.keyAlloc(&.{ "docjf", "profile1", "orders_profiles", "r" });
    defer alloc.free(docjf_prefix);
    const docjf_before = try ref_cursor.seekAtOrAfter(docjf_prefix);
    try std.testing.expect(docjf_before != null and std.mem.startsWith(u8, docjf_before.?.key, docjf_prefix));
    ref_cursor.close();
    ref_read_txn.abort();

    const deletes = [_][]const u8{"profile1"};
    try idx.applyBatch(&store, .{ .deleted_keys = deletes[0..] });
    try std.testing.expect((try idx.numericValue(&store, "sum_by_region", group)) == null);

    ref_read_txn = try store.beginReadTxn();
    ref_cursor = try ref_read_txn.openCursor();
    const docjf_after = try ref_cursor.seekAtOrAfter(docjf_prefix);
    try std.testing.expect(docjf_after == null or !std.mem.startsWith(u8, docjf_after.?.key, docjf_prefix));
    ref_cursor.close();
    ref_read_txn.abort();

    status_value = idx.status();
    try std.testing.expect(status_value.doc_join_fact_ref_delete_count >= 1);
}

