    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "order_early", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer_id\":\"c1\",\"amount\":100,\"order_time\":\"2026-05-10T09:00:00Z\"}" },
        .{ .key = "order_edge", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer_id\":\"c1\",\"amount\":25,\"order_time\":\"2026-05-10T10:00:00Z\"}" },
        .{ .key = "order_inside", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer_id\":\"c1\",\"amount\":50,\"order_time\":\"2026-05-10T10:45:00Z\"}" },
        .{ .key = "order_late", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer_id\":\"c1\",\"amount\":200,\"order_time\":\"2026-05-10T12:00:00Z\"}" },
        .{ .key = "profile1", .action = .upsert, .cleaned_value = "{\"kind\":\"profile\",\"id\":\"c1\",\"region\":\"west\",\"profile_time\":\"2026-05-10T10:30:00Z\"}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });
    const region_token = try idx.constraintTokenAlloc(alloc, "region", "west");
    defer alloc.free(region_token);
    const group = try token.canonicalTupleAlloc(alloc, &.{region_token});
    defer alloc.free(group);
    try std.testing.expectEqual(@as(f64, 75), (try idx.numericValue(&store, "sum_by_region", group)).?);
    const status_value = idx.status();
    try std.testing.expectEqual(@as(u64, 2), status_value.join_facts_scanned);
    try std.testing.expectEqual(@as(u64, 2), status_value.join_facts_matched);
}

test "algebraic lsm bulk ingest uses cursor-capable join matching" {
    const alloc = std.testing.allocator;
    var backend = lsm_backend.Backend.init(alloc, .{ .flush_threshold = 2 });
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{ .name = "docs" });
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "mixed",
        \\  "group_fields": [
        \\    {"name":"kind","path":"kind","type":"string"},
        \\    {"name":"customer","path":"customer","type":"string"},
        \\    {"name":"region","path":"region","type":"string"}
        \\  ],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "joins": [
        \\    {"name":"orders_customers","left_fields":["customer"],"right_fields":["customer"],"left_type_field":"kind","left_type_value":"order","right_type_field":"kind","right_type_value":"customer","max_fanout":8}
        \\  ],
        \\  "materializations": [
        \\    {"name":"sum_by_region","op":"sum","join":"orders_customers","group_by":["region"],"measure":"amount","group_side":"right","measure_side":"left"}
        \\  ]
        \\}
    ;
    var idx = try Index.open(alloc, "alg_lsm_bulk_join_cursor", cfg);
    defer idx.close();

    const customers = [_]derived_types.DerivedDocument{
        .{ .key = "c1", .action = .upsert, .cleaned_value = "{\"kind\":\"customer\",\"customer\":\"c1\",\"region\":\"west\"}" },
        .{ .key = "c2", .action = .upsert, .cleaned_value = "{\"kind\":\"customer\",\"customer\":\"c2\",\"region\":\"east\"}" },
    };
    try idx.applyBatchWithOptions(&store, .{ .documents = customers[0..] }, .{ .batch_options = .{ .mode = .bulk_ingest } });

    const orders = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer\":\"c1\",\"amount\":10}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer\":\"c1\",\"amount\":20}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer\":\"c2\",\"amount\":7}" },
    };
    try idx.applyBatchWithOptions(&store, .{ .documents = orders[0..] }, .{ .batch_options = .{ .mode = .bulk_ingest } });

    const west_token = try idx.constraintTokenAlloc(alloc, "region", "west");
    defer alloc.free(west_token);
    const west_group = try token.canonicalTupleAlloc(alloc, &.{west_token});
    defer alloc.free(west_group);
    const east_token = try idx.constraintTokenAlloc(alloc, "region", "east");
    defer alloc.free(east_token);
    const east_group = try token.canonicalTupleAlloc(alloc, &.{east_token});
    defer alloc.free(east_group);

    try std.testing.expectEqual(@as(f64, 30), (try idx.numericValue(&store, "sum_by_region", west_group)).?);
    try std.testing.expectEqual(@as(f64, 7), (try idx.numericValue(&store, "sum_by_region", east_group)).?);

    const overwrite = [_]derived_types.DerivedDocument{
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer\":\"c1\",\"amount\":40}" },
    };
    try idx.applyBatchWithOptions(&store, .{ .documents = overwrite[0..] }, .{ .batch_options = .{ .mode = .bulk_ingest } });
    try std.testing.expectEqual(@as(f64, 60), (try idx.numericValue(&store, "sum_by_region", west_group)).?);

    const status_value = idx.status();
    try std.testing.expect(status_value.join_facts_scanned >= 3);
    try std.testing.expect(status_value.join_facts_matched >= 3);
    const write_stats = backend.snapshotWriteStats();
    try std.testing.expect(write_stats.flushes + write_stats.sorted_ingest_runs >= 1);
}

test "algebraic index can execute bounded derived distributive join fold from join facts" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "mixed",
        \\  "group_fields": [
        \\    {"name":"kind","path":"kind","type":"string"},
        \\    {"name":"customer","path":"customer","type":"string"},
        \\    {"name":"region","path":"region","type":"string"}
        \\  ],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "joins": [
        \\    {"name":"orders_customers","left_fields":["customer"],"right_fields":["customer"],"left_type_field":"kind","left_type_value":"order","right_type_field":"kind","right_type_value":"customer","max_fanout":8}
        \\  ],
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_derived_join", cfg);
    defer idx.close();

    const docs = [_]derived_types.DerivedDocument{
        .{ .key = "c1", .action = .upsert, .cleaned_value = "{\"kind\":\"customer\",\"customer\":\"c1\",\"region\":\"west\"}" },
        .{ .key = "c2", .action = .upsert, .cleaned_value = "{\"kind\":\"customer\",\"customer\":\"c2\",\"region\":\"east\"}" },
        .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer\":\"c1\",\"amount\":10}" },
        .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer\":\"c1\",\"amount\":20}" },
        .{ .key = "o3", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer\":\"c2\",\"amount\":7}" },
    };
    try idx.applyBatch(&store, .{ .documents = docs[0..] });

    const sum_by_region_request = DerivedJoinFoldRequest{
        .join = .{ .name = "orders_customers", .group_side = "right", .measure_side = "left" },
        .op = .sum,
        .group_by = &.{"region"},
        .measure = "amount",
    };
    const entries = (try idx.scanDerivedJoinFoldEntries(&store, sum_by_region_request)).?;
    defer {
        for (entries) |*entry| entry.deinit(alloc);
        if (entries.len > 0) alloc.free(entries);
    }

    const west_token = try idx.constraintTokenAlloc(alloc, "region", "west");
    defer alloc.free(west_token);
    const west_group = try token.canonicalTupleAlloc(alloc, &.{west_token});
    defer alloc.free(west_group);
    const east_token = try idx.constraintTokenAlloc(alloc, "region", "east");
    defer alloc.free(east_token);
    const east_group = try token.canonicalTupleAlloc(alloc, &.{east_token});
    defer alloc.free(east_group);

    var found_west = false;
    var found_east = false;
    for (entries) |entry| {
        if (std.mem.eql(u8, entry.group_key, west_group)) {
            found_west = true;
            try std.testing.expectEqual(@as(f64, 30), try algebra.parseF64(entry.value));
        } else if (std.mem.eql(u8, entry.group_key, east_group)) {
            found_east = true;
            try std.testing.expectEqual(@as(f64, 7), try algebra.parseF64(entry.value));
        }
    }
    try std.testing.expect(found_west);
    try std.testing.expect(found_east);

    const join_access_fragments = [_]ir.TensorFragment{ .slice, .join };
    const join_fact_output_dims = [_]ir.Dimension{ .src, .dst, .scalar, .time, .bucket };
    const join_access_paths = [_]ir.PhysicalAccessPath{.{
        .owner = "orders_customers",
        .layout = .join_fact_rows,
        .fragments = join_access_fragments[0..],
        .output_dims = join_fact_output_dims[0..],
    }};
    const join_metadata = try derivedJoinFoldMetadataAlloc(alloc, sum_by_region_request);
    defer alloc.free(join_metadata);
    const join_step_inputs = [_]ir.TensorProgramRef{.{ .step = 0 }};
    const join_program_steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = join_fact_output_dims[0..],
            .semantic_id = "orders_customers",
            .owner = "orders_customers",
            .layout = .join_fact_rows,
        } },
        .{
            .expr = .{
                .fragment = .join,
                .input_dims = join_fact_output_dims[0..],
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "sum_by_region",
                .law_id = .sum,
                .metadata = join_metadata,
            },
            .inputs = join_step_inputs[0..],
        },
    };
    const join_program = ir.TensorProgram{
        .steps = join_program_steps[0..],
        .output = .{ .step = 1 },
    };
    const partials = (try idx.scanDistributedPartialsForTensorProgram(&store, join_access_paths[0..], join_program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, partials);
    try std.testing.expectEqual(@as(usize, 2), partials.len);
    var found_west_partial = false;
    var found_east_partial = false;
    for (partials) |partial| {
        try std.testing.expectEqual(law_mod.Id.sum, partial.law_id);
        try std.testing.expectEqualStrings("sum_by_region", partial.metric);
        if (std.mem.eql(u8, partial.canonical_axis, west_group)) {
            found_west_partial = true;
            try std.testing.expectEqual(@as(f64, 30), try algebra.parseF64(partial.value));
        } else if (std.mem.eql(u8, partial.canonical_axis, east_group)) {
            found_east_partial = true;
            try std.testing.expectEqual(@as(f64, 7), try algebra.parseF64(partial.value));
        }
    }
    try std.testing.expect(found_west_partial);
    try std.testing.expect(found_east_partial);

    const low_range_request = DerivedJoinFoldRequest{
        .join = .{ .name = "orders_customers", .group_side = "right", .measure_side = "left" },
        .op = .count,
        .range_field = "amount",
        .range_role = .measure,
        .range_kind = .numeric,
        .range_start = "0",
        .range_end = "20",
    };
    const high_range_request = DerivedJoinFoldRequest{
        .join = .{ .name = "orders_customers", .group_side = "right", .measure_side = "left" },
        .op = .count,
        .range_field = "amount",
        .range_role = .measure,
        .range_kind = .numeric,
        .range_start = "20",
        .range_end = "40",
    };
    const low_range_metadata = try derivedJoinFoldMetadataAlloc(alloc, low_range_request);
    defer alloc.free(low_range_metadata);
    const high_range_metadata = try derivedJoinFoldMetadataAlloc(alloc, high_range_request);
    defer alloc.free(high_range_metadata);
    const range_program_steps = [_]ir.TensorProgramStep{
        .{ .expr = .{
            .fragment = .slice,
            .output_dims = join_fact_output_dims[0..],
            .semantic_id = "orders_customers",
            .owner = "orders_customers",
            .layout = .join_fact_rows,
        } },
        .{
            .expr = .{
                .fragment = .join,
                .input_dims = join_fact_output_dims[0..],
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "amount_ranges",
                .law_id = .count,
                .metadata = low_range_metadata,
            },
            .inputs = join_step_inputs[0..],
        },
        .{
            .expr = .{
                .fragment = .join,
                .input_dims = join_fact_output_dims[0..],
                .output_dims = &distributed_bucket_scalar_output_dims,
                .semantic_id = "amount_ranges",
                .law_id = .count,
                .metadata = high_range_metadata,
            },
            .inputs = join_step_inputs[0..],
        },
    };
    const range_program_outputs = [_]ir.TensorProgramRef{ .{ .step = 1 }, .{ .step = 2 } };
    const range_program = ir.TensorProgram{
        .steps = range_program_steps[0..],
        .output = .{ .step = 1 },
        .outputs = range_program_outputs[0..],
    };
    const range_partials = (try idx.scanDistributedPartialsForTensorProgram(&store, join_access_paths[0..], range_program)) orelse return error.TestUnexpectedResult;
    defer distributed_mod.freePartials(alloc, range_partials);
    try std.testing.expectEqual(@as(usize, 2), range_partials.len);
    const low_axis = try token.canonicalTupleAlloc(alloc, &.{ "0", "20" });
    defer alloc.free(low_axis);
    const high_axis = try token.canonicalTupleAlloc(alloc, &.{ "20", "40" });
    defer alloc.free(high_axis);
    var found_low_range = false;
    var found_high_range = false;
    for (range_partials) |partial| {
        try std.testing.expectEqual(law_mod.Id.count, partial.law_id);
        try std.testing.expectEqualStrings("amount_ranges", partial.metric);
        if (std.mem.eql(u8, partial.canonical_axis, low_axis)) {
            found_low_range = true;
            try std.testing.expectEqual(@as(i64, 2), try algebra.parseI64(partial.value));
        } else if (std.mem.eql(u8, partial.canonical_axis, high_axis)) {
            found_high_range = true;
            try std.testing.expectEqual(@as(i64, 1), try algebra.parseI64(partial.value));
        }
    }
    try std.testing.expect(found_low_range);
    try std.testing.expect(found_high_range);

    const avg_entries = (try idx.scanDerivedJoinFoldEntries(&store, .{
        .join = .{ .name = "orders_customers", .group_side = "right", .measure_side = "left" },
        .op = .avg,
        .group_by = &.{"region"},
        .measure = "amount",
    })).?;
    defer {
        for (avg_entries) |*entry| entry.deinit(alloc);
        if (avg_entries.len > 0) alloc.free(avg_entries);
    }
    var found_west_avg = false;
    var found_east_avg = false;
    for (avg_entries) |entry| {
        if (std.mem.eql(u8, entry.group_key, west_group)) {
            found_west_avg = true;
            const avg = try algebra.parseAvg(entry.value);
            try std.testing.expectEqual(@as(f64, 30), avg.sum);
            try std.testing.expectEqual(@as(i64, 2), avg.count);
        } else if (std.mem.eql(u8, entry.group_key, east_group)) {
            found_east_avg = true;
            const avg = try algebra.parseAvg(entry.value);
            try std.testing.expectEqual(@as(f64, 7), avg.sum);
            try std.testing.expectEqual(@as(i64, 1), avg.count);
        }
    }
    try std.testing.expect(found_west_avg);
    try std.testing.expect(found_east_avg);

    const min_entries = (try idx.scanDerivedJoinFoldEntries(&store, .{
        .join = .{ .name = "orders_customers", .group_side = "right", .measure_side = "left" },
        .op = .min,
        .group_by = &.{"region"},
        .measure = "amount",
    })).?;
    defer {
        for (min_entries) |*entry| entry.deinit(alloc);
        if (min_entries.len > 0) alloc.free(min_entries);
    }
    var found_west_min = false;
    var found_east_min = false;
    for (min_entries) |entry| {
        if (std.mem.eql(u8, entry.group_key, west_group)) {
            found_west_min = true;
            try std.testing.expectEqual(@as(f64, 10), try algebra.parseF64(entry.value));
        } else if (std.mem.eql(u8, entry.group_key, east_group)) {
            found_east_min = true;
            try std.testing.expectEqual(@as(f64, 7), try algebra.parseF64(entry.value));
        }
    }
    try std.testing.expect(found_west_min);
    try std.testing.expect(found_east_min);

    const max_entries = (try idx.scanDerivedJoinFoldEntries(&store, .{
        .join = .{ .name = "orders_customers", .group_side = "right", .measure_side = "left" },
        .op = .max,
        .group_by = &.{"region"},
        .measure = "amount",
    })).?;
    defer {
        for (max_entries) |*entry| entry.deinit(alloc);
        if (max_entries.len > 0) alloc.free(max_entries);
    }
    var found_west_max = false;
    var found_east_max = false;
    for (max_entries) |entry| {
        if (std.mem.eql(u8, entry.group_key, west_group)) {
            found_west_max = true;
            try std.testing.expectEqual(@as(f64, 20), try algebra.parseF64(entry.value));
        } else if (std.mem.eql(u8, entry.group_key, east_group)) {
            found_east_max = true;
            try std.testing.expectEqual(@as(f64, 7), try algebra.parseF64(entry.value));
        }
    }
    try std.testing.expect(found_west_max);
    try std.testing.expect(found_east_max);

    const west_constraint = [_]ir.Constraint{.{ .field = "region", .value = "west" }};
    const constrained_entries = (try idx.scanDerivedJoinFoldEntries(&store, .{
        .join = .{ .name = "orders_customers", .group_side = "right", .measure_side = "left" },
        .op = .sum,
        .measure = "amount",
        .constraints = west_constraint[0..],
    })).?;
    defer {
        for (constrained_entries) |*entry| entry.deinit(alloc);
        if (constrained_entries.len > 0) alloc.free(constrained_entries);
    }
    try std.testing.expectEqual(@as(usize, 1), constrained_entries.len);
    try std.testing.expectEqual(@as(f64, 30), try algebra.parseF64(constrained_entries[0].value));

    const join_key_constraint = [_]ir.Constraint{.{ .field = "customer", .value = "c1" }};
    const join_key_entries = (try idx.scanDerivedJoinFoldEntries(&store, .{
        .join = .{ .name = "orders_customers", .group_side = "right", .measure_side = "left" },
        .op = .count,
        .group_by = &.{"region"},
        .constraints = join_key_constraint[0..],
    })).?;
    defer {
        for (join_key_entries) |*entry| entry.deinit(alloc);
        if (join_key_entries.len > 0) alloc.free(join_key_entries);
    }
    try std.testing.expectEqual(@as(usize, 1), join_key_entries.len);
    try std.testing.expectEqualStrings(west_group, join_key_entries[0].group_key);
    try std.testing.expectEqual(@as(i64, 2), try algebra.parseI64(join_key_entries[0].value));
}

test "algebraic distributed derived join partials merge canonical axes across shards" {
