    const right_docs = [_]derived_types.DerivedDocument{
        .{ .key = "rc2", .action = .upsert, .cleaned_value = "{\"kind\":\"customer\",\"customer\":\"c2\",\"region\":\"east\"}" },
        .{ .key = "ro2", .action = .upsert, .cleaned_value = "{\"kind\":\"order\",\"customer\":\"c2\",\"amount\":4}" },
        .{ .key = "rc1", .action = .upsert, .cleaned_value = "{\"kind\":\"customer\",\"customer\":\"c1\",\"region\":\"west\"}" },
