test "algebraic index persists query shape observations and recommendations" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "adaptive": {"observe": true, "lazy_materialization": false, "min_observations": 2},
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_observe_store", cfg);
    defer idx.close();

    const constraints = [_]ir.Constraint{.{ .field = "tenant", .value = "t1" }};
    const query = ir.Query{
        .kind = .terms,
        .aggregation_name = "amount_by_customer",
        .bucket_field = "customer",
        .constraints = constraints[0..],
        .metric = .{ .name = "amount", .op = .sum, .field = "amount" },
    };
    idx.recordObservedQueryShapeWithStore(&store, query, "no_materialization");
    idx.recordObservedQueryShapeWithStore(&store, query, "no_materialization");

    const shape = try adaptive_mod.shapeKeyAlloc(alloc, query);
    defer alloc.free(shape);
    const obs_key = try adaptive_mod.observationKeyAlloc(alloc, idx.name, shape);
    defer alloc.free(obs_key);
    const recommendation = try adaptive_mod.recommendationAlloc(alloc, query);
    defer alloc.free(recommendation);
    const state_key = try adaptive_mod.materializationStateKeyAlloc(alloc, idx.name, recommendation);
    defer alloc.free(state_key);

    var txn = try store.beginReadTxn();
    const obs_payload = try txn.get(obs_key);
    const obs_parts = try token.decodeTupleAlloc(alloc, obs_payload);
    defer {
        for (obs_parts) |part| alloc.free(part);
        alloc.free(obs_parts);
    }
    try std.testing.expectEqualStrings("observation:v1", obs_parts[0]);
    try std.testing.expectEqualStrings("2", obs_parts[2]);
    try std.testing.expectEqualStrings("no_materialization", obs_parts[3]);
    try std.testing.expectEqualStrings("recommended", obs_parts[5]);

    const state_payload = try txn.get(state_key);
    const state_parts = try token.decodeTupleAlloc(alloc, state_payload);
    defer {
        for (state_parts) |part| alloc.free(part);
        alloc.free(state_parts);
    }
    txn.abort();
    try std.testing.expectEqualStrings("materialization-state:v1", state_parts[0]);
    try std.testing.expectEqualStrings("recommended", state_parts[2]);
    try std.testing.expectEqualStrings("2", state_parts[3]);

    const materialization_states = try idx.scanPersistedMaterializationStates(&store);
    defer {
        for (materialization_states) |*state| state.deinit(alloc);
        alloc.free(materialization_states);
    }
    try std.testing.expectEqual(@as(usize, 1), materialization_states.len);
    try std.testing.expectEqual(adaptive_mod.Lifecycle.recommended, materialization_states[0].lifecycle);
    try std.testing.expectEqual(@as(u64, 2), materialization_states[0].observation_count);
    try std.testing.expectEqualStrings(recommendation, materialization_states[0].recommendation);

    var reopened = try Index.open(alloc, "alg_observe_store", cfg);
    defer reopened.close();
    try reopened.loadPersistedObservations(&store);
    const status_value = reopened.status();
    try std.testing.expectEqual(@as(u64, 2), status_value.observed_query_shape_count);
    try std.testing.expectEqual(@as(u64, 2), status_value.recommendation_count);
    try std.testing.expect(status_value.last_observed_query_shape != null);
    try std.testing.expect(status_value.last_recommended_materialization != null);
}

test "algebraic adaptive observations decay across idle evaluation windows" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"}],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "adaptive": {"observe": true, "lazy_materialization": false, "min_observations": 2, "observation_decay_after_misses": 1, "observation_decay_retain_percent": 50},
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_adaptive_decay", cfg);
    defer idx.close();

    const query = ir.Query{
        .kind = .terms,
        .aggregation_name = "amount_by_customer",
        .bucket_field = "customer",
        .metric = .{ .name = "amount", .op = .sum, .field = "amount" },
    };
    for (0..4) |_| idx.recordObservedQueryShapeWithStore(&store, query, "no_materialization");
    try std.testing.expectEqual(@as(u64, 0), try idx.evaluateAdaptiveCandidates(&store, 0));
    try std.testing.expectEqual(@as(u64, 1), try idx.evaluateAdaptiveCandidates(&store, 0));

    const observations = try idx.scanPersistedQueryObservations(&store);
    defer {
        for (observations) |*observation| observation.deinit(alloc);
        alloc.free(observations);
    }
    try std.testing.expectEqual(@as(usize, 1), observations.len);
    try std.testing.expectEqual(@as(u64, 2), observations[0].count);

    const candidates = try idx.scanPersistedAdaptiveCandidates(&store);
    defer {
        for (candidates) |*candidate| candidate.deinit(alloc);
        alloc.free(candidates);
    }
    try std.testing.expectEqual(@as(usize, 1), candidates.len);
    try std.testing.expectEqual(@as(u64, 2), candidates[0].observation_count);
    try std.testing.expectEqual(@as(u64, 1), candidates[0].idle_miss_count);
    try std.testing.expectEqual(@as(u64, 2), candidates[0].generation);

    const history = try idx.scanPersistedAdaptiveDecisions(&store, 8);
    defer {
        for (history) |*entry| entry.deinit(alloc);
        alloc.free(history);
    }
    try std.testing.expectEqual(@as(usize, 2), history.len);
    try std.testing.expectEqual(@as(u64, 1), history[0].generation);
    try std.testing.expectEqual(@as(u64, 2), history[1].generation);
    try std.testing.expectEqualStrings("lazy_materialization_disabled", history[0].decision);
    try std.testing.expectEqualStrings("lazy_materialization_disabled", history[1].previous_decision);
    try std.testing.expectEqualStrings("lazy_materialization_disabled", history[1].decision);
    try std.testing.expect(history[1].score_delta < 0);
}

test "algebraic adaptive backfill builds tensor rows from doc facts" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
