}

test "algebraic adaptive dematerialization cleanup survives lsm reopen" {
    const alloc = std.testing.allocator;
    var memory_storage = lsm_storage_io.MemoryStorage.init(alloc);
    defer memory_storage.deinit();

    const root_dir = "/memory/algebraic-adaptive-cleanup";
    const cfg =
        \\{
        \\  "version": 1,
        \\  "table": "orders",
        \\  "group_fields": [{"name":"customer","path":"customer","type":"string"},{"name":"tenant","path":"tenant","type":"string"}],
        \\  "measure_fields": [{"name":"amount","path":"amount","type":"number"}],
        \\  "adaptive": {"observe": true, "lazy_materialization": true, "dematerialization": true, "min_observations": 1, "max_backfill_rows_per_tick": 10, "min_estimated_scan_rows_saved": 1, "dematerialize_after_observation_misses": 1},
        \\  "materializations": []
        \\}
    ;
    const constraints = [_]ir.Constraint{.{ .field = "tenant", .value = "t1" }};
    const query = ir.Query{
        .kind = .terms,
        .aggregation_name = "amount_by_customer",
        .bucket_field = "customer",
        .constraints = constraints[0..],
        .metric = .{ .name = "amount", .op = .sum, .field = "amount" },
    };
    const recommendation = try adaptive_mod.recommendationAlloc(alloc, query);
    defer alloc.free(recommendation);
    const materialization_id = try adaptive_mod.materializationIdAlloc(alloc, recommendation);
    defer alloc.free(materialization_id);

    {
        var backend = try lsm_backend.Backend.open(alloc, root_dir, .{
            .flush_threshold = 1,
            .storage = memory_storage.storage(),
        });
        defer backend.close();
        const runtime_store = try backend.runtimeStore(alloc, .{ .name = "docs" });
        var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
        defer store.close();

        var idx = try Index.open(alloc, "alg_adaptive_lsm_cleanup", cfg);
        defer idx.close();

        const docs = [_]derived_types.DerivedDocument{
            .{ .key = "o1", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"tenant\":\"t1\",\"amount\":10}" },
            .{ .key = "o2", .action = .upsert, .cleaned_value = "{\"customer\":\"alice\",\"tenant\":\"t1\",\"amount\":20}" },
        };
        try idx.applyBatch(&store, .{ .documents = docs[0..] });
        idx.recordObservedQueryShapeWithStore(&store, query, "no_materialization");
        try std.testing.expectEqual(@as(u64, 1), try idx.evaluateAdaptiveCandidates(&store, 0));
        try std.testing.expect(try idx.runAdaptiveWork(&store, 0) > 0);

        const customer_token = try idx.constraintTokenAlloc(alloc, "customer", "alice");
        defer alloc.free(customer_token);
        const tenant_token = try idx.constraintTokenAlloc(alloc, "tenant", "t1");
        defer alloc.free(tenant_token);
        const axes = try token.canonicalTupleAlloc(alloc, &.{ customer_token, tenant_token });
        defer alloc.free(axes);
        const raw = (try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, axes, null)).?;
        defer alloc.free(raw);
        try std.testing.expectEqual(@as(f64, 30), try algebra.parseF64(raw));

        try std.testing.expectEqual(@as(u64, 1), try idx.evaluateAdaptiveCandidates(&store, 0));
        const candidates = try idx.scanPersistedAdaptiveCandidates(&store);
        defer {
            for (candidates) |*candidate| candidate.deinit(alloc);
            alloc.free(candidates);
        }
        try std.testing.expectEqual(@as(usize, 1), candidates.len);
        try std.testing.expectEqual(adaptive_mod.Lifecycle.dematerialize_recommended, candidates[0].lifecycle);

        try std.testing.expect(try idx.runAdaptiveWork(&store, 0) > 0);
        const removed_raw = try idx.adaptiveTensorRawValueAlloc(&store, materialization_id, axes, null);
        defer if (removed_raw) |bytes| alloc.free(bytes);
        try std.testing.expect(removed_raw == null);
        try store.sync(true);
    }

    {
        var reopened_backend = try lsm_backend.Backend.open(alloc, root_dir, .{
            .flush_threshold = 1,
            .storage = memory_storage.storage(),
        });
        defer reopened_backend.close();
        const reopened_runtime_store = try reopened_backend.runtimeStore(alloc, .{ .name = "docs" });
        var reopened_store = try docstore_mod.DocStore.openRuntime(alloc, reopened_runtime_store);
        defer reopened_store.close();

        var reopened_idx = try Index.open(alloc, "alg_adaptive_lsm_cleanup", cfg);
        defer reopened_idx.close();

        const customer_token = try reopened_idx.constraintTokenAlloc(alloc, "customer", "alice");
        defer alloc.free(customer_token);
        const tenant_token = try reopened_idx.constraintTokenAlloc(alloc, "tenant", "t1");
        defer alloc.free(tenant_token);
        const axes = try token.canonicalTupleAlloc(alloc, &.{ customer_token, tenant_token });
        defer alloc.free(axes);

        const removed_raw = try reopened_idx.adaptiveTensorRawValueAlloc(&reopened_store, materialization_id, axes, null);
        defer if (removed_raw) |bytes| alloc.free(bytes);
        try std.testing.expect(removed_raw == null);

        const cleaned_progress = try reopened_idx.scanPersistedAdaptiveProgress(&reopened_store);
        defer {
            for (cleaned_progress) |*progress| progress.deinit(alloc);
            if (cleaned_progress.len > 0) alloc.free(cleaned_progress);
        }
        try std.testing.expectEqual(@as(usize, 0), cleaned_progress.len);

        const cleaned_candidates = try reopened_idx.scanPersistedAdaptiveCandidates(&reopened_store);
        defer {
            for (cleaned_candidates) |*candidate| candidate.deinit(alloc);
            if (cleaned_candidates.len > 0) alloc.free(cleaned_candidates);
        }
        try std.testing.expectEqual(@as(usize, 0), cleaned_candidates.len);

        const stale_states = try reopened_idx.scanPersistedMaterializationStates(&reopened_store);
        defer {
            for (stale_states) |*state| state.deinit(alloc);
            alloc.free(stale_states);
        }
        try std.testing.expectEqual(@as(usize, 1), stale_states.len);
        try std.testing.expectEqual(adaptive_mod.Lifecycle.stale, stale_states[0].lifecycle);
    }
}

test "algebraic adaptive scans skip corrupt sidecar state rows" {
    const alloc = std.testing.allocator;
    var backend = @import("../../mem_backend.zig").Backend.init(alloc, .{});
    defer backend.close();
    const runtime_store = try backend.runtimeStore(alloc, .{});
    var store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store);
    defer store.close();

    const cfg =
        \\{
        \\  "version": 2,
        \\  "table": "orders",
        \\  "schema_version": 1,
        \\  "capability_fingerprint": "schema-a",
        \\  "adaptive": {"observe": true, "lazy_materialization": true},
        \\  "materializations": []
        \\}
    ;
    var idx = try Index.open(alloc, "alg_adaptive_corrupt", cfg);
    defer idx.close();

    const good_recommendation = "recommendation:good";
    const corrupt_recommendation = "recommendation:corrupt";
    const good_key = try adaptive_mod.materializationStateKeyAlloc(alloc, idx.name, good_recommendation);
    defer alloc.free(good_key);
    const corrupt_key = try adaptive_mod.materializationStateKeyAlloc(alloc, idx.name, corrupt_recommendation);
    defer alloc.free(corrupt_key);
    const good_payload = try idx.encodePersistedMaterializationStateAlloc(good_recommendation, .ready, 3);
    defer alloc.free(good_payload);

    var txn = try store.beginWriteTxn();
    errdefer txn.abort();
    try txn.put(good_key, good_payload);
    try txn.put(corrupt_key, "not-a-materialization-state");
    try txn.commit();

    const states = try idx.scanPersistedMaterializationStates(&store);
    defer {
        for (states) |*state| state.deinit(alloc);
        alloc.free(states);
    }
    try std.testing.expectEqual(@as(usize, 1), states.len);
    try std.testing.expectEqualStrings(good_recommendation, states[0].recommendation);
    try std.testing.expectEqual(adaptive_mod.Lifecycle.ready, states[0].lifecycle);

    var read_txn = try store.beginReadTxn();
    defer read_txn.abort();
    try std.testing.expect(try idx.persistedMaterializationStateReadyTxn(&read_txn, good_recommendation));
    try std.testing.expect(!try idx.persistedMaterializationStateReadyTxn(&read_txn, corrupt_recommendation));
}

